INSERT INTO categories VALUES(52,'Bottes','bottes-moto',1,'https://motopaco.ma/wp-content/uploads/2025/02/boots-1.png','Bottes',unistr('<div class="hero-header page-padding">\u000d\u000a<div class="regular-title">\u000d\u000a<div class="container hero-header-container"><header class="row woocommerce-products-header">\u000d\u000a<div class="col-lg-8">\u000d\u000a<div class="term-description">\u000d\u000a\u000d\u000a<span style="color: #000000">TCX fusionne la tradition artisanale de la cordonnerie avec la science moderne pour concevoir des chaussures de moto qui offrent une sensation, une liberté, site officiel de TCX Maroc</span>\u000d\u000a\u000d\u000a</div>\u000d\u000a</div>\u000d\u000a</header></div>\u000d\u000a</div>\u000d\u000a</div>'),0,0);
