INSERT INTO products VALUES(32,'DAINESE D-THROTTLE BACKPACK STEALTH-BLACK','dainese-d-throttle-backpack-stealth-black',unistr('<p>Le sac à dos Dainese D-Throttle Backpack Stealth Black allie style, praticité et robustesse pour répondre aux besoins des motards et des utilisateurs urbains. Conçu avec des matériaux résistants et durables, il offre un espace de rangement généreux permettant de transporter facilement vos effets personnels, équipements électroniques et accessoires du quotidien.<br />\u000aSon design ergonomique assure un excellent confort de portage grâce à ses bretelles réglables et rembourrées, tandis que son dos matelassé favorise une meilleure répartition de la charge. Doté de plusieurs compartiments et poches de rangement, il permet une organisation optimale de vos affaires lors de vos déplacements à moto, au travail ou en voyage.<br />\u000aAvec sa finition Stealth Black élégante et discrète, ce sac à dos reflète parfaitement l’esprit sportif et moderne de Dainese.<br />\u000aCaractéristiques principales :<br />\u000aGrande capacité de rangement<br />\u000aCompartiments multiples pour une organisation efficace<br />\u000aBretelles ergonomiques réglables et rembourrées<br />\u000aDos matelassé pour un meilleur confort<br />\u000aMatériaux résistants et durables<br />\u000aDesign moderne et finition Stealth Black<br />\u000aIdéal pour les trajets quotidiens, les voyages et l’usage moto</p>\u000a'),'',39,753,1699.0,1399.0,NULL,NULL,'published','DAINESE D-THROTTLE BACKPACK STEALTH-BLACK','DAINESE D-THROTTLE BACKPACK STEALTH-BLACK au Maroc. Achetez au meilleur prix chez MOTO PACO.',108,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(33,'T-shirt Dainese Quick Dry noir','t-shirt-dainese-quick-dry-noir',unistr('<p>Le T-shirt Dainese Quick Dry Noir est un vêtement technique conçu pour offrir un excellent confort lors des activités sportives, de la moto ou d’un usage quotidien. Fabriqué dans un tissu respirant à séchage rapide, il évacue efficacement l’humidité et la transpiration afin de maintenir la peau au sec même lors d’efforts prolongés.<br />\u000aSa coupe ergonomique assure une grande liberté de mouvement, tandis que sa matière légère procure une sensation agréable tout au long de la journée. Son design sobre et élégant, rehaussé du logo Dainese, en fait un choix polyvalent qui s’adapte aussi bien aux équipements sportifs qu’aux tenues décontractées.<br />\u000aCaractéristiques principales :<br />\u000aTissu technique à séchage rapide (Quick Dry)<br />\u000aExcellente respirabilité et évacuation de l’humidité<br />\u000aMatière légère et confortable<br />\u000aCoupe ergonomique favorisant la liberté de mouvement<br />\u000aColoris noir polyvalent et élégant<br />\u000aIdéal pour la pratique sportive, la moto et les activités de plein air<br />\u000aUn t-shirt performant et confortable, pensé pour accompagner les utilisateurs actifs dans toutes leurs activités.</p>\u000a'),'',46,753,599.0,499.0,NULL,NULL,'published','T-shirt Dainese Quick Dry noir','T-shirt Dainese Quick Dry noir au Maroc. Achetez au meilleur prix chez MOTO PACO.',125,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(34,'Dainese D-Storm Backpack','dainese-d-storm-backpack',unistr('<p>Le Dainese D-Storm Backpack est un sac à dos moto étanche conçu pour les motards et les amateurs d’activités de plein air qui recherchent une protection maximale contre les intempéries. Grâce à sa construction imperméable avec coutures soudées et fermeture à enroulement (roll-top), il protège efficacement vos effets personnels de la pluie, de l’humidité et des projections d’eau.<br />\u000aAvec une capacité de 26 litres, ce sac offre un espace généreux pour transporter vos affaires quotidiennes, votre équipement de voyage ou votre matériel de travail. Il est équipé d’un panneau d’organisation amovible compatible avec la plupart des ordinateurs portables jusqu’à 15 pouces, ainsi que de trois poches extérieures résistantes à l’eau pour garder vos accessoires à portée de main.<br />\u000aSon design aérodynamique réduit la résistance au vent pendant la conduite, tandis que le dos rembourré avec système de ventilation améliore le confort lors des longs trajets. Des inserts réfléchissants augmentent également la visibilité du motard dans des conditions de faible luminosité.<br />\u000aCaractéristiques principales<br />\u000aCapacité : 26 litres<br />\u000aConstruction 100 % étanche avec coutures soudées<br />\u000aFermeture roll-top imperméable<br />\u000aCompartiment avec panneau organisateur amovible<br />\u000aCompatible avec la plupart des ordinateurs portables 15 pouces<br />\u000aTrois poches extérieures résistantes à l’eau<br />\u000aDos rembourré avec circulation d’air<br />\u000aInserts réfléchissants pour une meilleure visibilité<br />\u000aDesign aérodynamique adapté à la moto<br />\u000aMatière : nylon 420D laminé TPU<br />\u000aPoids : environ 1,13 kg<br />\u000aCouleur : Stealth Black (Noir)</p>\u000a'),'',39,753,2299.0,1599.0,NULL,NULL,'published','Dainese D-Storm Backpack','Dainese D-Storm Backpack au Maroc. Achetez au meilleur prix chez MOTO PACO.',88,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(35,'Givi Leg Wallet Bag Easy-T EASY09S','givi-leg-wallet-bag-easy09s',unistr('<p>La Givi Easy-T EASY09S est une sacoche de jambe compacte de 1,5 litre, spécialement conçue pour les motards qui souhaitent garder leurs objets essentiels à portée de main sans encombrer les poches de leur veste ou pantalon. Son format discret permet de transporter facilement un smartphone, un portefeuille, des papiers, des clés ou d''autres petits accessoires indispensables lors de vos déplacements.<br />\u000aFabriquée en polyester Ripstop 600D résistant, elle est équipée d''une sangle de taille réglable et amovible ainsi que d''une sangle de cuisse ajustable assurant un maintien stable et confortable pendant la conduite. Son dos antidérapant améliore l''adhérence à la jambe et limite les mouvements indésirables.<br />\u000aLa sacoche dispose d''un compartiment principal spacieux, d''une poche avant à accès rapide avec porte-clés intégré, ainsi que d''une housse de pluie fournie pour protéger efficacement son contenu en cas d''intempéries. Des inserts réfléchissants renforcent également la visibilité du motard.<br />\u000aCaractéristiques principales<br />\u000aCapacité : 1,5 litre<br />\u000aPolyester Ripstop 600D haute résistance<br />\u000aCompartiment principal avec rangement pratique<br />\u000aPoche avant avec porte-clés intégré<br />\u000aSangle de taille réglable et amovible<br />\u000aSangle de cuisse réglable<br />\u000aDos antidérapant pour une meilleure stabilité<br />\u000aHousse de pluie incluse<br />\u000aInserts réfléchissants pour une visibilité accrue<br />\u000aCouleur : Noir</p>\u000a'),'',40,756,399.0,399.0,NULL,NULL,'published','Givi Leg Wallet Bag Easy-T EASY09S','Givi Leg Wallet Bag Easy-T EASY09S au Maroc. Achetez au meilleur prix chez MOTO PACO.',115,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(36,'Housse de Moto Givi S204 noir','housse-moto-givi-s204-noir',unistr('<p>La Housse de Moto Givi S204 Noir est une housse d’intérieur fabriquée en tissu élastique de haute qualité, conçue pour offrir une protection optimale contre la poussière, les rayures et les salissures lorsque votre moto est stationnée dans un garage ou un espace couvert. Grâce à sa matière extensible, elle épouse parfaitement les formes de la moto pour un ajustement précis et élégant. Elle convient à une large gamme de motos, des scooters GT aux motos sportives et routières, même équipées de valises latérales ou d’un top case. Facile à plier et à ranger, elle occupe très peu d’espace et intègre un logo GIVI réfléchissant sur le côté pour une finition soignée. Ses dimensions généreuses assurent une couverture complète du véhicule.</p>\u000a'),'',25,756,749.0,749.0,NULL,NULL,'published','Housse de Moto Givi S204 noir','Housse de Moto Givi S204 noir au Maroc. Achetez au meilleur prix chez MOTO PACO.',137,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(37,'GIVI ELITE 2L HYDRAPAK','givi-elite-2l-hydrapak',unistr('<p>Le GIVI Elite 2L HydraPak est une poche à eau d''une capacité de 2 litres, conçue pour être utilisée dans les sacs à dos compatibles avec un passage de tuyau d''hydratation. Elle est particulièrement adaptée aux activités tout-terrain (Off-Road) et aux longues sorties à moto. robuste lui permet de résister aux conditions les plus exigeantes.</p>\u000a'),'',16,756,449.0,449.0,NULL,NULL,'published','GIVI ELITE 2L HYDRAPAK','GIVI ELITE 2L HYDRAPAK au Maroc. Achetez au meilleur prix chez MOTO PACO.',107,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(38,'GIVI GRT721B MODULAR LOADING SYSTEM','givi-grt721b-modular-loading-system',unistr('<p>Le GIVI GRT721B Modular Loading System est un système modulable conçu pour optimiser le transport et le rangement sur votre moto. Il permet de combiner et d’adapter plusieurs sacs et accessoires GIVI pour créer une solution de stockage personnalisée, sécurisée et pratique selon vos besoins.<br />\u000aGrâce à ce système, chaque élément peut être facilement fixé, retiré ou remplacé, offrant une flexibilité maximale pour les trajets urbains comme pour les longues escapades. Idéal pour les motards qui recherchent organisation et efficacité dans le transport de leurs affaires.<br />\u000aCaractéristiques principales<br />\u000aSystème modulaire compatible avec les sacs GIVI GRT<br />\u000aPermet de combiner plusieurs sacs pour un rangement personnalisé<br />\u000aFixation sécurisée et stable sur la moto<br />\u000aFacile à installer et à retirer<br />\u000aMatériaux résistants et durables pour un usage quotidien ou intensif<br />\u000aPoints forts<br />\u000aFlexibilité maximale pour transporter vos affaires<br />\u000aOrganisation modulable selon vos besoins<br />\u000aAdapté aux trajets urbains et aux longues distances<br />\u000aCompatible avec différents sacs et accessoires GIVI<br />\u000aDesign robuste et fiable<br />\u000aLe GIVI GRT721B Modular Loading System est l’accessoire parfait pour les motards souhaitant un système de transport modulable, sécurisé et pratique, capable de s’adapter à toutes les configurations et besoins de voyage.</p>\u000a'),'',51,756,4999.0,4299.0,NULL,NULL,'published','GIVI GRT721B MODULAR LOADING SYSTEM','GIVI GRT721B MODULAR LOADING SYSTEM au Maroc. Achetez au meilleur prix chez MOTO PACO.',101,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(39,'EASYSH SMART PHONE HOLDER FOR EASY-T BAGS','easysh-smart-phone-holder-easy-t-bags',unistr('<p>Le EASYSH Smart Phone Holder est un accessoire pratique conçu pour fixer votre smartphone sur les sacs EASY-T de GIVI. Il offre une solution sécurisée et accessible pour garder votre téléphone à portée de main lors de vos trajets à moto, tout en le protégeant des vibrations et des mouvements.<br />\u000aFacile à installer sur les sacs EASY-T, ce support garantit que votre appareil reste stable et bien en place, que vous rouliez en ville ou sur route ouverte. Idéal pour l’utilisation de GPS, applications de navigation ou pour avoir votre téléphone accessible en toute sécurité.<br />\u000aCaractéristiques principales<br />\u000aSupport conçu pour smartphones, compatible avec tous les sacs EASY-T GIVI<br />\u000aInstallation rapide et sécurisée<br />\u000aProtection contre les vibrations et les chocs légers<br />\u000aAccès facile à l’écran et aux commandes tactiles<br />\u000aLéger et robuste, conçu pour durer<br />\u000aPoints forts<br />\u000aPermet d’utiliser le smartphone en toute sécurité sur la moto<br />\u000aCompatible avec tous les sacs EASY-T de GIVI<br />\u000aInstallation et retrait simples et rapides<br />\u000aIdéal pour le GPS et les applications de navigation<br />\u000aLe EASYSH Smart Phone Holder est l’accessoire parfait pour les motards souhaitant garder leur smartphone accessible et protégé lorsqu’il est utilisé avec un sac EASY-T.</p>\u000a'),'',51,13,129.0,129.0,NULL,NULL,'published','EASYSH SMART PHONE HOLDER FOR EASY-T BAGS','EASYSH SMART PHONE HOLDER FOR EASY-T BAGS au Maroc. Achetez au meilleur prix chez MOTO PACO.',85,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(40,'Dainese Tempest 3 D-Dry Pants Tempest 3 D-Dry Pants Hombre','dainese-tempest-3-d-dry-pants-homme',unistr('<p>Le Dainese Tempest 3 D-Dry Pants Homme est un pantalon moto touring conçu pour offrir une protection optimale et un confort maximal en toutes saisons. Idéal pour les longs trajets et les voyages à moto, il combine imperméabilité, respirabilité et isolation thermique dans un design robuste et fonctionnel.<br />\u000aGrâce à la membrane D-Dry®, ce pantalon garantit une excellente protection contre la pluie et le vent tout en assurant une bonne gestion de l’humidité pour rester au sec et à l’aise dans toutes les conditions. Sa conception technique en fait un choix fiable pour les motards qui roulent toute l’année.<br />\u000aLe Tempest 3 D-Dry est équipé de protections certifiées aux genoux, avec la possibilité d’ajouter des protections aux hanches pour un niveau de sécurité supérieur. Sa construction ergonomique et ses inserts extensibles offrent une grande liberté de mouvement, même lors des longues heures de conduite.<br />\u000aCaractéristiques principales<br />\u000aMembrane D-Dry® imperméable, respirante et coupe-vent<br />\u000aPantalon moto touring homme toutes saisons<br />\u000aProtections homologuées aux genoux<br />\u000aPrédisposition pour protections hanches<br />\u000aDoublure thermique amovible<br />\u000aConstruction résistante et durable<br />\u000aInserts extensibles pour plus de confort<br />\u000aAjustements à la taille et aux chevilles<br />\u000aPoints forts<br />\u000aProtection efficace contre pluie, vent et froid<br />\u000aConfort optimal pour longs trajets<br />\u000aUtilisation toutes saisons<br />\u000aSécurité certifiée Dainese<br />\u000aGrande liberté de mouvement<br />\u000aLe Dainese Tempest 3 D-Dry Pants Homme est idéal pour les motards voyageurs recherchant un pantalon touring imperméable, confortable et protecteur pour rouler en toute confiance toute l’année.</p>\u000a'),'',33,753,2799.0,2799.0,NULL,NULL,'published','Dainese Tempest 3 D-Dry Pants Tempest 3 D-Dry Pants Hombre','Dainese Tempest 3 D-Dry Pants Tempest 3 D-Dry Pants Hombre au Maroc. Achetez au meilleur prix chez MOTO PACO.',107,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(41,'Dainese Veloce D-Dry Veste textile moto','dainese-veloce-d-dry-veste-textile-moto',unistr('<p>La Dainese Veloce D-Dry est une veste textile moto polyvalente conçue pour offrir protection, confort et praticité au quotidien. Moderne et fonctionnelle, elle s’adresse aux motards urbains et routiers qui recherchent une veste fiable pour rouler par tous les temps.<br />\u000aÉquipée de la membrane D-Dry® imperméable et respirante, elle assure une excellente protection contre la pluie et le vent tout en maintenant un bon niveau de confort thermique. Elle permet de rester au sec et à l’aise lors des trajets quotidiens comme des sorties plus longues.<br />\u000aLa Veloce D-Dry intègre des protections certifiées aux épaules et aux coudes pour garantir un haut niveau de sécurité. Sa conception textile robuste assure une bonne résistance à l’usure, tandis que ses zones de ventilation offrent une circulation de l’air efficace lors des températures plus douces.<br />\u000aCaractéristiques principales<br />\u000aMembrane D-Dry® imperméable et respirante<br />\u000aVeste textile moto polyvalente urbaine et route<br />\u000aProtections homologuées aux épaules et aux coudes<br />\u000aPrédisposition pour dorsale<br />\u000aSystème de ventilation intégré<br />\u000aCoupe confortable adaptée à un usage quotidien<br />\u000aConstruction résistante et durable<br />\u000aStyle moderne et discret<br />\u000aPoints forts<br />\u000aProtection efficace contre la pluie et le vent<br />\u000aConfort pour usage quotidien et trajet longue durée<br />\u000aBonne ventilation pour mi-saison<br />\u000aSécurité certifiée Dainese<br />\u000aDesign sobre et polyvalent<br />\u000aLa Dainese Veloce D-Dry est idéale pour les motards recherchant une veste textile fiable, imperméable et confortable, adaptée à une utilisation quotidienne en ville comme sur route.</p>\u000a'),'',48,753,3499.0,2799.0,NULL,NULL,'published','Dainese Veloce D-Dry Veste textile moto','Dainese Veloce D-Dry Veste textile moto au Maroc. Achetez au meilleur prix chez MOTO PACO.',109,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(42,'Dainese Avro 5 Tex Jacket Veste de Moto black','dainese-avro-5-tex-jacket-black',unistr('<p>La Dainese Avro 5 Tex Jacket Black est une veste moto sportive en textile conçue pour offrir un excellent équilibre entre protection, confort et performance. Inspirée de l’univers racing de Dainese, elle est idéale pour les motards qui recherchent une veste dynamique pour la route et les trajets sportifs.<br />\u000aSa construction en tissu technique résistant assure une bonne durabilité et une excellente résistance à l’abrasion. La veste est équipée de protections certifiées aux épaules et aux coudes, garantissant un haut niveau de sécurité, avec la possibilité d’ajouter une protection dorsale pour une sécurité renforcée.<br />\u000aLa Avro 5 Tex dispose également de zones de ventilation stratégiquement placées, permettant une bonne circulation de l’air lors des températures élevées. Sa coupe sportive ergonomique offre un excellent maintien et une grande liberté de mouvement, idéale pour une conduite dynamique.<br />\u000aCaractéristiques principales<br />\u000aConstruction textile résistante et durable<br />\u000aStyle sportif inspiré du racing Dainese<br />\u000aProtections homologuées épaules et coudes<br />\u000aPrédisposition pour dorsale<br />\u000aSystème de ventilation pour plus de confort<br />\u000aCoupe ergonomique sportive<br />\u000aColoris noir sobre et élégant<br />\u000aIdéale pour usage route et conduite dynamique<br />\u000aPoints forts<br />\u000aExcellente protection pour une veste textile sportive<br />\u000aConfort adapté à la conduite active<br />\u000aBonne ventilation pour l’été et la mi-saison<br />\u000aStyle racing moderne et discret<br />\u000aSécurité certifiée Dainese<br />\u000aLa Dainese Avro 5 Tex Jacket Black est parfaite pour les motards qui souhaitent une veste sportive, confortable et protectrice pour une utilisation quotidienne ou des sorties plus dynamiques sur route.</p>\u000a'),'',48,753,3499.0,2799.0,NULL,NULL,'published','Dainese Avro 5 Tex Jacket Veste de Moto black','Dainese Avro 5 Tex Jacket Veste de Moto black au Maroc. Achetez au meilleur prix chez MOTO PACO.',120,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(43,'Alpinestars Hyde XT Drystar XF Jacket Black/Bright Red','alpinestars-hyde-xt-drystar-xf-jacket-black-bright-red',unistr('<p>La Alpinestars Hyde XT Drystar XF Jacket Black / Bright Red est une veste moto touring et adventure conçue pour offrir un excellent niveau de protection, de confort et de polyvalence en toutes conditions. Moderne et technique, elle s’adresse aux motards qui recherchent une veste performante pour les trajets quotidiens comme pour les longues distances.<br />\u000aÉquipée de la membrane Drystar® XF, elle garantit une excellente imperméabilité tout en assurant une bonne respirabilité, permettant de rester au sec et confortable même sous la pluie ou lors de conditions climatiques changeantes. Sa construction textile résistante offre une grande durabilité face à l’abrasion et à l’usage intensif.<br />\u000aLa Hyde XT Drystar XF intègre un système de ventilation efficace pour une meilleure circulation de l’air lors des fortes chaleurs, ainsi qu’une doublure thermique amovible pour s’adapter aux températures plus froides. Elle dispose également de protections certifiées aux épaules et aux coudes, avec la possibilité d’ajouter une protection dorsale pour un niveau de sécurité supérieur.<br />\u000aCaractéristiques principales<br />\u000aMembrane Drystar® XF imperméable et respirante<br />\u000aConstruction textile résistante et durable<br />\u000aDoublure thermique amovible<br />\u000aSystème de ventilation performant<br />\u000aProtections homologuées épaules et coudes<br />\u000aPrédisposition pour dorsale<br />\u000aCoupe ergonomique pour confort longue distance<br />\u000aColoris Black / Bright Red sportif et dynamique<br />\u000aPoints forts<br />\u000aProtection efficace contre pluie et vent<br />\u000aConfort adapté à toutes saisons<br />\u000aExcellente ventilation et modularité<br />\u000aSécurité certifiée Alpinestars<br />\u000aStyle sportif et moderne</p>\u000a'),'',48,764,3899.0,2799.0,NULL,NULL,'published','Alpinestars Hyde XT Drystar XF Jacket Black/Bright Red','Alpinestars Hyde XT Drystar XF Jacket Black/Bright Red au Maroc. Achetez au meilleur prix chez MOTO PACO.',74,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(44,'DAINESE SPLUGEN 3L D-DRY JACKET IRON-GATE/BLACK','dainese-splugen-3l-d-dry-jacket-iron-gate-black',unistr('<p>La Dainese Splugen 3L D-Dry Jacket Iron-Gate / Black est une veste moto touring haut de gamme conçue pour offrir une protection complète et un confort optimal en toutes saisons. Grâce à sa construction 3 couches laminées et à la membrane D-Dry® imperméable et respirante, elle assure une excellente résistance contre la pluie, le vent et le froid tout en maintenant une bonne gestion de la chaleur et de l’humidité.<br />\u000aPensée pour les motards voyageurs, cette veste combine modularité et performance. Ses doublures amovibles et son système de ventilation permettent de s’adapter facilement aux variations climatiques, garantissant un confort constant lors des longs trajets.<br />\u000aLa Splugen 3L intègre des protections certifiées aux épaules et aux coudes, avec la possibilité d’ajouter une dorsale pour un niveau de sécurité supérieur. Sa coupe ergonomique assure une grande liberté de mouvement, idéale pour le touring et les voyages à moto.<br />\u000aCaractéristiques principales<br />\u000aConstruction 3L (3 couches laminées)<br />\u000aMembrane D-Dry® imperméable, coupe-vent et respirante<br />\u000aDoublure thermique amovible pour toutes saisons<br />\u000aSystème de ventilation modulable<br />\u000aProtections homologuées épaules et coudes<br />\u000aPrédisposition pour dorsale<br />\u000aCoupe ergonomique pour confort longue distance<br />\u000aColoris Iron-Gate / Black sobre et technique<br />\u000aPoints forts<br />\u000aProtection efficace contre toutes les intempéries<br />\u000aConfort optimal pour les longs trajets<br />\u000aGrande modularité thermique<br />\u000aSécurité certifiée Dainese<br />\u000aDesign sobre et technique<br />\u000aLa Dainese Splugen 3L D-Dry Jacket Iron-Gate / Black est idéale pour les motards exigeants qui recherchent une veste touring fiable, confortable et performante pour rouler toute l’année, quelles que soient les conditions.</p>\u000a'),'',48,753,4999.0,3799.0,NULL,NULL,'published','DAINESE SPLUGEN 3L D-DRY JACKET IRON-GATE/BLACK','DAINESE SPLUGEN 3L D-DRY JACKET IRON-GATE/BLACK au Maroc. Achetez au meilleur prix chez MOTO PACO.',147,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(45,'Dainese Carve Master 3 Gore-Tex Motorcycle Textile Jacket- Black/grey/red','dainese-carve-master-3-gore-tex-jacket-black-grey-red',unistr('<p>La Dainese Carve Master 3 Gore-Tex Motorcycle Textile Jacket Black / Grey / Red est une veste moto touring haut de gamme conçue pour offrir un maximum de protection, de confort et de performance en toutes saisons. Idéale pour les longs trajets et les voyages à moto, elle combine technologie avancée, ergonomie et résistance aux conditions climatiques les plus exigeantes.<br />\u000aGrâce à sa membrane Gore-Tex® imperméable et respirante, cette veste garantit une protection totale contre la pluie et le vent tout en assurant une excellente gestion de l’humidité et de la transpiration. Sa construction textile robuste permet une grande durabilité et une utilisation intensive sur route.<br />\u000aLa Carve Master 3 est équipée d’un système de ventilation efficace et de doublures thermiques amovibles, permettant une adaptation facile aux variations de température. Elle offre également un haut niveau de sécurité avec des protections certifiées aux épaules et aux coudes, et la possibilité d’ajouter une protection dorsale.<br />\u000aCaractéristiques principales<br />\u000aMembrane Gore-Tex® imperméable, coupe-vent et respirante<br />\u000aConstruction textile résistante et durable<br />\u000aDoublure thermique amovible pour toutes saisons<br />\u000aSystème de ventilation performant<br />\u000aProtections homologuées épaules et coudes<br />\u000aPrédisposition pour dorsale<br />\u000aCoupe ergonomique pour le touring longue distance<br />\u000aColoris noir / gris / rouge sportif et dynamique<br />\u000aPoints forts<br />\u000aProtection optimale contre les intempéries<br />\u000aConfort élevé pour les longs trajets<br />\u000aUtilisation toutes saisons<br />\u000aSécurité certifiée Dainese<br />\u000aStyle sportif et premium</p>\u000a'),'',48,753,4999.0,3799.0,NULL,NULL,'published','Dainese Carve Master 3 Gore-Tex Motorcycle Textile Jacket- Black/grey/red','Dainese Carve Master 3 Gore-Tex Motorcycle Textile Jacket- Black/grey/red au Maroc. Achetez au meilleur prix chez MOTO PACO.',70,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(46,'Dainese Ladakh 3L D-Dry Jacket 63H Green Black','dainese-ladakh-3l-d-dry-jacket-63h-green-black',unistr('<p>La Dainese Ladakh 3L D-Dry Jacket 63H Green Black est une veste moto adventure haut de gamme conçue pour les motards qui recherchent polyvalence, protection et confort sur tous types de terrains et de conditions météorologiques. Grâce à sa construction 3 couches laminées et à la membrane D-Dry® imperméable et respirante, elle assure une excellente protection contre la pluie, le vent et le froid tout en maintenant un bon niveau de confort thermique.<br />\u000aPensée pour les longs voyages et l’aventure, la Ladakh 3L offre une grande modularité avec ses doublures amovibles et son système de ventilation efficace, permettant de s’adapter facilement aux variations de température. Sa coupe ergonomique garantit une liberté de mouvement optimale, même lors de la conduite en position debout sur moto trail ou adventure.<br />\u000aElle intègre des protections certifiées aux épaules et aux coudes, avec la possibilité d’ajouter une dorsale pour un niveau de sécurité encore supérieur. Ses nombreux réglages et poches fonctionnelles en font une veste pratique et adaptée aux expéditions longue distance.<br />\u000aCaractéristiques principales<br />\u000aConstruction 3L (3 couches laminées)<br />\u000aMembrane D-Dry® imperméable, coupe-vent et respirante<br />\u000aDoublure thermique amovible<br />\u000aSystème de ventilation modulable<br />\u000aProtections homologuées épaules et coudes<br />\u000aPrédisposition pour dorsale<br />\u000aCoupe ergonomique adaptée à l’aventure et au trail<br />\u000aColoris vert et noir 63H moderne et robuste<br />\u000aPoints forts<br />\u000aExcellente protection toutes saisons<br />\u000aIdéale pour l’aventure et les longs voyages<br />\u000aGrande modularité thermique<br />\u000aHaute résistance et durabilité<br />\u000aConfort optimal en position route et off-road<br />\u000aLa Dainese Ladakh 3L D-Dry Jacket 63H Green Black est la veste parfaite pour les motards aventuriers qui veulent une protection fiable, un confort longue durée et une performance optimale sur route comme en tout-terrain.</p>\u000a'),'',48,753,4599.0,3499.0,NULL,NULL,'published','Dainese Ladakh 3L D-Dry Jacket 63H Green Black','Dainese Ladakh 3L D-Dry Jacket 63H Green Black au Maroc. Achetez au meilleur prix chez MOTO PACO.',112,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(47,'Dainese Carve Master 3 Gore-Tex Jacket Black Ebony','dainese-carve-master-3-gore-tex-jacket-black-ebony',unistr('<p>La Dainese Carve Master 3 Gore-Tex Jacket Black Ebony est une veste moto touring haut de gamme conçue pour offrir une protection optimale et un confort exceptionnel en toutes saisons. Pensée pour les longs trajets et les motards voyageurs, elle combine performance, modularité et sécurité avancée.<br />\u000aÉquipée de la membrane Gore-Tex® imperméable et respirante, elle garantit une protection totale contre la pluie et le vent tout en assurant une excellente respirabilité. Sa construction technique permet de rouler confortablement même dans des conditions climatiques difficiles.<br />\u000aLa Carve Master 3 dispose d’un système de ventilation efficace et de doublures thermiques amovibles, ce qui la rend parfaitement adaptée à une utilisation toute l’année. Les protections certifiées aux épaules et aux coudes assurent un haut niveau de sécurité, avec la possibilité d’ajouter une protection dorsale.<br />\u000aCaractéristiques principales<br />\u000aMembrane Gore-Tex® imperméable, coupe-vent et respirante<br />\u000aDoublure thermique amovible pour toutes saisons<br />\u000aSystème de ventilation performant<br />\u000aProtections homologuées aux épaules et aux coudes<br />\u000aPrédisposition pour dorsale<br />\u000aCoupe ergonomique pour confort longue distance<br />\u000aColoris noir ébène sobre et élégant<br />\u000aConception touring haut de gamme<br />\u000aPoints forts<br />\u000aProtection maximale contre les intempéries<br />\u000aConfort idéal pour les longs trajets<br />\u000aUtilisation toutes saisons<br />\u000aSécurité certifiée Dainese<br />\u000aGrande durabilité et finition premium<br />\u000aLa Dainese Carve Master 3 Gore-Tex Black Ebony est la veste idéale pour les motards exigeants qui recherchent une protection complète, un confort longue durée et une performance fiable pour le touring et l’aventure.</p>\u000a'),'',48,753,4999.0,3799.0,NULL,NULL,'published','Dainese Carve Master 3 Gore-Tex Jacket Black Ebony','Dainese Carve Master 3 Gore-Tex Jacket Black Ebony au Maroc. Achetez au meilleur prix chez MOTO PACO.',109,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(48,'DAINESE SPLUGEN 3L D-DRY JACKET BLUE','dainese-splugen-3l-d-dry-jacket-blue',unistr('<p>La Dainese Splugen 3L D-Dry Jacket Blue est une veste moto touring haut de gamme conçue pour affronter toutes les conditions météorologiques. Grâce à sa construction 3 couches laminées et à la membrane D-Dry® imperméable et respirante, elle offre une protection optimale contre la pluie, le vent et le froid, tout en garantissant un excellent confort thermique et une bonne ventilation.<br />\u000aPolyvalente et technique, cette veste est idéale pour les motards aventuriers et les longs trajets. Sa conception modulaire permet de s’adapter facilement aux variations de température grâce à ses doublures amovibles et son système de ventilation intégré.<br />\u000aLa Splugen 3L assure également un haut niveau de sécurité avec ses protections certifiées aux épaules et aux coudes, tout en offrant la possibilité d’ajouter une protection dorsale. Sa coupe ergonomique garantit une excellente liberté de mouvement, même lors des longues heures de conduite.<br />\u000aCaractéristiques principales<br />\u000aConstruction 3L (3 couches laminées)<br />\u000aMembrane D-Dry® imperméable, coupe-vent et respirante<br />\u000aDoublures thermiques et intérieures amovibles<br />\u000aSystème de ventilation pour régulation thermique<br />\u000aProtections homologuées épaules et coudes<br />\u000aPrédisposition pour dorsale<br />\u000aCoupe ergonomique pour long trajet<br />\u000aColoris bleu moderne et élégant<br />\u000aPoints forts<br />\u000aProtection toutes saisons (pluie, froid, vent)<br />\u000aGrande polyvalence touring et aventure<br />\u000aConfort optimal sur longues distances<br />\u000aHaute sécurité certifiée Dainese<br />\u000aExcellente respirabilité et modularité</p>\u000a'),'',48,753,4999.0,3699.0,NULL,NULL,'published','DAINESE SPLUGEN 3L D-DRY JACKET BLUE','DAINESE SPLUGEN 3L D-DRY JACKET BLUE au Maroc. Achetez au meilleur prix chez MOTO PACO.',65,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(49,'TCX Street 3 WP Shoes','tcx-street-3-wp-shoes',unistr('<p>Les TCX Street 3 WP Shoes sont des chaussures moto urbaines conçues pour les motards qui souhaitent allier style décontracté, protection certifiée et confort au quotidien. Inspirées de l’univers des sneakers, elles offrent une apparence moderne et discrète tout en intégrant les technologies essentielles à la pratique de la moto.<br />\u000aGrâce à leur membrane WP (Waterproof), ces chaussures assurent une excellente protection contre la pluie et l’humidité, permettant de garder les pieds au sec lors des trajets urbains et des déplacements quotidiens. Leur conception respirante contribue également à un confort optimal, même lors d’une utilisation prolongée.<br />\u000aLes TCX Street 3 WP intègrent des renforts de protection au niveau des malléoles, du talon et de la pointe afin d’offrir une sécurité accrue sur la route. Leur semelle résistante et antidérapante garantit une excellente adhérence sur les repose-pieds comme sur les surfaces urbaines, assurant stabilité et confiance à chaque déplacement.<br />\u000aAvec leur design polyvalent, ces chaussures peuvent être portées aussi bien à moto qu’au quotidien, offrant un excellent compromis entre équipement de protection et chaussures de ville.<br />\u000aCaractéristiques principales<br />\u000aMembrane WP (Waterproof) imperméable et respirante<br />\u000aDesign urbain inspiré des sneakers<br />\u000aRenforts de protection aux malléoles, au talon et à la pointe<br />\u000aSemelle antidérapante à forte adhérence<br />\u000aConfort optimal pour la conduite et la marche<br />\u000aStyle moderne et polyvalent<br />\u000aAdaptées à une utilisation quotidienne en toutes saisons<br />\u000aPoints forts<br />\u000aProtection efficace contre la pluie et l’humidité<br />\u000aConfort élevé pour un usage quotidien<br />\u000aExcellente adhérence et stabilité<br />\u000aDesign discret adapté à la ville<br />\u000aSécurité moto certifiée dans un format urbain<br />\u000aLes TCX Street 3 WP Shoes sont le choix idéal pour les motards à la recherche de chaussures moto imperméables, confortables et élégantes, parfaitement adaptées aux trajets urbains et aux déplacements de tous les jours.</p>\u000a'),'',20,770,1999.0,1299.0,NULL,NULL,'published','TCX Street 3 WP Shoes','TCX Street 3 WP Shoes au Maroc. Achetez au meilleur prix chez MOTO PACO.',85,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(50,'TCX Street 3 Waterproof Brown Shoes','tcx-street-3-waterproof-brown-shoes',unistr('<p>Les TCX Street 3 Waterproof Brown Shoes sont des chaussures moto urbaines au style vintage et élégant, conçues pour offrir un excellent compromis entre protection, confort et praticité au quotidien. Avec leur finition marron raffinée inspirée des sneakers classiques, elles s’intègrent parfaitement à un usage urbain tout en répondant aux exigences de sécurité des motards.<br />\u000aDotées d’une membrane Waterproof, ces chaussures assurent une protection efficace contre la pluie et l’humidité, permettant de garder les pieds au sec lors des déplacements quotidiens et des trajets par temps variable. Leur conception respirante contribue également à un confort optimal tout au long de la journée.<br />\u000aLes TCX Street 3 Waterproof Brown intègrent des renforts de protection au niveau des malléoles, du talon et de la pointe afin d’offrir une sécurité accrue pendant la conduite. Leur semelle haute adhérence garantit une excellente stabilité sur les repose-pieds comme lors de la marche, offrant ainsi un confort remarquable sur et hors de la moto.<br />\u000aCaractéristiques principales<br />\u000aMembrane Waterproof imperméable et respirante<br />\u000aStyle urbain vintage avec finition marron élégante<br />\u000aRenforts de protection aux malléoles, au talon et à la pointe<br />\u000aSemelle antidérapante à forte adhérence<br />\u000aConfort optimal pour la conduite et la marche<br />\u000aFermeture à lacets pour un ajustement précis<br />\u000aAdaptées à un usage quotidien et toutes saisons<br />\u000aPoints forts<br />\u000aProtection efficace contre la pluie et l’humidité<br />\u000aDesign vintage et polyvalent<br />\u000aExcellente adhérence et stabilité<br />\u000aConfort durable pour les trajets quotidiens<br />\u000aSécurité moto certifiée dans un style urbain<br />\u000aLes TCX Street 3 Waterproof Brown Shoes sont le choix idéal pour les motards qui recherchent des chaussures moto imperméables, confortables et élégantes, capables de les accompagner aussi bien à moto qu’au quotidien.</p>\u000a'),'',20,770,1999.0,1299.0,NULL,NULL,'published','TCX Street 3 Waterproof Brown Shoes','TCX Street 3 Waterproof Brown Shoes au Maroc. Achetez au meilleur prix chez MOTO PACO.',85,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(51,'TCX STREET 3 WATERPROOF BOOT - GREEN/BROWN','tcx-street-3-waterproof-boot-green-brown',unistr('<p>Les TCX Street 3 Waterproof Boot Green / Brown sont des chaussures moto urbaines au style vintage et décontracté, conçues pour offrir un excellent niveau de protection, de confort et d’imperméabilité. Avec leur combinaison de couleurs vert et marron, elles se distinguent par un look original qui s’intègre parfaitement à un usage quotidien, sur la moto comme à pied.<br />\u000aÉquipées d’une membrane Waterproof, ces chaussures protègent efficacement contre la pluie et l’humidité tout en maintenant un bon niveau de respirabilité. Elles sont idéales pour les motards qui roulent toute l’année et souhaitent garder leurs pieds au sec quelles que soient les conditions météorologiques.<br />\u000aLa structure renforcée au niveau des malléoles, du talon et de la pointe assure une protection fiable en cas d’impact. La semelle spécialement développée par TCX offre une excellente adhérence sur les repose-pieds et les surfaces urbaines, garantissant stabilité et confort de marche.<br />\u000aCaractéristiques principales<br />\u000aMembrane Waterproof imperméable et respirante<br />\u000aStyle urbain vintage avec finition vert et marron<br />\u000aRenforts de protection aux malléoles, au talon et à la pointe<br />\u000aSemelle antidérapante à forte adhérence<br />\u000aConfort optimal pour la conduite et la marche<br />\u000aFermeture à lacets pour un ajustement précis<br />\u000aAdaptées à une utilisation quotidienne et toutes saisons<br />\u000aPoints forts<br />\u000aProtection efficace contre la pluie et l’humidité<br />\u000aLook original et élégant inspiré des sneakers urbaines<br />\u000aExcellent confort au quotidien<br />\u000aBonne adhérence et stabilité sur tous types de surfaces<br />\u000aSécurité moto certifiée dans un design moderne<br />\u000aLes TCX Street 3 Waterproof Boot Green / Brown sont le choix idéal pour les motards qui recherchent des chaussures moto imperméables, confortables et stylées, capables de les accompagner aussi bien en ville que lors de leurs déplacements quotidiens.</p>\u000a'),'',20,770,1999.0,1299.0,NULL,NULL,'published','TCX STREET 3 WATERPROOF BOOT - GREEN/BROWN','TCX STREET 3 WATERPROOF BOOT - GREEN/BROWN au Maroc. Achetez au meilleur prix chez MOTO PACO.',150,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(52,'TCX Street 3 Waterproof Black','tcx-street-3-waterproof-black',unistr('<p>Les TCX Street 3 Waterproof Black sont des chaussures moto urbaines conçues pour les motards qui recherchent un parfait équilibre entre style, protection et confort au quotidien. Avec leur design inspiré des sneakers modernes et leur finition entièrement noire, elles s’intègrent facilement à toutes les tenues tout en offrant la sécurité nécessaire pour la conduite à moto.<br />\u000aDotées d’une membrane Waterproof, ces chaussures assurent une protection efficace contre la pluie et l’humidité, permettant de garder les pieds au sec lors des trajets quotidiens et des sorties par temps incertain. Leur construction respirante contribue également à un confort optimal tout au long de la journée.<br />\u000aLes TCX Street 3 Waterproof intègrent des renforts de protection au niveau des malléoles, du talon et de la pointe, offrant une sécurité accrue en cas d’impact. Leur semelle spécialement conçue garantit une excellente adhérence sur les repose-pieds comme sur les surfaces urbaines, assurant stabilité et confiance à chaque déplacement.<br />\u000aCaractéristiques principales<br />\u000aMembrane Waterproof imperméable et respirante<br />\u000aDesign urbain moderne inspiré des sneakers<br />\u000aRenforts de protection aux malléoles, au talon et à la pointe<br />\u000aSemelle antidérapante avec excellente adhérence<br />\u000aConfort optimal pour la conduite et la marche<br />\u000aColoris noir élégant et polyvalent<br />\u000aAdaptées à une utilisation quotidienne en ville<br />\u000aPoints forts<br />\u000aProtection efficace contre la pluie et l’humidité<br />\u000aStyle discret et moderne pour un usage quotidien<br />\u000aExcellente stabilité et confort de marche<br />\u000aSécurité moto certifiée dans un format urbain<br />\u000aLes TCX Street 3 Waterproof Black sont le choix idéal pour les motards urbains qui souhaitent bénéficier d’une chaussure moto imperméable, confortable et élégante, adaptée aussi bien à la conduite qu’à la vie de tous les jours.</p>\u000a'),'',20,770,1999.0,1299.0,NULL,NULL,'published','TCX Street 3 Waterproof Black','TCX Street 3 Waterproof Black au Maroc. Achetez au meilleur prix chez MOTO PACO.',74,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(53,'BASKETS TCX STREET 3 T-DRY WATERPROOF NOIR BLANC','tcx-street-3-t-dry-waterproof-noir-blanc',unistr('<p>Les TCX Street 3 T-Dry Waterproof Noir / Blanc sont des baskets moto urbaines conçues pour allier style, confort et protection au quotidien. Avec leur design moderne inspiré des sneakers de ville, elles offrent toute la sécurité nécessaire à la conduite moto tout en restant discrètes et élégantes une fois descendu de la machine.<br />\u000aÉquipées de la membrane T-Dry Waterproof, ces chaussures assurent une excellente protection contre la pluie et l''humidité tout en maintenant une bonne respirabilité. Elles permettent ainsi de garder les pieds au sec lors des déplacements quotidiens, quelles que soient les conditions météorologiques.<br />\u000aLeur structure renforcée au niveau des malléoles, du talon et de la pointe offre une protection efficace contre les chocs et l''abrasion. La semelle extérieure, conçue pour garantir une adhérence optimale, assure une excellente stabilité aussi bien sur les repose-pieds que lors de la marche.<br />\u000aCaractéristiques principales<br />\u000aMembrane T-Dry Waterproof imperméable et respirante<br />\u000aDesign urbain moderne noir et blanc<br />\u000aRenforts de protection au talon, aux malléoles et à la pointe<br />\u000aSemelle résistante avec excellente adhérence<br />\u000aConfort élevé pour la conduite et la marche<br />\u000aFermeture par lacets pour un ajustement précis<br />\u000aAdaptées à un usage quotidien et toutes saisons<br />\u000aPoints forts<br />\u000aProtection efficace contre la pluie<br />\u000aStyle sneaker moderne et polyvalent<br />\u000aConfort optimal pour un usage quotidien<br />\u000aExcellente adhérence et stabilité<br />\u000aSécurité moto certifiée dans un format urbain<br />\u000aLes TCX Street 3 T-Dry Waterproof Noir / Blanc sont le choix idéal pour les motards qui recherchent des baskets moto élégantes, imperméables et confortables, capables de les accompagner aussi bien à moto qu’au quotidien.</p>\u000a'),'',20,770,1999.0,1299.0,NULL,NULL,'published','BASKETS TCX STREET 3 T-DRY WATERPROOF NOIR BLANC','BASKETS TCX STREET 3 T-DRY WATERPROOF NOIR BLANC au Maroc. Achetez au meilleur prix chez MOTO PACO.',112,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(54,'Dainese York Air Chaussures de moto','dainese-york-air-chaussures-moto',unistr('<p>Les Dainese York Air sont des chaussures moto urbaines conçues pour offrir un excellent compromis entre style, confort et ventilation. Inspirées des sneakers du quotidien, elles sont idéales pour les motards qui recherchent une paire légère et discrète pour les trajets en ville, notamment par temps chaud.<br />\u000aGrâce à leur construction Air ventilée, elles assurent une circulation optimale de l’air, permettant de garder les pieds au frais même lors des fortes températures. Leur structure renforcée intègre des protections sur les zones stratégiques afin d’assurer une sécurité adaptée à la conduite moto, tout en conservant une grande souplesse.<br />\u000aPolyvalentes et modernes, les York Air peuvent être portées aussi bien à moto qu’au quotidien. Leur semelle antidérapante garantit une bonne adhérence sur différents types de surfaces, tandis que leur design sobre s’adapte facilement à un usage urbain.<br />\u000aCaractéristiques principales<br />\u000aChaussures moto urbaines ventilées<br />\u000aTechnologie Air pour une meilleure respirabilité<br />\u000aRenforts de protection sur zones sensibles<br />\u000aSemelle antidérapante pour une bonne stabilité<br />\u000aConfort adapté à la conduite et à la marche<br />\u000aDesign sneaker moderne et discret<br />\u000aIdéales pour l’été et les fortes chaleurs<br />\u000aPoints forts<br />\u000aExcellente ventilation pour usage estival<br />\u000aConfort quotidien sur et hors moto<br />\u000aStyle urbain passe-partout<br />\u000aProtection adaptée à la conduite en ville<br />\u000aLes Dainese York Air sont parfaites pour les motards urbains recherchant des chaussures moto légères, respirantes et sécurisées pour leurs déplacements quotidiens.</p>\u000a'),'',20,753,2199.0,1299.0,NULL,NULL,'published','Dainese York Air Chaussures de moto','Dainese York Air Chaussures de moto au Maroc. Achetez au meilleur prix chez MOTO PACO.',62,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(55,'Dainese York Air Shoes, Basket Moto Homme','dainese-york-air-shoes-homme',unistr('<p>Les Dainese York Air Shoes sont des baskets moto pour homme conçues pour offrir un parfait équilibre entre style urbain, confort et protection. Inspirées des sneakers classiques, elles sont idéales pour les motards qui recherchent une chaussure légère et discrète pour un usage quotidien en ville.<br />\u000aGrâce à leur conception ventilée Air, elles assurent une excellente circulation de l’air, ce qui les rend particulièrement adaptées aux températures chaudes et aux trajets estivaux. Leur structure renforcée intègre des protections sur les zones sensibles afin de garantir une sécurité adaptée à la conduite moto, sans compromettre la souplesse ni le confort de marche.<br />\u000aPolyvalentes et modernes, les York Air Shoes peuvent être portées aussi bien à moto qu’au quotidien. Leur semelle antidérapante offre une bonne adhérence, tandis que leur design sobre permet de les associer facilement à une tenue urbaine.<br />\u000aCaractéristiques principales<br />\u000aBaskets moto homme au style urbain<br />\u000aConstruction Air ventilée pour une meilleure respirabilité<br />\u000aRenforts de protection sur zones stratégiques<br />\u000aSemelle antidérapante pour une bonne adhérence<br />\u000aConfort adapté à la conduite et à la marche<br />\u000aDesign sneaker moderne et discret<br />\u000aIdéales pour l’été et les fortes chaleurs<br />\u000aPoints forts<br />\u000aExcellente ventilation pour usage estival<br />\u000aConfort quotidien sur et hors moto<br />\u000aStyle sneaker passe-partout<br />\u000aProtection adaptée à la conduite urbaine<br />\u000aLes Dainese York Air Shoes Homme sont parfaites pour les motards urbains recherchant des baskets moto légères, respirantes et sécurisées pour les trajets quotidiens.</p>\u000a'),'',52,753,2199.0,1399.0,NULL,NULL,'published','Dainese York Air Shoes, Basket Moto Homme','Dainese York Air Shoes, Basket Moto Homme au Maroc. Achetez au meilleur prix chez MOTO PACO.',116,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(56,'Dainese Metropolis D-WP Shoes Chaussures de motoHomme','dainese-metropolis-d-wp-shoes-homme-2',unistr('<p>Les Dainese Metropolis D-WP Shoes pour homme sont des chaussures moto urbaines conçues pour offrir un excellent compromis entre protection, confort et imperméabilité. Idéales pour les trajets quotidiens en ville, elles allient le style d’une sneaker moderne aux exigences de sécurité propres à la conduite moto.<br />\u000aÉquipées de la membrane D-WP (Dainese Waterproof), elles assurent une bonne protection contre la pluie tout en conservant une respirabilité adaptée à un usage régulier. Leur conception renforcée au niveau des zones stratégiques permet de protéger efficacement le pied sans nuire au confort ni à la liberté de mouvement.<br />\u000aAvec leur design sobre et discret, les Metropolis D-WP s’intègrent facilement à un usage quotidien, que ce soit sur la moto ou à pied. Leur semelle antidérapante garantit une bonne adhérence sur différents types de surfaces, tandis que leur construction ergonomique assure un confort durable tout au long de la journée.<br />\u000aCaractéristiques principales<br />\u000aMembrane D-WP imperméable et respirante<br />\u000aChaussures moto urbaines pour homme<br />\u000aRenforts de protection sur zones sensibles<br />\u000aSemelle antidérapante pour une bonne stabilité<br />\u000aConfort adapté à la conduite et à la marche<br />\u000aDesign sobre et polyvalent<br />\u000aIdéales pour usage quotidien et urbain<br />\u000aPoints forts<br />\u000aProtection efficace contre la pluie<br />\u000aConfort longue durée pour usage quotidien<br />\u000aStyle discret adapté à toutes les situations<br />\u000aSécurité adaptée à la conduite moto en ville</p>\u000a'),'',20,753,2599.0,1399.0,NULL,NULL,'published','Dainese Metropolis D-WP Shoes Chaussures de motoHomme','Dainese Metropolis D-WP Shoes Chaussures de motoHomme au Maroc. Achetez au meilleur prix chez MOTO PACO.',119,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(57,'Dainese Metropolis D-wp Shoes Chaussures de motoHomme','dainese-metropolis-d-wp-shoes-homme',unistr('<p>Les Dainese Metropolis D-WP Shoes sont des chaussures moto urbaines pour homme, conçues pour offrir un excellent équilibre entre protection, confort et imperméabilité au quotidien. Polyvalentes et discrètes, elles sont idéales pour les trajets en ville et les déplacements réguliers, quelles que soient les conditions météo.<br />\u000aGrâce à la membrane D-WP (Dainese Waterproof), ces chaussures assurent une bonne protection contre la pluie tout en maintenant un certain niveau de respirabilité. Leur construction renforcée au niveau des zones sensibles garantit une sécurité adaptée à la conduite moto, sans compromettre le confort de marche.<br />\u000aAvec leur design sobre et moderne, les Metropolis D-WP s’intègrent facilement dans un usage quotidien, aussi bien sur la moto qu’en dehors. Leur semelle antidérapante offre une bonne adhérence, tandis que leur structure ergonomique assure un maintien confortable du pied.<br />\u000aCaractéristiques principales<br />\u000aMembrane D-WP imperméable (protection contre la pluie)<br />\u000aChaussures moto urbaines pour homme<br />\u000aRenforts de protection sur zones stratégiques<br />\u000aConfort adapté à la marche et à la conduite<br />\u000aSemelle antidérapante pour une bonne adhérence<br />\u000aDesign discret et polyvalent<br />\u000aIdéales pour usage quotidien et urbain<br />\u000aPoints forts<br />\u000aProtection efficace contre la pluie<br />\u000aConfort pour conduite et marche prolongée<br />\u000aStyle urbain sobre et passe-partout<br />\u000aSécurité adaptée à un usage moto quotidien</p>\u000a'),'',20,753,2599.0,1399.0,NULL,NULL,'published','Dainese Metropolis D-wp Shoes Chaussures de motoHomme','Dainese Metropolis D-wp Shoes Chaussures de motoHomme au Maroc. Achetez au meilleur prix chez MOTO PACO.',123,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(58,'Dainese York Air Shoes','dainese-york-air-shoes',unistr('<p>Les Dainese York D-WP sont des gants moto urbains conçus pour offrir une protection fiable et un confort optimal au quotidien, même par temps humide. Grâce à la membrane D-WP (Dainese Waterproof), ils assurent une excellente imperméabilité tout en conservant une bonne respirabilité, idéale pour les trajets en ville et les déplacements réguliers.<br />\u000aLeur design sobre et moderne s’adapte facilement à tous les styles de motards. Légers et ergonomiques, les York D-WP offrent une bonne liberté de mouvement et une prise en main confortable des commandes de la moto. Les renforts placés sur les zones sensibles renforcent la sécurité sans compromettre la souplesse.<br />\u000aPensés pour un usage urbain et mi-saison, ces gants sont parfaits pour affronter les variations de météo tout en gardant les mains au sec et protégées.<br />\u000aCaractéristiques principales<br />\u000aMembrane D-WP imperméable et respirante<br />\u000aConception ergonomique pour usage urbain<br />\u000aProtection renforcée sur les zones clés<br />\u000aBonne souplesse et confort de conduite<br />\u000aDesign léger et moderne<br />\u000aIdéal pour mi-saison et pluie légère<br />\u000aAjustement confortable et pratique</p>\u000a'),'',20,753,2399.0,1399.0,NULL,NULL,'published','Dainese York Air Shoes','Dainese York Air Shoes au Maroc. Achetez au meilleur prix chez MOTO PACO.',119,'2026-06-20 14:09:06',0,0,0,0);
