INSERT INTO products VALUES(63,'Dainese 1597 Athene Tex Motorcycle black gloves','gants-moto-dainese-athene-tex-1597-noir',unistr('<p>Les Dainese Athene Tex 1597 Black sont des gants moto légers et confortables, conçus pour offrir une excellente protection et une grande liberté de mouvement lors des trajets urbains et des déplacements quotidiens. Leur construction en tissu technique assure une bonne respirabilité, idéale pour une utilisation par temps chaud ou en mi-saison.<br />\u000aGrâce à leur design ergonomique, ces gants épousent parfaitement la forme de la main, garantissant une prise en main précise des commandes de la moto. Les renforts intégrés aux zones stratégiques améliorent la protection en cas de chute, tout en conservant un excellent confort de conduite.<br />\u000aLeur style sobre et élégant en coloris noir permet de les associer facilement à tout type d’équipement moto. Faciles à enfiler et légers, ils sont parfaits pour les motards recherchant un bon compromis entre sécurité, confort et praticité.<br />\u000aCaractéristiques principales<br />\u000aConstruction en textile technique léger et respirant<br />\u000aRenforts de protection sur les zones exposées<br />\u000aConfort élevé pour usage quotidien et urbain<br />\u000aBonne sensibilité et contrôle des commandes<br />\u000aDesign ergonomique ajusté à la main<br />\u000aColoris noir sobre et polyvalent<br />\u000aIdéal pour la mi-saison et l’été<br />\u000aPoints forts<br />\u000aLégers et confortables pour un usage quotidien<br />\u000aBonne ventilation pour éviter la surchauffe<br />\u000aProtection adaptée aux trajets urbains<br />\u000aStyle discret et moderne signé Dainese<br />\u000aLes Dainese Athene Tex 1597 Black sont des gants moto parfaits pour les motards urbains qui recherchent confort, légèreté et protection au quotidien.</p>\u000a'),'',54,753,799.0,799.0,NULL,NULL,'published','Dainese 1597 Athene Tex Motorcycle black gloves','Dainese 1597 Athene Tex Motorcycle black gloves au Maroc. Achetez au meilleur prix chez MOTO PACO.',61,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(64,'GIVI Tanklock Easy-T EASY01','givi-tanklock-easy-t-easy01',unistr('<p>Le GIVI Tanklock Easy-T EASY01 est une sacoche de réservoir compacte et fonctionnelle, conçue pour offrir aux motards une solution de rangement pratique, sécurisée et rapide à installer. Grâce au système de fixation Tanklock, elle se clipse et se déclipse facilement du réservoir à l’aide d’une bride dédiée, sans contact direct avec la peinture de la moto.<br />\u000aAvec son format léger et discret, la EASY01 est idéale pour transporter les objets essentiels du quotidien tels que le téléphone, le portefeuille, les clés ou les documents. Son design ergonomique permet un accès rapide au contenu, même lors des arrêts courts.<br />\u000aFabriquée avec des matériaux résistants et durables, cette sacoche garantit une bonne tenue dans le temps et une protection efficace contre l’usure quotidienne. Son style sobre de la gamme Easy-T s’adapte parfaitement à tous types de motos, qu’elles soient urbaines, sportives ou touring.<br />\u000aCaractéristiques principales<br />\u000aSystème de fixation Tanklock rapide et sécurisé<br />\u000aFormat compact et léger<br />\u000aCompartiment principal pour objets essentiels<br />\u000aMatériaux résistants et durables<br />\u000aDesign sobre et polyvalent<br />\u000aAccès facile au contenu<br />\u000aIdéale pour les trajets quotidiens<br />\u000aPoints forts<br />\u000aInstallation et retrait rapides sans effort<br />\u000aAucune marque sur le réservoir grâce au système Tanklock<br />\u000aParfaite pour un usage urbain et quotidien<br />\u000aCompacte et pratique pour les essentiels</p>\u000a'),'',39,756,849.0,849.0,NULL,NULL,'published','GIVI Tanklock Easy-T EASY01','GIVI Tanklock Easy-T EASY01 au Maroc. Achetez au meilleur prix chez MOTO PACO.',146,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(65,'Givi Easy05 Tanklock noir','givi-easy05-tanklock-noir',unistr('<p>La Givi Easy05 Tanklock Noir est une sacoche de réservoir compacte et pratique, conçue pour les motards à la recherche d’une solution de rangement simple, sécurisée et rapide à utiliser. Grâce au système Tanklock, elle se fixe et se retire facilement du réservoir à l’aide d’une bride spécifique, offrant une excellente stabilité sans contact direct avec la peinture de la moto.<br />\u000aAvec son format compact, la Easy05 est idéale pour transporter vos essentiels du quotidien : téléphone, portefeuille, clés, documents ou petits accessoires. Son design ergonomique permet un accès rapide au contenu, même pendant les pauses ou les arrêts courts.<br />\u000aFabriquée avec des matériaux résistants et durables, cette sacoche assure une bonne protection contre l’usure et les conditions de route. Sa finition noire sobre et élégante s’adapte parfaitement à tous les styles de motos, qu’elles soient urbaines, sportives ou touring.<br />\u000aCaractéristiques principales<br />\u000aFixation Tanklock rapide et sécurisée<br />\u000aFormat compact et pratique<br />\u000aCompartiment principal pour objets essentiels<br />\u000aMatériaux résistants et durables<br />\u000aDesign noir sobre et universel<br />\u000aAccès facile au contenu<br />\u000aIdéale pour usage quotidien et trajets courts<br />\u000aPoints forts<br />\u000aInstallation et retrait rapides grâce au système Tanklock<br />\u000aAucune pression directe sur le réservoir<br />\u000aParfaite pour les déplacements urbains<br />\u000aLégère, compacte et pratique<br />\u000aLa Givi Easy05 Tanklock Noir est la solution idéale pour les motards qui souhaitent une sacoche de réservoir fiable, discrète et facile à utiliser au quotidien.</p>\u000a'),'',39,756,999.0,999.0,NULL,NULL,'published','Givi Easy05 Tanklock noir','Givi Easy05 Tanklock noir au Maroc. Achetez au meilleur prix chez MOTO PACO.',76,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(66,'GIVE EASY06 12LTR','givi-easy06-12l-magnetic-tank-bag',unistr('<p>Le GIVI EASY06 12L Magnetic Tank Bag est une sacoche de réservoir magnétique pratique et compacte, conçue pour les motards qui recherchent une solution simple et efficace pour transporter leurs essentiels lors des trajets quotidiens ou des petites escapades.<br />\u000aAvec une capacité de 12 litres, cette sacoche offre suffisamment d’espace pour ranger un portefeuille, un téléphone, des documents, des gants ou encore de petits accessoires. Son système de fixation magnétique permet une installation rapide et sécurisée sur le réservoir de la moto, sans nécessiter de sangles complexes.<br />\u000aFabriqué à partir de matériaux résistants et durables, le GIVI EASY06 protège efficacement vos affaires contre les petites intempéries et l’usure quotidienne. Sa conception compacte assure une bonne stabilité pendant la conduite, tandis que sa forme ergonomique permet un accès facile au contenu même en position assise sur la moto.<br />\u000aCaractéristiques principales<br />\u000aCapacité de 12 litres<br />\u000aFixation magnétique rapide et pratique<br />\u000aCompartiment principal spacieux<br />\u000aMatériaux résistants et durables<br />\u000aFormat compact et ergonomique<br />\u000aAccès facile aux objets essentiels<br />\u000aIdéal pour trajets quotidiens et courts voyages<br />\u000aPoints forts<br />\u000aInstallation rapide sans sangles<br />\u000aParfait pour les déplacements urbains et périurbains<br />\u000aBonne capacité de rangement pour les essentiels<br />\u000aConception stable et pratique sur route<br />\u000aLe GIVI EASY06 12L Magnetic Tank Bag est une solution idéale pour les motards qui souhaitent allier praticité, simplicité et efficacité dans leurs déplacements quotidiens.</p>\u000a'),'',39,13,999.0,999.0,NULL,NULL,'published','GIVE EASY06 12LTR','GIVE EASY06 12LTR au Maroc. Achetez au meilleur prix chez MOTO PACO.',95,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(67,'GIVI Hip bag Enduro 8l GRT732','givi-hip-bag-enduro-8l-grt732',unistr('<p>Le GIVI Hip Bag Enduro 8L GRT732 est un sac banane technique conçu spécialement pour les pilotes d’enduro, de trail et d’aventure qui souhaitent transporter leur équipement essentiel sans encombrer leurs épaules. Grâce à sa capacité de 8 litres, il offre un excellent compromis entre espace de rangement, confort et liberté de mouvement lors de la conduite tout-terrain.<br />\u000aFabriqué à partir de matériaux résistants à l’abrasion et aux conditions difficiles, le GRT732 est conçu pour accompagner les motards sur les pistes les plus exigeantes. Son système de fixation à la taille assure une excellente stabilité même sur les terrains accidentés, tandis que sa conception ergonomique répartit efficacement le poids pour réduire la fatigue pendant les longues sorties.<br />\u000aLe compartiment principal spacieux permet de ranger outils, gants, documents, téléphone, portefeuille et autres accessoires indispensables. Plusieurs poches de rangement facilitent l’organisation du matériel et offrent un accès rapide à vos effets personnels. Les éléments réfléchissants intégrés améliorent la visibilité du pilote dans des conditions de faible luminosité.<br />\u000aCaractéristiques principales<br />\u000aCapacité de 8 litres adaptée aux sorties enduro et trail.<br />\u000aPort à la taille pour une meilleure liberté de mouvement.<br />\u000aConstruction robuste et résistante à l’usure.<br />\u000aCompartiment principal spacieux et poches de rangement pratiques.<br />\u000aCeinture réglable avec maintien sécurisé.<br />\u000aDesign ergonomique pour un confort optimal.<br />\u000aÉléments réfléchissants pour une meilleure visibilité.<br />\u000aPoints forts<br />\u000aAlternative idéale au sac à dos pour les longues randonnées tout-terrain.<br />\u000aRéduction de la charge sur les épaules et le dos.<br />\u000aAccès rapide aux accessoires et outils essentiels.<br />\u000aConçu pour les aventures enduro, trail et rallye.</p>\u000a'),'',39,756,999.0,999.0,NULL,NULL,'published','GIVI Hip bag Enduro 8l GRT732','GIVI Hip bag Enduro 8l GRT732 au Maroc. Achetez au meilleur prix chez MOTO PACO.',91,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(68,'GRT731 12LTR ENDURO BACKPACK','grt731-12l-enduro-backpack',unistr('<p>Le GRT731 12L Enduro Backpack est un sac à dos technique spécialement conçu pour les passionnés d’enduro, de trail et d’aventure tout-terrain. Compact, léger et résistant, il offre une capacité de 12 litres idéale pour transporter l’essentiel lors de vos sorties à moto, sans compromettre votre liberté de mouvement.<br />\u000aFabriqué avec des matériaux robustes et résistants à l’abrasion, ce sac à dos est pensé pour affronter les conditions les plus exigeantes. Son design ergonomique assure une excellente stabilité sur le dos, même sur les terrains accidentés, tandis que ses bretelles réglables et son système de maintien garantissent un confort optimal pendant la conduite.<br />\u000aLe compartiment principal permet de ranger facilement outils, vêtements de rechange, équipements électroniques et accessoires indispensables. Plusieurs poches et compartiments facilitent l’organisation du matériel, offrant un accès rapide à vos effets personnels. Les détails réfléchissants améliorent la visibilité du pilote dans des conditions de faible luminosité.<br />\u000aCaractéristiques principales<br />\u000aCapacité de 12 litres, idéale pour les sorties enduro et trail.<br />\u000aConstruction robuste résistante à l’usure et aux conditions difficiles.<br />\u000aDesign ergonomique pour un confort maximal à moto.<br />\u000aBretelles réglables et système de maintien stable.<br />\u000aCompartiments de rangement pratiques et accessibles.<br />\u000aÉléments réfléchissants pour une meilleure visibilité.<br />\u000aFormat compact et léger adapté à la conduite sportive.<br />\u000aPoints forts<br />\u000aConçu pour les aventures tout-terrain et les longues randonnées.<br />\u000aExcellente liberté de mouvement grâce à son format compact.<br />\u000aOrganisation efficace de l’équipement et des accessoires.<br />\u000aConfort de portage même sur les parcours exigeants.<br />\u000aLe GRT731 12L Enduro Backpack est le compagnon idéal des motards d’enduro et d’aventure qui recherchent un sac à dos fiable, confortable et parfaitement adapté aux contraintes du tout-terrain.</p>\u000a'),'',39,13,1499.0,1199.0,NULL,NULL,'published','GRT731 12LTR ENDURO BACKPACK','GRT731 12LTR ENDURO BACKPACK au Maroc. Achetez au meilleur prix chez MOTO PACO.',96,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(69,'GIVI Easy-T EASY14 Noir','givi-easy-t-easy14-noir',unistr('<p>Le GIVI Easy-T EASY14 Noir est un sac à dos moto pratique et polyvalent, conçu pour accompagner les motards au quotidien comme lors de leurs déplacements plus longs. Avec sa capacité généreuse et son design ergonomique, il offre un excellent compromis entre confort, fonctionnalité et résistance.<br />\u000aFabriqué à partir de matériaux robustes et résistants aux intempéries, ce sac à dos protège efficacement vos effets personnels. Son compartiment principal spacieux permet de transporter vêtements, accessoires et équipements essentiels, tandis que ses poches supplémentaires facilitent l''organisation de vos objets du quotidien. Les bretelles rembourrées et réglables assurent un port confortable, même lors des trajets prolongés.<br />\u000aGrâce à ses éléments réfléchissants, le GIVI Easy-T EASY14 améliore également la visibilité du motard dans des conditions de faible luminosité. Son style sobre et élégant en noir s''accorde parfaitement avec tous les types d''équipements et de motos.<br />\u000aPoints forts<br />\u000aCapacité adaptée aux trajets quotidiens et aux voyages.<br />\u000aMatériaux résistants et durables.<br />\u000aCompartiment principal spacieux et poches de rangement pratiques.<br />\u000aBretelles ergonomiques rembourrées pour un confort optimal.<br />\u000aÉléments réfléchissants pour une meilleure visibilité.<br />\u000aDesign moderne et finition noire élégante.<br />\u000aLe GIVI Easy-T EASY14 Noir est le choix idéal pour les motards recherchant un sac à dos fiable, confortable et fonctionnel pour leurs déplacements de tous les jours.</p>\u000a'),'',39,756,1299.0,1099.0,NULL,NULL,'published','GIVI Easy-T EASY14 Noir','GIVI Easy-T EASY14 Noir au Maroc. Achetez au meilleur prix chez MOTO PACO.',113,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(70,'Givi Easy13 noir','givi-easy13-noir',unistr('<p>La Givi EASY13 Noir est un sac à dos moto de 18 litres conçu pour un usage quotidien et les trajets à moto. Il combine une structure robuste, du confort et plusieurs solutions de rangement pratiques.<br />\u000aCaractéristiques principales<br />\u000aCapacité : 18 L<br />\u000aCompartiment rembourré pour ordinateur portable jusqu''à 16 pouces<br />\u000aPoche supérieure thermoformée pour lunettes ou accessoires fragiles<br />\u000aDeux poches latérales, dont une porte-bouteille<br />\u000aPoche filet amovible pour transporter un casque moto<br />\u000aBretelles ergonomiques rembourrées et réglables<br />\u000aSangle de maintien à la taille<br />\u000aInserts réfléchissants pour une meilleure visibilité<br />\u000aHousse de pluie résistante à l''eau incluse<br />\u000aMatériaux<br />\u000aPolyester Ripstop 600D<br />\u000aPolyester laminé PU<br />\u000aÉléments réfléchissants<br />\u000aMatériaux conformes à la réglementation REACH<br />\u000aHaute résistance aux UV (testée jusqu''à 500 heures selon ISO 4892-2)<br />\u000aDescription courte<br />\u000aLe Givi EASY13 Noir est un sac à dos moto semi-rigide de 18 L offrant un compartiment pour ordinateur portable, une poche thermoformée pour accessoires, un porte-casque amovible, une housse de pluie et des éléments réfléchissants, idéal pour les trajets quotidiens et les courtes escapades à moto.</p>\u000a'),'',39,756,1299.0,1099.0,NULL,NULL,'published','Givi Easy13 noir','Givi Easy13 noir au Maroc. Achetez au meilleur prix chez MOTO PACO.',124,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(71,'cst c-9297 25×8.00-12','cst-c-9297-25x8-00-12',unistr('<p>Le CST C-9297 est un pneu polyvalent conçu pour offrir une bonne traction et une durabilité fiable, particulièrement adapté aux surfaces variées.<br />\u000a Dimensions<br />\u000aTaille : 25×8.00-12<br />\u000a25 pouces : diamètre total du pneu<br />\u000a8.00 pouces : largeur du pneu<br />\u000a12 pouces : diamètre de la jante compatible<br />\u000a Utilisation<br />\u000aCe pneu est généralement utilisé pour :<br />\u000aQuads (ATV)<br />\u000aPetits véhicules utilitaires (UTV)<br />\u000aTondeuses autoportées<br />\u000aÉquipements agricoles légers<br />\u000a Caractéristiques principales<br />\u000aProfil robuste : sculpture étudiée pour une bonne adhérence sur terrain meuble, herbe ou terre<br />\u000aBonne stabilité : idéal pour les déplacements sur surfaces irrégulières<br />\u000aRésistance à l’usure : conçu pour durer même en usage fréquent<br />\u000a Avantages<br />\u000aPolyvalence d’utilisation<br />\u000aBonne traction hors route<br />\u000aConfort de conduite acceptable sur terrain accidenté</p>\u000a'),'',36,13,1090.0,1090.0,NULL,NULL,'published','cst c-9297 25×8.00-12','cst c-9297 25×8.00-12 au Maroc. Achetez au meilleur prix chez MOTO PACO.',121,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(72,'Givi OBKEV58 TREKKER OUTBACK EVO SMART Security Lock Monokey Motorcycle Top Case Black Aluminum 58 Liters','givi-obkev58-trekker-outback-evo-smart-topcase-monokey-58l',unistr('<p>Le Givi OBKEV58 Trekker Outback Evo Smart 58L Monokey Top Case est un top case premium en aluminium noir conçu pour les motards exigeants, idéal pour les voyages longue distance comme pour une utilisation quotidienne.<br />\u000a Présentation générale<br />\u000aIssu de la gamme Trekker Outback Evo de Givi, ce top case allie design robuste, grande capacité et technologies avancées. Sa finition en aluminium noir lui confère un style moderne et une excellente résistance aux conditions extrêmes.<br />\u000a Grande capacité de 58 litres<br />\u000aAvec un volume généreux de 58 litres, ce top case peut accueillir deux casques intégraux ou un équipement complet de voyage. Il est parfait pour les motards aventuriers ou les trajets du quotidien nécessitant un espace de rangement important.<br />\u000a Système Smart Security Lock<br />\u000aÉquipé du système Smart Security Lock, il offre une sécurité renforcée contre le vol.<br />\u000aCompatible avec une clé unique pour plusieurs valises Givi.<br />\u000aOuverture, fermeture et fixation simplifiées avec le système Monokey.<br />\u000a Construction robuste<br />\u000aStructure en aluminium avec renforts pour une durabilité maximale.<br />\u000aRésistant aux chocs, à la pluie et à la poussière.<br />\u000aJoints étanches pour protéger efficacement le contenu.<br />\u000a Fonctionnalités pratiques<br />\u000aSystème de fixation rapide Monokey pour montage/démontage facile.<br />\u000aPoignées intégrées pour le transport.<br />\u000aCompatible avec de nombreux accessoires : dossier passager, sac interne, éclairage intérieur.<br />\u000a Utilisation<br />\u000aCe top case est parfaitement adapté aux motos trail, routières et maxi-trails. Il répond aux besoins des motards recherchant un équipement fiable, sécurisé et spacieux pour leurs déplacements.</p>\u000a'),'',47,756,5999.0,4999.0,NULL,NULL,'published','Givi OBKEV58 TREKKER OUTBACK EVO SMART Security Lock Monokey Motorcycle Top Case Black Aluminum 58 Liters','Givi OBKEV58 TREKKER OUTBACK EVO SMART Security Lock Monokey Motorcycle Top Case Black Aluminum 58 Liters au Maroc. Achetez au meilleur prix chez MOTO PACO.',67,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(73,'Givi Trekker Outback Evo Smart topcase Monokey 58 L - OBKEV58A','givi-trekker-outback-evo-smart-topcase-monokey-58l-obkev58a',unistr('<p>Le Givi Trekker Outback Evo Smart 58L Monokey Topcase (référence OBKEV58A) est un top case haut de gamme conçu pour les motos d’aventure et de tourisme, alliant robustesse, grande capacité et technologies modernes.<br />\u000a Description générale<br />\u000aCe top case est fabriqué en aluminium anodisé, ce qui lui confère une excellente résistance aux chocs, aux intempéries et à la corrosion. Son design rectangulaire emblématique de la gamme Trekker Outback lui donne un look robuste et fonctionnel, parfaitement adapté aux longues expéditions.<br />\u000a Capacité et praticité<br />\u000aAvec une capacité de 58 litres, il peut contenir deux casques intégraux ou un grand volume d’équipement. L’intérieur spacieux est idéal pour les voyages longue distance, les trajets quotidiens ou le transport de matériel.<br />\u000a Système de fixation et sécurité<br />\u000aCompatible avec le système Monokey de Givi : fixation et retrait rapides avec une seule clé.<br />\u000aSystème Smart Security Lock : serrure renforcée pour une meilleure protection contre le vol.<br />\u000aPossibilité d’utiliser une clé unique pour plusieurs valises Givi.<br />\u000a Conception et durabilité<br />\u000aStructure en aluminium épais avec renforts aux coins.<br />\u000aCharnières solides et mécanisme d’ouverture fiable.<br />\u000aJoint d’étanchéité pour protéger le contenu contre la pluie et la poussière.<br />\u000a Fonctionnalités supplémentaires<br />\u000aCompatible avec divers accessoires : dossier passager, filet interne, éclairage intérieur.<br />\u000aPoignées intégrées pour faciliter le transport une fois détaché.<br />\u000aDesign pensé pour résister aux conditions extrêmes (voyage off-road, pluie, chaleur).<br />\u000a Utilisation<br />\u000aCe top case est particulièrement adapté aux motos trail, maxi-trails et routières. Il convient aussi bien aux motards voyageurs qu’aux utilisateurs quotidiens cherchant une solution de rangement fiable et spacieuse.</p>\u000a'),'',47,756,4999.0,4499.0,NULL,NULL,'published','Givi Trekker Outback Evo Smart topcase Monokey 58 L - OBKEV58A','Givi Trekker Outback Evo Smart topcase Monokey 58 L - OBKEV58A au Maroc. Achetez au meilleur prix chez MOTO PACO.',87,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(74,'Duro Pneu DI-K911 - Avant - 25 x 8 x 12','pneu-duro-di-k911-avant-25x8x12',unistr('<p>Le pneu Duro DI-K911 Avant 25x8x12 est un pneu tout-terrain conçu pour les quads (ATV) et SSV (UTV), spécialement adapté à une utilisation en position avant, offrant précision de conduite et stabilité.<br />\u000a Description générale<br />\u000aLe Duro DI-K911 est conçu pour garantir une excellente maniabilité et un bon contrôle directionnel. Son profil permet une adhérence efficace sur différents types de terrains, notamment les chemins secs, le sable et les surfaces légèrement accidentées.<br />\u000a Caractéristiques principales<br />\u000aDimensions : 25 x 8 x 12<br />\u000aPosition : Avant<br />\u000aType : pneu tout-terrain ATV / UTV<br />\u000aProfil : optimisé pour direction et stabilité<br />\u000aMontage : jante 12 pouces<br />\u000a Avantages<br />\u000aExcellente précision de conduite<br />\u000aBonne adhérence sur terrains variés<br />\u000aStabilité renforcée à l’avant<br />\u000aConfort de roulage amélioré<br />\u000aUsure régulière pour une meilleure longévité<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aPosition avant de quad ou SSV<br />\u000aRandonnée tout-terrain<br />\u000aTerrains mixtes (sec, sable, léger off-road)<br />\u000aUsage loisir et utilitaire<br />\u000a En résumé, le Duro DI-K911 Avant 25x8x12 est un pneu fiable et polyvalent, parfait pour améliorer la maniabilité et la stabilité de votre véhicule en tout-terrain.</p>\u000a'),'',36,13,1999.0,1999.0,NULL,NULL,'published','Duro Pneu DI-K911 - Avant - 25 x 8 x 12','Duro Pneu DI-K911 - Avant - 25 x 8 x 12 au Maroc. Achetez au meilleur prix chez MOTO PACO.',78,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(75,'25x8.00-12 Maxxis C9311 Ancla M/T 6PR 43J E TL','pneu-maxxis-c9311-ancla-mt-25x8-00-12',unistr('<p>Le pneu Maxxis C9311 Ancla M/T 25x8.00-12 6PR 43J TL est un pneu tout-terrain conçu pour les quads (ATV) et SSV (UTV), spécialement développé pour offrir une excellente traction en conditions difficiles.<br />\u000a Description générale<br />\u000aLe Maxxis Ancla M/T est un pneu de type “Mud Terrain” (boue) conçu pour maximiser l’adhérence sur les terrains meubles et glissants. Grâce à son profil agressif et ses crampons profonds, il garantit une excellente motricité dans la boue, le sable et les chemins accidentés.<br />\u000a Caractéristiques principales<br />\u000aDimensions : 25x8.00-12<br />\u000aModèle : Maxxis C9311 Ancla M/T<br />\u000aIndice de charge/vitesse : 43J<br />\u000aStructure : 6PR (6 plis) → grande résistance aux chocs<br />\u000aType : TL (Tubeless, sans chambre à air)<br />\u000aUsage : Mud Terrain (boue et tout-terrain)<br />\u000a Avantages<br />\u000aExcellente traction en boue et terrain meuble<br />\u000aBonne résistance aux perforations et chocs<br />\u000aProfil agressif pour une meilleure accroche<br />\u000aStabilité renforcée en conditions difficiles<br />\u000aConçu pour usage intensif off-road<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aQuads sportifs et utilitaires<br />\u000aSSV / UTV<br />\u000aTerrains boueux, humides et sablonneux<br />\u000aRandonnée et usage tout-terrain extrême<br />\u000a En résumé, le Maxxis C9311 Ancla M/T 25x8.00-12 est un pneu robuste et performant, parfait pour les utilisateurs recherchant une adhérence maximale en conditions boueuses et difficiles.</p>\u000a'),'',36,13,1699.0,1699.0,NULL,NULL,'published','25x8.00-12 Maxxis C9311 Ancla M/T 6PR 43J E TL','25x8.00-12 Maxxis C9311 Ancla M/T 6PR 43J E TL au Maroc. Achetez au meilleur prix chez MOTO PACO.',121,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(76,'DUNLOP kt 406 at25 10 12','pneu-dunlop-kt406-at25x10-12',unistr('<p>Le pneu Dunlop KT406 AT25x10-12 est un pneu tout-terrain conçu pour les quads (ATV) et SSV (UTV), offrant un excellent compromis entre performance, confort et durabilité.<br />\u000a Description générale<br />\u000aLe Dunlop KT406 AT25x10-12 est spécialement développé pour une utilisation polyvalente en off-road. Il assure une bonne adhérence sur différents types de terrains tels que les chemins secs, le sable et les surfaces légèrement accidentées, tout en garantissant une conduite stable et sécurisée.<br />\u000a Caractéristiques principales<br />\u000aModèle : Dunlop KT406<br />\u000aDimensions : AT25x10-12<br />\u000aType : pneu tout-terrain ATV / UTV<br />\u000aMontage : jante 12 pouces<br />\u000aProfil : optimisé pour traction et stabilité<br />\u000a Avantages<br />\u000aBonne adhérence sur terrains variés<br />\u000aExcellente stabilité de conduite<br />\u000aConfort amélioré en usage tout-terrain<br />\u000aBonne résistance à l’usure<br />\u000aPolyvalent pour usage loisir et utilitaire<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aRandonnée en quad<br />\u000aUtilisation en SSV / UTV<br />\u000aTerrains mixtes (sec, sable, léger off-road)<br />\u000aUsage quotidien ou loisir<br />\u000a En résumé, le Dunlop KT406 AT25x10-12 est un pneu fiable et polyvalent, parfait pour les utilisateurs recherchant performance et durabilité en tout-terrain.</p>\u000a'),'',36,13,1899.0,1899.0,NULL,NULL,'published','DUNLOP kt 406 at25 10 12','DUNLOP kt 406 at25 10 12 au Maroc. Achetez au meilleur prix chez MOTO PACO.',142,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(77,'kenda 25x10 12','pneu-kenda-25x10-12',unistr('<p>Le pneu Kenda 25x10-12 ATV/UTV Tire est un pneu tout-terrain conçu pour les quads (ATV) et SSV (UTV), offrant un excellent équilibre entre adhérence, stabilité et durabilité.<br />\u000a Description générale<br />\u000aCe pneu Kenda en dimension 25x10-12 est conçu pour une utilisation polyvalente en off-road. Il assure une bonne traction sur différents types de terrains comme les chemins secs, le sable, les pistes forestières et les surfaces légèrement boueuses.<br />\u000a Caractéristiques principales<br />\u000aDimensions : 25x10-12<br />\u000aType : pneu tout-terrain ATV / UTV<br />\u000aMontage : jante 12 pouces<br />\u000aProfil : optimisé pour traction et stabilité<br />\u000aUtilisation : avant ou arrière selon le véhicule<br />\u000a Avantages<br />\u000aBonne adhérence sur terrains variés<br />\u000aConduite stable et sécurisée<br />\u000aPolyvalence pour usage loisir et utilitaire<br />\u000aBonne résistance à l’usure<br />\u000aConfort de conduite en tout-terrain<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aRandonnée en quad<br />\u000aUtilisation en SSV / UTV<br />\u000aTerrains mixtes (sec, sable, léger off-road)<br />\u000aUsage quotidien ou loisir<br />\u000a En résumé, le pneu Kenda 25x10-12 est un choix fiable et polyvalent pour les utilisateurs recherchant performance et durabilité en tout-terrain.</p>\u000a'),'',36,13,1599.0,1599.0,NULL,NULL,'published','kenda 25x10 12','kenda 25x10 12 au Maroc. Achetez au meilleur prix chez MOTO PACO.',107,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(78,'DUNLOP AT25x10-12','pneu-dunlop-at25x10-12',unistr('<p>Le pneu Dunlop AT25x10-12 est un pneu tout-terrain conçu pour les quads (ATV) et SSV (UTV), offrant une excellente combinaison de performance, durabilité et confort de conduite.<br />\u000a Description générale<br />\u000aLe Dunlop AT25x10-12 est spécialement développé pour une utilisation polyvalente en tout-terrain. Son profil permet d’assurer une bonne adhérence sur différents types de surfaces, telles que les chemins secs, le sable et les terrains légèrement accidentés.<br />\u000a Caractéristiques principales<br />\u000aDimensions : AT25x10-12<br />\u000aType : pneu tout-terrain ATV / UTV<br />\u000aProfil : dessin optimisé pour traction et stabilité<br />\u000aMontage : compatible jantes 12 pouces<br />\u000a Avantages<br />\u000aBonne adhérence sur terrains variés<br />\u000aExcellente stabilité de conduite<br />\u000aConfort amélioré en utilisation off-road<br />\u000aUsure régulière pour une longue durée de vie<br />\u000aPolyvalent pour usage loisir et utilitaire<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aRandonnée en quad<br />\u000aUtilisation quotidienne en SSV<br />\u000aTerrains mixtes (sec, sable, léger off-road)<br />\u000aActivités utilitaires<br />\u000a En résumé, le Dunlop AT25x10-12 est un pneu fiable et polyvalent, parfaitement adapté aux utilisateurs recherchant un bon équilibre entre performance et durabilité en tout-terrain.</p>\u000a'),'',36,13,1599.0,1599.0,NULL,NULL,'published','DUNLOP AT25x10-12','DUNLOP AT25x10-12 au Maroc. Achetez au meilleur prix chez MOTO PACO.',111,'2026-06-20 14:09:06',0,0,0,0);
