INSERT INTO products VALUES(80,'Polaris  PxT  26x11R12','pneu-polaris-pxt-26x11r12',unistr('<p>Le pneu Polaris PxT 26x11R12 est un pneu tout-terrain conçu pour les quads (ATV) et SSV (UTV), offrant une excellente polyvalence et des performances fiables sur différents types de terrains.<br />\u000a Description générale<br />\u000aLe Polaris PxT est spécialement développé pour assurer une bonne adhérence et une conduite stable en conditions off-road. Son profil permet une utilisation efficace aussi bien sur terrains secs que légèrement boueux, tout en conservant un bon confort de roulage.<br />\u000a Caractéristiques principales<br />\u000aDimensions : 26x11R12<br />\u000aType : pneu tout-terrain ATV / UTV<br />\u000aProfil : dessin optimisé pour traction et stabilité<br />\u000aMontage : compatible avec jantes 12 pouces<br />\u000a Avantages<br />\u000aBonne adhérence sur terrains variés<br />\u000aConduite stable et sécurisée<br />\u000aPolyvalent pour usage loisir et utilitaire<br />\u000aUsure régulière pour une durée de vie prolongée<br />\u000aConfort de conduite appréciable<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aRandonnée en quad<br />\u000aUtilisation quotidienne en SSV<br />\u000aTerrains mixtes (sec, sable, léger off-road)<br />\u000aActivités utilitaires<br />\u000a En résumé, le Polaris PxT 26x11R12 est un pneu fiable et polyvalent, parfait pour les utilisateurs recherchant un bon compromis entre performance, confort et durabilité en tout-terrain.</p>\u000a'),'',36,13,1599.0,1599.0,NULL,NULL,'published','Polaris  PxT  26x11R12','Polaris  PxT  26x11R12 au Maroc. Achetez au meilleur prix chez MOTO PACO.',81,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(81,'GIVI EA126 Cargo bag 80l Black','givi-ea126-cargo-bag-80l-black',unistr('<p>Le sac de transport GIVI EA126 Cargo Bag 80L Black est une solution de bagagerie souple et spacieuse, idéale pour les motards recherchant un grand volume de rangement pour leurs longs trajets.<br />\u000a Description générale<br />\u000aLe GIVI EA126 est un sac cargo de grande capacité (80 litres) conçu pour s’adapter facilement à l’arrière de la moto. Sa conception robuste et fonctionnelle permet de transporter efficacement vos affaires tout en assurant une bonne stabilité pendant la conduite.<br />\u000a Caractéristiques principales<br />\u000aCapacité : 80 litres<br />\u000aCouleur : Noir<br />\u000aType : sac cargo souple moto<br />\u000aMatériau : tissu résistant à l’usure<br />\u000aFixation : sangles réglables pour une installation sécurisée<br />\u000aTransport : poignées pratiques pour un port facile<br />\u000a Avantages<br />\u000aTrès grande capacité de rangement<br />\u000aInstallation simple et rapide sur la moto<br />\u000aBonne résistance aux conditions extérieures<br />\u000aPolyvalent pour voyages, road trips et usage quotidien<br />\u000aLéger et facile à transporter<br />\u000a Utilisation recommandée<br />\u000aCe sac est idéal pour :<br />\u000aVoyages longue distance à moto<br />\u000aTransport de bagages volumineux<br />\u000aUtilisation quotidienne ou occasionnelle<br />\u000aMotards touring et adventure<br />\u000a En résumé, le GIVI EA126 Cargo Bag 80L est un sac pratique, robuste et spacieux, parfait pour transporter tout votre équipement en toute sécurité lors de vos déplacements à moto.</p>\u000a'),'',39,756,999.0,999.0,NULL,NULL,'published','GIVI EA126 Cargo bag 80l Black','GIVI EA126 Cargo bag 80l Black au Maroc. Achetez au meilleur prix chez MOTO PACO.',123,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(82,'Kenda Bearclaw K299 Mud Snow ATV UTV Tire 26x9 26-9-12 26x9x12','pneu-kenda-bearclaw-k299-26x9-12-mud-snow',unistr('<p>Le pneu Kenda Bearclaw K299 26x9-12 ATV/UTV Mud & Snow est un pneu tout-terrain conçu pour offrir une excellente performance en conditions difficiles, notamment dans la boue et la neige. Il est destiné aux quads (ATV) et SSV (UTV) qui nécessitent une forte adhérence et une grande fiabilité en off-road.<br />\u000a Description générale<br />\u000aLe Kenda Bearclaw K299 est reconnu pour son profil agressif avec des crampons profonds, spécialement étudiés pour améliorer la traction sur les terrains meubles, glissants ou accidentés. Il garantit une excellente motricité et un meilleur contrôle du véhicule, même dans des conditions extrêmes.<br />\u000a Caractéristiques principales<br />\u000aDimensions : 26x9-12 / 26-9-12 / 26x9x12<br />\u000aModèle : Kenda Bearclaw K299<br />\u000aType : Mud & Snow (boue et neige)<br />\u000aApplication : ATV / UTV (quad et buggy)<br />\u000aProfil : crampons agressifs pour traction renforcée<br />\u000a Avantages<br />\u000aExcellente adhérence en boue et neige<br />\u000aBonne stabilité sur terrains glissants<br />\u000aTraction renforcée en conditions extrêmes<br />\u000aBonne résistance à l’usure en usage off-road<br />\u000aContrôle amélioré du véhicule<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aRandonnées tout-terrain<br />\u000aConditions boueuses et enneigées<br />\u000aQuads et SSV utilitaires ou sportifs<br />\u000aTerrains accidentés et meubles<br />\u000a En résumé, le Kenda Bearclaw K299 26x9-12 est un pneu fiable et performant, conçu pour affronter les terrains les plus difficiles avec sécurité et efficacité.</p>\u000a'),'',36,13,1449.0,1449.0,NULL,NULL,'published','Kenda Bearclaw K299 Mud Snow ATV UTV Tire 26x9 26-9-12 26x9x12','Kenda Bearclaw K299 Mud Snow ATV UTV Tire 26x9 26-9-12 26x9x12 au Maroc. Achetez au meilleur prix chez MOTO PACO.',142,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(83,'Kenda Bearclaw Rear 25X12.50-9 25x12-9 25x12x9 56F 6 Ply a/t All Terrain Atv/Utv Tire','pneu-kenda-bearclaw-rear-25x12-50-9-56f-6-ply',unistr('<p>Le pneu Kenda Bearclaw Rear 25x12.50-9 56F 6 Ply ATV/UTV est un pneu tout-terrain arrière conçu pour les quads (ATV) et SSV (UTV), offrant une excellente<br />\u000aLe Kenda Bearclaw est réputé pour son profil agressif avec des crampons profonds et larges, spécialement conçu pour améliorer l’adhérence dans la boue, les terrains meubles et les surfaces accidentées. Il garantit une excellente motricité à l’arrière du véhicule pour une meilleure poussée et stabilité.<br />\u000a Caractéristiques principales<br />\u000aDimensions : 25x12.50-9 / 25x12-9 / 25x12x9<br />\u000aIndice de charge / vitesse : 56F<br />\u000aStructure : 6 Ply (6 plis) → haute résistance aux chocs et crevaisons<br />\u000aType : pneu tout-terrain A/T (All Terrain)<br />\u000aPosition : arrière (Rear)<br />\u000a Avantages<br />\u000aExcellente traction en terrain boueux et meuble<br />\u000aTrès bonne résistance aux perforations<br />\u000aStabilité renforcée à l’arrière du véhicule<br />\u000aBonne durabilité en usage intensif<br />\u000aAdapté aux conditions off-road exigeantes<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aQuads sportifs et utilitaires<br />\u000aSSV / UTV<br />\u000aRandonnée tout-terrain<br />\u000aTerrains boueux, sablonneux et forestiers<br />\u000a En résumé, le Kenda Bearclaw Rear 25x12.50-9 est un pneu arrière fiable et puissant, conçu pour offrir accroche, stabilité et performance en conditions tout-terrain extrêmes.</p>\u000a'),'',36,13,1449.0,1449.0,NULL,NULL,'published','Kenda Bearclaw Rear 25X12.50-9 25x12-9 25x12x9 56F 6 Ply a/t All Terrain Atv/Utv Tire','Kenda Bearclaw Rear 25X12.50-9 25x12-9 25x12x9 56F 6 Ply a/t All Terrain Atv/Utv Tire au Maroc. Achetez au meilleur prix chez MOTO PACO.',134,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(84,'PNEU QUAD ET BUGGY 25X10-12 KENDA K3203 MASTODON AT','pneu-kenda-k3203-mastodon-at-25x10-12',unistr('<p>Le pneu Kenda K3203 Mastodon AT 25x10-12 est un pneu tout-terrain robuste conçu pour les quads et buggys, offrant une excellente performance sur les terrains difficiles et variés.<br />\u000a Description générale<br />\u000aLe Kenda Mastodon AT est spécialement développé pour les utilisateurs recherchant adhérence, stabilité et résistance en usage off-road. Son profil agressif permet une excellente accroche sur la boue, les chemins rocailleux, le sable et les surfaces irrégulières.<br />\u000a Caractéristiques principales<br />\u000aDimensions : 25x10-12<br />\u000aModèle : Kenda K3203 Mastodon AT<br />\u000aType : pneu tout-terrain Quad & Buggy<br />\u000aStructure : carcasse renforcée pour une meilleure résistance aux chocs<br />\u000aProfil : crampons larges et profonds pour une traction maximale<br />\u000a Avantages<br />\u000aExcellente traction en tout-terrain<br />\u000aTrès bonne résistance aux crevaisons et impacts<br />\u000aStabilité renforcée sur terrains accidentés<br />\u000aBonne évacuation de la boue et des débris<br />\u000aDurabilité élevée en usage intensif<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aQuads sportifs et utilitaires<br />\u000aBuggys / SSV<br />\u000aRandonnée tout-terrain<br />\u000aTerrains boueux, sablonneux et rocheux<br />\u000a En résumé, le Kenda K3203 Mastodon AT 25x10-12 est un pneu fiable et performant, parfait pour les conducteurs qui recherchent robustesse et accroche maximale en toutes conditions hors route.</p>\u000a'),'',36,13,1449.0,1449.0,NULL,NULL,'published','PNEU QUAD ET BUGGY 25X10-12 KENDA K3203 MASTODON AT','PNEU QUAD ET BUGGY 25X10-12 KENDA K3203 MASTODON AT au Maroc. Achetez au meilleur prix chez MOTO PACO.',139,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(85,'Pneu MAXXIS POLARIS 2.0 MU10 26x14R12','pneu-maxxis-polaris-2-0-mu10-26x14r12',unistr('<p>Le pneu Maxxis Polaris 2.0 MU10 26x14R12 est un pneu tout-terrain conçu pour offrir une excellente performance sur les quads (ATV) et SSV (UTV), notamment sur les terrains difficiles et exigeants.<br />\u000a Description générale<br />\u000aCe modèle est spécialement développé pour garantir une adhérence optimale et une bonne motricité sur différents types de surfaces : boue, sable, rochers et chemins accidentés. Son profil agressif permet une meilleure accroche et une conduite plus stable en conditions hors route.<br />\u000a Caractéristiques principales<br />\u000aDimensions : 26x14R12<br />\u000aType : pneu tout-terrain ATV/SSV<br />\u000aProfil : crampons larges pour une meilleure traction<br />\u000aStructure : carcasse renforcée pour plus de résistance (selon version MU10 Polaris 2.0)<br />\u000a Avantages<br />\u000aTrès bonne traction en tout-terrain<br />\u000aExcellente stabilité sur terrains irréguliers<br />\u000aBonne résistance aux chocs et à l’usure<br />\u000aConfort de conduite amélioré en off-road<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aRandonnée en quad et SSV<br />\u000aUtilisation agricole ou utilitaire<br />\u000aTerrains boueux, sablonneux et rocheux<br />\u000aConduite tout-terrain intensive<br />\u000a En résumé, le Maxxis Polaris 2.0 MU10 26x14R12 est un pneu fiable et performant, conçu pour offrir sécurité, adhérence et durabilité en conditions tout-terrain.</p>\u000a'),'',36,13,1899.0,1899.0,NULL,NULL,'published','Pneu MAXXIS POLARIS 2.0 MU10 26x14R12','Pneu MAXXIS POLARIS 2.0 MU10 26x14R12 au Maroc. Achetez au meilleur prix chez MOTO PACO.',92,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(86,'Pneu MAXXIS Bighorn 2.0 MU10 27x12R12 55N 6PR TL','pneu-maxxis-bighorn-2-0-mu10-27x12r12-55n-6pr-tl',unistr('<p>Le pneu Maxxis Bighorn 2.0 MU10 27x12R12 55N 6PR TL est un pneu tout-terrain de haute qualité, spécialement conçu pour les quads (ATV) et SSV (UTV). Il offre une excellente combinaison de traction, durabilité et confort, idéale pour les terrains les plus exigeants.<br />\u000a Description générale<br />\u000aGrâce à son profil agressif et ses crampons larges et espacés, ce pneu garantit une adhérence optimale sur une grande variété de surfaces : boue, sable, rochers et chemins accidentés. Sa conception permet une évacuation efficace de la boue, améliorant ainsi la motricité et la stabilité.<br />\u000a Caractéristiques techniques<br />\u000aDimensions : 27x12R12<br />\u000aIndice de charge : 55N<br />\u000aStructure : 6PR (6 plis) → excellente résistance aux chocs et aux crevaisons<br />\u000aType : TL (Tubeless, sans chambre à air)<br />\u000aBande de roulement : design directionnel pour une traction maximale<br />\u000a Avantages<br />\u000aTrès bonne traction en tout-terrain<br />\u000aExcellente stabilité latérale<br />\u000aGrande robustesse pour une utilisation intensive<br />\u000aUsure régulière pour une longue durée de vie<br />\u000aConfort de conduite amélioré<br />\u000a Utilisation recommandée<br />\u000aCe pneu est idéal pour :<br />\u000aRandonnée tout-terrain<br />\u000aUtilisation agricole et professionnelle<br />\u000aTerrains mixtes (boue, sable, cailloux)<br />\u000aConduite sportive en quad et SSV<br />\u000a En résumé, le Maxxis Bighorn 2.0 MU10 27x12R12 est un pneu performant, fiable et polyvalent, parfaitement adapté aux utilisateurs recherchant sécurité et efficacité en toutes conditions hors route.</p>\u000a'),'',36,13,1899.0,1899.0,NULL,NULL,'published','Pneu MAXXIS Bighorn 2.0 MU10 27x12R12 55N 6PR TL','Pneu MAXXIS Bighorn 2.0 MU10 27x12R12 55N 6PR TL au Maroc. Achetez au meilleur prix chez MOTO PACO.',131,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(87,'Pneu MAXXIS Bighorn 2.0 MU10 26x14R12 55N 6PR TL','pneu-maxxis-bighorn-2-0-mu10-26x14r12-55n-6pr-tl',unistr('<p>Le pneu Maxxis Bighorn 2.0 MU10 26x14R12 55N 6PR TL est un pneu tout-terrain haut de gamme conçu pour les quads (ATV) et SSV (UTV), offrant une excellente combinaison de traction, robustesse et confort de conduite.<br />\u000a Description générale<br />\u000aGrâce à son profil agressif et ses crampons espacés, ce pneu assure une adhérence optimale sur tous types de terrains : boue, sable, rochers et pistes accidentées. Il est idéal pour les utilisateurs exigeants recherchant performance et fiabilité.<br />\u000a Caractéristiques techniques<br />\u000aDimensions : 26x14R12<br />\u000aIndice de charge : 55N<br />\u000aStructure : 6PR (6 plis) → meilleure résistance aux perforations<br />\u000aType : TL (Tubeless, sans chambre à air)<br />\u000aBande de roulement : design directionnel pour une traction renforcée<br />\u000a Avantages<br />\u000aExcellente motricité en tout-terrain<br />\u000aGrande stabilité latérale, même sur terrains irréguliers<br />\u000aDurabilité élevée grâce à sa carcasse renforcée<br />\u000aConfort de conduite amélioré avec une bonne absorption des chocs<br />\u000a Utilisation recommandée<br />\u000aCe pneu est parfait pour :<br />\u000aRandonnée tout-terrain<br />\u000aUtilisation agricole ou professionnelle<br />\u000aTerrains mixtes (boue, sable, cailloux)<br />\u000aConduite sportive en quad ou SSV<br />\u000a En résumé, le Maxxis Bighorn 2.0 MU10 26x14R12 est un choix fiable pour ceux qui recherchent un pneu performant, résistant et polyvalent pour toutes leurs sorties hors route.</p>\u000a'),'',36,13,1899.0,1899.0,NULL,NULL,'published','Pneu MAXXIS Bighorn 2.0 MU10 26x14R12 55N 6PR TL','Pneu MAXXIS Bighorn 2.0 MU10 26x14R12 55N 6PR TL au Maroc. Achetez au meilleur prix chez MOTO PACO.',131,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(88,'Pneu MAXXIS Bighorn 2.0 MU10 26x11R12 55N 6PR TL','pneu-maxxis-bighorn-2-0-mu10-26x11r12-55n-6pr-tl',unistr('<p>Le pneu Maxxis Bighorn 2.0 MU10 26x11R12 55N 6PR TL est un pneu tout-terrain (ATV/UTV) reconnu pour sa robustesse et ses excellentes performances hors route.<br />\u000a Description générale<br />\u000aCe modèle est conçu pour offrir une adhérence maximale sur une grande variété de terrains : boue, sable, rochers et chemins accidentés. Il est particulièrement apprécié pour sa polyvalence et sa durabilité.<br />\u000a Caractéristiques techniques<br />\u000aDimensions : 26x11R12<br />\u000aIndice de charge : 55N<br />\u000aStructure : 6PR (6 plis) → grande résistance aux chocs et aux crevaisons<br />\u000aType : TL (Tubeless, sans chambre à air)<br />\u000aProfil : crampons larges et espacés pour une meilleure traction<br />\u000a Avantages<br />\u000aExcellente traction hors route, même en conditions difficiles<br />\u000aBonne stabilité et contrôle sur terrains irréguliers<br />\u000aRésistance accrue grâce à sa construction renforcée<br />\u000aUsure relativement uniforme pour une longue durée de vie<br />\u000a Utilisation recommandée<br />\u000aIdéal pour :<br />\u000aQuad (ATV) et SSV (UTV)<br />\u000aRandonnée tout-terrain<br />\u000aTravail agricole ou utilitaire<br />\u000aTerrains mixtes (sec, humide, boueux)<br />\u000a En résumé, le Maxxis Bighorn 2.0 MU10 est un pneu fiable et polyvalent, parfait pour les utilisateurs recherchant performance et solidité en tout-terrain.</p>\u000a'),'',36,13,1899.0,1899.0,NULL,NULL,'published','Pneu MAXXIS Bighorn 2.0 MU10 26x11R12 55N 6PR TL','Pneu MAXXIS Bighorn 2.0 MU10 26x11R12 55N 6PR TL au Maroc. Achetez au meilleur prix chez MOTO PACO.',82,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(89,'FURYGAN - Pantalon Killington Noir / Gris','furygan-pantalon-killington-noir-gris',unistr('<p>Ce pantalon est conçu pour offrir une protection maximale lors de vos trajets :<br />\u000aRenforts résistants aux abrasions<br />\u000aZones renforcées aux genoux et hanches<br />\u000aÉventuellement compatibles avec protections CE (si incluses ou à ajouter)<br />\u000a Une sécurité renforcée pour rouler l’esprit tranquille.<br />\u000a Confort et ergonomie<br />\u000aCoupe ergonomique conçue pour la position de conduite<br />\u000aTissu respirant qui aide à évacuer l’humidité<br />\u000aPanneaux flexibles permettant liberté de mouvement<br />\u000aPossibilité d’ajustement à la taille pour un meilleur confort<br />\u000a Adapté à toutes les saisons<br />\u000aLe pantalon Killington 6494 est polyvalent, idéal pour :<br />\u000asorties printemps/été grâce à une bonne ventilation<br />\u000atrajets quotidiens<br />\u000aroutes sinueuses comme balades plus longues<br />\u000a Détails pratiques<br />\u000aFermeture à bouton + zip<br />\u000aPoches fonctionnelles pour ranger vos petits objets<br />\u000aCoutures solides et finitions durables<br />\u000a En résumé<br />\u000aLe pantalon de moto Killington 6494 est un choix parfait si vous recherchez un équipement moto confortable, protecteur et fonctionnel. Il combine une protection renforcée aux zones critiques, une conception ergonomique et un look adapté pour tous les styles de motards.</p>\u000a'),'',33,13,2699.0,2699.0,NULL,NULL,'published','FURYGAN - Pantalon Killington Noir / Gris','FURYGAN - Pantalon Killington Noir / Gris au Maroc. Achetez au meilleur prix chez MOTO PACO.',138,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(90,'Rev''it  3 FTU721 Jacket SOLAR 3 - NOIR','revit-solar-3-ftu721-veste-noir',unistr('<p>La Solar 3 est conçue autour de panneaux mesh larges qui assurent une ventilation optimale, idéale pour rouler par temps chaud sans surchauffe. Le tissu respirant permet une circulation d’air maximale, tout en restant confortable même sur de longues distances.<br />\u000a Protection certifiée<br />\u000aProtections CE au niveau des épaules et coudes<br />\u000aCompartiment pour renfort dorsale CE (non inclus ou fourni selon version)<br />\u000aConstruction robuste avec des zones renforcées aux endroits stratégiques<br />\u000a Une sécurité accrue sans compromettre la liberté de mouvement.<br />\u000a Conception pratique<br />\u000aFermetures éclair robustes et ajustables<br />\u000aPossibilité d’ajouter une doublure thermique ou une membrane pluie (selon accessoires compatibles)<br />\u000aCoupe ergonomique, proche du corps mais confortable<br />\u000aRéglages aux manches, taille et poignets pour un ajustement personnalisé<br />\u000a Style et fonctionnalité<br />\u000aLa Solar 3 en noir allie un design moderne et discret avec des détails fonctionnels pratiques pour le motard quotidien ou sportif.<br />\u000aLook sobre et élégant<br />\u000aLogos discrets<br />\u000aCouleur facile à assortir avec d’autres équipements<br />\u000a Résumé<br />\u000aLa Rev’it Solar 3 Jacket (FTU721) est une veste moto légère, ventilée et protectrice, adaptée à une utilisation estivale ou intermédiaire. Elle offre un excellent équilibre entre confort, sécurité et style, faisant d’elle un choix idéal pour les motards qui veulent rester bien aérés, protégés et performants sur la route.</p>\u000a'),'',48,811,1799.0,1799.0,NULL,NULL,'published','Rev''it  3 FTU721 Jacket SOLAR 3 - NOIR','Rev''it  3 FTU721 Jacket SOLAR 3 - NOIR au Maroc. Achetez au meilleur prix chez MOTO PACO.',98,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(91,'QUAD LOCK GALAXY S26 ULTRA','quad-lock-galaxy-s26-ultra-coque-fixation',unistr('<p>Grâce au système Quad Lock breveté, votre Galaxy S26 Ultra se clipse en un quart de tour sur tous les supports compatibles.<br />\u000a Ce mécanisme assure un maintien stable et fiable, même sur routes cahoteuses ou à grande vitesse.<br />\u000a Protection quotidienne renforcée<br />\u000aCoque résistante aux chocs et aux rayures<br />\u000aMatériaux de haute qualité garantissant durabilité et confort<br />\u000aBords légèrement surélevés pour protéger l’écran et les caméras<br />\u000aIdéale pour une utilisation urbaine ou sportive<br />\u000a Design ergonomique<br />\u000aProfil mince et léger pour une prise en main confortable<br />\u000aAccès facile aux boutons, ports et fonctions du téléphone<br />\u000aCompatible avec la recharge sans fil (sans retirer la coque)<br />\u000a Compatibilité étendue<br />\u000aLa coque fonctionne avec toute la gamme d’accessoires Quad Lock :<br />\u000aSupports moto et vélo<br />\u000aSupports pour voiture<br />\u000aBras articulés et stands de bureau<br />\u000aAccessoires complémentaires<br />\u000a En résumé<br />\u000aLa coque Quad Lock pour Galaxy S26 Ultra combine sécurité, fonctionnalité et robustesse. Elle permet de protéger votre smartphone tout en facilitant sa fixation sur divers supports, idéale pour les utilisateurs actifs et les déplacements quotidiens.</p>\u000a'),'',60,13,699.0,699.0,NULL,NULL,'published','QUAD LOCK GALAXY S26 ULTRA','QUAD LOCK GALAXY S26 ULTRA au Maroc. Achetez au meilleur prix chez MOTO PACO.',126,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(92,'QUAD LOCK GALAXY S25 ULTRA','quad-lock-galaxy-s25-ultra-coque-fixation',unistr('<p>Grâce à son dispositif breveté Quad Lock, votre Galaxy S25 Ultra se clipse en un quart de tour sur tous les supports compatibles.<br />\u000a Ce système innovant garantit un maintien ultra fiable, même sur terrains accidentés ou routes rapides.<br />\u000a Protection quotidienne<br />\u000aCoque robuste offrant une bonne résistance aux chocs<br />\u000aMatériaux de qualité combinant rigidité et flexibilité<br />\u000aBords légèrement surélevés pour protéger l’écran et les modules photo<br />\u000aConçue pour un usage intensif au quotidien<br />\u000a Design fin et fonctionnel<br />\u000aProfil mince et ergonomique pour une prise en main confortable<br />\u000aAccès libre à tous les boutons, ports et fonctions du téléphone<br />\u000aCompatible avec la recharge sans fil (sans retirer la coque)<br />\u000a Compatibilité étendue<br />\u000aLa coque est compatible avec toute la gamme Quad Lock :<br />\u000aSupports moto et vélo<br />\u000aSupports de voiture<br />\u000aBras flexibles et supports de bureau<br />\u000aAccessoires additionnels Quad Lock<br />\u000a En résumé<br />\u000aLa coque Quad Lock pour Galaxy S25 Ultra combine protection efficace, design pratique et un système de fixation simple et fiable, idéale pour ceux qui utilisent leur smartphone en déplacement, sport ou au quotidien.</p>\u000a'),'',16,13,699.0,699.0,NULL,NULL,'published','QUAD LOCK GALAXY S25 ULTRA','QUAD LOCK GALAXY S25 ULTRA au Maroc. Achetez au meilleur prix chez MOTO PACO.',71,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(93,'QUAD LOCK GALAXY S24 ULTRA','quad-lock-galaxy-s24-ultra-coque-fixation',unistr('<p>Grâce à son système de verrouillage breveté Quad Lock, la coque permet de fixer votre smartphone en un simple geste (¼ de tour) sur un large choix de supports : moto, vélo, voiture ou bureau.<br />\u000a Maintien ultra fiable même à haute vitesse ou sur routes irrégulières.<br />\u000a Protection renforcée<br />\u000aCoque résistante aux chocs avec structure en polycarbonate et TPU<br />\u000aBords surélevés pour protéger l’écran et les caméras<br />\u000aProtection idéale pour un usage quotidien ou sportif<br />\u000a Design fin et pratique<br />\u000aProfil mince et ergonomique<br />\u000aPrise en main confortable<br />\u000aAccès facile à tous les boutons et ports<br />\u000aCompatible avec la recharge sans fil<br />\u000a Compatibilité étendue<br />\u000aCompatible avec tous les accessoires Quad Lock :<br />\u000aSupports moto, vélo, voiture<br />\u000aBras articulés et supports bureau<br />\u000aTête de charge sans fil (en option)<br />\u000a En résumé<br />\u000aLa coque Quad Lock Galaxy S24 Ultra est le choix idéal pour ceux qui recherchent une solution fiable, robuste et polyvalente pour fixer leur smartphone en toute sécurité, que ce soit en déplacement ou au quotidien.</p>\u000a'),'',16,13,699.0,699.0,NULL,NULL,'published','QUAD LOCK GALAXY S24 ULTRA','QUAD LOCK GALAXY S24 ULTRA au Maroc. Achetez au meilleur prix chez MOTO PACO.',105,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(94,'GIVI SR - Support topcase Monolock ou Monokey SR7070','givi-sr7070-support-topcase-monolock-monokey',unistr('<p>Le GIVI SR7070 est un support spécifique pour top case conçu pour accueillir les systèmes Monolock et Monokey. Robuste et fiable, il permet d’équiper votre moto d’un top case en toute sécurité, tout en conservant une installation propre et parfaitement adaptée au modèle de moto.<br />\u000a Caractéristiques principales<br />\u000aType : support top case spécifique<br />\u000aCompatibilité : systèmes Monokey et Monolock<br />\u000aMatériau : structure en acier renforcé avec finition noire<br />\u000aMontage : sur points de fixation d’origine<br />\u000aCharge maximale : environ 6 kg<br />\u000aUtilisation : support pour top case ou porte-bagages<br />\u000a Important :<br />\u000aLa platine n’est pas incluse<br />\u000aÀ associer avec :<br />\u000aPlaques Monokey : M5, M8A, M8B, M9A, M9B<br />\u000aPlaques Monolock : M5M, M6M<br />\u000a Avantages<br />\u000aCompatible avec deux systèmes : Monokey et Monolock<br />\u000aFixation solide et sécurisée pour top case<br />\u000aInstallation simple sans modification importante<br />\u000aStructure robuste adaptée aux trajets quotidiens et touring<br />\u000aPermet d’ajouter facilement une solution de bagagerie<br />\u000a Compatibilité<br />\u000aConçu spécifiquement pour certaines motos (ex : SYM ADX 300 2024+)<br />\u000a Vérifiez toujours la compatibilité avec votre modèle de moto avant achat<br />\u000a En résumé<br />\u000aLe GIVI SR7070 est un support polyvalent et robuste qui permet d’installer facilement un top case Monolock ou Monokey. Idéal pour les motards souhaitant ajouter une solution de transport fiable et évolutive, il garantit sécurité, praticité et compatibilité avec une large gamme de bagagerie GIVI.</p>\u000a'),'',45,756,999.0,999.0,NULL,NULL,'published','GIVI SR - Support topcase Monolock ou Monokey SR7070','GIVI SR - Support topcase Monolock ou Monokey SR7070 au Maroc. Achetez au meilleur prix chez MOTO PACO.',90,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(95,'Givi Waterproof Side Bag Gravel-T GRT725 Canyon MONOKEY CAM-SIDE','givi-grt725-canyon-sacoche-laterale-etanche-cam-side',unistr('<p>La GIVI GRT725 Canyon est une sacoche latérale étanche de la gamme Gravel-T, conçue pour les motards aventuriers recherchant une solution souple, robuste et 100% imperméable. Compatible avec le système MONOKEY CAM-SIDE, elle s’installe facilement sur les supports dédiés et garantit une fixation fiable, même en conditions extrêmes.<br />\u000a Caractéristiques principales<br />\u000aType : sacoche latérale souple étanche<br />\u000aGamme : Gravel-T / Canyon<br />\u000aCapacité : environ 25 à 30 litres<br />\u000aMatériau : tissu haute résistance avec revêtement étanche<br />\u000aSystème de fixation : MONOKEY CAM-SIDE<br />\u000aFermeture : roll-top pour une étanchéité maximale<br />\u000aCouleur : noir avec finitions techniques<br />\u000a Avantages<br />\u000a100% étanche : protège efficacement contre pluie, boue et poussière<br />\u000aUltra résistante : conçue pour le off-road et les conditions extrêmes<br />\u000aFixation sécurisée CAM-SIDE : maintien stable même sur terrains difficiles<br />\u000aFlexible et légère : alternative idéale aux valises aluminium<br />\u000aPolyvalente : adaptée au touring, adventure et voyages longue distance<br />\u000a Compatibilité<br />\u000aSupports GIVI CAM-SIDE (PL_CAM, PLO_CAM, etc.)<br />\u000aCompatible avec systèmes MONOKEY CAM-SIDE<br />\u000a Vérifiez la compatibilité avec votre support moto GIVI<br />\u000a En résumé :<br />\u000aLa GIVI GRT725 Canyon Gravel-T est une sacoche latérale idéale pour les motards aventure. Étanche, robuste et légère, elle offre une excellente alternative aux valises rigides tout en garantissant une fixation sécurisée grâce au système CAM-SIDE. Parfaite pour les longs trajets et les terrains exigeants.</p>\u000a'),'',39,756,4999.0,4999.0,NULL,NULL,'published','Givi Waterproof Side Bag Gravel-T GRT725 Canyon MONOKEY CAM-SIDE','Givi Waterproof Side Bag Gravel-T GRT725 Canyon MONOKEY CAM-SIDE au Maroc. Achetez au meilleur prix chez MOTO PACO.',99,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(96,'GIVI Cylinder bag 40l Black EA115BK','givi-ea115bk-sac-cylindrique-40l-noir',unistr('<p>Le GIVI EA115BK est un sac cylindrique de 40 litres, idéal pour les motards recherchant une solution de transport spacieuse, étanche et pratique. Conçu pour les longs trajets et les aventures, il protège efficacement vos affaires contre la pluie, la poussière et les conditions difficiles.<br />\u000a Caractéristiques principales<br />\u000aType : sac cylindrique (dry bag)<br />\u000aCapacité : 40 litres<br />\u000aMatériau : polyester enduit PVC, étanche et résistant<br />\u000aCouleur : noir<br />\u000aFermeture : système roll-top pour une étanchéité optimale<br />\u000aFixation : sangles ajustables pour montage sur selle ou porte-bagages<br />\u000aTransport : poignée et bandoulière pour un usage hors moto<br />\u000a Avantages<br />\u000aGrande capacité (40L) : idéal pour voyages et longs trajets<br />\u000a100% étanche : protège vos affaires de la pluie et de l’humidité<br />\u000aPolyvalent : se fixe facilement sur différentes parties de la moto<br />\u000aRésistant : conçu pour les conditions exigeantes (touring et aventure)<br />\u000aPratique : facile à transporter grâce à sa bandoulière<br />\u000a Compatibilité<br />\u000aConvient à toutes les motos<br />\u000aCompatible avec selle, porte-bagages ou top case<br />\u000a En résumé :<br />\u000aLe GIVI EA115BK Sac Cylindrique 40L Noir est un choix idéal pour les motards qui ont besoin d’un espace de rangement étanche, robuste et polyvalent. Parfait pour les voyages, il garantit la protection de vos affaires quelles que soient les conditions.</p>\u000a'),'',39,756,799.0,799.0,NULL,NULL,'published','GIVI Cylinder bag 40l Black EA115BK','GIVI Cylinder bag 40l Black EA115BK au Maroc. Achetez au meilleur prix chez MOTO PACO.',84,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(97,'GIVI XL02 Sac cargo X-Line Noir','givi-xl02-sac-cargo-x-line-noir',unistr('<p>Le GIVI XL02 est un sac cargo X-Line noir conçu pour transporter vos affaires facilement sur votre moto. Compact, robuste et pratique, il offre une solution de rangement flexible pour vos trajets urbains comme pour vos aventures longues distances.<br />\u000a Caractéristiques principales<br />\u000aType : sac cargo moto<br />\u000aCapacité : environ 20 à 25 L (adaptable selon usage)<br />\u000aMatériau : polyester résistant et imperméable<br />\u000aCouleur : noir élégant<br />\u000aInstallation : sangles et attaches rapides pour fixation sur moto ou top case<br />\u000aFonctionnalité : sac léger, modulable et facile à transporter<br />\u000a Avantages<br />\u000aTransport pratique : idéal pour les affaires personnelles et équipements légers<br />\u000aRésistant et étanche : protège vos affaires des intempéries<br />\u000aPolyvalent : peut être utilisé comme sac sur top case, porte-bagages ou solo<br />\u000aCompact et léger : facile à fixer et à retirer<br />\u000aDesign moderne : s’adapte à tous types de motos et styles</p>\u000a'),'',47,756,2249.0,2249.0,NULL,NULL,'published','GIVI XL02 Sac cargo X-Line Noir','GIVI XL02 Sac cargo X-Line Noir au Maroc. Achetez au meilleur prix chez MOTO PACO.',61,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(98,'GIVI PLO_CAM - Side cases holders PLO2174CAM','givi-plo2174cam-support-valises-laterales-cam-side',unistr('<p>Le GIVI PLO2174CAM est un support spécifique pour valises latérales doté du système PLO_CAM / CAM-SIDE, conçu pour accueillir les valises aluminium Trekker Outback EVO et autres modèles compatibles. Robuste et parfaitement ajusté à la moto, il garantit une fixation stable et sécurisée, idéale pour le touring et l’aventure.<br />\u000a Caractéristiques principales<br />\u000aType : support latéral PLO_CAM (CAM-SIDE)<br />\u000aCompatibilité : valises aluminium GIVI Trekker Outback EVO<br />\u000aMatériau : acier tubulaire renforcé avec finition noire<br />\u000aInstallation : montage sur points de fixation d’origine<br />\u000aConception : spécifique à un modèle de moto pour un ajustement précis<br />\u000aSystème : CAM-SIDE pour fixation rapide et sécurisée<br />\u000a Avantages<br />\u000aFixation ultra solide : idéale pour charges lourdes et longs trajets<br />\u000aCompatible aluminium : conçu pour les valises Trekker Outback EVO<br />\u000aRésistance maximale : supporte vibrations, chocs et conditions difficiles<br />\u000aMontage précis : s’intègre parfaitement à la moto<br />\u000aFiabilité GIVI : matériaux de haute qualité et longue durée de vie<br />\u000a Compatibilité<br />\u000aValises GIVI Trekker Outback EVO (CAM-SIDE)<br />\u000aSupport spécifique PLO2174CAM (selon modèle de moto)<br />\u000a Vérifiez la compatibilité avec votre moto avant l’achat<br />\u000a En résumé :<br />\u000aLe GIVI PLO2174CAM est un support latéral haut de gamme conçu pour les motards exigeants. Grâce à son système CAM-SIDE et sa structure renforcée, il offre une fixation fiable et durable pour vos valises aluminium, idéale pour le touring et les aventures longue distance.</p>\u000a'),'',45,756,2749.0,2749.0,NULL,NULL,'published','GIVI PLO_CAM - Side cases holders PLO2174CAM','GIVI PLO_CAM - Side cases holders PLO2174CAM au Maroc. Achetez au meilleur prix chez MOTO PACO.',83,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(99,'GIVI PLOS_CAM - Support valises latérales PLOS5108CAM','givi-plos5108cam-support-valises-laterales-cam-side',unistr('<p>Le GIVI PLOS5108CAM est un support spécifique pour valises latérales équipé du système PL ONE-FIT CAM-SIDE, conçu pour accueillir les valises aluminium Trekker Outback EVO et les sacoches compatibles CAM-SIDE. Il est particulièrement adapté aux motos adventure comme les BMW R1200GS / R1250GS.<br />\u000a Caractéristiques principales<br />\u000aType : support latéral PL ONE-FIT CAM-SIDE<br />\u000aCompatibilité : valises GIVI Trekker Outback EVO et sacoches CAM-SIDE<br />\u000aMatériau : acier tubulaire renforcé (diamètre 18 mm)<br />\u000aConception : côté droit profilé pour dégagement de l’échappement<br />\u000aInstallation : montage sur points de fixation d’origine<br />\u000aOption : compatible avec kit 11RKIT pour système démontable rapide<br />\u000a Avantages<br />\u000aFixation ultra robuste : idéal pour charges lourdes et usage aventure<br />\u000aCompatibilité aluminium : conçu pour valises Trekker Outback<br />\u000aAdaptation parfaite : design spécifique à la moto avec dégagement échappement<br />\u000aPolyvalence : compatible valises rigides et sacoches souples CAM-SIDE<br />\u000aÉvolutif : possibilité de conversion en support à démontage rapide<br />\u000a Compatibilité<br />\u000aBMW R1200GS (2013–2018)<br />\u000aBMW R1250GS / Adventure (2019–2024)<br />\u000aCompatible avec :<br />\u000aTrekker Outback EVO 37L / 44L / 48L<br />\u000aVersions asymétriques (33L / 40L côté échappement)<br />\u000aSacoches Canyon CAM-SIDE</p>\u000a'),'',45,756,2749.0,2749.0,NULL,NULL,'published','GIVI PLOS_CAM - Support valises latérales PLOS5108CAM','GIVI PLOS_CAM - Support valises latérales PLOS5108CAM au Maroc. Achetez au meilleur prix chez MOTO PACO.',141,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(100,'GIVI PL_CAM - Support valises latérales PL5146CAM','givi-pl5146cam-support-valises-laterales-cam-side',unistr('<p>Le GIVI PL5146CAM est un support spécifique pour valises latérales équipé du système PL_CAM, conçu pour accueillir les valises aluminium Trekker Outback et autres modèles compatibles CAM-SIDE. Robuste et fiable, il est idéal pour les motards adeptes de voyages et d’aventures.<br />\u000a Caractéristiques principales<br />\u000aType : support latéral pour valises (système CAM-SIDE)<br />\u000aCompatibilité : valises aluminium GIVI Trekker Outback<br />\u000aMatériau : acier tubulaire renforcé avec finition noire<br />\u000aInstallation : montage sur points de fixation d’origine<br />\u000aConception : spécifique à un modèle de moto pour un ajustement parfait<br />\u000a Avantages<br />\u000aFixation ultra sécurisée : système CAM-SIDE robuste pour charges lourdes<br />\u000aIdéal pour valises aluminium : conçu pour le touring et le off-road<br />\u000aRésistance maximale : supporte les conditions difficiles (routes, pistes, vibrations)<br />\u000aMontage précis : s’adapte parfaitement à la moto<br />\u000aDurabilité GIVI : matériaux de haute qualité et finition résistante<br />\u000a Compatibilité<br />\u000aValises GIVI Trekker Outback (CAM-SIDE)<br />\u000aSupport spécifique PL5146CAM (selon modèle de moto)<br />\u000a Vérifiez la compatibilité exacte avec votre moto avant l’achat<br />\u000a En résumé :<br />\u000aLe GIVI PL5146CAM est un support haut de gamme conçu pour les valises aluminium. Grâce à son système CAM-SIDE, il offre une fixation extrêmement solide et fiable, parfaite pour les aventures, le touring et les longs trajets avec bagages.</p>\u000a'),'',45,756,2999.0,2999.0,NULL,NULL,'published','GIVI PL_CAM - Support valises latérales PL5146CAM','GIVI PL_CAM - Support valises latérales PL5146CAM au Maroc. Achetez au meilleur prix chez MOTO PACO.',107,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(101,'GIVI PL - Support valises latérales PL5146','givi-pl5146-support-valises-laterales',unistr('<p>Le GIVI PL5146 est un support spécifique pour valises latérales conçu pour permettre l’installation de valises rigides GIVI sur votre moto. Robuste et fiable, il garantit une fixation stable et sécurisée pour vos bagages, idéal pour le touring et les longs trajets.<br />\u000a Caractéristiques principales<br />\u000aType : support latéral pour valises<br />\u000aCompatibilité : valises latérales GIVI (type Monokey selon configuration)<br />\u000aMatériau : acier renforcé avec finition noire résistante<br />\u000aInstallation : montage sur points de fixation d’origine<br />\u000aConception : spécifique à un modèle de moto pour un ajustement parfait<br />\u000a Avantages<br />\u000aFixation sécurisée : maintien stable des valises même à haute vitesse<br />\u000aRobustesse : structure en acier résistante aux charges et aux vibrations<br />\u000aCompatibilité GIVI : adapté aux valises latérales de la marque<br />\u000aInstallation simple : montage sans modification majeure<br />\u000aIdéal pour le voyage : parfait pour transporter bagages et équipements<br />\u000a Compatibilité<br />\u000aSupport spécifique pour moto (référence PL5146)<br />\u000a Il est recommandé de vérifier la compatibilité exacte avec votre modèle de moto et les valises GIVI utilisées.<br />\u000a En résumé :<br />\u000aLe GIVI PL5146 est un support indispensable pour installer vos valises latérales en toute sécurité. Solide, fiable et parfaitement adapté, il vous permet de voyager avec sérénité en transportant vos bagages sur votre moto.</p>\u000a'),'',45,756,2499.0,2499.0,NULL,NULL,'published','GIVI PL - Support valises latérales PL5146','GIVI PL - Support valises latérales PL5146 au Maroc. Achetez au meilleur prix chez MOTO PACO.',71,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(102,'GIVI E233S dossier pour Alaska 44l Noir','givi-e233s-dosseret-alaska-44l-noir',unistr('<p>Le GIVI E233S est un dosseret passager noir spécialement conçu pour le top case Trekker Alaska 44L. Il améliore le confort du passager en offrant un appui moelleux et ergonomique lors des trajets, notamment sur longues distances.<br />\u000a Caractéristiques principales<br />\u000aType : dosseret passager pour top case<br />\u000aCompatibilité : GIVI Trekker Alaska 44L (ALA44)<br />\u000aMatériau : mousse haute densité avec revêtement résistant<br />\u000aFinition : noir élégant, parfaitement assorti au top case<br />\u000aInstallation : fixation simple et rapide sur le couvercle du top case<br />\u000a Avantages<br />\u000aConfort accru du passager : appui dorsal agréable et ergonomique<br />\u000aIdéal pour longs trajets : réduit la fatigue et améliore l’expérience de conduite<br />\u000aDesign intégré : s’adapte parfaitement au top case Alaska 44L<br />\u000aMatériaux durables : résistants aux intempéries et à l’usure<br />\u000aInstallation facile : montage rapide avec kit de fixation inclus Compatibilité<br />\u000aTop case GIVI Trekker Alaska 44L (ALA44)<br />\u000aNon compatible avec d’autres modèles sans adaptation<br />\u000a💡 En résumé :<br />\u000aLe GIVI E233S est l’accessoire idéal pour améliorer le confort du passager sur votre top case Alaska 44L. Pratique, esthétique et facile à installer, il rend vos trajets plus agréables, surtout sur longues distances.</p>\u000a'),'',16,756,749.0,499.0,NULL,NULL,'published','GIVI E233S dossier pour Alaska 44l Noir','GIVI E233S dossier pour Alaska 44l Noir au Maroc. Achetez au meilleur prix chez MOTO PACO.',90,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(104,'GIVI BF - Fixation Tanklock BF36','givi-bf-fixation-tanklock-bf36',unistr('<p>La GIVI BF – Fixation Tanklock BF36 est un accessoire indispensable pour installer vos sacoches de réservoir BF36 sur votre moto. Elle permet un montage rapide, sécurisé et stable grâce au système Tanklock, garantissant que votre sacoche reste parfaitement fixée pendant vos trajets.<br />\u000a Caractéristiques principales<br />\u000aType : fixation Tanklock pour sacoche BF36<br />\u000aCompatibilité : sacoche GIVI BF36<br />\u000aInstallation : rapide et simple sur platine Tanklock GIVI<br />\u000aMatériau : plastique et métal renforcé pour solidité et durabilité<br />\u000aFonction : maintien sécurisé de la sacoche sur le réservoir<br />\u000a Avantages<br />\u000aMontage rapide et pratique grâce au système Tanklock<br />\u000aMaintien sûr et stable de la sacoche BF36<br />\u000aCompatible avec toutes les motos équipées d’une platine Tanklock GIVI<br />\u000aMatériaux durables pour une utilisation longue durée<br />\u000aFacile à installer et à retirer sans outils complexes<br />\u000a Compatibilité<br />\u000aSacoche de réservoir GIVI BF36<br />\u000aToutes les motos équipées d’une platine Tanklock GIVI<br />\u000a En résumé :<br />\u000aLa GIVI BF – Fixation Tanklock BF36 assure une installation sécurisée et stable de votre sacoche de réservoir BF36. Simple, rapide et robuste, elle est l’accessoire parfait pour transporter vos affaires en toute sécurité lors de vos trajets à moto.</p>\u000a'),'',43,756,749.0,749.0,NULL,NULL,'published','GIVI BF - Fixation Tanklock BF36','GIVI BF - Fixation Tanklock BF36 au Maroc. Achetez au meilleur prix chez MOTO PACO.',114,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(105,'GIVI M10 PLAQUE D''ADAPTATION MONOKEY','givi-m10-plaque-adaptation-monokey-2',unistr('<p>La GIVI M10 est une plaque d’adaptation Monokey conçue pour faciliter l’installation de top cases ou accessoires GIVI sur votre moto. Elle assure un montage sûr et stable, compatible avec toutes les motos disposant de points de fixation pour système Monokey.<br />\u000a Caractéristiques principales<br />\u000aType : plaque d’adaptation Monokey<br />\u000aMatériau : acier robuste et résistant à la corrosion<br />\u000aFonction : permet d’installer un top case Monokey sur différents modèles de motos<br />\u000aInstallation : facile, sur points de fixation existants, sans modification du châssis<br />\u000aCompatibilité : compatible avec tous les top cases GIVI Monokey<br />\u000a Avantages<br />\u000aMontage sécurisé et stable de votre top case GIVI<br />\u000aPermet l’installation sur des motos ne disposant pas d’un support spécifique<br />\u000aMatériau robuste et durable pour une utilisation longue durée<br />\u000aCompatible avec tous les top cases et accessoires Monokey GIVI<br />\u000aInstallation simple et rapide, sans outils compliqués<br />\u000a Compatibilité<br />\u000aToutes les motos compatibles avec les supports Monokey GIVI<br />\u000aConvient pour installer top cases Monokey ou accessoires similaires<br />\u000a En résumé :<br />\u000aLa GIVI M10 Plaque d’Adaptation Monokey est l’accessoire indispensable pour monter facilement et en toute sécurité vos top cases GIVI sur n’importe quelle moto compatible. Robuste, durable et simple à installer, elle assure stabilité et sécurité pour vos trajets.</p>\u000a'),'',45,756,949.0,949.0,NULL,NULL,'published','GIVI M10 PLAQUE D''ADAPTATION MONOKEY','GIVI M10 PLAQUE D''ADAPTATION MONOKEY au Maroc. Achetez au meilleur prix chez MOTO PACO.',130,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(106,'Givi B32N Bold Monolock Top Case - 32 Litre','givi-b32n-bold-monolock-top-case-32l',unistr('<p>Le GIVI B32N Bold est un top case Monolock de 32 litres, conçu pour les motards recherchant sécurité, praticité et design moderne. Sa capacité permet de transporter un casque intégral ou vos bagages essentiels pour vos trajets quotidiens ou balades.<br />\u000a Caractéristiques principales<br />\u000aType : Top Case Monolock<br />\u000aCapacité : 32 litres<br />\u000aMatériau : plastique haute résistance avec finition noire mate<br />\u000aSystème de verrouillage : Monolock, pratique et sécurisé<br />\u000aPoids : léger pour faciliter le transport et la manipulation<br />\u000aAccessoires compatibles : dosseret passager et supports GIVI Monolock<br />\u000aRésistance : conçu pour résister aux chocs, rayures et intempéries<br />\u000a Avantages<br />\u000aCapacité idéale pour un casque intégral ou bagages essentiels<br />\u000aMatériau robuste et durable pour une protection optimale<br />\u000aInstallation rapide et sécurisée sur platine Monolock GIVI<br />\u000aDesign moderne et élégant compatible avec toutes les motos<br />\u000aRésistant aux intempéries, parfait pour usage quotidien ou balades<br />\u000a Compatibilité<br />\u000aToutes les motos équipées d’une platine Monolock GIVI<br />\u000aParfait pour une utilisation quotidienne ou pour des trajets courts et moyens<br />\u000a En résumé :<br />\u000aLe GIVI B32N Bold Monolock 32L combine capacité, sécurité et design compact. Léger et robuste, il protège vos affaires tout en s’adaptant facilement à votre moto grâce au système Monolock.</p>\u000a'),'',47,756,999.0,999.0,NULL,NULL,'published','Givi B32N Bold Monolock Top Case - 32 Litre','Givi B32N Bold Monolock Top Case - 32 Litre au Maroc. Achetez au meilleur prix chez MOTO PACO.',100,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(107,'GIVI OBKEV44BL -  Linkes Seitengehäuse Givi Trekker Outback EVO Aluminium Schwarz 44lt','givi-obkev44bl-trekker-outback-evo-valise-laterale-aluminium-44l-noir',unistr('<p>Le GIVI OBKEV44BL est un top case latéral gauche de la série Trekker Outback EVO, conçu en aluminium robuste avec une finition noire élégante. Avec sa capacité de 44 litres, il offre un espace de rangement sécurisé et résistant pour vos bagages lors de longs trajets ou d’aventures touring.<br />\u000a Caractéristiques principales<br />\u000aType : valise latérale gauche Trekker Outback EVO<br />\u000aCapacité : 44 litres<br />\u000aMatériau : aluminium robuste avec finition noire mate<br />\u000aSystème de verrouillage : Monokey EVO sécurisé<br />\u000aRésistance : conçu pour résister aux intempéries, aux chocs et aux rayures<br />\u000aAccessoires compatibles : possibilité d’ajouter support ou top case central<br />\u000a Avantages<br />\u000aProtection maximale des bagages : aluminium durable et robuste<br />\u000aGrande capacité de stockage : 44 litres pour casques, équipements ou vêtements<br />\u000aSystème de verrouillage Monokey EVO : sécurité et praticité<br />\u000aDesign élégant et moderne : finition noire mate adaptée au style touring et aventure<br />\u000aRésistant aux intempéries : idéal pour les longs trajets et conditions difficiles<br />\u000a Compatibilité<br />\u000aValise latérale compatible avec toutes les motos équipées de platine Monokey EVO<br />\u000aPartie gauche pour montage en kit Trekker Outback EVO<br />\u000a En résumé :<br />\u000aLe GIVI OBKEV44BL est la solution idéale pour les motards qui souhaitent transporter leurs affaires en toute sécurité tout en conservant un style élégant et robuste. Sa construction en aluminium noir et sa grande capacité de 44 litres le rendent parfait pour les aventures longue distance et le touring.</p>\u000a'),'',47,756,3999.0,3999.0,NULL,NULL,'published','GIVI OBKEV44BL -  Linkes Seitengehäuse Givi Trekker Outback EVO Aluminium Schwarz 44lt','GIVI OBKEV44BL -  Linkes Seitengehäuse Givi Trekker Outback EVO Aluminium Schwarz 44lt au Maroc. Achetez au meilleur prix chez MOTO PACO.',125,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(108,'GIVI TRK52BB TREKKER LITE 52L NOIR','givi-trk52bb-trekker-lite-top-case-52l-noir',unistr('<p>Le GIVI TRK52BB Trekker Lite 52L est un top case noir robuste et spacieux, conçu pour les motards qui recherchent capacité, légèreté et durabilité. Avec ses 52 litres de capacité, il peut accueillir deux casques intégraux ou vos bagages pour les longs trajets.<br />\u000a Caractéristiques principales<br />\u000aType : Top Case Trekker Lite<br />\u000aCapacité : 52 litres<br />\u000aMatériau : polymère haute résistance, finition noire mate<br />\u000aSystème de verrouillage : Monokey, sécurisé et pratique<br />\u000aAccessoires compatibles : dosseret passager, support de chargement<br />\u000aPoids : léger pour une manipulation facile<br />\u000aRésistance : conçu pour le touring et les aventures sur route<br />\u000a Avantages<br />\u000aGrande capacité : idéal pour longs trajets ou transport de deux casques intégraux<br />\u000aRobustesse et durabilité : matériaux de qualité supérieure résistants aux chocs et aux rayures<br />\u000aSystème Monokey sécurisé : verrouillage fiable et pratique<br />\u000aDesign élégant et moderne : finition noire mate discrète et esthétique<br />\u000aPolyvalent : compatible avec la plupart des motos équipées d’une platine Monokey<br />\u000a Compatibilité<br />\u000aToutes les motos équipées d’une platine Monokey GIVI<br />\u000aIdéal pour le touring, la moto quotidienne ou les balades longues distances<br />\u000a En résumé :<br />\u000aLe GIVI TRK52BB Trekker Lite 52L noir combine capacité, sécurité et légèreté, ce qui en fait le top case idéal pour les motards qui souhaitent transporter bagages et casques de manière pratique et sécurisée, tout en conservant un style moderne et élégant.</p>\u000a'),'',47,756,2499.0,2499.0,NULL,NULL,'published','GIVI TRK52BB TREKKER LITE 52L NOIR','GIVI TRK52BB TREKKER LITE 52L NOIR au Maroc. Achetez au meilleur prix chez MOTO PACO.',105,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(109,'GIVI ALA44 Trekker Alaska Top Case Monokey Aluminium','givi-ala44-trekker-alaska-top-case-aluminium-monokey',unistr('<p>Le GIVI ALA44 Trekker Alaska est un top case Monokey en aluminium conçu pour le touring et les voyages longue distance. Il offre une capacité généreuse tout en garantissant robustesse, sécurité et résistance aux conditions difficiles.<br />\u000a Caractéristiques principales<br />\u000aType : Top case Trekker Alaska Monokey<br />\u000aCapacité : 44 litres (suffisante pour 2 casques intégraux ou bagages de longue distance)<br />\u000aMatériau : aluminium anodisé de haute qualité, finition robuste et durable<br />\u000aSystème de verrouillage : Monokey, pratique et sécurisé<br />\u000aRésistance : conçu pour le touring et l’aventure, résistant aux intempéries et aux impacts<br />\u000aAccessoires : possibilité d’ajouter dosseret passager et support de chargement<br />\u000a Avantages<br />\u000aGrande capacité de rangement : idéal pour longs trajets ou voyages<br />\u000aRobustesse maximale : aluminium de qualité premium, résistant aux chocs et aux rayures<br />\u000aSécurité renforcée : système Monokey avec fermeture centralisée<br />\u000aRésistant aux intempéries : protège vos affaires contre pluie, poussière et soleil<br />\u000aPolyvalent et modulable : compatible avec la plupart des motos équipées de platine Monokey GIVI<br />\u000a Compatibilité<br />\u000aCompatible avec toutes les motos équipées d’une platine Monokey GIVI<br />\u000aIdéal pour les motards touring ou aventuriers souhaitant transporter bagages et équipements<br />\u000a En résumé :<br />\u000aLe GIVI ALA44 Trekker Alaska combine capacité, sécurité et durabilité grâce à sa construction en aluminium. Parfait pour les longues distances, ce top case Monokey protège vos affaires tout en offrant un look élégant et robuste pour votre moto.</p>\u000a'),'',47,756,2999.0,2999.0,NULL,NULL,'published','GIVI ALA44 Trekker Alaska Top Case Monokey Aluminium','GIVI ALA44 Trekker Alaska Top Case Monokey Aluminium au Maroc. Achetez au meilleur prix chez MOTO PACO.',101,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(110,'SACOCHE DE RÉSERVOIR GIVI WL902 WEIGHTLESS TANKLOCKED 5L','givi-wl902-sacoche-reservoir-tanklock-5l',unistr('<p>La GIVI WL902 est une sacoche de réservoir légère et compacte d’une capacité de 5 litres, conçue pour le système Tanklock de GIVI. Elle offre un accès facile à vos affaires essentielles tout en garantissant une fixation sécurisée sur la moto.<br />\u000a Caractéristiques principales<br />\u000aCapacité : 5 litres<br />\u000aType : sacoche de réservoir Weightless, compatible système Tanklock<br />\u000aMatériau : tissu résistant, imperméable et durable<br />\u000aFixation : se verrouille facilement sur la platine Tanklock GIVI<br />\u000aDesign : compact et léger, parfait pour un usage quotidien ou les balades courtes<br />\u000aFermeture : zip étanche pour protéger vos affaires de la pluie<br />\u000a Avantages<br />\u000aInstallation rapide et sécurisée : système Tanklock fiable et simple<br />\u000aLégère et compacte : n’alourdit pas la moto et reste pratique<br />\u000aRésistante aux intempéries : protège vos objets contre la pluie et la poussière<br />\u000aAccès facile : idéal pour téléphone, portefeuille, documents ou petits objets<br />\u000aPolyvalente : convient pour moto, scooter ou roadster<br />\u000a Compatibilité<br />\u000aToutes les motos équipées d’une platine Tanklock GIVI<br />\u000aIdéale pour une utilisation quotidienne ou pour de courtes balades<br />\u000a En résumé :<br />\u000aLa sacoche de réservoir GIVI WL902 5L Weightless Tanklocked combine légèreté, praticité et sécurité. Elle est parfaite pour transporter vos petits objets essentiels sans encombrer votre moto, tout en offrant une fixation fiable grâce au système Tanklock.</p>\u000a'),'',51,756,1599.0,1599.0,NULL,NULL,'published','SACOCHE DE RÉSERVOIR GIVI WL902 WEIGHTLESS TANKLOCKED 5L','SACOCHE DE RÉSERVOIR GIVI WL902 WEIGHTLESS TANKLOCKED 5L au Maroc. Achetez au meilleur prix chez MOTO PACO.',99,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(111,'Givi TNH9226 tubular engine guard CFMoto 450 MT','givi-tnh9226-protection-tubulaire-moteur-cfmoto-450mt',unistr('<p>Le GIVI TNH9226 est un kit de protections tubulaires pour moteur spécialement conçu pour la CFMOTO 450 MT. Ces crash bars protègent le moteur et les carénages de votre moto contre les chocs et les rayures en cas de chute ou de contact avec des obstacles.<br />\u000a Caractéristiques principales<br />\u000aType : crash bar / protection tubulaire moteur<br />\u000aMatériau : acier tubulaire haute résistance avec finition noire poudrée<br />\u000aInstallation : montage sur points de fixation d’origine, facile et sécurisé<br />\u000aCompatibilité : conçu pour CFMOTO 450 MT (modèles 2024 et suivants)<br />\u000aFinition : robuste et résistante à la corrosion<br />\u000a Avantages<br />\u000aProtection maximale du moteur : réduit les risques de dommages en cas de chute<br />\u000aPréservation du carénage : protège les parties sensibles de la moto<br />\u000aQualité GIVI : matériaux durables et finition premium<br />\u000aInstallation simple : ne nécessite pas de modifications sur le châssis<br />\u000aDesign discret et esthétique : s’intègre parfaitement à la ligne de la moto<br />\u000a Compatibilité<br />\u000aCFMOTO 450 MT (à partir de 2024)<br />\u000aMontage direct sur points de fixation d’origine sans altérer la structure<br />\u000a En résumé :<br />\u000aLe GIVI TNH9226 est l’accessoire indispensable pour protéger votre CFMOTO 450 MT. Ces protections tubulaires garantissent sécurité et sérénité lors de vos trajets urbains ou aventuriers, tout en maintenant l’esthétique de la moto.</p>\u000a'),'',21,756,1999.0,1999.0,NULL,NULL,'published','Givi TNH9226 tubular engine guard CFMoto 450 MT','Givi TNH9226 tubular engine guard CFMoto 450 MT au Maroc. Achetez au meilleur prix chez MOTO PACO.',61,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(112,'GIVI Additional mounting kit 5145KIT','givi-5145kit-kit-fixation-additionnel-pare-brise',unistr('<p>Le GIVI 5145KIT est un kit de fixation additionnel conçu pour permettre le montage de pare-brise ou d’accessoires Givi sur des motos spécifiques nécessitant un support complémentaire.<br />\u000a Caractéristiques principales<br />\u000aType : kit de montage spécifique<br />\u000aUtilisation : nécessaire pour installer certains pare-brise Givi<br />\u000aContenu : supports, entretoises, visserie et éléments de fixation<br />\u000aCompatibilité : conçu pour des modèles de motos précis (selon configuration)<br />\u000aInstallation : se monte en complément des points de fixation d’origine<br />\u000a Avantages<br />\u000aMontage sécurisé : garantit une fixation stable et fiable du pare-brise<br />\u000aCompatibilité étendue : permet d’adapter certains écrans Givi sur des motos spécifiques<br />\u000aQualité Givi : matériaux robustes et durables<br />\u000aInstallation facilitée : kit complet avec tous les éléments nécessaires<br />\u000aAjustement précis : conçu pour une intégration parfaite<br />\u000a Compatibilité<br />\u000aLe GIVI 5145KIT est un kit spécifique utilisé avec certains pare-brise Givi (souvent en complément d’un modèle précis).<br />\u000a Il est indispensable de vérifier :<br />\u000ale pare-brise compatible<br />\u000ala moto concernée<br />\u000a En résumé :<br />\u000aLe GIVI 5145KIT est un accessoire indispensable pour assurer une installation correcte et sécurisée de certains pare-brise Givi, en garantissant une compatibilité parfaite avec votre moto.</p>\u000a'),'',28,756,499.0,499.0,NULL,NULL,'published','GIVI Additional mounting kit 5145KIT','GIVI Additional mounting kit 5145KIT au Maroc. Achetez au meilleur prix chez MOTO PACO.',115,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(113,'GIVI D9226ST SPECIFIC SCREEN TRANSPARENT','givi-d9226st-pare-brise-cfmoto-450mt',unistr('<p>Le GIVI D9226ST est un pare-brise spécifique transparent de type touring (ST), conçu pour offrir une protection aérodynamique supérieure et améliorer le confort de conduite, notamment lors des longs trajets.<br />\u000a Caractéristiques principales<br />\u000aType : bulle haute transparente (version ST – touring)<br />\u000aMatériau : plexiglas de haute qualité, résistant aux chocs et aux rayures<br />\u000aMontage : spécifique, se fixe directement sur les points d’origine<br />\u000aFinition : transparente pour une visibilité optimale<br />\u000aConception : adaptée à un modèle de moto précis (selon compatibilité constructeur)<br />\u000a Avantages<br />\u000aProtection renforcée contre le vent : réduit les turbulences au niveau du casque et du torse<br />\u000aConfort longue distance : idéal pour le touring et les trajets autoroutiers<br />\u000aVisibilité parfaite : transparence totale sans déformation<br />\u000aRéduction de la fatigue : meilleure gestion du flux d’air<br />\u000aQualité GIVI : robustesse, durabilité et finition haut de gamme<br />\u000a Compatibilité<br />\u000aLe GIVI D9226ST est un pare-brise spécifique conçu pour un modèle de moto particulier (selon année et version).<br />\u000a Il est important de vérifier la compatibilité exacte avec votre moto avant l’achat.<br />\u000a En résumé :<br />\u000aLe GIVI D9226ST est une solution idéale pour les motards souhaitant améliorer leur confort et leur protection contre le vent, tout en conservant une excellente visibilité grâce à sa finition transparente.</p>\u000a'),'',34,756,1199.0,1199.0,NULL,NULL,'published','GIVI D9226ST SPECIFIC SCREEN TRANSPARENT','GIVI D9226ST SPECIFIC SCREEN TRANSPARENT au Maroc. Achetez au meilleur prix chez MOTO PACO.',144,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(114,'Givi D294ST Pare-brise','givi-d294st-pare-brise-kymco-downtown-xtown',unistr('<p>Le Givi D294ST est un pare-brise transparent de type touring conçu pour améliorer le confort de conduite en offrant une protection aérodynamique supérieure. Il remplace la bulle d’origine et s’adapte parfaitement aux points de fixation existants selon les modèles compatibles.<br />\u000a Caractéristiques principales<br />\u000aType : bulle haute transparente (version ST = touring)<br />\u000aMatériau : plexiglas robuste et résistant aux impacts<br />\u000aMontage : installation facile sur supports d’origine<br />\u000aHauteur : plus élevée que la bulle d’origine pour une meilleure protection<br />\u000aFinition : transparente pour une visibilité optimale<br />\u000a Avantages<br />\u000aProtection efficace contre le vent : réduit les turbulences au niveau du casque<br />\u000aConfort longue distance : idéal pour les trajets urbains et touring<br />\u000aVisibilité claire : aucune gêne visuelle grâce à la transparence<br />\u000aProtection contre les éléments : pluie, insectes et projections<br />\u000aDesign élégant : s’intègre parfaitement au style de la moto/scooter<br />\u000a Compatibilité<br />\u000aLe Givi D294ST est compatible avec certains modèles spécifiques (moto ou scooter selon version).<br />\u000a Il est recommandé de vérifier la compatibilité exacte avec votre véhicule avant achat.<br />\u000a En résumé :<br />\u000aLe Givi D294ST est une excellente solution pour améliorer la protection et le confort de conduite, particulièrement pour les utilisateurs réguliers ou les amateurs de longues distances.</p>\u000a'),'',34,756,1199.0,1199.0,NULL,NULL,'published','Givi D294ST Pare-brise','Givi D294ST Pare-brise au Maroc. Achetez au meilleur prix chez MOTO PACO.',83,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(115,'Givi D9225ST Windscreen Compatible with CFMOTO 800M','givi-d9225st-pare-brise-cfmoto-800mt',unistr('<p>Le Givi D9225ST est un pare-brise transparent (version ST = touring) spécialement conçu pour la CFMOTO 800MT. Il remplace la bulle d’origine pour offrir une protection aérodynamique nettement améliorée, idéale pour les trajets longs et le touring.<br />\u000a Caractéristiques principales<br />\u000aType : bulle haute transparente<br />\u000aMatériau : plexiglas robuste et résistant<br />\u000aMontage : installation directe sur les fixations d’origine<br />\u000aPosition : plus haute que la bulle d’origine pour une meilleure protection<br />\u000aHomologation : conforme à un usage routier<br />\u000a Avantages<br />\u000aProtection supérieure contre le vent : réduit les turbulences au niveau du casque et du torse<br />\u000aConfort longue distance : diminue la fatigue du pilote sur autoroute<br />\u000aVisibilité optimale : finition transparente pour une vision claire<br />\u000aProtection contre les éléments : pluie, insectes et projections<br />\u000aLook touring : améliore l’esthétique et le côté aventure de la moto<br />\u000a Compatibilité<br />\u000aMoto : CFMOTO 800MT<br />\u000aAdapté aux modèles standard et touring (selon configuration d’origine)<br />\u000a En résumé :<br />\u000aLe Givi D9225ST est le choix idéal pour les motards qui souhaitent améliorer le confort et la protection de leur CFMOTO 800MT, notamment pour les voyages et les longues distances.</p>\u000a'),'',34,756,999.0,999.0,NULL,NULL,'published','Givi D9225ST Windscreen Compatible with CFMOTO 800M','Givi D9225ST Windscreen Compatible with CFMOTO 800M au Maroc. Achetez au meilleur prix chez MOTO PACO.',71,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(116,'Givi D9260S Smoked Windshield For VOGE Valico 900 DSX','givi-d9260s-pare-brise-fume-voge-valico-900-dsx',unistr('<p>Le Givi D9260S est un pare-brise spécifique conçu pour la moto VOGE Valico 900 DSX (modèles 2024–2025). Il remplace directement la bulle d’origine sans nécessiter de modifications.<br />\u000a Caractéristiques principales<br />\u000aType : pare-brise fumé (teinte légère)<br />\u000aDimensions : 43 cm (hauteur) x 45 cm (largeur)<br />\u000aHauteur supplémentaire : +8,5 cm par rapport à l’origine<br />\u000aMontage : installation simple sur les fixations d’origine<br />\u000aHomologation : compatible usage routier<br />\u000a Avantages<br />\u000aMeilleure protection contre le vent : réduit la pression de l’air sur le pilote, surtout à vitesse élevée<br />\u000aConfort accru sur longs trajets : moins de fatigue grâce à une meilleure déviation du flux d’air<br />\u000aProtection contre les éléments : pluie, insectes et débris<br />\u000aRéduction de l’éblouissement : teinte fumée limitant les reflets du soleil<br />\u000aDesign esthétique : look plus sportif et moderne<br />\u000a Compatibilité<br />\u000aMoto : VOGE Valico 900 DSX (à partir de 2024)<br />\u000aRemplacement direct de la bulle d’origine<br />\u000a En résumé :<br />\u000aLe Givi D9260S est un excellent choix pour améliorer le confort et la protection aérodynamique de votre Voge 900 DSX, tout en apportant une touche esthétique grâce à sa finition fumée.</p>\u000a'),'',34,756,999.0,999.0,NULL,NULL,'published','Givi D9260S Smoked Windshield For VOGE Valico 900 DSX','Givi D9260S Smoked Windshield For VOGE Valico 900 DSX au Maroc. Achetez au meilleur prix chez MOTO PACO.',95,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(117,'BULLE HAUT GIVI D8717ST TRANSPARENT INTERCHANGEABLE','givi-d8717st-bulle-haute-transparent-interchangeable',unistr('<p>La D8717ST est fabriquée en polycarbonate résistant aux chocs et rayures, garantissant durabilité et sécurité. Son système interchangeable permet de modifier rapidement la hauteur ou d’adapter la bulle à différents styles de conduite. Idéale pour réduire le vent et les turbulences, elle améliore le confort sur route et autoroute tout en conservant un design moderne.<br />\u000a Caractéristiques principales<br />\u000a Type : bulle haute transparente interchangeable<br />\u000a Matériau : polycarbonate robuste et résistant aux rayures<br />\u000a Système interchangeable : montage facile et rapide sur différents modèles<br />\u000a Protection : réduit le vent et les turbulences pour le pilote<br />\u000a Installation : kit complet fourni avec visserie et notice<br />\u000a Installation<br />\u000aMontage simple sur les points de fixation existants<br />\u000aAucun perçage ou modification nécessaire<br />\u000aCompatible avec différents modèles grâce au système interchangeable<br />\u000a Utilité<br />\u000aLe Givi D8717ST est idéal pour :<br />\u000aaméliorer le confort du pilote en réduisant le vent<br />\u000aprotéger contre les intempéries et projections<br />\u000aadapter rapidement la bulle selon les conditions de conduite<br />\u000aajouter un style moderne et fonctionnel à la moto<br />\u000a Parfait pour les motards recherchant confort, protection et modularité avec une bulle de qualité supérieure.</p>\u000a'),'',34,756,999.0,999.0,NULL,NULL,'published','BULLE HAUT GIVI D8717ST TRANSPARENT INTERCHANGEABLE','BULLE HAUT GIVI D8717ST TRANSPARENT INTERCHANGEABLE au Maroc. Achetez au meilleur prix chez MOTO PACO.',65,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(118,'GIVI D9701ST WINDSCREEN TRANSPARENT INTERCHANGEABLE','givi-d9701st-pare-brise-transparent-interchangeable',unistr('<p>Le D9701ST est fabriqué en polycarbonate résistant aux chocs et aux rayures, garantissant durabilité et sécurité. Son système interchangeable permet de modifier facilement le pare-brise selon les conditions de conduite ou les préférences du pilote. Ce pare-brise est idéal pour améliorer l’aérodynamisme et réduire le vent, offrant ainsi plus de confort sur route et autoroute.<br />\u000a Caractéristiques principales<br />\u000a Type : pare-brise transparent universel Matériau : polycarbonate robuste et résistant aux rayures<br />\u000a Système interchangeable : installation facile sur différents modèles<br />\u000a Protection : réduit le vent et les turbulences<br />\u000a Installation rapide : kit complet fourni avec visserie et notice<br />\u000a Installation<br />\u000aMontage facile sur les points de fixation existants<br />\u000aAucun perçage ou modification nécessaire<br />\u000aCompatible avec de nombreux modèles grâce au système interchangeable<br />\u000a Utilité<br />\u000aLe Givi D9701ST est idéal pour :<br />\u000aaméliorer le confort du pilote en réduisant le vent<br />\u000aprotéger contre les intempéries et projections<br />\u000aadapter rapidement le pare-brise selon les conditions de conduite<br />\u000aajouter un style moderne et fonctionnel à la moto<br />\u000a Indispensable pour les motards recherchant confort, protection et modularité avec un pare-brise de qualité.</p>\u000a'),'',34,756,999.0,999.0,NULL,NULL,'published','GIVI D9701ST WINDSCREEN TRANSPARENT INTERCHANGEABLE','GIVI D9701ST WINDSCREEN TRANSPARENT INTERCHANGEABLE au Maroc. Achetez au meilleur prix chez MOTO PACO.',68,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(119,'SUPPORT VALISES GIVI PL9257 VOGE DS525X / DS625X','givi-pl9257-support-valises-voge-ds525x-ds625x',unistr('<p>Le PL9257 est conçu pour s’adapter parfaitement aux VOGE DS525X et DS625X, garantissant une fixation stable des valises latérales Givi. Son design assure une excellente résistance aux charges et aux vibrations, tout en préservant l’esthétique de la moto.<br />\u000a Caractéristiques principales<br />\u000a Compatibilité spécifique : VOGE DS525X et DS625X<br />\u000a Système Monokey : compatible avec les valises latérales Givi<br />\u000a Structure robuste : acier tubulaire pour une grande durabilité<br />\u000a Fixation sécurisée : stabilité optimale même avec charge maximale<br />\u000a Finition durable : traitement anticorrosion pour usage longue durée<br />\u000a Installation<br />\u000aMontage sur les points d’origine de la moto<br />\u000aAucun perçage ni modification nécessaire<br />\u000aKit de montage et notice inclus<br />\u000a Utilité<br />\u000aLe Givi PL9257 est idéal pour :<br />\u000atransporter vos valises latérales Givi de manière sécurisée<br />\u000avoyager avec plus de capacité de rangement<br />\u000aaméliorer le confort et la praticité pour les trajets urbains et longue distance<br />\u000a Parfait pour les motards propriétaires d’une VOGE DS525X ou DS625X qui souhaitent équiper leur moto d’une bagagerie latérale fiable et résistante.</p>\u000a'),'',45,756,1999.0,1999.0,NULL,NULL,'published','SUPPORT VALISES GIVI PL9257 VOGE DS525X / DS625X','SUPPORT VALISES GIVI PL9257 VOGE DS525X / DS625X au Maroc. Achetez au meilleur prix chez MOTO PACO.',86,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(120,'GIVI PL8717 MONOKEY','givi-pl8717-support-valises-laterales-monokey',unistr('<p>Le PL8717 est conçu pour s’adapter parfaitement à des modèles spécifiques de motos (notamment certaines Benelli TRK 702 selon version), garantissant une intégration optimale et une excellente stabilité. Il permet de fixer facilement des valises latérales Monokey pour augmenter la capacité de chargement de votre moto.<br />\u000a Caractéristiques principales<br />\u000a Système Monokey : compatible avec les valises latérales rigides Givi<br />\u000a Support spécifique : conçu pour une moto dédiée (vérifier compatibilité exacte)<br />\u000a Structure robuste : acier renforcé pour une résistance maximale<br />\u000a Fixation sécurisée : excellente stabilité même avec charge importante<br />\u000a Finition durable : traitement anticorrosion pour une longue durée de vie<br />\u000a Installation<br />\u000aMontage sur les points de fixation d’origine<br />\u000aKit complet avec visserie et notice inclus<br />\u000aAucun perçage ni modification nécessaire<br />\u000a Utilité<br />\u000aLe Givi PL8717 est idéal pour :<br />\u000ainstaller des valises latérales en toute sécurité<br />\u000avoyager avec plus de capacité de rangement<br />\u000aaméliorer le confort et la praticité pour les trajets longue distance<br />\u000a Indispensable pour équiper votre moto d’une bagagerie latérale fiable et résistante avec système Monokey.</p>\u000a'),'',45,756,1499.0,1499.0,NULL,NULL,'published','GIVI PL8717 MONOKEY','GIVI PL8717 MONOKEY au Maroc. Achetez au meilleur prix chez MOTO PACO.',126,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(121,'Givi PLO1188MK Specific Pannier Holder for Monokey Cases for Honda X-ADV 21-','givi-plo1188mk-support-valises-monokey-honda-x-adv',unistr('<p>Le PLO1188MK est un support latéral tubulaire spécialement conçu pour s’intégrer parfaitement à la Honda X-ADV 750 (2021 et +). Il permet de monter des valises latérales Monokey de manière stable, tout en conservant un bon équilibre et une esthétique harmonieuse.<br />\u000a Caractéristiques principales<br />\u000a Compatibilité spécifique : Honda X-ADV 750 (2021 et versions suivantes)<br />\u000a Système Monokey : compatible avec les valises latérales rigides Givi<br />\u000a Structure tubulaire robuste : acier renforcé pour une grande résistance<br />\u000a Fixation sécurisée : excellente stabilité même avec charge importante<br />\u000a Finition durable : traitement anticorrosion pour une longue durée de vie<br />\u000a Installation<br />\u000aSe fixe sur les points d’origine de la moto<br />\u000aKit de montage et notice inclus<br />\u000aAucun perçage ni modification nécessaire<br />\u000a Utilité<br />\u000aLe Givi PLO1188MK est idéal pour :<br />\u000ainstaller des valises latérales sur votre Honda X-ADV<br />\u000avoyager avec une grande capacité de rangement<br />\u000aaméliorer le confort et la praticité lors de longs trajets<br />\u000a Indispensable pour les motards souhaitant équiper leur Honda X-ADV 2021+ d’une bagagerie latérale solide et fiable.</p>\u000a'),'',45,756,1999.0,1999.0,NULL,NULL,'published','Givi PLO1188MK Specific Pannier Holder for Monokey Cases for Honda X-ADV 21-','Givi PLO1188MK Specific Pannier Holder for Monokey Cases for Honda X-ADV 21- au Maroc. Achetez au meilleur prix chez MOTO PACO.',148,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(122,'GIVI PL9059 MONOKEY SIDE FRAMES','givi-pl9059-support-valises-laterales-monokey',unistr('<p>Le PL9059 permet de monter facilement des valises latérales Givi compatibles Monokey. Conçu sur mesure pour des modèles spécifiques de moto, il assure une intégration parfaite sans compromettre le confort de conduite ni l’esthétique.<br />\u000a Caractéristiques principales<br />\u000a Système Monokey : compatible avec les valises latérales rigides Givi<br />\u000a Support spécifique : conçu pour une moto précise (vérifier compatibilité)<br />\u000a Structure robuste : acier renforcé pour une grande durabilité<br />\u000a Fixation sécurisée : excellente stabilité même à pleine charge<br />\u000a Finition de qualité : traitement anticorrosion pour une longue durée de vie<br />\u000a Installation<br />\u000aSe fixe sur les points d’origine de la moto<br />\u000aKit de montage et notice inclus<br />\u000aAucun perçage ni modification nécessaire<br />\u000a Utilité<br />\u000aLe Givi PL9059 est idéal pour :<br />\u000ainstaller des valises latérales rigides en toute sécurité<br />\u000avoyager avec une grande capacité de rangement<br />\u000aaméliorer le confort et la praticité lors de longs trajets<br />\u000a Indispensable pour les motards souhaitant équiper leur moto d’une bagagerie latérale fiable et résistante.</p>\u000a'),'',45,756,1499.0,1499.0,NULL,NULL,'published','GIVI PL9059 MONOKEY SIDE FRAMES','GIVI PL9059 MONOKEY SIDE FRAMES au Maroc. Achetez au meilleur prix chez MOTO PACO.',78,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(123,'Givi V47NNT Tech Monokey Top-Case in Carbon-Look Transparent Reflectors - BlackGrey','givi-v47nnt-tech-monokey-top-case-carbon-look-noir-gris',unistr('<p>Le Givi V47NNT Tech Monokey Top-Case Carbon Look Noir/Gris est un top case moto haut de gamme offrant une capacité généreuse et un design moderne avec finition effet carbone. Idéal pour les trajets quotidiens comme pour les longs voyages, il combine style, sécurité et praticité.<br />\u000a🧳 Description générale<br />\u000aLe V47NNT Tech dispose d’une capacité de 47 litres, permettant de ranger facilement deux casques modulables ou un équipement complet. Sa finition noir/gris avec insert effet carbone lui donne un look élégant et sportif, tandis que ses réflecteurs transparents fumés renforcent son style moderne.<br />\u000a Caractéristiques principales<br />\u000a Capacité : 47 litres (jusqu’à 2 casques)<br />\u000a Système Monokey : fixation rapide, sécurisée et universelle Givi<br />\u000a Design premium : finition carbone + coloris noir/gris<br />\u000a **</p>\u000a'),'',47,756,2499.0,2499.0,NULL,NULL,'published','Givi V47NNT Tech Monokey Top-Case in Carbon-Look Transparent Reflectors - BlackGrey','Givi V47NNT Tech Monokey Top-Case in Carbon-Look Transparent Reflectors - BlackGrey au Maroc. Achetez au meilleur prix chez MOTO PACO.',100,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(125,'TRK35BB 35LTR TREKKER LITE BLACK','givi-trk35bb-35l-trekker-lite-noir',unistr('<p>La TRK35BB est fabriquée en aluminium léger et durable avec finition noire. Sa capacité de 35 litres permet de transporter des vêtements, accessoires ou équipements pour vos voyages et sorties. Elle est compatible avec les supports Givi Trekker Lite et dispose d’un système de verrouillage sécurisé pour protéger vos affaires contre les vols et intempéries.<br />\u000a Caractéristiques principales<br />\u000a Capacité : 35 litres<br />\u000a Matériaux : aluminium léger et robuste, finition noire<br />\u000a Compatibilité : supports Givi Trekker Lite (vendus séparément)<br />\u000a Sécurité : verrouillage intégré avec clé<br />\u000a Installation facile : montage rapide et sûr sur la moto<br />\u000a Installation<br />\u000aSe fixe sur les supports Trekker Lite spécifiques<br />\u000aMontage simple sans perçage ni modification de la moto<br />\u000aNotice et kit de montage inclus<br />\u000a Utilité<br />\u000aLa Givi TRK35BB 35L est idéale pour :<br />\u000ales voyages de moyenne et longue distance<br />\u000atransporter vos effets personnels de manière sécurisée<br />\u000aprotéger vos affaires contre les chocs et les intempéries</p>\u000a'),'',47,13,3499.0,3499.0,NULL,NULL,'published','TRK35BB 35LTR TREKKER LITE BLACK','TRK35BB 35LTR TREKKER LITE BLACK au Maroc. Achetez au meilleur prix chez MOTO PACO.',139,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(126,'Givi OBKEV37BR Trekker Outback EVO Smart 37 lt noir valise droite','givi-obkev37br-trekker-outback-evo-37l-noir-valise-droite',unistr('<p>La valise droite OBKEV37BR est fabriquée en aluminium noir robuste, résistante aux chocs et aux intempéries. Elle s’intègre parfaitement avec le système Trekker Outback EVO et offre un accès facile au contenu grâce à son ouverture sécurisée et ergonomique. Sa capacité de 37 litres permet de transporter vos affaires personnelles, vêtements et équipements de manière pratique et sécurisée.<br />\u000a Caractéristiques principales<br />\u000a Capacité : 37 litres (valise droite)<br />\u000a Matériaux : aluminium noir robuste et durable<br />\u000a Système EVO : compatible avec les supports Trekker Outback EVO<br />\u000a Sécurité : verrouillage à clé intégré<br />\u000a Design ergonomique : ouverture facile et accès pratique au contenu<br />\u000a Installation<br />\u000aSe fixe sur les supports Trekker Outback EVO (vendus séparément)<br />\u000aMontage rapide et sécurisé, sans perçage<br />\u000aNotice de montage incluse<br />\u000a Utilité<br />\u000aLa Givi OBKEV37BR est idéale pour :<br />\u000ales voyages longue distance ou l’aventure moto<br />\u000atransporter vos effets personnels en toute sécurité<br />\u000aprotéger vos affaires contre les intempéries et les chocs</p>\u000a'),'',51,756,4499.0,4499.0,NULL,NULL,'published','Givi OBKEV37BR Trekker Outback EVO Smart 37 lt noir valise droite','Givi OBKEV37BR Trekker Outback EVO Smart 37 lt noir valise droite au Maroc. Achetez au meilleur prix chez MOTO PACO.',149,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(127,'Givi ALA36BPACK2 Trekker Alaska Panniers (Pair) Black - 72 Litre Total Capacity','givi-ala36bpack2-trekker-alaska-valises-laterales-noir',unistr('<p>Les Trekker Alaska ALA36BPACK2 se montent facilement sur les supports latéraux Givi. Elles sont fabriquées en aluminium robuste avec finition noire, offrant résistance aux chocs et aux intempéries. Chaque valise a une capacité de 36 litres, pour un total de 72 litres, parfaite pour transporter vêtements, outils et équipements lors de vos aventures.<br />\u000a Caractéristiques principales<br />\u000a Capacité totale : 72 litres (2 x 36 L)<br />\u000a Matériaux robustes : aluminium noir durable, résistant aux chocs et rayures<br />\u000a Compatibilité : s’adapte aux supports Givi Trekker Alaska<br />\u000a Sécurité : verrouillage à clé pour chaque valise<br />\u000a Design pratique : montage rapide et ergonomique, facilité d’accès au contenu<br />\u000a🔧 Installation<br />\u000aSe monte sur les supports latéraux Givi Trekker Alaska (vendus séparément)<br />\u000aMontage simple avec notice incluse<br />\u000aAucun perçage ou modification nécessaire sur la moto<br />\u000a Utilité<br />\u000aLes Givi ALA36BPACK2 Trekker Alaska Panniers sont idéales pour :<br />\u000ales voyages longue distance ou expéditions moto<br />\u000atransporter vos affaires de manière sécurisée et organisée<br />\u000aprotéger vos effets contre les intempéries et les chocs</p>\u000a'),'',47,756,4999.0,4999.0,NULL,NULL,'published','Givi ALA36BPACK2 Trekker Alaska Panniers (Pair) Black - 72 Litre Total Capacity','Givi ALA36BPACK2 Trekker Alaska Panniers (Pair) Black - 72 Litre Total Capacity au Maroc. Achetez au meilleur prix chez MOTO PACO.',115,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(128,'Givi FB9059 Smartphone','givi-fb9059-support-smartphone-moto',unistr('<p>Le FB9059 permet de fixer solidement votre smartphone, assurant une stabilité optimale même sur routes sinueuses ou terrains accidentés. Ce support est universel et s’adapte à la majorité des modèles de motos et smartphones, tout en offrant un montage discret et sécurisé.<br />\u000a Caractéristiques principales<br />\u000a Support universel : compatible avec la plupart des smartphones<br />\u000a Fixation sécurisée : maintien stable sur le guidon même à haute vitesse<br />\u000a Matériaux résistants : plastique et métal durable<br />\u000a Installation simple : montage rapide avec kit inclus<br />\u000a Design ergonomique : discret et pratique pour la conduite<br />\u000a Installation<br />\u000aMontage facile sur les points de fixation du guidon<br />\u000aKit complet inclus pour un montage sûr et rapide<br />\u000aAucun perçage ni modification nécessaire<br />\u000a Utilité<br />\u000aLe Givi FB9059 est idéal pour :<br />\u000aaccéder facilement à votre smartphone pour la navigation ou la communication<br />\u000asécuriser votre téléphone contre les vibrations et chocs<br />\u000aaméliorer le confort et la praticité lors de vos trajets urbains ou longues distances</p>\u000a'),'',16,756,499.0,499.0,NULL,NULL,'published','Givi FB9059 Smartphone','Givi FB9059 Smartphone au Maroc. Achetez au meilleur prix chez MOTO PACO.',110,'2026-06-20 14:09:06',0,0,0,0);
