INSERT INTO products VALUES(133,'Crossbar GIVI FB9257 For Gps-Telefoni-Smartphone Voge Mountain Pass 525 Dsx','givi-fb9257-crossbar-gps-telephone-smartphone-voge-mountain-pass-525-dsx',unistr('<p>Cette barre FB9257 est spécialement compatible avec la Voge Mountain Pass 525 DSX, offrant une solution stable pour fixer vos appareils électroniques pendant vos trajets. Elle permet un accès facile aux appareils tout en les maintenant solidement, même sur routes sinueuses ou en conduite dynamique.<br />\u000a Caractéristiques principales<br />\u000a Compatibilité spécifique : Voge Mountain Pass 525 DSX<br />\u000a Support multiple appareils : GPS, téléphone, smartphone<br />\u000a Fixation sécurisée : maintien stable et sûr sur le guidon<br />\u000a Matériaux robustes : acier traité et finition durable<br />\u000a Installation simple : kit complet fourni, montage rapide<br />\u000a Installation<br />\u000aSe fixe sur les points d’origine de la moto<br />\u000aNotice et kit de visserie inclus<br />\u000aAucun perçage ni modification permanente nécessaire<br />\u000a Utilité<br />\u000aLe Givi FB9257 Crossbar est idéal pour :<br />\u000aaccéder facilement à vos appareils électroniques pendant la conduite<br />\u000asécuriser vos équipements électroniques contre les chocs et vibrations<br />\u000aaméliorer le confort et la praticité pour les trajets quotidiens ou les longues distances</p>\u000a'),'',16,756,499.0,499.0,NULL,NULL,'published','Crossbar GIVI FB9257 For Gps-Telefoni-Smartphone Voge Mountain Pass 525 Dsx','Crossbar GIVI FB9257 For Gps-Telefoni-Smartphone Voge Mountain Pass 525 Dsx au Maroc. Achetez au meilleur prix chez MOTO PACO.',106,'2026-06-20 14:09:06',0,0,0,0);
INSERT INTO products VALUES(134,'Givi TN9226 CFMoto 450 MT tubular engine guard','givi-tn9226-pare-carter-cfmoto-450mt',unistr('<p>Spécifiquement développé pour la CFMOTO 450MT, ce pare-carter s’intègre parfaitement au design de la moto tout en offrant une protection renforcée des parties sensibles comme le moteur et le cadre.<br />\u000a Caractéristiques principales<br />\u000a Compatibilité dédiée : CFMOTO 450MT<br />\u000a Protection renforcée : protège le moteur en cas de chute ou de choc<br />\u000a Structure tubulaire en acier : haute résistance et durabilité<br />\u000a Finition soignée : revêtement noir anticorrosion<br />\u000a Intégration parfaite : design adapté à la moto<br />\u000a Installation<br />\u000aMontage sur les points de fixation d’origine<br />\u000aAucun perçage requis<br />\u000aKit de fixation et notice inclus<br />\u000aInstallation simple (recommandé avec outils standards)<br />\u000a Utilité<br />\u000aLe pare-carter Givi TN9226 est idéal pour :<br />\u000asécuriser votre moto lors de trajets urbains ou off-road<br />\u000alimiter les dégâts en cas de chute<br />\u000aprotéger les composants coûteux du moteur<br />\u000a C’est un accessoire essentiel pour les motards qui utilisent leur CFMOTO 450MT en aventure ou au quotidien.</p>\u000a'),'',21,756,1999.0,1999.0,NULL,NULL,'published','Givi TN9226 CFMoto 450 MT tubular engine guard','Givi TN9226 CFMoto 450 MT tubular engine guard au Maroc. Achetez au meilleur prix chez MOTO PACO.',101,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(135,'Givi E237 set gomme adesive protezione coperchio bauletto OBKE58','givi-e237-protection-couvercle-top-case-obke58',unistr('<p>Ce kit comprend des gommes adhésives résistantes qui se fixent directement sur le dessus du couvercle du top case. Elles protègent efficacement contre les rayures, les frottements et l’usure liée au transport d’objets ou de bagages supplémentaires.<br />\u000a Caractéristiques principales<br />\u000a Compatibilité spécifique : top case Givi Trekker Outback OBKE58 (58L)<br />\u000a Protection efficace : limite les rayures et l’abrasion<br />\u000a Fixation adhésive : installation simple, sans perçage<br />\u000a Matériau durable : caoutchouc résistant aux intempéries<br />\u000a Améliore l’adhérence : idéal pour transporter des sacs sur le couvercle<br />\u000a🔧 Installation<br />\u000aNettoyer soigneusement la surface du couvercle<br />\u000aRetirer le film protecteur<br />\u000aPositionner et coller les gommes adhésives<br />\u000aPresser fermement pour une bonne adhérence<br />\u000a Utilité<br />\u000aLe kit Givi E237 est idéal pour :<br />\u000aprotéger le top case contre les dommages du quotidien<br />\u000atransporter des sacs ou objets sur le couvercle sans glissement<br />\u000aprolonger la durée de vie de votre valise moto</p>\u000a'),'',28,756,199.0,199.0,NULL,NULL,'published','Givi E237 set gomme adesive protezione coperchio bauletto OBKE58','Givi E237 set gomme adesive protezione coperchio bauletto OBKE58 au Maroc. Achetez au meilleur prix chez MOTO PACO.',66,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(136,'Givi Bf98 Tanklock Flange','givi-bf98-tanklock-flange',unistr('<p>La bride BF98 se fixe directement sur le bouchon du réservoir de la moto, offrant une solution pratique pour transporter une sacoche sans sangles ni aimants. Grâce au système Tanklock, la sacoche se clipse et se déclipse en quelques secondes.<br />\u000a Caractéristiques principales<br />\u000a Système Tanklock Givi : fixation rapide et intuitive<br />\u000a Montage sans modification : installation sur la trappe du réservoir<br />\u000a Sécurité optimale : maintien stable même à haute vitesse<br />\u000a Protection du réservoir : aucun contact direct avec la sacoche<br />\u000a Fabrication robuste : matériaux résistants à l’usure et aux vibrations<br />\u000a Installation<br />\u000aSe monte en utilisant les vis d’origine du bouchon de réservoir<br />\u000aInstallation simple et rapide (quelques minutes)<br />\u000aAucun perçage ni adaptation nécessaire<br />\u000a Utilité<br />\u000aLa bride Givi BF98 est indispensable pour les motards souhaitant utiliser une sacoche de réservoir Tanklock. Elle garantit :<br />\u000aun accès facile au réservoir<br />\u000aune fixation fiable et pratique au quotidien</p>\u000a'),'',16,756,249.0,249.0,NULL,NULL,'published','Givi Bf98 Tanklock Flange','Givi Bf98 Tanklock Flange au Maroc. Achetez au meilleur prix chez MOTO PACO.',64,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(137,'Givi BF96 Flangia Borse Serbatoio Tanklock Yamaha Tracer 9 GT / +','givi-bf96-tanklock-yamaha-tracer-9-gt-plus',unistr('<p>Le BF96 Tanklock est une bride de fixation qui se monte directement sur le bouchon du réservoir de carburant. Il permet d’installer et de retirer rapidement une sacoche de réservoir Tanklock sans utiliser de sangles ou d’aimants.<br />\u000a Caractéristiques principales :<br />\u000aSystème de fixation rapide Tanklock (clic sécurisé)<br />\u000aInstallation spécifique à certains modèles de motos<br />\u000aNe touche pas la peinture du réservoir (pas de rayures)<br />\u000aMontage simple avec les vis du bouchon de réservoir<br />\u000aCompatible uniquement avec les sacoches GIVI Tanklock<br />\u000a Avantages :<br />\u000aPratique : fixation et retrait en quelques secondes<br />\u000aSécurisé : maintien stable même à haute vitesse<br />\u000aEsthétique : design discret et intégré<br />\u000a En résumé, le GIVI BF96 est une solution idéale pour les motards qui souhaitent utiliser une sacoche de réservoir de manière rapide, propre et sans abîmer leur moto.</p>\u000a'),'',16,756,249.0,249.0,NULL,NULL,'published','Givi BF96 Flangia Borse Serbatoio Tanklock Yamaha Tracer 9 GT / +','Givi BF96 Flangia Borse Serbatoio Tanklock Yamaha Tracer 9 GT / + au Maroc. Achetez au meilleur prix chez MOTO PACO.',87,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(139,'Givi Windshield Kit A7067A for SYMPHONY ST 50-125-200','givi-windshield-kit-a7067a-symphony-st-50-125-200',unistr('<p>Le kit pare‑brise Givi A7067A est un accessoire spécifique de fixation conçu pour installer un pare‑brise Givi (référence 7067A) sur les scooters SYM Symphony ST 50, 125 et 200 produits entre 2021 et 2025. Ce kit n’est pas un pare‑brise en lui‑même, mais les supports et pièces nécessaires pour monter le pare‑brise 7067A sur ces modèles de moto/scooter.<br />\u000a Montage spécifique<br />\u000aLe kit A7067A contient les éléments de fixation dédiés (supports, vis, rondelles et autres pièces) permettant de monter solidement le pare‑brise Givi 7067A sur le carénage avant du SYM Symphony ST. Il est spécifique à ce modèle et ne convient pas à d’autres scooters sans les pièces adaptées.<br />\u000a Compatibilité moto/scooter<br />\u000aIl est compatible uniquement avec les modèles SYM Symphony ST 50, 125 et 200 de la série 2021 à 2025, offrant une solution de montage parfaitement adaptée et stable.<br />\u000a Fonction principale<br />\u000aCette fixation permet d’installer le pare‑brise Givi 7067A (non inclus), qui améliore la protection contre le vent et les intempéries pendant la conduite, pour une expérience plus confortable sur route.<br />\u000a À noter : ce kit est un kit de montage uniquement, il ne comprend pas le pare‑brise lui‑même ; celui‑ci doit être acheté séparément.</p>\u000a'),'',27,756,699.0,699.0,NULL,NULL,'published','Givi Windshield Kit A7067A for SYMPHONY ST 50-125-200','Givi Windshield Kit A7067A for SYMPHONY ST 50-125-200 au Maroc. Achetez au meilleur prix chez MOTO PACO.',74,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(140,'Givi Inner Bag T522 for V58 Top Case','givi-inner-bag-t522-v58-top-case',unistr('<p>La GIVI Inner Bag T522 est une sacoche intérieure spécialement conçue pour être utilisée dans les top cases de la série V58 Maxia 5 (58 L), comme accessoire pratique pour organiser et transporter facilement vos affaires à l’intérieur du coffre.<br />\u000a Sacoche intérieure pour Top Case<br />\u000aElle s’insère parfaitement à l’intérieur des top cases V58 Maxia 5, permettant de ranger les objets de manière organisée et de les sortir facilement.<br />\u000a Éléments pratiques inclus<br />\u000a Poignées avec protection pour transporter la sacoche facilement hors du top case.<br />\u000a Sangle d’épaule réglable pour porter la sacoche confortablement.<br />\u000a Poche avant extérieure zippée pour accéder rapidement à de petits objets sans ouvrir entièrement la sacoche.<br />\u000a Inserts réfléchissants pour une meilleure visibilité lorsqu’elle est utilisée hors de la moto ou dans des conditions moins bien éclairées.<br />\u000a Utilisation pratique : cette sacoche est idéale pour séparer et organiser vos vêtements, vos accessoires (gants, câbles, documents, etc.) à l’intérieur du top case, ce qui rend plus simple le rangement et la récupération de vos affaires lorsque vous n’êtes pas sur la moto.</p>\u000a'),'',39,756,399.0,399.0,NULL,NULL,'published','Givi Inner Bag T522 for V58 Top Case','Givi Inner Bag T522 for V58 Top Case au Maroc. Achetez au meilleur prix chez MOTO PACO.',102,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(141,'GIVI Sacoche de réservoir Tanklock X-Line XL06B','givi-sacoche-reservoir-tanklock-x-line-xl06b',unistr('<p> GIVI Sacoche de réservoir Tanklock X‑Line XL06B — Description en français<br />\u000aLa sacoche de réservoir GIVI X‑Line XL06B Tanklock est une sacoche universelle compatible avec le système de fixation TANKLOCK, conçue pour être installée autour du bouchon de réservoir de la moto à l’aide d’une bride spécifique (vendue séparément).<br />\u000a Capacité de stockage<br />\u000aElle offre un volume d’environ 15 litres pour transporter vos accessoires de route, et peut être extensible jusqu’à environ 20 litres pour les longs trajets ou un chargement plus important.<br />\u000a Matériaux robustes<br />\u000aFabriquée en polyester haute densité 1200D W/R avec inserts en TPU pour une bonne résistance à l’eau et aux intempéries, avec une partie supérieure et inférieure thermoformées pour plus de rigidité et de protection du contenu.<br />\u000a Fonctionnalités pratiques<br />\u000a Porte‑carte transparent avec système d’accroche rapide magnétique (Fidlock®), pratique pour suivre votre itinéraire.<br />\u000a Sac intérieur amovible et imperméable résistant à la pluie et aux conditions difficiles.<br />\u000a Trous de drainage pour évacuer l’eau et l’humidité du sac.<br />\u000a Poche frontale pour accéder rapidement à de petits objets.<br />\u000a Passe‑câble compatible avec systèmes de charge 12 V pour appareils électroniques.<br />\u000a Tirette compatibleavec un cadenas (non inclus), poignée de transport et sangle d’épaule pour transporter la sacoche hors de la moto.<br />\u000a Inserts réfléchissants sur les côtés pour une meilleure visibilité la nuit.<br />\u000a Fixation<br />\u000aLe système TANKLOCK se monte via une bride BF_ _ spécifique à chaque moto, qui n’est pas fournie avec la sacoche. Il faut donc vérifier la compatibilité de la bride avec votre modèle avant l’achat.<br />\u000a À savoir : avant de monter la sacoche, assurez‑vous que sa taille et son positionnement n’entravent pas la maniabilité ou le guidon de votre moto une fois installée</p>\u000a'),'',39,756,1999.0,1999.0,NULL,NULL,'published','GIVI Sacoche de réservoir Tanklock X-Line XL06B','GIVI Sacoche de réservoir Tanklock X-Line XL06B au Maroc. Achetez au meilleur prix chez MOTO PACO.',87,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(142,'Givi SR1166','givi-sr1166',unistr('<p>Le Givi SR1166 est un support arrière spécifique conçu pour certaines motos (comme la Honda ADV‑350 ou Forza 350) afin de monter facilement une valise ou un top case Givi.<br />\u000aDescription (en français)<br />\u000a Support arrière spécifique pour top‑case compatible avec les systèmes MONOKEY® ou MONOLOCK®.<br />\u000a Il s’installe directement sur la moto (fixation dédiée) et permet de fixer une platine pour top case Givi adaptée.<br />\u000a Compatible avec différentes platines de top‑case Givi (ex. M5, M7, M8A, M8B, M9A, M9B ou M5M/M6M selon le système choisi).<br />\u000a Charge maximale recommandée : environ 6 kg.<br />\u000a Il ne comprend pas la platine elle‑même ni le top case : ceux‑ci se commandent séparément.<br />\u000aCe support permet donc de fixer solidement une valise ou un coffre Givi à l’arrière de la moto, facilitant le transport de bagages lors de vos trajets.<br />\u000aSouhaites‑tu une fiche technique complète (matériaux, dimensions, poids, compatibilité moto par moto) ?</p>\u000a'),'',45,756,499.0,499.0,NULL,NULL,'published','Givi SR1166','Givi SR1166 au Maroc. Achetez au meilleur prix chez MOTO PACO.',106,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(143,'E198B INNER LIGHT FOR CASES','givi-e198b-eclairage-interieur-valises',unistr('<p>Le Givi E198B est un éclairage intérieur conçu pour les valises et top cases Givi. Il permet de voir clairement l’intérieur de vos valises, même dans l’obscurité, facilitant l’accès et l’organisation de vos affaires lors de vos trajets ou à l’arrêt.<br />\u000a Caractéristiques principales<br />\u000aÉclairage intérieur pratique : illumine vos valises pour un accès rapide et facile<br />\u000aInstallation simple : compatible avec la majorité des valises et top cases Givi<br />\u000aÉconomie d’énergie : lumière LED faible consommation<br />\u000aRobuste et durable : matériaux résistants aux vibrations et aux conditions extérieures<br />\u000aFonction automatique : s’allume à l’ouverture de la valise et s’éteint à la fermeture<br />\u000a Utilisation<br />\u000aL’éclairage intérieur Givi E198B est idéal pour :<br />\u000aorganiser vos affaires dans l’obscurité<br />\u000aretrouver rapidement vos objets sans devoir sortir tout le contenu<br />\u000aaméliorer la praticité et le confort lors de voyages ou trajets nocturnes<br />\u000aune installation simple et rapide sur vos valises Givi<br />\u000a En résumé<br />\u000aLe Givi E198B transforme vos valises Givi en espaces lumineux et pratiques, permettant d’accéder facilement à vos affaires en toute sécurité, même la nuit.</p>\u000a'),'',16,13,299.0,299.0,NULL,NULL,'published','E198B INNER LIGHT FOR CASES','E198B INNER LIGHT FOR CASES au Maroc. Achetez au meilleur prix chez MOTO PACO.',139,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(144,'S120 - Electric socket Givi USB/USB-C on handlebars','givi-s120-prise-electrique-usb-usb-c-guidon',unistr('<p>La Givi S120 est une prise électrique USB/USB-C pour guidon de moto, conçue pour alimenter vos appareils électroniques en toute sécurité pendant vos trajets. Compatible avec la majorité des motos, elle permet de charger smartphones, GPS, caméras ou autres accessoires USB directement depuis le guidon.<br />\u000a Caractéristiques principales<br />\u000aDouble port : USB-A et USB-C pour charger différents appareils simultanément<br />\u000aInstallation guidon : se fixe facilement sur la plupart des guidons de moto<br />\u000aProtection contre les intempéries : étanche et résistante aux projections d’eau et poussière<br />\u000aCompatibilité universelle : fonctionne avec smartphones, GPS, caméras et autres appareils USB<br />\u000aTension adaptée : 12V – idéal pour motos et scooters<br />\u000aConstruction robuste : matériaux durables pour usage intensif sur route<br />\u000a Utilisation<br />\u000aLa prise Givi S120 est parfaite pour :<br />\u000arecharger vos appareils pendant vos trajets moto<br />\u000ales longues balades ou voyages<br />\u000agarder vos GPS ou smartphones alimentés en permanence<br />\u000aune installation rapide et sûre sur guidon<br />\u000a En résumé<br />\u000aLa Givi S120 est une prise électrique USB/USB-C pratique et robuste pour le guidon de votre moto. Elle assure alimentation continue et protection contre les intempéries, idéale pour tous les motards qui veulent rester connectés en déplacement.</p>\u000a'),'',16,756,349.0,349.0,NULL,NULL,'published','S120 - Electric socket Givi USB/USB-C on handlebars','S120 - Electric socket Givi USB/USB-C on handlebars au Maroc. Achetez au meilleur prix chez MOTO PACO.',116,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(145,'OBKEV58B OUTBACK EVO SMART 58 BLACK','givi-obkev58b-trekker-outback-evo-smart-58l-top-case-noir',unistr('<p>Le Givi OBKEV58B Trekker Outback EVO Smart 58L est un top case en aluminium haut de gamme, conçu pour les motos trail et adventure. Avec sa grande capacité de 58 litres, il est idéal pour les longs voyages et les motards ayant besoin d’un espace de rangement généreux. Sa finition Black Line noire lui apporte un style moderne et robuste.<br />\u000a Caractéristiques principales<br />\u000aCapacité 58 litres : peut accueillir deux casques intégraux ou un grand volume de bagages<br />\u000aConstruction en aluminium : résistante aux chocs, à la corrosion et aux conditions extrêmes<br />\u000aVersion Smart : système de fermeture sécurisé, pratique et fiable<br />\u000aSystème MONOKEY® : fixation rapide et sécurisée sur supports compatibles<br />\u000aÉtanchéité optimale : protège vos affaires contre la pluie et la poussière<br />\u000aDesign Black Line : finition noire élégante et durable<br />\u000aStructure renforcée : coins robustes pour une meilleure protection<br />\u000a Compatibilité<br />\u000a Compatible avec :<br />\u000aSupports Givi MONOKEY®<br />\u000a Non compatible avec :<br />\u000aSystèmes MONOLOCK®<br />\u000a Utilisation<br />\u000aLe top case Givi OBKEV58B est idéal pour :<br />\u000ales voyages longue distance<br />\u000ales motos trail et adventure<br />\u000atransporter bagages volumineux et équipements<br />\u000aune utilisation sur route et tout-terrain<br />\u000a En résumé<br />\u000aLe Givi OBKEV58B Trekker Outback EVO Smart 58L est un top case spacieux, robuste et fiable. Parfait pour les aventuriers, il offre une capacité maximale, une grande résistance et une sécurité optimale pour tous vos trajets moto.</p>\u000a'),'',47,13,5899.0,4999.0,NULL,NULL,'published','OBKEV58B OUTBACK EVO SMART 58 BLACK','OBKEV58B OUTBACK EVO SMART 58 BLACK au Maroc. Achetez au meilleur prix chez MOTO PACO.',148,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(146,'OBKEV42B OUTBACK EVO SMART 42 BLACK','givi-obkev42b-trekker-outback-evo-smart-42l-top-case-noir',unistr('<p>Le Givi OBKEV42B Trekker Outback EVO Smart 42L est un top case en aluminium conçu pour les motos trail et adventure. Compact, robuste et élégant avec sa finition noire Black Line, il offre une capacité de 42 litres, idéale pour transporter vos effets personnels lors de vos trajets quotidiens ou vos voyages.<br />\u000a Caractéristiques principales<br />\u000aCapacité 42 litres : permet de transporter un casque intégral ou vos équipements essentiels<br />\u000aConstruction en aluminium : légère, résistante aux chocs et aux conditions extrêmes<br />\u000aVersion Smart : système de fermeture pratique et sécurisé<br />\u000aSystème MONOKEY® : fixation rapide et fiable sur support compatible<br />\u000aÉtanchéité optimale : protège efficacement contre la pluie et la poussière<br />\u000aDesign Black Line : finition noire moderne et résistante<br />\u000aStructure renforcée : coins robustes pour une meilleure durabilité<br />\u000a Compatibilité<br />\u000a Compatible avec :<br />\u000aSupports Givi MONOKEY®<br />\u000a Non compatible avec :<br />\u000aSystèmes MONOLOCK®<br />\u000a Utilisation<br />\u000aLe top case Givi OBKEV42B est idéal pour :<br />\u000ales trajets quotidiens<br />\u000ales voyages et road trips<br />\u000atransporter casque, vêtements et accessoires<br />\u000aune utilisation sur route et tout-terrain</p>\u000a'),'',47,13,4999.0,3999.0,NULL,NULL,'published','OBKEV42B OUTBACK EVO SMART 42 BLACK','OBKEV42B OUTBACK EVO SMART 42 BLACK au Maroc. Achetez au meilleur prix chez MOTO PACO.',127,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(147,'Givi OBKEVS33BR Trekker Outback EVO Smart 33 lt case black right','givi-obkevs33br-trekker-outback-evo-smart-33l-valise-droite-noire',unistr('<p>La Givi OBKEVS33BR Trekker Outback EVO Smart 33L est une valise latérale droite en aluminium spécialement conçue pour les motos trail et adventure. Compacte et robuste, elle offre une capacité de 33 litres, idéale pour compléter un ensemble de bagagerie asymétrique et équilibré. Sa finition Black Line noire lui confère un look moderne et premium.<br />\u000a⚙️ Caractéristiques principales<br />\u000aCapacité 33 litres : idéale pour transporter vos effets essentiels<br />\u000aConstruction en aluminium : légère, solide et résistante aux chocs et aux conditions extrêmes<br />\u000aVersion Smart : système de fermeture simplifié, pratique et sécurisé<br />\u000aFixation MONOKEY® CAM-SIDE : montage rapide et fiable sur supports compatibles<br />\u000aÉtanchéité optimale : protège efficacement contre la pluie et la poussière<br />\u000aDesign Black Line : finition noire élégante et résistante<br />\u000aStructure renforcée : coins robustes pour une meilleure protection<br />\u000a Compatibilité<br />\u000a Compatible avec :<br />\u000aSupports latéraux Givi MONOKEY® CAM-SIDE<br />\u000a Non compatible avec :<br />\u000aSupports MONOKEY® standard<br />\u000aSystèmes MONOLOCK®<br />\u000a Utilisation<br />\u000aLa valise Givi OBKEVS33BR est idéale pour :<br />\u000ales voyages longue distance<br />\u000aune utilisation sur motos trail et adventure<br />\u000atransporter des bagages en toute sécurité<br />\u000arouler sur route comme en tout-terrain<br />\u000a En résumé<br />\u000aLa Givi OBKEVS33BR Trekker Outback EVO Smart 33L est une valise latérale droite compacte, robuste et fiable. Parfaite pour compléter votre équipement de bagagerie, elle garantit sécurité, durabilité et praticité pour toutes vos aventures moto.<br />\u000aSi tu veux, je peux aussi te préparer slug + mots-clés SEO + méta description pour ce produit </p>\u000a'),'',47,756,3999.0,3999.0,NULL,NULL,'published','Givi OBKEVS33BR Trekker Outback EVO Smart 33 lt case black right','Givi OBKEVS33BR Trekker Outback EVO Smart 33 lt case black right au Maroc. Achetez au meilleur prix chez MOTO PACO.',64,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(148,'Givi valise OBKEV37BL Trekker Outback EVO Smart 37 lt noir gauche','givi-obkev37bl-trekker-outback-evo-smart-37l-valise-gauche-noire',unistr('<p>La Givi OBKEV37BL Trekker Outback EVO Smart 37L est une valise latérale gauche en aluminium conçue pour les motos trail et adventure. Compacte, robuste et élégante avec sa finition noire Black Line, elle offre une capacité de 37 litres, idéale pour transporter vos essentiels lors de vos trajets quotidiens ou vos voyages.<br />\u000a Caractéristiques principales<br />\u000aCapacité 37 litres : parfaite pour transporter vêtements, accessoires ou équipements<br />\u000aConstruction en aluminium : robuste, légère et résistante aux chocs<br />\u000aVersion Smart : système de fermeture simplifié, pratique et sécurisé<br />\u000aSystème de fixation MONOKEY® CAM-SIDE : montage rapide sur supports compatibles<br />\u000aÉtanchéité optimale : protège efficacement contre la pluie et la poussière<br />\u000aDesign Black Line : finition noire moderne et résistante<br />\u000aCoins renforcés : meilleure protection en cas de chute<br />\u000a Compatibilité<br />\u000a Compatible avec :<br />\u000aSupports latéraux Givi MONOKEY® CAM-SIDE<br />\u000a Non compatible avec :<br />\u000aSupports MONOKEY® standard<br />\u000aSystèmes MONOLOCK®</p>\u000a'),'',47,756,3999.0,3999.0,NULL,NULL,'published','Givi valise OBKEV37BL Trekker Outback EVO Smart 37 lt noir gauche','Givi valise OBKEV37BL Trekker Outback EVO Smart 37 lt noir gauche au Maroc. Achetez au meilleur prix chez MOTO PACO.',115,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(149,'Givi OBKE48BL Trekker Outback EVO 48 lt left black side case','givi-obke48bl-trekker-outback-evo-48l-valise-gauche-noire',unistr('<p>La Givi OBKE48BL Trekker Outback EVO 48L est une valise latérale gauche en aluminium conçue pour les motos d’aventure et les longs voyages. Robuste, étanche et sécurisée, elle offre une grande capacité de 48 litres, idéale pour transporter vos affaires en toute sécurité sur tous types de terrains. Sa finition noire Black Line lui donne un look moderne et premium.<br />\u000a⚙️ Caractéristiques principales<br />\u000aCapacité 48 litres : permet de ranger un casque intégral et divers équipements<br />\u000aConstruction en aluminium : légère, résistante aux chocs et aux conditions extrêmes<br />\u000aSystème de fixation MONOKEY® CAM-SIDE : montage rapide et sécurisé sur supports compatibles<br />\u000aSerrure sécurisée : système de verrouillage fiable pour protéger vos bagages<br />\u000aÉtanchéité optimale : protège efficacement contre la pluie et la poussière<br />\u000aDesign Black Line : finition noire élégante et résistante<br />\u000aCoins renforcés : meilleure protection en cas de chute ou choc<br />\u000a Compatibilité<br />\u000a Compatible avec :<br />\u000aSupports latéraux Givi MONOKEY® CAM-SIDE<br />\u000a Non compatible avec :<br />\u000aSupports MONOKEY® standard<br />\u000aSupports MONOLOCK®</p>\u000a'),'',47,756,3999.0,3999.0,NULL,NULL,'published','Givi OBKE48BL Trekker Outback EVO 48 lt left black side case','Givi OBKE48BL Trekker Outback EVO 48 lt left black side case au Maroc. Achetez au meilleur prix chez MOTO PACO.',121,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(150,'GIVI TREKKER OUTBACK EVO SMART LEFT SIDE CASE BLACK LINE 48L','givi-trekker-outback-evo-smart-left-48l-black-line',unistr('<p>La Givi Trekker Outback Evo Smart 48L – Black Line est une valise latérale gauche haut de gamme conçue pour les motos d’aventure et les road trips. Résistante et sécurisée, elle offre une capacité généreuse de 48 litres, idéale pour transporter vos bagages sur de longues distances. Son design Black Line lui confère une esthétique moderne et élégante.<br />\u000a Caractéristiques principales<br />\u000aCapacité 48L : espace suffisant pour un casque intégral et des bagages supplémentaires<br />\u000aConstruction robuste : alliage d’aluminium léger et résistant aux chocs et intempéries<br />\u000aSystème Smart Lock : serrure intégrée pour un verrouillage sécurisé et facile<br />\u000aDesign Black Line : finition noire élégante et moderne<br />\u000aCompatibilité Trekker Outback Evo : s’adapte à la plupart des motos adventure grâce aux supports latéraux Givi<br />\u000aÉtanche : protège vos affaires de la pluie et de la poussière<br />\u000aAccessoires modulables : poignée, sangles internes et mousses pour organiser le contenu<br />\u000a Utilisation<br />\u000aLa valise Givi Trekker Outback Evo Smart 48L est idéale pour :<br />\u000avoyages longue distance et aventures moto<br />\u000ale transport sécurisé de bagages, vêtements et équipements<br />\u000aune utilisation sur routes, autoroutes et terrains tout-terrain<br />\u000aun montage rapide et sûr grâce aux supports latéraux Givi<br />\u000a En résumé<br />\u000aLa Givi Trekker Outback Evo Smart Black Line 48L est une valise latérale gauche solide, spacieuse et élégante, conçue pour les motards qui recherchent sécurité, praticité et style sur toutes leurs aventures.<br />\u000aSi tu veux, je peux aussi te préparer le slug WordPress + mots-clés SEO + méta description pour cette valise afin de l’optimiser pour ton site.<br />\u000aVeux‑tu que je fasse ça ?</p>\u000a'),'',47,756,3999.0,3999.0,NULL,NULL,'published','GIVI TREKKER OUTBACK EVO SMART LEFT SIDE CASE BLACK LINE 48L','GIVI TREKKER OUTBACK EVO SMART LEFT SIDE CASE BLACK LINE 48L au Maroc. Achetez au meilleur prix chez MOTO PACO.',66,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(151,'GIVI Sport-T ST608+','givi-sport-t-st608-plus-sacoche-reservoir',unistr('<p>La Givi Sport-T ST608+ est une sacoche de réservoir sportive conçue pour offrir un accès facile à vos affaires pendant vos trajets à moto. Compatible avec le système Tanklock, elle garantit un montage rapide et sécurisé, idéal pour les motards recherchant confort et praticité sur la route ou en balade sportive.<br />\u000a Caractéristiques principales<br />\u000aSystème Tanklock : fixation rapide et démontage simple sans outils<br />\u000aCapacité modulable : idéale pour ranger téléphone, portefeuille, lunettes, documents ou petits objets<br />\u000aMatériaux résistants et imperméables : protège vos affaires contre l’humidité et l’usure<br />\u000aDesign sportif et ergonomique : adapté aux motos sportives pour un maintien stable sur le réservoir<br />\u000aPoches et compartiments internes : pour une organisation optimale de vos affaires<br />\u000aCompatibilité universelle : fonctionne avec la majorité des réservoirs équipés du système Tanklock Givi<br />\u000a Utilisation<br />\u000aLa sacoche Sport-T ST608+ est parfaite pour :<br />\u000ales trajets quotidiens ou balades sportives<br />\u000agarder vos objets essentiels à portée de main<br />\u000aun transport sécurisé et stable sur le réservoir<br />\u000aun usage pratique et rapide, avec montage/démontage facile</p>\u000a'),'',39,756,599.0,599.0,NULL,NULL,'published','GIVI Sport-T ST608+','GIVI Sport-T ST608+ au Maroc. Achetez au meilleur prix chez MOTO PACO.',113,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(152,'Givi T443D Inner Bags For V35 / V37 Side Cases','givi-t443d-sacs-interieurs-v35-v37',unistr('<p>Le Givi T443D est un sac intérieur spécialement conçu pour les valises latérales Givi V35 et V37. Il permet de ranger et organiser vos affaires facilement tout en facilitant le transport hors de la moto. Ces sacs intérieurs rendent vos voyages plus pratiques et vos valises plus modulables.<br />\u000a Caractéristiques principales<br />\u000aCompatibilité : conçu pour les valises latérales Givi V35 et V37<br />\u000aMatériaux résistants : tissus durables et légers, adaptés à un usage quotidien<br />\u000aPoignées de transport : facile à sortir de la valise et transporter comme un sac à main ou un sac de voyage<br />\u000aOrganisation pratique : compartiments intérieurs pour séparer vos affaires<br />\u000aInstallation simple : glisse facilement dans les valises V35 / V37<br />\u000a Utilisation<br />\u000aLe sac intérieur Givi T443D est parfait pour :<br />\u000aorganiser vos affaires personnelles dans la valise latérale<br />\u000atransporter vos objets hors de la moto sans les sortir un par un<br />\u000agarder vos bagages propres et bien rangés<br />\u000aun usage quotidien, pour le travail ou les voyages<br />\u000a En résumé<br />\u000aLe Givi T443D rend vos valises latérales V35 et V37 plus pratiques et modulables. Léger, solide et facile à transporter, c’est l’accessoire idéal pour tout motard souhaitant organiser ses bagages de manière efficace et sécurisée.</p>\u000a'),'',39,756,899.0,899.0,NULL,NULL,'published','Givi T443D Inner Bags For V35 / V37 Side Cases','Givi T443D Inner Bags For V35 / V37 Side Cases au Maroc. Achetez au meilleur prix chez MOTO PACO.',138,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(153,'Kit de Réparation Pneu Tubeless Givi S450','givi-s450-kit-reparation-pneu-tubeless',unistr('<p>Le Givi S450 est un kit de réparation pour pneus tubeless, conçu pour permettre aux motards de réparer rapidement une crevaison sur route ou en balade. Compact et pratique, il est pensé pour un usage rapide et sécurisé en cas de crevaison d’un pneu tubeless.<br />\u000a Caractéristiques principales<br />\u000aSpécial pneus tubeless : efficace pour réparer la majorité des crevaisons légères<br />\u000aKit complet : comprend outils, mèches, applicateur et notice d’utilisation<br />\u000aCompact et léger : facile à transporter sur la moto, dans une sacoche ou top case<br />\u000aInstallation rapide : solution d’urgence pour reprendre la route rapidement<br />\u000aRésistant et durable : matériaux de qualité pour garantir l’efficacité du kit<br />\u000a Utilisation<br />\u000aLe kit Givi S450 est idéal pour :<br />\u000aréparer une crevaison tubeless en urgence<br />\u000avoyager sereinement sans dépendre d’un garage<br />\u000ausage sur routes, autoroutes ou chemins légers<br />\u000atransporter facilement dans un sacoche, top case ou sac à dos<br />\u000a En résumé<br />\u000aLe Givi S450 est un kit indispensable pour tout motard utilisant des pneus tubeless. Compact, complet et facile à utiliser, il permet de réparer rapidement une crevaison et de continuer le trajet en toute sécurité.</p>\u000a'),'',36,756,499.0,499.0,NULL,NULL,'published','Kit de Réparation Pneu Tubeless Givi S450','Kit de Réparation Pneu Tubeless Givi S450 au Maroc. Achetez au meilleur prix chez MOTO PACO.',74,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(154,'GIVI SACOCHE DE RÉSERVOIR XS319Y TANKLOCK','givi-xs319y-sacoche-reservoir-tanklock',unistr('<p>La Givi XS319Y est une sacoche de réservoir pour moto équipée du système Tanklock, qui permet un montage et un démontage rapide et sécurisé sur la plupart des motos compatibles. Pratique pour les trajets quotidiens ou les balades, elle offre un accès facile à vos objets essentiels tout en restant parfaitement fixée.<br />\u000a Caractéristiques principales<br />\u000aSystème Tanklock : installation rapide, démontage facile sans outils<br />\u000aCapacité modulable : idéale pour ranger téléphone, portefeuille, cartes, lunettes et petits objets<br />\u000aMatériaux robustes : tissu résistant à l’usure et à l’humidité<br />\u000aDesign ergonomique : forme adaptée au réservoir pour un maintien stable et discret<br />\u000aPoches et compartiments : pour organiser vos affaires et y accéder rapidement<br />\u000aCompatible moto : se fixe sur tous les réservoirs équipés de l’adaptateur Tanklock Givi<br />\u000a Utilisation<br />\u000aLa sacoche XS319Y est parfaite pour :<br />\u000ales courtes et longues balades<br />\u000agarder vos objets essentiels à portée de main<br />\u000aun usage quotidien ou pour les voyages moto<br />\u000aun transport sécurisé et pratique sans gêner la conduite<br />\u000a En résumé<br />\u000aLa Givi XS319Y Tanklock est une sacoche de réservoir pratique, robuste et facilement amovible. Son système Tanklock assure un montage rapide et sûr, tandis que son design ergonomique et ses compartiments bien pensés rendent chaque trajet plus confortable et organisé.</p>\u000a'),'',39,756,699.0,699.0,NULL,NULL,'published','GIVI SACOCHE DE RÉSERVOIR XS319Y TANKLOCK','GIVI SACOCHE DE RÉSERVOIR XS319Y TANKLOCK au Maroc. Achetez au meilleur prix chez MOTO PACO.',118,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(155,'T11N UNIVERSAL SMALL ELASTIC CARGO NET','givi-t11n-filet-elastique-universel',unistr('<p>Le Givi T11N est un filet de chargement élastique universel conçu pour sécuriser vos bagages sur une moto ou un scooter. Pratique et polyvalent, il permet de maintenir en place des petits objets ou sacs sur le porte-paquet, top case ou valise ouverte.<br />\u000a Caractéristiques principales<br />\u000aTaille compacte et universelle : s’adapte à la plupart des motos, scooters et top cases<br />\u000aMatériau élastique et résistant : maintien sûr des bagages sans les abîmer<br />\u000aCrochets intégrés : fixation facile sur le porte-bagages ou top case<br />\u000aPolyvalent : idéal pour sacs, casques, sacs à dos ou petits objets<br />\u000aPortable et léger : peut être rangé facilement lorsqu’il n’est pas utilisé<br />\u000a Utilisation<br />\u000aLe filet Givi T11N est idéal pour :<br />\u000asécuriser petits bagages sur le porte-paquet ou top case<br />\u000amaintenir des objets en mouvement pendant le trajet<br />\u000atransporter sacs à dos, casques ou colis légers<br />\u000ausage quotidien ou pour de courts trajets<br />\u000a En résumé<br />\u000aLe Givi T11N est un filet élastique pratique, léger et universel, parfait pour sécuriser rapidement vos petits bagages sur votre moto ou scooter. Un accessoire simple mais indispensable pour chaque motard.</p>\u000a'),'',16,13,199.0,199.0,NULL,NULL,'published','T11N UNIVERSAL SMALL ELASTIC CARGO NET','T11N UNIVERSAL SMALL ELASTIC CARGO NET au Maroc. Achetez au meilleur prix chez MOTO PACO.',143,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(156,'M10 PLAQUE D''ADAPTATION MONOKEY','givi-m10-plaque-adaptation-monokey',unistr('<p>La Givi M10 est une plaque d’adaptation en aluminium conçue pour permettre la fixation d’un top case équipé du système MONOKEY® sur une moto. Elle se monte sur un support arrière compatible (type Monorack) pour offrir une base solide et sécurisée.<br />\u000a Caractéristiques principales<br />\u000aCompatibilité MONOKEY® : permet l’installation de tous les top cases Givi utilisant ce système<br />\u000aConstruction en aluminium : légère, robuste et résistante à la corrosion<br />\u000aFixation sécurisée : assure un maintien fiable du top case même sur longues distances<br />\u000aDesign universel : s’adapte aux supports Givi compatibles (selon modèle de moto)<br />\u000aPré-équipée : livrée avec kit de fixation<br />\u000a Compatibilité<br />\u000a✔️ Compatible avec :<br />\u000aTop cases Givi MONOKEY®<br />\u000a Nécessite :<br />\u000aUn support spécifique moto (Monorack ou porte-paquet compatible Givi)<br />\u000a Non compatible avec :<br />\u000aSystème MONOLOCK®</p>\u000a'),'',45,13,699.0,699.0,NULL,NULL,'published','M10 PLAQUE D''ADAPTATION MONOKEY','M10 PLAQUE D''ADAPTATION MONOKEY au Maroc. Achetez au meilleur prix chez MOTO PACO.',115,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(157,'Givi E248 Backrest for ALP44 ALPINA Top Case','givi-e248-dossier-top-case-alpina-alp44',unistr('<p>Le Givi E248 est un dossier (backrest) spécialement conçu pour le top case ALPINA ALP44 de Givi. Il améliore considérablement le confort du passager en offrant un appui dorsal ergonomique lors des trajets à moto.<br />\u000a Caractéristiques principales<br />\u000aConfort accru : rembourrage souple pour un meilleur maintien du dos du passager<br />\u000aDesign intégré : s’harmonise parfaitement avec le style du top case ALP44<br />\u000aMatériaux résistants : conçu pour résister aux intempéries et à l’usure<br />\u000aMontage facile : installation simple avec kit de fixation fourni<br />\u000aAccessoire officiel Givi : parfaitement adapté au top case ALPINA<br />\u000a Compatibilité<br />\u000a✔️ Compatible uniquement avec :<br />\u000aTop case Givi ALPINA ALP44<br />\u000aUtilisation<br />\u000aLe dossier Givi E248 est idéal pour :<br />\u000ales voyages à deux<br />\u000ales longs trajets<br />\u000aaméliorer le confort et la sécurité du passager</p>\u000a'),'',51,756,399.0,399.0,NULL,NULL,'published','Givi E248 Backrest for ALP44 ALPINA Top Case','Givi E248 Backrest for ALP44 ALPINA Top Case au Maroc. Achetez au meilleur prix chez MOTO PACO.',96,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(158,'Givi PLR5127 Specific Pannier Holder for Monokey Cases for BMW F 750 GS, F 800 GS, F 850 GS, F900 GS','givi-plr5127-support-valises-monokey-bmw-f750gs-f800gs-f850gs-f900gs',unistr('<p>Le Givi PLR5127 est un support latéral spécifique conçu pour installer des valises sur certaines motos BMW GS. Il appartient à la gamme PLR (Rapid Release), ce qui signifie qu’il peut être monté et démonté rapidement selon les besoins.<br />\u000aIl permet de fixer des valises latérales compatibles avec le système MONOKEY® de Givi, reconnu pour sa robustesse et sa polyvalence.<br />\u000a Caractéristiques principales<br />\u000aFixation rapide (PLR) : système démontable sans outils complexes, idéal pour retirer les supports lorsque non utilisés<br />\u000aCompatibilité MONOKEY® : fonctionne avec de nombreuses valises Givi (Trekker, Dolomiti, Alaska, etc.)<br />\u000aStructure solide en acier : assure une excellente stabilité même en charge<br />\u000aDesign discret : après démontage, peu d’éléments restent visibles sur la moto<br />\u000aMontage spécifique : conçu pour s’adapter parfaitement aux points de fixation d’origine<br />\u000a Compatibilité moto<br />\u000aLe PLR5127 est compatible avec plusieurs modèles BMW GS, notamment :<br />\u000aF 750 GS<br />\u000aF 800 GS<br />\u000aF 850 GS<br />\u000aF 900 GS / Adventure</p>\u000a'),'',43,756,2999.0,2999.0,NULL,NULL,'published','Givi PLR5127 Specific Pannier Holder for Monokey Cases for BMW F 750 GS, F 800 GS, F 850 GS, F900 GS','Givi PLR5127 Specific Pannier Holder for Monokey Cases for BMW F 750 GS, F 800 GS, F 850 GS, F900 GS au Maroc. Achetez au meilleur prix chez MOTO PACO.',126,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(159,'Givi BF17 TanklockGivi BF17 Tanklock','givi-bf17-tanklock-support-sac-reservoir',unistr('<p>Le Givi BF17 Tanklock est un support innovant conçu pour fixer rapidement et en toute sécurité un sac de réservoir Givi sur votre moto. Grâce à son système Tanklock, l’installation et le retrait du sac se font en quelques secondes, sans outils supplémentaires, tout en garantissant une fixation stable même lors de trajets à grande vitesse.<br />\u000aFabriqué avec des matériaux robustes et durables, le BF17 assure une protection fiable pour votre sac et vos effets personnels, tout en respectant la finition de votre réservoir. Compatible avec la majorité des modèles de motos, il transforme l’utilisation de votre sac de réservoir en une solution pratique et sécurisée pour le transport d’objets essentiels comme le téléphone, le portefeuille, les documents ou autres petits accessoires.<br />\u000aLe système Tanklock permet également de positionner facilement le sac à la place exacte souhaitée et de le verrouiller rapidement, offrant un confort optimal pour les trajets courts ou longs.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : BF17<br />\u000aType : Support Tanklock pour sac de réservoir<br />\u000aMatériau : Résistant et durable<br />\u000aInstallation : rapide et sans outils<br />\u000aCompatibilité : la plupart des motos avec réservoir compatible Tanklock<br />\u000aAvantages : fixation sécurisée, pratique et rapide, stabilité même à grande vitesse</p>\u000a'),'',43,756,189.0,189.0,NULL,NULL,'published','Givi BF17 TanklockGivi BF17 Tanklock','Givi BF17 TanklockGivi BF17 Tanklock au Maroc. Achetez au meilleur prix chez MOTO PACO.',92,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(160,'Givi Easy EA145B waist bag','givi-ea145b-sac-banane-waist-bag',unistr('<p>Le sac banane Givi Easy EA145B est un accessoire pratique et polyvalent conçu pour transporter vos objets personnels en toute sécurité lors de vos déplacements à moto ou à vélo, ou même pour un usage quotidien. Léger et compact, il se porte confortablement autour de la taille, laissant vos mains libres tout en gardant vos effets essentiels à portée de main.<br />\u000aFabriqué avec des matériaux résistants et durables, le EA145B protège vos affaires contre l’usure et les légères projections. Il est doté de poches bien organisées, offrant un accès rapide à votre téléphone, portefeuille, clés et autres petits objets indispensables.<br />\u000aGrâce à son design ergonomique et ajustable, ce sac s’adapte à toutes les morphologies et garantit un maintien sûr, même lors de déplacements rapides ou d’activités dynamiques.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : EA145B<br />\u000aType : Sac banane / waist bag<br />\u000aMatériau : Résistant et durable<br />\u000aCapacité : compacte, adaptée aux petits objets essentiels<br />\u000aPort : autour de la taille, réglable<br />\u000aAvantages : mains libres, organisation pratique, sécurité et confort</p>\u000a'),'',39,756,312.0,312.0,NULL,NULL,'published','Givi Easy EA145B waist bag','Givi Easy EA145B waist bag au Maroc. Achetez au meilleur prix chez MOTO PACO.',67,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(161,'KIT DE PROTECTION POUR PARE-CHOCS MOTEUR GIVI Z2159R','givi-z2159r-kit-protection-pare-chocs-moteur',unistr('<p>Le kit de protection pour pare-chocs moteur Givi Z2159R est spécialement conçu pour protéger les composants sensibles de votre moto en cas de chute ou de contact avec des obstacles. Ce kit robuste agit comme un bouclier, minimisant les risques de dommages au moteur et aux parties inférieures de la moto.<br />\u000aFabriqué avec des matériaux résistants et de haute qualité, le Z2159R offre une excellente durabilité et absorbe efficacement les impacts. Il est idéal pour les motards qui pratiquent la route comme l’aventure ou le tout-terrain, où le risque de contact avec des obstacles est plus élevé.<br />\u000aLe kit est conçu pour un montage facile et sécurisé sur les pare-chocs moteur d’origine de la moto, sans modification structurelle, garantissant à la fois protection et maintien optimal.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : Z2159R<br />\u000aType : Kit de protection pour pare-chocs moteur<br />\u000aMatériau : Plastique et métal résistant aux impacts<br />\u000aInstallation : montage direct sur pare-chocs moteur<br />\u000aAvantages : protège le moteur et les parties inférieures de la moto, résistant et durable, montage facile</p>\u000a'),'',16,756,189.0,189.0,NULL,NULL,'published','KIT DE PROTECTION POUR PARE-CHOCS MOTEUR GIVI Z2159R','KIT DE PROTECTION POUR PARE-CHOCS MOTEUR GIVI Z2159R au Maroc. Achetez au meilleur prix chez MOTO PACO.',66,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(162,'GILET AD ALTA VISIBILITA'' [GIVI] VEST02 TREKKER VEST - UNIVERSALE','givi-vest02-trekker-vest-gilet-haute-visibilite',unistr('<p>Le gilet haute visibilité Givi VEST02 Trekker Vest est conçu pour améliorer la sécurité des motards et cyclistes en augmentant leur visibilité sur la route. Grâce à sa couleur vive et à ses bandes réfléchissantes, ce gilet assure que le pilote est parfaitement visible, de jour comme de nuit.<br />\u000aFabriqué avec des matériaux légers et respirants, le VEST02 Trekker Vest est confortable à porter par-dessus n’importe quel vêtement ou équipement de moto. Sa coupe universelle permet de s’adapter à toutes les morphologies et offre une grande liberté de mouvement pendant la conduite.<br />\u000aCe gilet pratique et polyvalent est idéal pour les trajets urbains, les longs voyages ou toute situation nécessitant une visibilité accrue, contribuant ainsi à réduire les risques d’accident.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : VEST02 Trekker Vest<br />\u000aType : Gilet haute visibilité universel<br />\u000aCouleur : Jaune vif avec bandes réfléchissantes<br />\u000aTaille : Universelle<br />\u000aMatériau : Léger, respirant et durable<br />\u000aAvantages : améliore la visibilité, sécurité accrue, confortable et facile à porter</p>\u000a'),'',24,756,599.0,599.0,NULL,NULL,'published','GILET AD ALTA VISIBILITA'' [GIVI] VEST02 TREKKER VEST - UNIVERSALE','GILET AD ALTA VISIBILITA'' [GIVI] VEST02 TREKKER VEST - UNIVERSALE au Maroc. Achetez au meilleur prix chez MOTO PACO.',128,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(163,'HOUSSE DE PROTECTION POUR MOTO IMPERMÉABLE S203XL - GIVI','givi-s203xl-housse-protection-impermeable-moto',unistr('<p>La housse de protection imperméable pour moto Givi S203XL est conçue pour protéger efficacement votre moto contre la pluie, la poussière, les rayons UV et autres agressions extérieures. Idéale pour un usage extérieur ou intérieur, elle offre une protection complète tout en restant facile à utiliser et à ranger.<br />\u000aFabriquée avec un matériau résistant et imperméable de haute qualité, cette housse protège votre moto des intempéries et des éclaboussures tout en empêchant l’accumulation de poussière et de saleté. Sa conception robuste et ses coutures renforcées garantissent une durabilité optimale sur le long terme.<br />\u000aLa S203XL est équipée de sangles de fixation et d’élastiques ajustables pour maintenir la housse bien en place, même par vent fort. Elle s’adapte parfaitement à la majorité des motos de grande taille et facilite le stockage ou la couverture de votre véhicule pour un entretien facile.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : S203XL<br />\u000aType : Housse de protection imperméable pour moto<br />\u000aMatériau : Résistant et imperméable<br />\u000aTaille : XL – adaptée aux grandes motos<br />\u000aFixation : sangles et élastiques pour un maintien sécurisé<br />\u000aAvantages : protection contre pluie, poussière et UV, durable, facile à installer et à ranger</p>\u000a'),'',25,756,529.0,529.0,NULL,NULL,'published','HOUSSE DE PROTECTION POUR MOTO IMPERMÉABLE S203XL - GIVI','HOUSSE DE PROTECTION POUR MOTO IMPERMÉABLE S203XL - GIVI au Maroc. Achetez au meilleur prix chez MOTO PACO.',90,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(164,'GIVI XL10 X-LINE : un sac malin pour optimiser vos valises aluminium','givi-xl10-x-line-sac-interne-valises-aluminium',unistr('<p>Le sac Givi XL10 X-LINE est un accessoire malin conçu pour optimiser l’espace de vos valises aluminium Givi. Grâce à sa conception ingénieuse et compacte, il permet d’organiser vos affaires à l’intérieur de la valise tout en facilitant le transport et la protection de vos objets personnels.<br />\u000aFabriqué avec des matériaux résistants et légers, le XL10 X-LINE est idéal pour ranger vêtements, accessoires ou petits équipements lors de vos trajets à moto. Son design pratique et modulable vous permet de l’utiliser seul ou à l’intérieur de vos valises aluminium pour maximiser l’espace disponible et garder vos affaires bien organisées.<br />\u000aDe plus, ce sac est facile à insérer et à retirer, ce qui le rend parfait pour les voyageurs qui cherchent un rangement rapide et efficace sans compromettre la sécurité ou le confort.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : XL10 X-LINE<br />\u000aType : Sac interne / sac d’organisation pour valises aluminium<br />\u000aMatériau : Résistant et léger<br />\u000aAvantages : optimisation de l’espace, rangement organisé, transport facile<br />\u000aCompatibilité : toutes les valises aluminium Givi</p>\u000a'),'',51,756,1879.0,1879.0,NULL,NULL,'published','GIVI XL10 X-LINE : un sac malin pour optimiser vos valises aluminium','GIVI XL10 X-LINE : un sac malin pour optimiser vos valises aluminium au Maroc. Achetez au meilleur prix chez MOTO PACO.',150,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(165,'Givi Canyon side cargo bag Waterproof 8 liters-grt722b-side','givi-canyon-side-cargo-bag-8l-grt722b-side',unistr('<p>Le sac latéral étanche Givi Canyon 8 litres (GRT722B-SIDE) est un accessoire pratique et robuste conçu pour les motards et aventuriers. Conçu pour être fixé facilement sur le côté de la moto, il offre un espace de rangement supplémentaire tout en protégeant vos affaires des intempéries grâce à son matériau totalement étanche.<br />\u000aAvec une capacité de 8 litres, ce sac est idéal pour transporter des objets personnels, outils ou petits équipements lors de vos trajets quotidiens ou de vos aventures sur route et hors route. Sa conception compacte et légère permet de ne pas gêner la maniabilité de la moto, tout en restant solide et durable face aux conditions les plus difficiles.<br />\u000aLe Givi Canyon Side Bag se fixe en toute sécurité grâce à son système de fixation pratique et rapide, permettant de l’installer ou de le retirer facilement selon vos besoins.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : GRT722B-SIDE<br />\u000aType : Sac latéral moto étanche<br />\u000aCapacité : 8 litres<br />\u000aMatériau : Résistant et imperméable<br />\u000aInstallation : Fixation latérale rapide et sécurisée<br />\u000aAvantages : protection contre l’eau, léger et compact, durable et pratique</p>\u000a'),'',51,756,899.0,899.0,NULL,NULL,'published','Givi Canyon side cargo bag Waterproof 8 liters-grt722b-side','Givi Canyon side cargo bag Waterproof 8 liters-grt722b-side au Maroc. Achetez au meilleur prix chez MOTO PACO.',72,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(167,'GIVI Windscreen d6122s','givi-d6122s-pare-brise-transparent',unistr('<p>Le pare-brise transparent Givi D6122S est conçu pour offrir une protection optimale au pilote contre le vent, les insectes et les projections sur la route. Sa transparence garantit une excellente visibilité et une conduite plus agréable, même lors de trajets longs ou à grande vitesse.<br />\u000aFabriqué avec des matériaux robustes et durables, ce pare-brise améliore l’aérodynamisme du scooter ou de la moto, réduisant la fatigue liée à la pression du vent. Son design élégant s’intègre parfaitement au style du véhicule.<br />\u000aLe Givi D6122S se monte facilement sur les points de fixation d’origine, sans nécessiter de modifications supplémentaires, pour une installation rapide et sécurisée.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : D6122S<br />\u000aType : Pare-brise / bulle moto<br />\u000aCouleur : Transparent<br />\u000aInstallation : montage direct sur les fixations d’origine<br />\u000aAvantages : protection contre le vent, confort amélioré, v</p>\u000a'),'',16,756,769.0,769.0,NULL,NULL,'published','GIVI Windscreen d6122s','GIVI Windscreen d6122s au Maroc. Achetez au meilleur prix chez MOTO PACO.',79,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(168,'PARABREZZA GIVI D6107ST PRONTO A MONTAGGIO FOR KYMCO 350','givi-d6107st-pare-brise-transparent',unistr('<p>Le pare-brise transparent Givi D6107ST est conçu pour améliorer le confort et la protection du pilote lors des trajets à moto ou scooter. Il protège efficacement contre le vent, les insectes et les projections, tout en offrant une excellente visibilité grâce à sa finition transparente.<br />\u000aFabriqué avec des matériaux résistants et durables, le D6107ST améliore l’aérodynamisme et réduit la fatigue lors des longs trajets ou des conduites à grande vitesse. Son design s’intègre parfaitement au style de la moto ou du scooter, tout en restant élégant et discret.<br />\u000aCe pare-brise se fixe directement sur les points de montage d’origine, permettant une installation simple et rapide sans nécessiter de modifications supplémentaires.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : D6107ST<br />\u000aType : Pare-brise / bulle moto<br />\u000aCouleur : Transparent<br />\u000aInstallation : montage direct sur les fixations d’origine<br />\u000aAvantages : protection contre le vent, confort accru, visibilité optimale</p>\u000a'),'',16,756,1449.0,1449.0,NULL,NULL,'published','PARABREZZA GIVI D6107ST PRONTO A MONTAGGIO FOR KYMCO 350','PARABREZZA GIVI D6107ST PRONTO A MONTAGGIO FOR KYMCO 350 au Maroc. Achetez au meilleur prix chez MOTO PACO.',128,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(169,'Windscreen Givi High Smoke Bmw F750GS-D5127S','givi-d5127s-pare-brise-high-smoke-bmw-f750gs',unistr('<p>Le pare-brise haute fumée Givi D5127S est spécialement conçu pour la moto BMW F750GS. Grâce à sa teinte « High Smoke », il offre une protection efficace contre le vent, les projections et les intempéries tout en réduisant l’éblouissement solaire pour le pilote.<br />\u000aFabriqué avec des matériaux résistants et durables, ce pare-brise améliore l’aérodynamisme de la moto et le confort de conduite, particulièrement sur les longs trajets ou à grande vitesse. Sa finition fumée ajoute une touche de style moderne et sportive à la moto.<br />\u000aLe Givi D5127S se monte directement sur les points de fixation d’origine, ce qui permet une installation rapide et sécurisée sans modifications supplémentaires.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : D5127S<br />\u000aType : Pare-brise / bulle moto<br />\u000aCouleur : High Smoke (fumé foncé)<br />\u000aInstallation : montage direct sur les fixations d’origine<br />\u000aCompatibilité : BMW F750GS<br />\u000aAvantages : meilleure protection contre le vent, confort accru, style moderne, réduction de l’éblouissement</p>\u000a'),'',16,756,929.0,929.0,NULL,NULL,'published','Windscreen Givi High Smoke Bmw F750GS-D5127S','Windscreen Givi High Smoke Bmw F750GS-D5127S au Maroc. Achetez au meilleur prix chez MOTO PACO.',138,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(170,'Givi Windscreen d7713st','givi-d7713st-pare-brise-transparent',unistr('<p>Le pare-brise transparent Givi D7713ST est un accessoire conçu pour améliorer la protection aérodynamique et le confort de conduite. Grâce à sa conception spécifique, il protège efficacement le pilote contre le vent, les insectes et les projections de la route, tout en conservant une excellente visibilité.<br />\u000aFabriqué avec des matériaux de haute qualité, ce pare-brise offre une grande résistance et une durabilité optimale, même lors d’une utilisation intensive ou sur de longs trajets. Son design transparent s’intègre parfaitement au style de la moto et améliore l’aérodynamisme pour une conduite plus confortable à vitesse élevée.<br />\u000aLe pare-brise Givi D7713ST est conçu pour remplacer directement le pare-brise d’origine et s’installe facilement en utilisant les points de fixation existants, sans modification de la moto.</p>\u000a'),'',31,756,999.0,999.0,NULL,NULL,'published','Givi Windscreen d7713st','Givi Windscreen d7713st au Maroc. Achetez au meilleur prix chez MOTO PACO.',80,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(171,'D5146ST - Screen Givi Transparent BMW R 1300 GS Adventure (25)','givi-d5146st-pare-brise-transparent-bmw-r1300gs-adventure',unistr('<p>Le pare-brise transparent Givi D5146ST est spécialement conçu pour la moto BMW R 1300 GS Adventure (modèle 2025). Il offre une protection aérodynamique améliorée tout en conservant un design élégant et une visibilité claire pour le pilote.<br />\u000aFabriqué avec des matériaux résistants et de haute qualité, ce pare-brise transparent aide à réduire la pression du vent sur le torse et le casque du conducteur, améliorant ainsi le confort lors des trajets longs ou à grande vitesse. Sa conception est étudiée pour s’intégrer parfaitement au style et aux lignes de la moto.<br />\u000aLe D5146ST remplace directement le pare-brise d’origine et se fixe sur les points de montage existants de la moto, ce qui permet une installation simple et rapide sans modifications.<br />\u000aCaractéristiques principales<br />\u000aMarque : Givi<br />\u000aModèle : D5146ST<br />\u000aType : Pare-brise / bulle moto<br />\u000aCouleur : Transparent<br />\u000aMontage : remplace le pare-brise d’origine<br />\u000aCompatibilité : BMW R 1300 GS Adventure (2025)<br />\u000aAvantages : meilleure protection contre le vent, visibilité optimale et confort accru sur longs trajets.</p>\u000a'),'',16,756,999.0,999.0,NULL,NULL,'published','D5146ST - Screen Givi Transparent BMW R 1300 GS Adventure (25)','D5146ST - Screen Givi Transparent BMW R 1300 GS Adventure (25) au Maroc. Achetez au meilleur prix chez MOTO PACO.',125,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(172,'D6122ST - Windscreen Givi Transparent','givi-d6122st-windscreen-transparent',unistr('<p>Le Givi D6122ST Transparent Windscreen est un pare-brise transparent spécialement conçu pour améliorer le confort et la protection du conducteur. Fabriqué avec des matériaux résistants et de haute qualité, il offre une excellente visibilité tout en protégeant efficacement contre le vent, les insectes et les projections pendant la conduite.<br />\u000aCe pare-brise est développé pour s’adapter parfaitement au scooter Kymco AK 550 Premium (modèles 2023 à 2025). Il se monte directement à la place du pare-brise d’origine, en utilisant les mêmes points de fixation, ce qui facilite l’installation.<br />\u000aGrâce à sa conception aérodynamique, il réduit la pression du vent sur le torse et la tête du conducteur, ce qui améliore le confort, notamment lors des trajets à grande vitesse ou sur de longues distances.<br />\u000aCaractéristiques principales<br />\u000aCouleur : transparent<br />\u000aDimensions : environ 60 × 64,5 cm (hauteur × largeur)<br />\u000aInstallation : remplace le pare-brise d’origine<br />\u000aCompatibilité : Kymco AK 550 Premium (2023–2025)<br />\u000aAvantages : meilleure protection contre le vent, visibilité claire et design élégant</p>\u000a'),'',31,756,1061.0,1061.0,NULL,NULL,'published','D6122ST - Windscreen Givi Transparent','D6122ST - Windscreen Givi Transparent au Maroc. Achetez au meilleur prix chez MOTO PACO.',82,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(173,'Casque Cross KENNY TRACK GRAPHIC Rouge','casque-cross-kenny-track-graphic-rouge',unistr('<p>Le Kenny Racing Track Graphic Rouge est un casque de motocross conçu pour offrir sécurité, confort et style aux pilotes passionnés de tout-terrain. Son design graphique moderne avec sa couleur rouge dynamique apporte un look sportif tout en garantissant une protection fiable sur les pistes.<br />\u000aDoté d’une coque légère et résistante, ce casque assure une excellente protection contre les impacts. Son système de ventilation performant permet une circulation d’air efficace afin de garder la tête au frais pendant la conduite, même lors des sessions les plus intenses.<br />\u000aL’intérieur du casque est rembourré, amovible et lavable, garantissant un confort optimal et un entretien facile. Sa large ouverture est compatible avec la plupart des masques motocross, offrant ainsi une excellente visibilité et un maintien parfait.<br />\u000aCaractéristiques :<br />\u000aCoque légère et résistante<br />\u000aDesign Graphic Rouge moderne et sportif<br />\u000aSystème de ventilation efficace<br />\u000aIntérieur confortable, amovible et lavable<br />\u000aCompatible avec masques motocross<br />\u000aAvantages :<br />\u000aProtection idéale pour motocross, enduro et off-road<br />\u000aConfort optimal pendant les longues sessions<br />\u000aStyle racing dynamique<br />\u000aMaintien et visibilité excellents sur la piste<br />\u000aLe Casque Cross Kenny Track Graphic Rouge est parfait pour les pilotes qui recherchent performance, sécurité et style pour leurs aventures tout-terrain. </p>\u000a'),'',53,890,1899.0,1299.0,NULL,NULL,'published','Casque Cross KENNY TRACK GRAPHIC Rouge','Casque Cross KENNY TRACK GRAPHIC Rouge au Maroc. Achetez au meilleur prix chez MOTO PACO.',74,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(174,'Casque Kenny Track gris','casque-kenny-track-gris',unistr('<p>Le Kenny Racing Track Gris est un casque de motocross conçu pour offrir sécurité, confort et performance aux passionnés de tout-terrain. Avec son design moderne en couleur grise, il allie style sobre et efficacité pour accompagner les pilotes sur toutes les pistes.<br />\u000aSa coque légère et résistante assure une excellente protection contre les impacts, tandis que le système de ventilation optimisé permet une circulation d’air efficace pour garder la tête au frais pendant la conduite. L’intérieur du casque est rembourré, amovible et lavable, garantissant un confort durable et un entretien facile.<br />\u000aCompatible avec la plupart des masques motocross, ce casque offre une visibilité optimale et un maintien parfait, idéal pour les pratiques de motocross, enduro et off-road.<br />\u000aCaractéristiques :<br />\u000aCoque légère et résistante<br />\u000aDesign moderne Gris<br />\u000aSystème de ventilation efficace<br />\u000aIntérieur confortable, amovible et lavable<br />\u000aCompatible avec masques motocross<br />\u000aAvantages :<br />\u000aProtection fiable pour motocross et enduro<br />\u000aConfort optimal lors des longues sorties<br />\u000aStyle sobre et sportif<br />\u000aExcellente stabilité et visibilité sur la piste<br />\u000aLe Casque Kenny Track Gris est un choix idéal pour les pilotes qui recherchent sécurité, confort et style pour leurs aventures tout-terrain. </p>\u000a'),'',53,890,1899.0,1199.0,NULL,NULL,'published','Casque Kenny Track gris','Casque Kenny Track gris au Maroc. Achetez au meilleur prix chez MOTO PACO.',77,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(175,'Casque Kenny unlimited rouge','casque-kenny-unlimited-rouge',unistr('<p>Le Kenny Racing Unlimited Rouge est un casque de motocross conçu pour offrir sécurité, confort et style aux passionnés de tout-terrain. Avec sa couleur rouge dynamique et son design sportif, il apporte un look moderne tout en garantissant une protection efficace sur les pistes.<br />\u000aSa coque légère et résistante assure une excellente protection contre les impacts, tandis que le système de ventilation optimisé permet une bonne circulation de l’air afin de garder la tête au frais pendant la conduite. L’intérieur du casque est confortable, amovible et lavable, facilitant l’entretien et assurant un confort durable.<br />\u000aLe casque est compatible avec la plupart des masques de motocross, offrant une visibilité optimale et un maintien parfait lors de vos sorties en motocross, enduro ou tout-terrain.<br />\u000aCaractéristiques :<br />\u000aCoque légère et résistante<br />\u000aDesign sportif Rouge moderne<br />\u000aSystème de ventilation efficace<br />\u000aIntérieur confortable, amovible et lavable<br />\u000aCompatible avec masques motocross<br />\u000aAvantages :<br />\u000aProtection fiable pour motocross, enduro et off-road<br />\u000aConfort optimal lors des longues sessions<br />\u000aStyle dynamique et moderne<br />\u000aExcellente stabilité et visibilité sur la piste<br />\u000aLe Casque Kenny Unlimited Rouge est un choix idéal pour les pilotes qui recherchent performance, sécurité et style lors de leurs aventures tout-terrain.</p>\u000a'),'',53,890,2399.0,1499.0,NULL,NULL,'published','Casque Kenny unlimited rouge','Casque Kenny unlimited rouge au Maroc. Achetez au meilleur prix chez MOTO PACO.',84,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(176,'KENNY CASQUE CROSS TRACK GRAPHIC','casque-cross-kenny-track-graphic',unistr('<p>Le Kenny Racing Track Graphic est un casque de motocross conçu pour offrir sécurité, confort et style aux pilotes de tout niveau. Avec son design graphique moderne et sportif, il apporte un look dynamique tout en assurant une protection fiable lors des sorties tout-terrain.<br />\u000aSa coque légère et résistante protège efficacement contre les impacts, tandis que le système de ventilation performant permet une bonne circulation de l’air pour garder la tête au frais pendant la conduite. L’intérieur du casque est rembourré, amovible et lavable, garantissant un confort optimal et un entretien facile.<br />\u000aCe casque est compatible avec la plupart des masques motocross, offrant une excellente visibilité et un maintien parfait pendant la pratique.<br />\u000aCaractéristiques :<br />\u000aCoque légère et résistante<br />\u000aDesign Graphic moderne et sportif<br />\u000aSystème de ventilation efficace<br />\u000aIntérieur confortable, amovible et lavable<br />\u000aCompatible avec masques de motocross<br />\u000aAvantages :<br />\u000aProtection fiable pour le motocross et l’enduro<br />\u000aConfort optimal lors des longues sessions<br />\u000aLook racing moderne<br />\u000aIdéal pour les pilotes off-road et tout-terrain<br />\u000aLe Casque Cross Kenny Track Graphic est un excellent choix pour les pilotes qui recherchent performance, sécurité et style sur toutes les pistes de motocross. </p>\u000a'),'',53,890,0.0,NULL,NULL,NULL,'published','KENNY CASQUE CROSS TRACK GRAPHIC','KENNY CASQUE CROSS TRACK GRAPHIC au Maroc. Achetez au meilleur prix chez MOTO PACO.',71,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(177,'Casque Kenny Performance jaune fluo','casque-kenny-performance-jaune-fluo',unistr('<h3 class="" data-start="214" data-end="266">Casque Kenny Performance Graphic – Jaune Fluo</h3>\u000a<p class="" data-start="268" data-end="387"><span class="relative -mx-px my-[-0.2rem] rounded px-px py-[0.2rem] transition-colors duration-100 ease-in-out">Le <strong data-start="3" data-end="39">Casque Kenny Performance Graphic</strong> en jaune fluo est conçu pour les pilotes de motocross et d''enduro recherchant à la fois sécurité, confort et style percutant.</span> <span class="relative -mx-px my-[-0.2rem] rounded px-px py-[0.2rem] transition-colors duration-100 ease-in-out">Doté de la technologie MIPS, il offre une protection accrue contre les impacts multidirectionnels.</span>​<span class="ms-1 inline-flex max-w-full items-center relative top-[-0.094rem] animate-[show_150ms_ease-in]"><a class="flex h-6 overflow-hidden rounded-xl px-2.5 text-[0.5625em] font-medium text-token-text-secondary! bg-[#F4F4F4]! dark:bg-[#303030]! transition-colors duration-150 ease-in-out" href="https://www.dafy-moto.com/casque-performance-kenny.html?utm_source=chatgpt.com" target="_blank" rel="noopener"><span class="relative start-0 bottom-0 flex h-full w-full items-center"><span class="flex h-4 w-full items-center justify-between absolute"><span class="max-w-full grow truncate overflow-hidden text-center">La Becanerie</span><span class="ms-1 -me-1 flex h-full items-center rounded-full px-1 text-[#8F8F8F]">+3</span></span><span class="flex h-4 w-full items-center justify-between"><span class="max-w-full grow truncate overflow-hidden text-center">Dafy Moto</span><span class="ms-1 -me-1 flex h-full items-center rounded-full px-1 text-[#8F8F8F]">+3</span></span><span class="flex h-4 w-full items-center justify-between absolute"><span class="max-w-full grow truncate overflow-hidden text-center">Wolff KTM, votre Boutique KTM en ligne</span><span class="ms-1 -me-1 flex h-full items-center rounded-full px-1 text-[#8F8F8F]">+3</span></span></span></a></span></p>\u000a<h4 class="" data-start="389" data-end="426">Caractéristiques principales :</h4>\u000a<ul data-start="427" data-end="953">\u000a<li class="" data-start="427" data-end="503">\u000a<p class="" data-start="429" data-end="503"><strong data-start="429" data-end="463">Coque en polycarbonate injecté</strong> : <span class="relative -mx-px my-[-0.2rem] rounded px-px py-[0.2rem] transition-colors duration-100 ease-in-out">robuste et légère pour une meilleure protection.</span></p>\u000a</li>\u000a<li class="" data-start="504" data-end="566">\u000a<p class="" data-start="506" data-end="566"><strong data-start="506" data-end="526">Technologie MIPS</strong> : <span class="relative -mx-px my-[-0.2rem] rounded px-px py-[0.2rem] transition-colors duration-100 ease-in-out">réduit les forces rotationnelles lors des impacts.</span></p>\u000a</li>\u000a<li class="" data-start="567" data-end="642">\u000a<p class="" data-start="569" data-end="642"><strong data-start="569" data-end="602">Intérieur amovible et lavable</strong> : <span class="relative -mx-px my-[-0.2rem] rounded px-px py-[0.2rem] transition-colors duration-100 ease-in-out">en tissu hypoallergénique pour un entretien facile.</span></p>\u000a</li>\u000a<li class="" data-start="643" data-end="718">\u000a<p class="" data-start="645" data-end="718"><strong data-start="645" data-end="678">Fermeture par boucle double D</strong> : <span class="relative -mx-px my-[-0.2rem] rounded px-px py-[0.2rem] transition-colors duration-100 ease-in-out">ajustable pour une sécurité renforcée.</span></p>\u000a</li>\u000a<li class="" data-start="719" data-end="787">\u000a<p class="" data-start="721" data-end="787"><strong data-start="721" data-end="747">Homologation ECE 22.06</strong> : <span class="relative -mx-px my-[-0.2rem] rounded px-px py-[0.2rem] transition-colors duration-100 ease-in-out">conforme aux normes européennes en vigueur.</span></p>\u000a</li>\u000a<li class="" data-start="788" data-end="839">\u000a<p class="" data-start="790" data-end="839"><strong data-start="790" data-end="799">Poids</strong> : <span class="relative -mx-px my-[-0.2rem] rounded px-px py-[0.2rem] transition-colors duration-100 ease-in-out">environ 1260 g (±50 g).</span></p>\u000a</li>\u000a<li class="" data-start="840" data-end="953">\u000a<p class="" data-start="842" data-end="953"><strong data-start="842" data-end="865">Tailles disponibles</strong> : <span class="relative -mx-px my-[-0.2rem] rounded px-px py-[0.2rem] bg-[#FCECC1] dark:bg-[#64572A] transition-colors duration-100 ease-in-out">XS à XXL, avec deux tailles de calotte pour un ajustement optimal.</span>​</p>\u000a</li>\u000a</ul>\u000a'),'',53,890,1899.0,1499.0,NULL,NULL,'published','Casque Kenny Performance Jaune Fluo','Casque Kenny Performance Jaune Fluo au Maroc. Achetez au meilleur prix chez MOTO PACO.',76,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(178,'Casque motocross Kenny Titanium Graphic Navy Orange','casque-motocross-kenny-titanium-graphic-navy-orange',unistr('<p>Casque Motocross Kenny Titanium Graphic Navy Orange<br />\u000aLe Kenny Racing Titanium Graphic Navy Orange est un casque de motocross alliant style, confort et protection pour tous les pilotes off-road. Son design moderne bleu marine et orange lui donne un look dynamique et sportif, parfait pour se démarquer sur les pistes.<br />\u000aConçu avec une coque légère et résistante, il offre une protection optimale contre les impacts. Le système de ventilation avancé assure une circulation d’air efficace, gardant la tête fraîche même lors de longues sorties. L’intérieur du casque est rembourré, confortable et démontable, facilitant le nettoyage et l’entretien.<br />\u000aCompatible avec la plupart des masques de motocross, ce casque garantit un maintien parfait et une visibilité optimale.<br />\u000aCaractéristiques :<br />\u000aCoque robuste et légère en polycarbonate ou composite<br />\u000aDesign graphique Navy Orange moderne<br />\u000aVentilation optimisée pour garder la tête au frais<br />\u000aIntérieur confortable, amovible et lavable<br />\u000aCompatible avec masques motocross<br />\u000aAvantages :<br />\u000aProtection fiable pour motocross, enduro et off-road<br />\u000aConfort optimal pour les longues sessions<br />\u000aLook dynamique et moderne<br />\u000aMaintien et visibilité excellents sur les pistes<br />\u000aLe Casque Kenny Titanium Graphic Navy Orange est idéal pour les pilotes qui recherchent sécurité, style et confort sur tous leurs parcours tout-terrain.</p>\u000a'),'',53,890,2899.0,1899.0,NULL,NULL,'published','Casque motocross Kenny Titanium Graphic Navy Orange','Casque motocross Kenny Titanium Graphic Navy Orange au Maroc. Achetez au meilleur prix chez MOTO PACO.',95,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(179,'CASQUE CROSS KENNY TITANIUM BLACK ORANGE','casque-cross-kenny-titanium-black-orange-2',unistr('<p>Casque Cross Kenny Titanium Black Orange<br />\u000aLe Kenny Racing Titanium Black Orange est un casque de motocross conçu pour offrir protection, confort et performance aux pilotes de tout niveau. Avec son design moderne noir et orange, il apporte un style sportif tout en garantissant une excellente sécurité sur les pistes et les chemins tout-terrain.<br />\u000aSa coque résistante et légère assure une protection optimale contre les impacts, tandis que le système de ventilation efficace permet une bonne circulation de l’air pour garder la tête au frais pendant la conduite. L’intérieur du casque est rembourré, confortable et démontable, facilitant ainsi l’entretien et le lavage.<br />\u000aIdéal pour les amateurs de motocross, enduro et off-road, ce casque offre un excellent maintien et une visibilité parfaite grâce à sa large ouverture compatible avec la plupart des masques cross.<br />\u000aCaractéristiques :<br />\u000aCoque robuste et légère<br />\u000aDesign sportif Black / Orange<br />\u000aSystème de ventilation performant<br />\u000aIntérieur confortable et démontable<br />\u000aCompatible avec masques de motocross<br />\u000aAvantages :<br />\u000aProtection fiable pour la pratique du motocross<br />\u000aConfort optimal lors des longues sessions<br />\u000aStyle moderne et dynamique<br />\u000aIdéal pour motocross, enduro et tout-terrain<br />\u000aLe casque Kenny Titanium Black Orange est parfait pour les pilotes qui recherchent sécurité, confort et look racing sur toutes leurs sorties off-road. 🏍️🔥</p>\u000a'),'',53,890,3199.0,1999.0,NULL,NULL,'published','CASQUE CROSS KENNY TITANIUM BLACK ORANGE','CASQUE CROSS KENNY TITANIUM BLACK ORANGE au Maroc. Achetez au meilleur prix chez MOTO PACO.',106,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(181,'quad lock wireless charger','quad-lock-wireless-charger-chargeur-sans-fil-moto',unistr('<p>Le Quad Lock Wireless Charger est un chargeur sans fil pratique et performant conçu pour être utilisé avec les supports Quad Lock. Il permet de recharger votre smartphone facilement pendant vos trajets, sans avoir besoin de brancher de câble directement sur le téléphone.<br />\u000aGrâce à la technologie de charge sans fil, votre téléphone se recharge automatiquement dès qu’il est fixé sur le support Quad Lock compatible. Ce système est idéal pour les motards qui utilisent leur smartphone pour la navigation GPS, les applications de conduite ou la musique lors de longs trajets.<br />\u000aConçu avec des matériaux résistants et une protection contre les intempéries, le Quad Lock Wireless Charger assure une utilisation fiable même dans des conditions difficiles.<br />\u000aCaractéristiques :<br />\u000aCharge sans fil rapide compatible avec la technologie Qi<br />\u000aCompatible avec les supports Quad Lock<br />\u000aInstallation simple et rapide<br />\u000aConception résistante aux intempéries<br />\u000aIdéal pour une utilisation moto, scooter ou vélo<br />\u000aAvantages :<br />\u000aRecharge du smartphone pendant la conduite<br />\u000aPas besoin de câble branché au téléphone<br />\u000aFixation stable et sécurisée<br />\u000aParfait pour la navigation GPS sur la route<br />\u000aLe Quad Lock Wireless Charger est l’accessoire parfait pour les utilisateurs de supports Quad Lock qui souhaitent garder leur smartphone chargé en permanence pendant leurs déplacements.</p>\u000a'),'',31,13,999.0,999.0,NULL,NULL,'published','quad lock wireless charger','quad lock wireless charger au Maroc. Achetez au meilleur prix chez MOTO PACO.',82,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(182,'Quad lock pro','quad-lock-pro-support-telephone-moto',unistr('<p>Le Quad Lock Pro est un support téléphone moto haut de gamme conçu pour offrir une fixation extrêmement solide et sécurisée à votre smartphone pendant vos trajets. Grâce à son système de verrouillage Quad Lock reconnu mondialement, votre téléphone se fixe rapidement et reste parfaitement stable, même à grande vitesse ou sur routes irrégulières.<br />\u000aFabriqué avec des matériaux de qualité supérieure, le Quad Lock Pro garantit une durabilité exceptionnelle et une excellente résistance aux vibrations et aux conditions extérieures. Son design élégant et robuste s’intègre parfaitement au guidon de votre moto.<br />\u000aIdéal pour les motards qui utilisent leur téléphone pour la navigation GPS, les applications de conduite ou la musique, ce support permet un accès facile à l’écran tout en gardant les mains sur le guidon.<br />\u000aCaractéristiques :<br />\u000aSystème de verrouillage Quad Lock sécurisé<br />\u000aConstruction robuste et durable<br />\u000aInstallation simple et rapide sur le guidon<br />\u000aRotation possible en mode portrait ou paysage<br />\u000aCompatible avec les coques Quad Lock<br />\u000aAvantages :<br />\u000aMaintien ultra stable du smartphone<br />\u000aUtilisation idéale pour le GPS en moto<br />\u000aDesign élégant et professionnel<br />\u000aInstallation rapide sans outils complexes<br />\u000aLe Quad Lock Pro est l’accessoire parfait pour les motards qui recherchent sécurité, stabilité et praticité lors de leurs déplacements.</p>\u000a'),'',31,13,999.0,999.0,NULL,NULL,'published','Quad lock pro','Quad lock pro au Maroc. Achetez au meilleur prix chez MOTO PACO.',72,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(183,'Anti Vibration quad lock-Support Téléphone Moto','anti-vibration-quad-lock-support-telephone-moto',unistr('<p>Le support téléphone moto Quad Lock avec module anti-vibration est conçu pour offrir une fixation ultra-sécurisée de votre smartphone pendant vos trajets à moto. Grâce à son système de verrouillage breveté, votre téléphone reste parfaitement stable même sur les routes accidentées.<br />\u000aLe module anti-vibration intégré réduit efficacement les vibrations du moteur et de la route, protégeant ainsi les composants sensibles de votre smartphone, notamment la caméra.<br />\u000aFabriqué avec des matériaux robustes et durables, ce support est idéal pour les motards qui utilisent leur téléphone pour la navigation GPS, la musique ou les appels en mains libres.<br />\u000aCaractéristiques :<br />\u000aSystème de fixation Quad Lock sécurisé et rapide<br />\u000aTechnologie anti-vibration pour protéger le smartphone<br />\u000aInstallation facile sur le guidon de la moto<br />\u000aRotation possible pour un mode portrait ou paysage<br />\u000aCompatible avec les coques Quad Lock ou adaptateur universel<br />\u000aAvantages :<br />\u000aMaintien extrêmement solide même à grande vitesse<br />\u000aProtection contre les vibrations du moteur<br />\u000aAccès facile au téléphone pendant la conduite<br />\u000aParfait pour les motards, scooters et amateurs de road trips qui souhaitent garder leur smartphone visible et sécurisé sur la route.</p>\u000a'),'',60,13,289.0,289.0,NULL,NULL,'published','Anti Vibration quad lock-Support Téléphone Moto','Anti Vibration quad lock-Support Téléphone Moto au Maroc. Achetez au meilleur prix chez MOTO PACO.',141,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(184,'Support de téléphone pour guidon moto Quad Lock Pro noir','support-telephone-guidon-moto-quad-lock-pro',unistr('<p>Le support de téléphone Quad Lock Pro pour guidon moto est l’accessoire idéal pour garder votre smartphone sécurisé et accessible lors de vos trajets à moto ou en scooter. Conçu pour un montage sur guidon, il permet une fixation solide et stable, même sur routes accidentées, tout en conservant un accès facile à votre appareil pour la navigation, la musique ou les appels mains libres.<br />\u000aFabriqué avec des matériaux de haute qualité, ce support assure une excellente résistance aux vibrations, aux chocs et aux intempéries. Son système de fixation Quad Lock breveté garantit un verrouillage rapide et sûr du téléphone, tout en permettant un détachement simple lorsque vous quittez votre moto.<br />\u000aCaractéristiques principales :<br />\u000aSupport universel pour guidon de moto ou scooter<br />\u000aCompatible avec la plupart des smartphones grâce au système Quad Lock<br />\u000aCouleur : noir<br />\u000aMontage sécurisé et rapide sur guidon<br />\u000aRésistant aux vibrations et aux chocs<br />\u000aAccès facile à l’écran et aux commandes du téléphone<br />\u000aIdéal pour la navigation GPS, appels mains libres et applications mobiles<br />\u000aLe Quad Lock Pro est parfait pour les motards et les passionnés de moto qui veulent sécurité, praticité et confort lors de leurs trajets. </p>\u000a'),'',60,13,899.0,899.0,NULL,NULL,'published','Support de téléphone pour guidon moto Quad Lock Pro noir','Support de téléphone pour guidon moto Quad Lock Pro noir au Maroc. Achetez au meilleur prix chez MOTO PACO.',64,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(185,'GIVI D1181S SMOKE WINDSCHERM HONDA SH','givi-d1181s-smoke-windscherm-honda-sh',unistr('<p>Le GIVI D1181S est un pare-brise fumé conçu spécialement pour les scooters Honda SH, offrant à la fois style et protection. Ce modèle protège efficacement le conducteur contre le vent, les intempéries et les projections, améliorant le confort lors des trajets urbains ou sur route.<br />\u000aFabriqué en matière acrylique de haute qualité, le pare-brise GIVI D1181S est résistant aux rayures et aux impacts légers, tout en conservant une excellente transparence pour la visibilité. Sa teinte fumée apporte une touche esthétique moderne au scooter, tout en réduisant l’éblouissement du soleil pour le conducteur.<br />\u000aCaractéristiques principales :<br />\u000aModèle : D1181S<br />\u000aCouleur : fumé / smoke<br />\u000aCompatible : Honda SH<br />\u000aMatériau : acrylique résistant aux rayures<br />\u000aProtection contre le vent et les intempéries<br />\u000aDesign moderne et élégant<br />\u000aMontage facile, adapté aux fixations d’origine<br />\u000aLe GIVI D1181S Smoke Windscherm est idéal pour ceux qui souhaitent combiner protection, confort et style sur leur scooter Honda SH. </p>\u000a'),'',31,756,899.0,899.0,NULL,NULL,'published','GIVI D1181S SMOKE WINDSCHERM HONDA SH','GIVI D1181S SMOKE WINDSCHERM HONDA SH au Maroc. Achetez au meilleur prix chez MOTO PACO.',105,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(188,'Lot de 3 paires de chaussettes tennis blanches KTM homme','lot-3-paires-chaussettes-tennis-blanches-ktm-homme',unistr('<p>Le lot de 3 paires de chaussettes tennis blanches KTM pour homme est conçu pour offrir confort, maintien et style au quotidien. Parfaites pour le sport ou pour une utilisation quotidienne, ces chaussettes garantissent une sensation de douceur et un excellent ajustement tout au long de la journée.<br />\u000aFabriquées dans des matériaux respirants et élastiques, elles assurent une bonne circulation de l’air et aident à garder les pieds secs, même pendant les activités physiques. Leur coupe type tennis offre un maintien optimal au niveau de la cheville et du mollet, tandis que les zones renforcées assurent durabilité et résistance à l’usure.<br />\u000aLeur design sobre blanc avec le logo emblématique de KTM apporte une touche sportive et élégante, parfaite pour les amateurs de la marque et les passionnés de moto.<br />\u000aCaractéristiques principales :<br />\u000aLot de 3 paires de chaussettes homme<br />\u000aStyle tennis / sport<br />\u000aCouleur : blanc<br />\u000aConfortables et respirantes<br />\u000aMaintien optimal et bonne élasticité<br />\u000aIdéales pour le sport ou l’usage quotidien</p>\u000a'),'',31,13,199.0,149.0,NULL,NULL,'published','Lot de 3 paires de chaussettes tennis blanches KTM homme','Lot de 3 paires de chaussettes tennis blanches KTM homme au Maroc. Achetez au meilleur prix chez MOTO PACO.',95,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(189,'lot de 3 paires de chaussettes tennis noires KTM homme','lot-3-paires-chaussettes-tennis-noires-ktm-homme',unistr('<p>Le lot de 3 paires de chaussettes tennis noires KTM pour homme est conçu pour offrir confort, résistance et style au quotidien. Idéales pour le sport ou pour une utilisation quotidienne, ces chaussettes assurent un bon maintien du pied et une sensation de douceur tout au long de la journée.<br />\u000aFabriquées dans un mélange de matières souples et respirantes, elles permettent une bonne évacuation de l’humidité et aident à garder les pieds au sec. Leur coupe type tennis offre un excellent maintien au niveau de la cheville et du mollet, tandis que les zones renforcées améliorent la durabilité.<br />\u000aAvec leur design sobre noir et le logo emblématique de KTM, ces chaussettes allient performance et style sportif, parfaites pour les amateurs de la marque et les passionnés de moto.<br />\u000aCaractéristiques principales :<br />\u000aLot de 3 paires de chaussettes homme<br />\u000aStyle tennis / sport<br />\u000aCouleur : noir<br />\u000aConfortables et respirantes<br />\u000aMaintien optimal et bonne élasticité</p>\u000a'),'',31,13,199.0,149.0,NULL,NULL,'published','lot de 3 paires de chaussettes tennis noires KTM homme','lot de 3 paires de chaussettes tennis noires KTM homme au Maroc. Achetez au meilleur prix chez MOTO PACO.',137,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(190,' hevik gants moto auster nero hgs115mbs','hevik-auster-nero-hgs115mbs',unistr('<p>Les gants moto Hevik Auster Nero HGS115MBS sont conçus pour les motards recherchant un excellent équilibre entre protection, confort et style. Avec leur design élégant en coloris noir, ils s’adaptent parfaitement à une utilisation quotidienne, aussi bien en ville que sur route.<br />\u000aFabriqués à partir de matériaux résistants et confortables, ces gants offrent une bonne durabilité tout en garantissant une grande liberté de mouvement. Ils intègrent des protections au niveau des articulations pour améliorer la sécurité lors de la conduite, ainsi que des renforts stratégiques sur la paume afin d’assurer une meilleure adhérence sur les poignées.<br />\u000aLeur conception ergonomique permet un ajustement naturel de la main, tandis que la fermeture réglable au poignet assure un maintien sûr et personnalisé. Les gants Hevik Auster sont également pensés pour offrir un bon confort thermique, ce qui les rend adaptés à une utilisation régulière.</p>\u000a'),'',54,13,549.0,449.0,NULL,NULL,'published',' hevik gants moto auster nero hgs115mbs',' hevik gants moto auster nero hgs115mbs au Maroc. Achetez au meilleur prix chez MOTO PACO.',84,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(191,'Gants estivo HEVIK','gants-estivo-hevik',unistr('<p>Les gants estivaux HEVIK sont spécialement conçus pour offrir confort, protection et respirabilité pendant la conduite par temps chaud. Fabriqués avec des matériaux légers et ventilés, ils permettent une excellente circulation de l’air afin de garder les mains fraîches et sèches même lors des trajets prolongés en été.<br />\u000aLeur conception ergonomique assure une grande liberté de mouvement et une prise en main optimale des commandes de la moto. La plupart des modèles intègrent des protections au niveau des articulations et des renforts sur la paume pour améliorer la sécurité tout en conservant un bon niveau de confort.<br />\u000aGrâce à leur fermeture réglable au poignet, les gants estivaux HEVIK offrent un ajustement précis et sécurisé. Leur design moderne et sportif s’adapte parfaitement aux motards recherchant à la fois style, performance et protection pour la saison estivale. </p>\u000a'),'',54,13,549.0,449.0,NULL,NULL,'published','Gants estivo HEVIK','Gants estivo HEVIK au Maroc. Achetez au meilleur prix chez MOTO PACO.',132,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(192,'Hevik Quasar Gloves color Black/Grey HGS113MG','hevik-quasar-gloves-black-grey-hgs113mg',unistr('<p>Les Hevik Quasar HGS113MG sont des gants de moto d’été au style sportif et urbain, conçus pour offrir un excellent équilibre entre confort, protection et liberté de mouvement. Leur design moderne noir et gris s’adapte parfaitement à une utilisation quotidienne en ville comme aux sorties sur route.<br />\u000aGrâce à leur construction légère et à leurs inserts élastiques, ces gants assurent une grande flexibilité et un confort optimal pendant la conduite. Ils intègrent des protections rigides au niveau des articulations et des phalanges pour améliorer la sécurité sans compromettre la mobilité. La fermeture réglable par scratch au poignet permet un ajustement précis et facilite l’enfilage.<br />\u000aCaractéristiques principales :<br />\u000aGants de moto d’été légers et respirants<br />\u000aCouleur : Noir / Gris<br />\u000aProtections rigides sur les articulations et les doigts<br />\u000aInserts élastiques pour plus de confort et de mobilité<br />\u000aFermeture au poignet avec bande velcro réglable<br />\u000aCompatible écran tactile sur l’index<br />\u000aInserts réfléchissants pour une meilleure visibilité<br />\u000aCertifiés selon la norme européenne EN 13594:2015 – niveau 1</p>\u000a'),'',31,13,549.0,449.0,NULL,NULL,'published','Hevik Quasar Gloves color Black/Grey HGS113MG','Hevik Quasar Gloves color Black/Grey HGS113MG au Maroc. Achetez au meilleur prix chez MOTO PACO.',119,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(193,'GANTS KENNY TRACK NOIR','kenny-track-noir-gants',unistr('<p>Les gants Kenny Track Noir sont réalisés en textile respirant et durable, garantissant une bonne ventilation et un confort optimal même lors des longues sessions de pilotage. La paume renforcée assure une excellente adhérence sur le guidon et les commandes, tout en protégeant contre l’usure et l’abrasion.<br />\u000aLa coupe ergonomique avec doigts préformés permet un contrôle précis et une meilleure sensibilité pour les mouvements rapides. La fermeture réglable au poignet offre un ajustement sûr et facile, maintenant le gant en place pendant toute la durée de la conduite.<br />\u000aLeur design noir sobre et sportif s’adapte parfaitement à tous les équipements motocross et enduro, offrant un look élégant et professionnel.<br />\u000aCaractéristiques principales<br />\u000aTextile léger et respirant pour plus de confort<br />\u000aPaume renforcée pour une meilleure adhérence et durabilité<br />\u000aDoigts préformés pour un contrôle précis<br />\u000aFermeture ajustable au poignet<br />\u000aDesign sobre et sportif noir</p>\u000a'),'',54,890,239.0,239.0,NULL,NULL,'published','GANTS KENNY TRACK NOIR','GANTS KENNY TRACK NOIR au Maroc. Achetez au meilleur prix chez MOTO PACO.',89,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(194,'GANTS KENNY TRACK ADULTE ','kenny-track-gants-adulte',unistr('<p>Les gants Kenny Track pour adultes sont fabriqués avec des matériaux textiles respirants et résistants, permettant une bonne ventilation et un confort optimal même lors de longues sessions de conduite. Leur paume renforcée assure une adhérence maximale sur le guidon et les commandes, tout en offrant une bonne protection contre l’abrasion.<br />\u000aLa coupe ergonomique avec doigts préformés améliore le contrôle et la sensibilité, tandis que la fermeture ajustable au poignet garantit un maintien sûr et un ajustement rapide. Leur design moderne et sportif s’adapte parfaitement à l’équipement motocross ou enduro des pilotes adultes.<br />\u000aCaractéristiques principales<br />\u000aConstruction en textile léger et respirant<br />\u000aPaume renforcée pour plus de durabilité et adhérence<br />\u000aDoigts préformés pour un meilleur contrôle<br />\u000aFermeture ajustable au poignet pour un maintien sûr<br />\u000aDesign sportif pour adultes</p>\u000a'),'',54,890,239.0,239.0,NULL,NULL,'published','GANTS KENNY TRACK ADULTE ','GANTS KENNY TRACK ADULTE  au Maroc. Achetez au meilleur prix chez MOTO PACO.',107,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(195,'GANTS KENNY TITANIUM NOIRS','gants-kenny-titanium-noirs',unistr('<p>Les gants Kenny Titanium Noirs sont fabriqués à partir de matériaux textiles légers et respirants, permettant une bonne ventilation pendant l’effort. Cette conception aide à garder les mains au sec et améliore le confort lors des sessions prolongées de motocross ou d’enduro.<br />\u000aLa paume renforcée assure une excellente adhérence sur le guidon et les commandes de la moto, tout en offrant une bonne résistance à l’abrasion. Leur coupe ergonomique avec doigts préformés garantit une grande précision de pilotage et une meilleure sensibilité des commandes.<br />\u000aLes gants disposent également d’une fermeture ajustable au poignet, permettant un maintien sûr et un ajustement rapide. Leur design noir sobre et sportif s’intègre facilement avec la plupart des équipements motocross et enduro.<br />\u000aCaractéristiques principales<br />\u000aConstruction en textile léger et respirant<br />\u000aPaume renforcée pour plus de durabilité<br />\u000aExcellente adhérence sur le guidon<br />\u000aDoigts préformés pour un meilleur contrôle<br />\u000aFermeture ajustable au poignet<br />\u000aDesign sobre et sportif noir</p>\u000a'),'',54,890,449.0,449.0,NULL,NULL,'published','GANTS KENNY TITANIUM NOIRS','GANTS KENNY TITANIUM NOIRS au Maroc. Achetez au meilleur prix chez MOTO PACO.',137,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(196,'Gants Longs Kenny Titanium Orange','kenny-titanium-orange-gants-longs',unistr('<p>Les gants longs Kenny Titanium Orange sont conçus pour les pilotes qui recherchent performance et résistance sur les terrains exigeants. Leur construction en textile léger et respirant permet une bonne circulation de l’air, gardant les mains au frais pendant l’effort.<br />\u000aLa paume est renforcée avec un matériau résistant à l’abrasion, offrant une excellente adhérence sur le guidon et les commandes, même dans des conditions difficiles. Les renforts stratégiquement placés assurent une meilleure protection contre les chocs et les frottements.<br />\u000aLeur coupe ergonomique avec doigts préformés améliore la précision et le contrôle de la moto. Les gants sont également équipés d’une fermeture ajustable au poignet, garantissant un maintien sûr et confortable pendant la conduite.<br />\u000aGrâce à leur design moderne et leur couleur orange vive, les Kenny Titanium apportent aussi un style racing parfaitement adapté aux équipements motocross.<br />\u000aCaractéristiques principales<br />\u000aConstruction en textile léger et respirant<br />\u000aPaume renforcée pour une meilleure résistance à l’abrasion<br />\u000aExcellente adhérence sur les commandes<br />\u000aDoigts préformés pour plus de précision<br />\u000aFermeture ajustable au poignet<br />\u000aDesign racing avec couleur orange dynamique</p>\u000a'),'',54,890,449.0,449.0,NULL,NULL,'published','Gants Longs Kenny Titanium Orange','Gants Longs Kenny Titanium Orange au Maroc. Achetez au meilleur prix chez MOTO PACO.',60,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(197,'DAINES X-RIDE 2 ERGO-TEK','dainese-x-ride-2-ergo-tek-gloves',unistr('<p>Les gants moto X-Ride 2 Ergo-Tek offrent une excellente liberté de mouvement grâce à leur construction associant cuir de chèvre souple et textile extensible. Cette combinaison garantit légèreté, respirabilité et confort thermique, même lors des journées chaudes ou des longs trajets.<br />\u000aPour la sécurité, ils intègrent la technologie Ergo-Tek sur les articulations, une protection flexible qui absorbe les chocs tout en conservant une grande mobilité des doigts. Les gants disposent également de renforts au niveau de la paume, d’inserts en résine thermoplastique sur le petit doigt et d’un système de protection latérale pour réduire les risques en cas de chute.<br />\u000aLa paume en cuir avec inserts en suède Amica et zones de grip renforcées améliore l’adhérence sur les commandes de la moto. Les gants sont aussi dotés de la technologie Smart Touch, permettant d’utiliser un smartphone ou un GPS sans retirer les gants.<br />\u000aCertifiés CE EN 13594 niveau 1, ils garantissent un niveau de protection conforme aux normes européennes pour l’équipement moto.<br />\u000aCaractéristiques principales<br />\u000aConstruction en cuir de chèvre et mesh extensible respirant<br />\u000aProtection des articulations Ergo-Tek<br />\u000aRenforts de paume et inserts de protection latérale<br />\u000aPaume en suède Amica pour une meilleure adhérence<br />\u000aCompatible écrans tactiles (Smart Touch)<br />\u000aDoigts pré-courbés pour plus d’ergonomie<br />\u000aFermeture ajustable au poignet<br />\u000aCertification CE EN 13594 niveau 1</p>\u000a'),'',31,13,999.0,999.0,NULL,NULL,'published','DAINES X-RIDE 2 ERGO-TEK','DAINES X-RIDE 2 ERGO-TEK au Maroc. Achetez au meilleur prix chez MOTO PACO.',115,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(198,'REV''IT! ACCESS GLOVES','rev-it-access-gloves',unistr('<p>Les gants moto REV''IT! Access sont pensés pour les pilotes qui veulent un équipement fiable sans compromis sur la sécurité. Leur construction en textile extensible avec revêtement en polyuréthane assure souplesse, durabilité et bonne liberté de mouvement pendant la conduite. La paume en microfibre renforcée améliore l’adhérence sur les commandes de la moto, garantissant un meilleur contrôle.<br />\u000aPour la protection, ces gants intègrent une coque rigide thermoplastique au niveau des articulations, complétée par des renforts en mousse EVA et mémoire de forme qui absorbent les chocs. Ils sont également certifiés CE EN 13594 niveau 1 KP, preuve de leur conformité aux normes de sécurité pour l’équipement moto.<br />\u000aGrâce à leur tissu entièrement ventilé, les Access offrent une excellente circulation de l’air, permettant de garder les mains au frais lors des trajets par temps chaud. Leur manchette courte avec fermeture velcro et languette d’enfilage facilite l’ajustement et le retrait rapide des gants.<br />\u000aEnfin, les bouts des doigts sont compatibles avec les écrans tactiles, ce qui permet d’utiliser un smartphone ou un GPS sans retirer les gants.<br />\u000aCaractéristiques principales<br />\u000aTissu extensible et ventilé pour plus de confort<br />\u000aCoque rigide de protection des articulations<br />\u000aRenforts en mousse EVA et mémoire de forme<br />\u000aPaume en microfibre avec zone de grip<br />\u000aCompatible écrans tactiles (index et pouce)<br />\u000aManchette courte avec fermeture velcro<br />\u000aCertification CE EN 13594 niveau 1 KP</p>\u000a'),'',54,811,799.0,699.0,NULL,NULL,'published','REV''IT! ACCESS GLOVES','REV''IT! ACCESS GLOVES au Maroc. Achetez au meilleur prix chez MOTO PACO.',60,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(199,'FIVE GLOVES GLOBE EVO MOTORCYCLE GLOVES','five-gloves-globe-evo-motorcycle-gloves',unistr('<p>Les Five Gloves Globe Evo Motorcycle Gloves sont des gants de moto conçus pour offrir confort, protection et polyvalence, particulièrement adaptés à une utilisation quotidienne en ville ou pour les trajets courts. Voici une description en français :<br />\u000aDescription :<br />\u000aLes gants de moto Globe Evo de la marque Five Gloves combinent légèreté, protection et ergonomie. Conçus principalement en textile extensible et respirant, ils assurent un bon confort de conduite même par temps chaud. Leur coupe ergonomique permet une excellente liberté de mouvement et un bon contrôle des commandes de la moto.<br />\u000aIls sont équipés d’une coque de protection discrète sur les articulations, offrant une protection efficace contre les impacts tout en conservant un design sobre et moderne. La paume renforcée améliore la résistance à l’abrasion et la durabilité du gant.<br />\u000aLes Globe Evo disposent également d’un système tactile sur l’index et le pouce, permettant d’utiliser un smartphone ou un GPS sans retirer les gants. Leur fermeture par scratch au poignet assure un ajustement rapide et sécurisé.<br />\u000aCaractéristiques principales :<br />\u000aTissu extensible et respirant pour plus de confort<br />\u000aCoque de protection sur les articulations<br />\u000aPaume renforcée pour une meilleure résistance<br />\u000aCompatible écrans tactiles<br />\u000aFermeture ajustable par scratch<br />\u000aIdéal pour la conduite urbaine et les trajets quotidiens</p>\u000a'),'',31,13,799.0,699.0,NULL,NULL,'published','FIVE GLOVES GLOBE EVO MOTORCYCLE GLOVES','FIVE GLOVES GLOBE EVO MOTORCYCLE GLOVES au Maroc. Achetez au meilleur prix chez MOTO PACO.',69,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(200,'GANTS FURYGAN JET D3O® EVO NOIR BLANC','gants-furygan-jet-d3o-evo-noir-blanc-2',unistr('<p> GANTS FURYGAN JET D3O® EVO NOIR / BLANC<br />\u000aLes Furygan Jet D3O® Evo sont des gants de moto légers et ventilés, conçus pour offrir un excellent équilibre entre confort, protection et liberté de mouvement. Idéals pour une utilisation en ville ou lors de trajets quotidiens, ils sont particulièrement adaptés aux saisons chaudes grâce à leur conception respirante.<br />\u000a Protection<br />\u000aCoque de protection D3O® sur les métacarpes : matériau souple qui se rigidifie lors d’un impact pour absorber les chocs.<br />\u000aPaume 100 % cuir de chèvre pour une meilleure résistance à l’abrasion et une excellente adhérence.<br />\u000aRenforts supplémentaires sur la paume pour plus de sécurité.<br />\u000aGants homologués CE EN 13594 pour l’équipement moto.<br />\u000a Confort et ergonomie<br />\u000aConception souple, légère et ventilée pour rouler confortablement par temps chaud.<br />\u000aStretch sur les doigts pour améliorer la mobilité et la précision.<br />\u000aSerrage précis au poignet avec fermeture velcro pour un maintien optimal.<br />\u000a Technologie pratique<br />\u000aFurygan Sensitive Science : permet d’utiliser un smartphone ou GPS tactile sans retirer les gants.<br />\u000a Caractéristiques principales<br />\u000aCouleur : Noir / Blanc<br />\u000aMatières : polyamide, cuir de chèvre et matériaux renforcés<br />\u000aType : gants moto courts été / mi-saison<br />\u000aTailles : du S au 3XL<br />\u000a Atouts : légèreté, ventilation, bonne protection D3O et compatibilité écran tactile.</p>\u000a'),'',54,13,799.0,699.0,NULL,NULL,'published','GANTS FURYGAN JET D3O® EVO NOIR BLANC','GANTS FURYGAN JET D3O® EVO NOIR BLANC au Maroc. Achetez au meilleur prix chez MOTO PACO.',112,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(201,'Furygan-TEKTO evo noir-blanck','furygan-tekto-evo-noir-blanc',unistr('<p>Le blouson TEKTO Evo Noir/Blanc de Furygan est un équipement moto au design sportif, conçu pour offrir une excellente protection et un grand confort au quotidien. Fabriqué à partir de matériaux résistants à l’abrasion, il assure une bonne durabilité tout en restant léger et agréable à porter.<br />\u000aIl est équipé de protections homologuées CE aux épaules et aux coudes, garantissant une sécurité optimale en cas de chute. Le blouson peut également recevoir une protection dorsale Furygan (en option) pour renforcer la protection du pilote.<br />\u000aGrâce à ses zones de ventilation et sa doublure intérieure confortable, le TEKTO Evo s’adapte aussi bien aux trajets urbains qu’aux sorties plus longues. Sa coupe ergonomique et ses ajustements aux poignets et à la taille permettent un maintien parfait et une grande liberté de mouvement.<br />\u000aAvec son look moderne noir et blanc, ce blouson allie style sportif, sécurité et praticité, ce qui en fait un choix idéal pour les motards recherchant un équipement fiable et élégant.<br />\u000a Points forts :<br />\u000aProtections CE aux épaules et aux coudes<br />\u000aEmplacement pour dorsale (optionnelle)<br />\u000aMatériaux résistants à l’abrasion<br />\u000aConfort et ventilation optimisés<br />\u000aDesign sportif noir/blanc</p>\u000a'),'',31,13,799.0,699.0,NULL,NULL,'published','Furygan-TEKTO evo noir-blanck','Furygan-TEKTO evo noir-blanck au Maroc. Achetez au meilleur prix chez MOTO PACO.',76,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(202,'GANTS FURYGAN JET D3O® EVO NOIR BLANC','gants-furygan-jet-d3o-evo-noir-blanc',unistr('<p> GANTS FURYGAN JET D3O® EVO NOIR BLANC<br />\u000aLes gants Furygan Jet D3O® Evo Noir / Blanc sont des gants moto légers et ventilés, parfaits pour une utilisation urbaine et estivale. Ils combinent confort, protection et souplesse, tout en affichant un design sportif et moderne.<br />\u000a Caractéristiques principales<br />\u000aProtection D3O® aux métacarpes : coque souple et ergonomique qui durcit à l’impact pour une protection efficace tout en restant confortable au quotidien.<br />\u000aConstruction en textile et mesh : favorise la circulation de l’air pour garder les mains au frais pendant les fortes chaleurs.<br />\u000aPaume renforcée : améliore la résistance à l’abrasion et la durabilité.<br />\u000aCoupe préformée : offre une excellente liberté de mouvement et un bon ressenti des commandes.<br />\u000aFermeture par velcro au poignet : ajustement rapide et maintien sécurisé.<br />\u000aCompatibilité écran tactile : permet d’utiliser smartphone ou GPS sans retirer les gants.<br />\u000a Utilisation<br />\u000aIdéals pour la moto en ville, les trajets quotidiens et les balades estivales, ces gants offrent un bon équilibre entre ventilation et sécurité.<br />\u000aColoris<br />\u000aNoir / Blanc – style sobre avec touche sportive contrastée.</p>\u000a'),'',54,13,0.0,NULL,NULL,NULL,'draft','GANTS FURYGAN JET D3O® EVO NOIR BLANC','GANTS FURYGAN JET D3O® EVO NOIR BLANC au Maroc. Achetez au meilleur prix chez MOTO PACO.',147,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(204,'ARMEGA HIPER Goggle RACR-Mirror Silver Lens','armega-hiper-goggle-racr-mirror-silver-lens',unistr('<p>Le masque ARMEGA HIPER RACR avec lentille miroir argentée (Mirror Silver Lens) est un équipement haut de gamme conçu pour les sports tout‑terrain comme le motocross, le VTT ou l’enduro. Il offre une vision claire et nette, une protection fiable contre les impacts et un confort optimal, même lors des sorties les plus exigeantes.<br />\u000a🔍 Points forts :<br />\u000aLentille Ultra HD Mirror Silver : lentille optiquement précise qui maximise la clarté et réduit les reflets du soleil.<br />\u000aTechnologie HiPER : améliore le contraste et les couleurs pour une perception accrue du terrain.<br />\u000aSystème de changement rapide de lentille : changement facile et rapide de la lentille selon les conditions.<br />\u000aVerre incassable de 2 mm : lentille robuste, résistante aux chocs et aux impacts.<br />\u000aMonture à double injection : cadre durable et solide, conçu pour durer dans le temps.<br />\u000aVentilation optimisée : entrées d’air renforcées pour une meilleure circulation et moins de buée.<br />\u000aMousse faciale triple couche perforée : absorbe la transpiration et améliore le confort autour du visage.<br />\u000aSangle ultra large avec grip silicone : maintien parfait du masque sur le casque, même en mouvement intense.<br />\u000aProtège‑nez amovible : protège efficacement contre les projections de boue et de débris.1</p>\u000a'),'',31,13,1690.0,1399.0,NULL,NULL,'published','ARMEGA HIPER Goggle RACR-Mirror Silver Lens','ARMEGA HIPER Goggle RACR-Mirror Silver Lens au Maroc. Achetez au meilleur prix chez MOTO PACO.',143,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(205,'ARMEGA Goggle Clark-Clear Lens','armega-goggle-clark-clear-lens',unistr('<p>Le masque ARMEGA Clark avec lentille transparente (Clear Lens) est un équipement de protection haut de gamme conçu pour les sports tout‑terrain comme le motocross, l’enduro ou le VTT . Il allie clarté visuelle exceptionnelle, confort et robustesse pour offrir une expérience optimale aux pilotes, même dans des conditions difficiles.<br />\u000a🔍 Caractéristiques principales<br />\u000aLentille ULTRA HD transparente : offre une clarté optique inégalée, idéale pour voir chaque détail du terrain sans distorsion.<br />\u000aSystème de changement rapide de lentille : permet de remplacer facilement l’objectif selon les conditions d’éclairage.<br />\u000aLentille résistante aux chocs : lentille de 2 mm en polycarbonate moulé par injection pour une protection accrue contre les impacts.<br />\u000aMonture solide à double injection : offre robustesse et durabilité pour résister aux contraintes des sorties intensives.<br />\u000aVentilation optimisée : prises d’air forcées augmentent la circulation d’air et réduisent la formation de buée derrière les lentilles.<br />\u000aMousse faciale perforée triple couche : absorbe la transpiration tout en améliorant le confort autour du visage.<br />\u000aJoint de compression ergonomique : maintient le masque bien en place, même lors de mouvements rapides.<br />\u000aSangle ultra‑large avec grip en silicone : bande de 48 mm pour un maintien sécurisé sur le casque sans glisser.<br />\u000aProtège‑nez amovible : augmente la protection contre la boue, les pierres et autres projections.<br />\u000aLe masque ARMEGA Goggle Clark – Clear Lens est idéal pour les pilotes qui veulent une vision claire sans coloration de lentille, une excellente protection et un confort durable lors de leurs sorties tout‑terrain.</p>\u000a'),'',31,13,1199.0,999.0,NULL,NULL,'published','ARMEGA Goggle Clark-Clear Lens','ARMEGA Goggle Clark-Clear Lens au Maroc. Achetez au meilleur prix chez MOTO PACO.',137,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(206,'ARMEGA Goggle Albar - Mirror Silver Flash Lens','armega-goggle-albar-mirror-silver-flash-lens',unistr('<p>🥽 Description du masque ARMEGA Goggle Albar – Mirror Silver Flash Lens<br />\u000aLe masque ARMEGA est une paire de lunettes de protection haut de gamme conçue pour le motocross, l’enduro, le VTT ou d’autres sports tout‑terrain. Il offre une vision claire, une excellente protection et un grand confort, même dans des conditions exigeantes.<br />\u000a🔍 Caractéristiques principales :<br />\u000aLentille Ultra HD : lentille de haute qualité offrant une clarté optique exceptionnelle pour une meilleure perception de la piste.<br />\u000aLentille Mirror Silver Flash : effet miroir argenté qui réduit les reflets du soleil et donne un look moderne et sportif.<br />\u000aSystème de changement rapide de lentille : permet de remplacer facilement la lentille en fonction des conditions d’éclairage.<br />\u000aCadre robuste à double injection : construction solide et durable pour une longue durée de vie.<br />\u000aÉcran incassable et résistant aux chocs : lentille moulée par injection de 2 mm conçue pour résister aux impacts.<br />\u000aVentilation optimisée : prises d’air intégrées pour augmenter la circulation d’air et réduire la buée.<br />\u000aMousse faciale triple couche : absorbe la transpiration et améliore le confort autour du visage.<br />\u000aSangle ultra‑large avec bande en silicone pour maintenir le masque bien en place sur le casque.<br />\u000aProtège‑nez amovible pour une protection supplémentaire contre les projections de boue ou de gravier.<br />\u000a Ce masque est unisexe et adapté aux pilotes adultes cherchant une combinaison de performance, clarté visuelle et confort lors de leurs sorties.</p>\u000a'),'',32,13,1390.0,1199.0,NULL,NULL,'published','ARMEGA Goggle Albar - Mirror Silver Flash Lens','ARMEGA Goggle Albar - Mirror Silver Flash Lens au Maroc. Achetez au meilleur prix chez MOTO PACO.',113,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(207,'SP PHONE CASE for iPhone 17 Pro Max','sp-connect-phone-case-iphone-17-pro-max',unistr('<p>SP Connect Phone Case pour iPhone 17 Pro Max – Protection et Fixation Sécurisée<br />\u000aLa SP Connect Phone Case pour iPhone 17 Pro Max combine protection maximale et fixation rapide et sécurisée sur tous les supports SP Connect. Conçue pour un usage quotidien comme pour les activités sportives, elle sécurise votre smartphone tout en conservant un design fin et élégant.<br />\u000aCompatibilité précise : spécialement conçue pour iPhone 17 Pro Max.<br />\u000aFixation rapide et fiable : verrouillage simple et sécurisé sur tous les supports SP Connect.<br />\u000aProtection renforcée : protège efficacement contre les chocs, rayures et petites chutes.<br />\u000aDesign fin et ergonomique : légère, agréable en main et accès complet aux boutons et ports.<br />\u000aIdéale pour le vélo, la moto, la voiture ou toute activité sportive, cette coque transforme votre iPhone 17 Pro Max en appareil prêt à l’usage partout, en toute sécurité.</p>\u000a'),'',60,13,699.0,599.0,NULL,NULL,'published','SP PHONE CASE for iPhone 17 Pro Max','SP PHONE CASE for iPhone 17 Pro Max au Maroc. Achetez au meilleur prix chez MOTO PACO.',110,'2026-06-20 14:09:07',0,0,0,0);
