INSERT INTO products VALUES(230,'SP Connect Universal Phone Case','sp-connect-universal-phone-case',unistr('<p>SP Connect Universal Phone Case – Protection et compatibilité universelle<br />\u000aLa SP Connect Universal Phone Case est l’accessoire indispensable pour sécuriser votre smartphone lors de toutes vos activités. Conçue pour s’adapter à la majorité des téléphones, cette coque universelle offre une protection robuste contre les chocs et rayures, tout en permettant une fixation facile sur les supports SP Connect.<br />\u000aCompatibilité universelle : s’adapte à presque tous les modèles de smartphones.<br />\u000aFixation rapide et sécurisée : verrouillage simple sur tous les supports SP Connect.<br />\u000aProtection renforcée : protège votre appareil des chocs, rayures et petites chutes.<br />\u000aDesign pratique et élégant : fine, légère, et facile à manipuler même en déplacement.<br />\u000aIdéale pour le vélo, la moto, la voiture ou les activités sportives, cette coque transforme votre téléphone en un appareil prêt à être utilisé partout, en toute sécurité.<br />\u000a Astuce SEO :<br />\u000aIntègre le mot-clé principal “SP Connect Universal Phone Case” dès la première phrase.<br />\u000aAjoute éventuellement des mots-clés secondaires comme “coque universelle smartphone SP Connect” ou “support téléphone SP Connect” dans la description et les balises alt des images.</p>\u000a'),'',60,13,0.0,NULL,NULL,NULL,'published','SP Connect Universal Phone Case','SP Connect Universal Phone Case au Maroc. Achetez au meilleur prix chez MOTO PACO.',89,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(232,'sp connect ball head mount','sp-connect-ballhead-mount-pro-spc',unistr('<p> SP Connect Ball Head Mount<br />\u000aLe SP Connect Ball Head Mount est un support articulé conçu pour offrir une orientation flexible et précise de votre smartphone. Grâce à sa rotule intégrée (ball head), il permet d’ajuster facilement l’angle de vue pour un confort optimal, que ce soit en mode portrait ou paysage.<br />\u000aCompatible avec le système breveté Twist-to-Lock de SP Connect, il assure une fixation rapide et sécurisée de votre téléphone sur les supports compatibles de la marque.<br />\u000a Caractéristiques principales<br />\u000aRotule ajustable à 360° : permet un réglage précis de l’inclinaison et de l’orientation.<br />\u000aSystème Twist-to-Lock : verrouillage simple par rotation à 90°.<br />\u000aFixation solide et stable : maintien fiable même en cas de vibrations.<br />\u000aMatériaux robustes : conception durable adaptée à un usage quotidien.<br />\u000aCompatible avec l’écosystème SP Connect : fonctionne avec les coques et accessoires de la gamme.<br />\u000a Idéal pour<br />\u000aVélo<br />\u000aMoto<br />\u000aVoiture<br />\u000aScooter<br />\u000aUtilisation professionnelle ou loisirs<br />\u000aLe SP Connect Ball Head Mount est la solution idéale pour ceux qui recherchent une flexibilité maximale d’orientation tout en conservant une fixation sûre et rapide.</p>\u000a'),'',60,13,0.0,NULL,NULL,NULL,'published','sp connect ball head mount','sp connect ball head mount au Maroc. Achetez au meilleur prix chez MOTO PACO.',142,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(233,'sp connect universal phone clamp','sp-connect-universal-phone-clamp',unistr('<p> SP Connect Universal Phone Clamp<br />\u000aLe SP Connect Universal Phone Clamp est un support universel ajustable conçu pour fixer solidement presque tous les smartphones aux supports de la gamme SP Connect (vélo, moto, voiture, etc.).<br />\u000aGrâce à son système de serrage réglable, il maintient fermement le téléphone, avec ou sans coque, sans nécessiter de housse spécifique.<br />\u000a Caractéristiques principales<br />\u000a Compatibilité universelle : s’adapte à la plupart des smartphones grâce à son système de serrage ajustable.<br />\u000a Installation sans outil : réglage rapide et simple.<br />\u000a Système breveté Twist-to-Lock : fixation sécurisée par rotation à 90° sur les supports SP Connect compatibles.<br />\u000a Maintien robuste : conçu pour résister aux vibrations et aux mouvements, idéal pour le vélo ou la moto.<br />\u000a Compatible avec l’écosystème SP Connect : fonctionne avec l’ensemble des supports et accessoires de la marque.<br />\u000a Idéal pour<br />\u000aCyclisme<br />\u000aMoto<br />\u000aTrottinette<br />\u000aVoiture<br />\u000aActivités outdoor<br />\u000aLe SP Connect Universal Phone Clamp est la solution parfaite pour ceux qui souhaitent utiliser leur smartphone avec les supports SP Connect sans changer de coque ni coller d’adaptateur.<br />\u000aSi tu veux, je peux aussi te faire une version courte pour fiche produit e-commerce ou une description optimisée SEO.</p>\u000a'),'',60,13,0.0,NULL,NULL,NULL,'published','sp connect universal phone clamp','sp connect universal phone clamp au Maroc. Achetez au meilleur prix chez MOTO PACO.',148,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(234,'SP Connect Hardwire Cable for Wireless Charging Module - 12V','sp-connect-hardwire-cable-12v',unistr('<p>Le SP Connect Hardwire Cable est conçu pour alimenter directement votre Wireless Charging Module en 12V, offrant une solution fiable et sécurisée pour charger votre smartphone pendant vos trajets en moto ou en voiture. Avec ce câble, fini les batteries faibles : votre téléphone reste toujours prêt à l’usage.<br />\u000aFacile à installer et compatible avec tous les modules de charge sans fil SP Connect, ce câble robuste assure un courant stable et continu, protégeant à la fois votre smartphone et le module de charge. Parfait pour les motards et automobilistes qui souhaitent profiter d’un chargement rapide, pratique et sécurisé, même en déplacement.<br />\u000a Points forts<br />\u000a Alimentation directe 12V pour module de charge sans fil SP Connect<br />\u000a Installation simple et rapide<br />\u000a Câble robuste pour une charge stable et sécurisée<br />\u000a Compatible avec tous les modules Wireless Charging SP Connect<br />\u000a Idéal pour moto, scooter ou voiture</p>\u000a'),'',2,13,0.0,NULL,NULL,NULL,'draft','SP Connect Hardwire Cable for Wireless Charging Module - 12V','SP Connect Hardwire Cable for Wireless Charging Module - 12V au Maroc. Achetez au meilleur prix chez MOTO PACO.',97,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(235,'SP CONNECT Adhesive Mount Pro Automotive Mount','sp-connect-adhesive-mount-pro',unistr('<p>Le SP Connect Adhesive Mount Pro est un support automobile conçu pour fixer votre smartphone en toute sécurité sur le tableau de bord ou toute surface plane de votre véhicule. Grâce à son adhésif haute résistance, il offre une stabilité maximale, même sur routes accidentées, et permet un accès facile à votre GPS, appels mains libres et applications pendant vos trajets.<br />\u000aCompatible avec toutes les coques SP Connect, ce support est discret, élégant et robuste, garantissant une installation rapide sans outils supplémentaires. Idéal pour les conducteurs qui souhaitent rester connectés en toute sécurité et garder leur smartphone à portée de main sans compromettre la visibilité ou la sécurité au volant.<br />\u000a Points forts<br />\u000a Fixation adhésive sur tableau de bord ou surface plane<br />\u000a Installation facile, sans outils<br />\u000a Compatible avec toutes les coques SP Connect<br />\u000a Maintien stable même sur routes accidentées<br />\u000a Design discret et élégant pour tous types de véhicules</p>\u000a'),'',60,13,399.0,399.0,NULL,NULL,'published','SP CONNECT Adhesive Mount Pro Automotive Mount','SP CONNECT Adhesive Mount Pro Automotive Mount au Maroc. Achetez au meilleur prix chez MOTO PACO.',132,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(236,'sp connect clutch mount pro','sp-connect-clutch-mount-pro',unistr('<p>Le SP Connect Clutch Mount Pro est un support conçu pour fixer votre smartphone directement sur le levier d’embrayage de votre moto. Ce support robuste et fiable assure une stabilité maximale même sur routes cahoteuses, vous permettant d’utiliser votre GPS, répondre à vos appels ou accéder à vos applications en toute sécurité.<br />\u000aCompatible avec toutes les coques SP Connect, ce support se monte facilement et offre une solution pratique et sécurisée pour les motards qui veulent rester connectés sans compromettre la sécurité. Son design discret et élégant s’intègre parfaitement à votre moto tout en garantissant un maintien solide pour votre smartphone.<br />\u000a Points forts<br />\u000a Fixation sur levier d’embrayage moto<br />\u000a Installation simple et rapide<br />\u000a Compatible avec toutes les coques SP Connect<br />\u000a Maintien stable sur routes accidentées<br />\u000a Design discret et élégant</p>\u000a'),'',60,13,499.0,499.0,NULL,NULL,'published','sp connect clutch mount pro','sp connect clutch mount pro au Maroc. Achetez au meilleur prix chez MOTO PACO.',78,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(237,'SP CONNECT CLUTCH MOUNT PRO CHROME','sp-connect-clutch-mount-pro-chrome',unistr('<p>Le SP Connect Clutch Mount Pro Chrome est un support robuste et élégant qui permet de fixer votre smartphone directement sur le levier d’embrayage de votre moto. Conçu pour les motards exigeants, ce support offre une maintien solide et sécurisé, permettant une navigation fluide avec GPS, des appels mains libres ou un accès rapide à vos applications préférées en toute sécurité.<br />\u000aFabriqué en matériaux durables avec une finition chrome haut de gamme, le SP Connect Clutch Mount Pro associe performance et style. Facile à installer et compatible avec une large gamme de coques SP Connect, il est l’accessoire idéal pour les passionnés de moto qui veulent rester connectés sans compromettre leur sécurité.<br />\u000a Points forts<br />\u000a Support pour levier d’embrayage moto<br />\u000a Installation simple et rapide<br />\u000a Compatible avec les coques SP Connect<br />\u000a Finition chrome élégante et résistante<br />\u000a Stable même sur routes cahoteuses</p>\u000a'),'',60,13,499.0,499.0,NULL,NULL,'published','SP CONNECT CLUTCH MOUNT PRO CHROME','SP CONNECT CLUTCH MOUNT PRO CHROME au Maroc. Achetez au meilleur prix chez MOTO PACO.',108,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(238,'Quad Lock Brake Clutch Motorcycle Mount - Compatible MAG and Original Cases for Motorcycle Phone Mount Holder','quad-lock-brake-clutch-motorcycle-mount',unistr('<p>Transformez votre moto en un espace connecté avec le Quad Lock Brake Clutch Motorcycle Mount, compatible avec tous les iPhone et Android équipés des coques Quad Lock MAG ou Original. Ce support innovant se fixe directement sur le levier de frein ou d’embrayage pour un accès facile et sécurisé à votre téléphone, même à grande vitesse.<br />\u000aFabriqué en matériaux robustes et légers, il garantit une stabilité maximale tout en résistant aux vibrations et aux conditions météo difficiles. Parfait pour les motards, ce support permet de naviguer, suivre vos itinéraires ou utiliser votre GPS en toute sécurité sans jamais quitter la route des yeux.<br />\u000a Points forts<br />\u000a Compatible coques Quad Lock MAG et Original<br />\u000a Installation rapide sur levier de frein ou d’embrayage<br />\u000a Matériaux robustes et légers, résistant aux vibrations<br />\u000a Accès pratique au téléphone pour GPS, navigation ou appels<br />\u000a Conçu pour toutes les conditions météo</p>\u000a'),'',60,13,1299.0,1199.0,NULL,NULL,'published','Quad Lock Brake Clutch Motorcycle Mount - Compatible MAG and Original Cases for Motorcycle Phone Mount Holder','Quad Lock Brake Clutch Motorcycle Mount - Compatible MAG and Original Cases for Motorcycle Phone Mount Holder au Maroc. Achetez au meilleur prix chez MOTO PACO.',137,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(239,'quad lock mag iphone 17 pro-max','quad-lock-mag-case-iphone-17-pro-max',unistr('<p>Protégez et optimisez votre iPhone 17 Pro Max avec la Quad Lock MAG Case, une coque ultra-robuste qui combine protection antichoc avancée et aimantation MagSafe puissante. Conçue pour les utilisateurs actifs, cette coque offre une sécurité maximale sans sacrifier le design ou la fonctionnalité.<br />\u000aFabriquée avec des matériaux de haute qualité, la Quad Lock MAG Case est fine, légère et facile à clipser, tout en garantissant une protection renforcée contre les chutes, rayures et impacts quotidiens. Grâce à la technologie magnéto-compatible, elle s’intègre parfaitement à l’écosystème MagSafe pour un chargement sans fil rapide et sécurisé.<br />\u000aQue vous soyez en déplacement, en sport ou au travail, la Quad Lock MAG Case vous assure la tranquillité d’esprit — votre iPhone 17 Pro Max reste protégé et toujours prêt à l’usage.<br />\u000a Points forts<br />\u000a Protection supérieure antichoc<br />\u000a Compatible MagSafe & accessoires Quad Lock<br />\u000a Supporte le chargement sans fil<br />\u000a Design fin et robuste<br />\u000a Idéale pour un usage quotidien et les activités en mouvement</p>\u000a'),'',60,13,800.0,749.0,NULL,NULL,'published','quad lock mag iphone 17 pro-max','quad lock mag iphone 17 pro-max au Maroc. Achetez au meilleur prix chez MOTO PACO.',86,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(240,'Quad Lock MAG Case - iPhone - 17 Pro','quad-lock-mag-case-iphone-17-pro',unistr('<p>Quad Lock MAG Case - iPhone - 17 Pro<br />\u000aPerformance you can trust<br />\u000aQuad Lock cases feature the secure locking mechanism that is compatible with all original swivel and lock mounts, as well as an impact-resistant cover and protective lining.<br />\u000aFeatures<br />\u000aSecure Quad Lock interface<br />\u000aSupplied with MAG ring fitted in black<br />\u000aComposite construction (TPU/PC)<br />\u000aNickel-plated 52-H neodymium magnets<br />\u000aSoft, protective lining<br />\u000aShock absorbing shell<br />\u000aEnables wireless charging<br />\u000aCompatible with original Quad Lock Twist-Lock mounts and heads<br />\u000aCompatible with Quad Lock MAG heads<br />\u000aFurther Information<br />\u000aWith a tough polycarbonate core and a shock-absorbing TPU outer shell, you can be sure your phone is protected every day. With its slim profile and soft material, it''s perfect for everyday use. Quad Lock MAG cases are thinner and flatter and feature a customizable MAG ring.<br />\u000aQuad Lock MAG cases are compatible with all Quad Lock MAG and Quad Lock original mounts. With Quad Lock MAG you can mount your phone even faster. Simply position your phone and the magnets will do the rest.<br />\u000aScope of delivery: 1 x Quad Lock MAG™ case with mounted MAG ring in black</p>\u000a'),'',60,13,800.0,749.0,NULL,NULL,'published','Quad Lock MAG Case - iPhone - 17 Pro','Quad Lock MAG Case - iPhone - 17 Pro au Maroc. Achetez au meilleur prix chez MOTO PACO.',76,'2026-06-20 14:09:07',0,0,0,0);
