INSERT INTO products VALUES(245,'GIVI PLO2171CAM YAMAHA > TRACER 9 / TRACER 9 GT / TRACER 9 GT+ (25)','givi-plo2171cam-support-valises-aluminium-yamaha-tracer-9-gt-gt-plus',unistr('<p>Support latéral pour valise, spécifique PL ONE-FIT, configuré pour les valises MONOKEY® CAM-SIDE Trekker Outback, ou sacoches latérales MONOKEY® CAM-SIDE Canyon<br />\u000a18 mm diamètre / à combiner avec 07RKIT pour conversion en supports latéraux pour valise à démontage rapide</p>\u000a'),'',51,756,2899.0,2899.0,NULL,NULL,'published','GIVI PLO2171CAM YAMAHA > TRACER 9 / TRACER 9 GT / TRACER 9 GT+ (25)','GIVI PLO2171CAM YAMAHA > TRACER 9 / TRACER 9 GT / TRACER 9 GT+ (25) au Maroc. Achetez au meilleur prix chez MOTO PACO.',116,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(247,'Givi Support Valises Monokey PLO3118MK Suzuki V-Strom 1050 DE (20-25)','givi-plo3118mk-support-valises-monokey-suzuki-v-strom-1050-de',unistr('<p>Porte-bagages Givi PLO3118MK. Porte-bagages latéral PL ONE-FIT spécifique configuré pour les sacoches MONOKEY®. A Combinez avec le 06RKIT pour le transformer en porte-bagages latéral à fixation rapide. Il n''est pas compatible avec le boîtier TRK35 Trekker ni avec le GRT709 ou le GRT720.</p>\u000a<p>Diamètre : 18mm</p>\u000a'),'',51,756,3199.0,2599.0,NULL,NULL,'published','Givi Support Valises Monokey PLO3118MK Suzuki V-Strom 1050 DE (20-25)','Givi Support Valises Monokey PLO3118MK Suzuki V-Strom 1050 DE (20-25) au Maroc. Achetez au meilleur prix chez MOTO PACO.',70,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(248,'PARE-CARTERS GIVI (TN5129) BMW F750GS/F850GS','pare-carters-givi-tn5129-bmw-f750gs-f850gs',unistr('<p>POURQUOI CHOISIR CE PRODUIT ?<br />\u000aProtection latérale<br />\u000aTrès pratique<br />\u000aRéduit les dommages au minimum</p>\u000a<p>Notice de montage ici<br />\u000aNé avec l''objectif d''ajouter une protection latérale aux motos tout-terrain, les pare-carters en métal sont devenus des accessoires aujourd''hui très utiles aux possesseurs de motos naked, customs et semi-carénées. En cas de chute du véhicule, par exemple de la béquille, la présence des pare-carters moto réduit les dommages au minimum.<br />\u000aChaque pare-carter Givi a été conçu pour s''adapter parfaitement à chaque modèle de moto.<br />\u000aNB : il est recommandé de faire le montage par un mécanicien qualifié</p>\u000a<p>- Pare-carters tubulaires spécifiques, finition noire<br />\u000a- Tube acier de 25 mm de diamètre</p>\u000a'),'',21,756,2999.0,2599.0,NULL,NULL,'published','PARE-CARTERS GIVI (TN5129) BMW F750GS/F850GS','PARE-CARTERS GIVI (TN5129) BMW F750GS/F850GS au Maroc. Achetez au meilleur prix chez MOTO PACO.',64,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(249,'GIVI PLO_CAM - Support valises latérales PLO7713CAM  KTM 1290 Super Adventure','givi-plo7713cam-support-valises-laterales-ktm-1290-super-adventure',unistr('<p>Kits de fixation valise Givi Support Valises Trekker Outback PLO7713CAM KTM 1290 Super Adventure (21)<br />\u000aLe support PLO7713CAM de Givi est un support spécifique pour monter les valises latérales Givi Monokey Trekker Outback sur les deux-roues suivants :</p>\u000a<p>KTM : 1290 Super Adventure R (2021 > 2024)<br />\u000aKTM : 1290 Super Adventure S (2021 > 2024)<br />\u000aATTENTION : A combiner avec le 09RKIT pour conversion en supports latéraux pour valise à demontage rapide</p>\u000a'),'',51,756,3399.0,2999.0,NULL,NULL,'published','GIVI PLO_CAM - Support valises latérales PLO7713CAM  KTM 1290 Super Adventure','GIVI PLO_CAM - Support valises latérales PLO7713CAM  KTM 1290 Super Adventure au Maroc. Achetez au meilleur prix chez MOTO PACO.',135,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(250,'Support top case GIVI moto aluminium Yamaha Tracer 9 / Tracer 9 GT / Tracer 9 GT+','support-top-case-givi-aluminium-yamaha-tracer-9-gt-gt-plus',unistr('<p>Le support top case moto en aluminium de la marque Givi est un accessoire indispensable pour les propriétaires de Yamaha Tracer 9, Tracer 9 GT et Tracer 9 GT+. Conçu pour allier robustesse et légèreté, ce support en aluminium offre une solution pratique pour transporter vos affaires lors de vos déplacements à moto.</p>\u000a<p>Avec une conception soignée, le support assure une fixation stable et sécurisée de votre top case, permettant une utilisation sans souci même sur de longues distances. Sa fabrication en aluminium garantit une résistance aux intempéries et aux chocs, ce qui le rend idéal pour les amoureux de la moto qui apprécient l''aventure en toute sérénité.</p>\u000a<p>Voici quelques caractéristiques remarquables de ce support :</p>\u000a<p>Matériau de qualité : fabriqué en aluminium durable pour une meilleure longévité.<br />\u000aDesign ergonomique : conçu pour s’adapter parfaitement à votre Yamaha Tracer 9, Tracer 9 GT ou Tracer 9 GT+<br />\u000aInstallation facile : un système de montage qui ne nécessite pas de modifications complexes de votre moto.<br />\u000aCompatibilité : spécialement conçu pour s''harmoniser avec les lignes et l''esthétique de la Yamaha Tracer 9.<br />\u000aQue vous planifiez une escapade le week-end ou que vous ayez besoin d''un espace supplémentaire pour vos trajets quotidiens, ce support top case s''avère être un allié précieux. En optant pour le support Givi, vous assurez non seulement la praticité de vos voyages, mais aussi l’élégance de votre moto.</p>\u000a<p>En somme, ce support top case en aluminium Givi est un choix judicieux pour tous ceux qui souhaitent maximiser l''usage de leur Yamaha Tracer 9, tout en combinant fonctionnalité et esthétisme. Ne laissez pas le manque de place freiner vos aventures et optez pour un support qui saura répondre à toutes vos attentes.<br />\u000aInformations complémentaires<br />\u000a-<br />\u000aMarque\u0009Givi<br />\u000aRéférence fournisseur\u0009SRA2171<br />\u000aCouleur\u0009noir<br />\u000aCouleur dominante\u0009Noir<br />\u000aConstructeur\u0009Yamaha</p>\u000a'),'',51,756,1899.0,1699.0,NULL,NULL,'published','Support top case GIVI moto aluminium Yamaha Tracer 9 / Tracer 9 GT / Tracer 9 GT+','Support top case GIVI moto aluminium Yamaha Tracer 9 / Tracer 9 GT / Tracer 9 GT+ au Maroc. Achetez au meilleur prix chez MOTO PACO.',119,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(251,'Givi SRA7713 KTM Super Adventure 1290 21- Aluminum Rear Rack specific for Monokey Top Case','givi-sra7713-porte-bagages-aluminium-monokey-ktm-1290-super-adventure',unistr('<p>Support de top case Givi Support Monokey SRA7713 KTM 1290 Super Adventure (21-24)<br />\u000aLe support Monokey SRA7713 de Givi est un support spécifique pour monter les top cases Givi uniquement compatible avec les :  </p>\u000a<p>KTM :<br />\u000a1290 Super Adventure R (2021 > 2024)<br />\u000a1290 Super Adventure S (2021 > 2024)</p>\u000a<p>ATTENTION :<br />\u000aSupport conçu avec une platine intégrée, uniquement compatible avec les top cases Givi Monokey</p>\u000a'),'',51,756,2199.0,1899.0,NULL,NULL,'published','Givi SRA7713 KTM Super Adventure 1290 21- Aluminum Rear Rack specific for Monokey Top Case','Givi SRA7713 KTM Super Adventure 1290 21- Aluminum Rear Rack specific for Monokey Top Case au Maroc. Achetez au meilleur prix chez MOTO PACO.',97,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(252,'GIVI - Sacoche latérale X-Line XL09 Monokey® Noir','givi-xl09-x-line-sacoche-laterale-monokey-noir',unistr('<p>SAC LATÉRAL DE 33 LITRES AVEC SYSTÈME D’ACCROCHAGE MONOKEY®, AVEC SAC INTÉRIEUR IMPERMÉABLE. POUVANT ÊTRE UTILISÉ COMME TOP BAG. ELLES SONT COMPATIBLES AVEC LES SUPPORTS DE VALISES LATÉRALES TUBULAIRES PL_ _ / PLO_ _ MK<br />\u000aicona caratteristica giviicona caratteristica giviicona caratteristica givi  iconiconiconiconiconicon<br />\u000aSac latéral de 33 litres avec système d’accrochage MONOKEY®, avec sac intérieur imperméable. Pouvant être utilisé comme top bag<br />\u000aLe sac latéral XL09 X-Line, disposant d’une capacité de 33 litres et avec système d’accrochage MONOKEY®, est la solution parfaite pour les voyages en moto. Il est vendu à l’unité et peut servir également de top bag arrière.<br />\u000aLa caractéristique distinctive de ce nouveau sac de la gamme X-Line est le sac intérieur pratique de 25 litres, amovible et complètement imperméable, et la présence d’un compartiment intérieur séparé. Cette trousse pratique permet de sortir facilement ce qu’il faut du sac latéral sans avoir à le démonter.<br />\u000aLe design raffiné met l’accent sur la fonctionnalité et la convivialité, tandis que les matériaux de haute qualité garantissent des performances optimales notamment lors des longs trajets, ainsi qu’une résistance aux UV jusqu’à 1500 heures.<br />\u000aLe sac XL09 est également muni de doubles sangles sur le dessus qui s''avèrent utiles pour transporter des blousons en softshell ou des imperméables. Comme tous les sacs pour moto de la ligne X-Line, le XL09 latéral regorge de caractéristiques techniques qui le rendent extrêmement pratique à utiliser :</p>\u000a<p>• Sac intérieur imperméable et amovible, résistant à de fortes pluies et à des conditions extrêmes, de 25 litres<br />\u000a• Sangle élastique de retenue du sac intérieur<br />\u000a• Compartiment intérieur indépendant du sac imperméable, de 8 litres<br />\u000a• Poche intérieure porte-documents<br />\u000a• Poche frontale extérieure<br />\u000a• Quatre trous pour l’évacuation de l’eau et de l’humidité positionnés sur le fond du sac<br />\u000a• Poignée rembourrée ergonomique pour le transport à la main<br />\u000a• Sangle d’épaule réglable pour le transport<br />\u000a• Ouverture principale avec curseurs compatibles avec l’ajout d’un cadenas de sécurité (non inclus)<br />\u000a• Insert réfléchissant sur le contour pour une visibilité accrue</p>\u000a'),'',51,756,2799.0,2199.0,NULL,NULL,'published','GIVI - Sacoche latérale X-Line XL09 Monokey® Noir','GIVI - Sacoche latérale X-Line XL09 Monokey® Noir au Maroc. Achetez au meilleur prix chez MOTO PACO.',63,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(253,'GIVI Tanklock BF79 Fuel Tank Bag Flange, for VOGE VALICO 525DSX, Valico 900DSX','givi-bf79-bride-reservoir-tanklock-voge-valico-525-dsx',unistr('<p>Bride métallique spécifique pour la fixation des sacoches de réservoir TANKLOCK, TanklockED</p>\u000a'),'',51,756,220.0,220.0,NULL,NULL,'published','GIVI Tanklock BF79 Fuel Tank Bag Flange, for VOGE VALICO 525DSX, Valico 900DSX','GIVI Tanklock BF79 Fuel Tank Bag Flange, for VOGE VALICO 525DSX, Valico 900DSX au Maroc. Achetez au meilleur prix chez MOTO PACO.',65,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(254,'GIVI GRT709B CANYON PAIRE DE SACOCHES CAVALIÈRES IMPERMÉABLES AVEC SYSTÈME D’ACCROCHAGE UNIFIT, 35+35 L','givi-grt709b-canyon-sacoches-cavalieres-impermeables-70l',unistr('<p>icona caratteristica giviicona caratteristica giviicona caratteristica givi  iconiconiconiconiconiconicon<br />\u000aPaire de sacoches cavalières imperméables avec système d’accrochage Unifit, 35+35 l<br />\u000aLes sacoches latérales GRT709B Unifit offrent une capacité de chargement de 35 litres par côté et sont conçues pour les amateurs de parcours tout-terrain qui ne veulent pas renoncer à la commodité et à la sécurité de leurs bagages. Elles sont équipées du système d’accrochage UNIFIT, qui permet de les fixer aux porte-bagages latéraux tubulaires PL et PL_CAM de GIVI, ainsi qu’à la plupart des cadres latéraux du marché.<br />\u000aLe corps principal de la sacoche est composé de matériaux extrêmement résistants aux chocs et à l’abrasion, tels que le Cordura et l’Hypalon, et est également renforcé intérieurement par des inserts amovibles en plastique, pour en rigidifier le fond et les côtés. Le sac intérieur pratique, imperméable et amovible, soudé à haute fréquence, garantit la résistance aux fortes pluies et aux conditions extrêmes, et le système de fermeture « roll top » est renforcé par l’utilisation de boucles avec système de sécurité extralock intégré. La sacoche possède un rabat avant amovible en Hypalon, utile pour la protéger en cas de chocs. Elle comporte également 6 points de compression de la charge et une poche intérieure solide.<br />\u000aLes passants latéraux du système M.O.L.L.E. dont elles sont munies, positionnés sur les côtés des sacs, permettent d’attacher des charges supplémentaires, les rendant modulables avec d’autres modèles de la gamme Canyon comme la petite sacoche GRT730, afin d’y ranger outils, trousses de premiers secours, ou bien deux gourdes.</p>\u000a<p>Matériaux :<br />\u000a• Nylon Cordura<br />\u000a• Hypalon<br />\u000a• 1680D/ Revêtement PU haute résistance<br />\u000a• Ripstop Nylon TPU<br />\u000a• Matériaux extérieurs à haute résistance aux rayons UV</p>\u000a<p>En standard :<br />\u000a• Sac intérieur amovible imperméable couleur sable, soudé à haute fréquence pour résister à de fortes pluies et à des conditions extrêmes<br />\u000a• Système modulable d’expansion du chargement : équipées des fentes du système M.O.L.L.E. sur les côtés, qui permettent d’y fixer d’autres modèles de la gamme Canyon comme la sacoche GRT730 ou de petits accessoires<br />\u000a• Rabat avant amovible, équipé à l’arrière d’une solide poche filet<br />\u000a• Renforts intérieurs amovibles en plastique, pour rigidifier le fond et le côté des sacoches<br />\u000a• Boucles de fermeture sur le haut avec système extralock intégré, pour plus de sécurité<br />\u000a• Anneaux prévus pour accrocher un verrou de sécurité<br />\u000a• 8 points de compression du chargement<br />\u000a• Poignée ergonomique pour le transport à main<br />\u000a• Clé Security Lock avec cache pare-poussière<br />\u000a• Impressions à motifs réfléchissants pour plus de visibilité</p>\u000a<p>NB : Étant donné que les sacoches sont souples, il revient au client de vérifier qu’après les avoir accrochées au porte-bagages et remplies, elles n’interfèrent pas avec le pot d’échappement de la moto et ne soient pas investies des gaz qui s’en échappent.</p>\u000a'),'',51,756,7999.0,5999.0,NULL,NULL,'published','GIVI GRT709B CANYON PAIRE DE SACOCHES CAVALIÈRES IMPERMÉABLES AVEC SYSTÈME D’ACCROCHAGE UNIFIT, 35+35 L','GIVI GRT709B CANYON PAIRE DE SACOCHES CAVALIÈRES IMPERMÉABLES AVEC SYSTÈME D’ACCROCHAGE UNIFIT, 35+35 L au Maroc. Achetez au meilleur prix chez MOTO PACO.',142,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(255,'PARE-BRISE GIVI DF5146 BMW GSA 1300','givi-df5146-pare-brise-moto',unistr('<p>Paire de déflecteurs latéraux protège-mains plus grands que l’origine, fumés<br />\u000ase monte à la place de déflecteurs d’origine</p>\u000a'),'',2,756,1399.0,1299.0,NULL,NULL,'published','PARE-BRISE GIVI DF5146 BMW GSA 1300','PARE-BRISE GIVI DF5146 BMW GSA 1300 au Maroc. Achetez au meilleur prix chez MOTO PACO.',148,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(256,'GIVI TANKLOCK BF84','givi-bf84-bride-reservoir-tanklock',unistr('<p>Bride métallique spécifique pour la fixation des sacoches de réservoir TANKLOCK, TanklockED<br />\u000aen présence de la sacoche TANKLOCK, le guidon doit être incliné de 10°</p>\u000a'),'',51,756,220.0,220.0,NULL,NULL,'published','GIVI TANKLOCK BF84','GIVI TANKLOCK BF84 au Maroc. Achetez au meilleur prix chez MOTO PACO.',62,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(257,'GIVI GRT730 PETITE SACOCHE DE PROTÈGE-CARTER IMPERMÉABLE, 4 L','givi-grt730-sacoche-protege-carter-impermeable-4l',unistr('<p>PETITE SACOCHE DE PROTÈGE-CARTER IMPERMÉABLE, 4 L</p>\u000a<p>La sacoche de protège-carter imperméable de 4 litres est conçue pour pouvoir vous accompagner même sur les terrains les plus accidentés ; vous pouvez la monter sur le protège-carter, voire sur la selle des motos enduro de petite cylindrée, grâce à deux sangles réglables munies de boucle à came et fermoir cartable, qui garantissent le maintien de la tension. Ses petites dimensions permettent d’accueillir largement deux gourdes ou une série d’outils qui pourraient se révéler utiles pour affronter toutes les embûches.<br />\u000aLa sacoche peut également être montée comme petite charge supplémentaire, combinée à d’autres modèles de la gamme Canyon, comme les sacoches cavalières ou le duffel, de sorte qu’il est possible de moduler la configuration du bagage et l’adapter à tous les besoins de chargement.<br />\u000aLa fermeture à enroulement et les matériaux résistants à l’abrasion dont elle est faite, soudés à haute fréquence, assurent l’imperméabilité même sous les pluies les plus intenses.</p>\u000a<p>Matériaux :<br />\u000a• TPU 840D haute solidité, double enduction – résiste à l’eau et aux déchirures<br />\u000a• Hypalon<br />\u000a• PVC antidérapant au dos, afin d’augmenter la stabilité<br />\u000a• Matériaux extérieurs à haute résistance aux rayons UV</p>\u000a<p>En standard :<br />\u000a• Système modulable d’expansion du chargement : équipée des fentes latérales du système M.O.L.L.E., qui permettent de fixer la sacoche à d’autres modèles de la gamme Canyon, tels que le GRT20B, le GRT709B, le GRT725 et le GRT721B.<br />\u000a• Fixation au protège-carter ...</p>\u000a'),'',51,756,849.0,749.0,NULL,NULL,'published','GIVI GRT730 PETITE SACOCHE DE PROTÈGE-CARTER IMPERMÉABLE, 4 L','GIVI GRT730 PETITE SACOCHE DE PROTÈGE-CARTER IMPERMÉABLE, 4 L au Maroc. Achetez au meilleur prix chez MOTO PACO.',147,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(258,'Pare-carters tubulaires spécifiques TN2171GIVI pour Yamaha Tracer 9 / GT / GT+ 2025 et +','pare-carters-givi-tn2171-yamaha-tracer-9-gt-gt-plus-2025',unistr('<h2>Pare-carters tubulaires GIVI TN2171 – Yamaha Tracer 9 / GT / GT+ (2025 et +)</h2>\u000a<p>Les <strong>pare-carters tubulaires GIVI TN2171</strong> sont conçus spécifiquement pour les<br />\u000a<strong>Yamaha Tracer 9, Tracer 9 GT et Tracer 9 GT+ à partir de 2025</strong>.<br />\u000aIls assurent une <strong>protection optimale du moteur et des carénages</strong> en cas de chute ou de glissade.</p>\u000a<p>Fabriqués en <strong>acier tubulaire haute résistance</strong>, ces crash bars offrent une excellente<br />\u000aabsorption des chocs tout en conservant l’esthétique et l’équilibre de la moto.</p>\u000a<h3>Caractéristiques</h3>\u000a<ul>\u000a<li>Modèle : <strong>GIVI TN2171</strong></li>\u000a<li>Pare-carters / crash bars tubulaires</li>\u000a<li>Protection moteur et bas de carénage</li>\u000a<li>Acier robuste haute qualité</li>\u000a<li>Finition noire résistante</li>\u000a<li>Montage spécifique sans modification</li>\u000a<li>Notice et kit de fixation inclus</li>\u000a</ul>\u000a<h3>Compatibilité</h3>\u000a<ul>\u000a<li>Yamaha Tracer 9 – 2025 et +</li>\u000a<li>Yamaha Tracer 9 GT – 2025 et +</li>\u000a<li>Yamaha Tracer 9 GT+ – 2025 et +</li>\u000a</ul>\u000a<p><strong>Idéal pour les motards exigeants</strong>, ces pare-carters GIVI sont parfaits pour un usage<br />\u000aquotidien, le touring et les longs voyages.</p>\u000a'),unistr('<p>Pare-carters tubulaires GIVI TN2171 pour Yamaha Tracer 9 / GT / GT+ 2025 et +. Protection moteur robuste en acier, montage spécifique sans modification, finition noire.</p>\u000a'),21,756,2699.0,2699.0,NULL,NULL,'published','Pare-carters tubulaires spécifiques TN2171GIVI pour Yamaha Tracer 9 / GT / GT+ 2025 et +',unistr('<p>Pare-carters tubulaires GIVI TN2171 pour Yamaha Tracer 9 / GT / GT+ 2025 et +. Protection moteur robuste en acier, montage spécifique sans modification, finition noire.</p>\u000a'),493,'2026-06-20 14:09:07',0,1,0,0);
INSERT INTO products VALUES(259,'Casque Kenny TITANIUM Blanc/Noir','kenny-casque-titanium-white-black',unistr('<ul>\u000a<li><span dir="auto"><span dir="auto">Construction de la coque en fibres tri-composites</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Casque intégral tout-terrain</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Intérieur antibactérien amovible et lavable</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Jugulaire rembourrée réglable avec fermeture à anneau en D</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Finition peinture et vernis</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Approbation ECE 22-05</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Poids : 1100 g (+/- 50 g) – graphique</span></span></li>\u000a</ul>\u000a<p>&nbsp;</p>\u000a<p>Casque Kenny TITANIUM Blanc/Noir</p>\u000a'),unistr('<ul>\u000a<li><span dir="auto"><span dir="auto">Construction de la coque en fibres tri-composites</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Casque intégral tout-terrain</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Intérieur antibactérien amovible et lavable</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Jugulaire rembourrée réglable avec fermeture à anneau en D</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Finition peinture et vernis</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Approbation ECE 22-05</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Poids : 1100 g (+/- 50 g) – graphique</span></span></li>\u000a<li></li>\u000a</ul>\u000a'),53,890,3200.0,1990.0,NULL,NULL,'published','Casque Kenny TITANIUM Blanc/Noir',unistr('<ul>\u000a<li><span dir="auto"><span dir="auto">Construction de la coque en fibres tri-composites</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Casque intégral tout-terrain</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Intérieur antibactérien amovible et lavable</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Jugulaire rembourrée réglable avec fermeture à anneau en D</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Finition peinture et vernis</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Approbation ECE 22-05</span></span></li>\u000a<li><span dir="auto"><span dir="auto">Poids : 1100 g (+/- 50 g) – graphique</span></span></li>\u000a<li></li>\u000a</ul>\u000a'),83,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(260,'CASQUE CROSS KENNY TITANIUM BLACK ORANGE','casque-cross-kenny-titanium-black-orange',unistr('<p>Casque Cross Kenny Titanium Graphic<br />\u000aCasque fibre en tri-composite<br />\u000aCasque tout-terrain intégral à mentonnière fixe<br />\u000aIntérieur amovible en tissu hypoallergénique entièrement démontable et lavable<br />\u000aFermeture par double boucle ajustable<br />\u000aFinition peinture 8 vernis<br />\u000aHomologation ECE 22-05<br />\u000aPoids : 1100g (+ ou - 50g) - graphic<br />\u000aPoids : 990g (+ ou - 50g) - carbone<br />\u000a2 tailles de coque : XS &gt; M et L &gt; XXL</p>\u000a'),'',53,890,3799.0,2399.0,NULL,NULL,'published','CASQUE CROSS KENNY TITANIUM BLACK ORANGE','CASQUE CROSS KENNY TITANIUM BLACK ORANGE au Maroc. Achetez au meilleur prix chez MOTO PACO.',104,'2026-06-20 14:09:07',0,0,0,0);
INSERT INTO products VALUES(261,'GIVI WL902 TANKLOCKED SACOCHE DE RÉSERVOIR SEMI-RIGIDE TANKLOCKED®, 5 LITRES','givi-sac-reservoir-wl902',unistr('<p>Sacoche de réservoir semi-rigide TANKLOCKED®, 5 litres</p>\u000a<p>La sacoche de réservoir de la ligne Weightless permet de compléter l’équipement semi-rigide et offre aux motos à vocation touristique et sportive un look « total black » à la texture diamant particulièrement seyante.<br />\u000aLa sacoche est dotée du système d’accrochage / décrochage rapide TANKLOCKED, la sécurité du contenu étant également augmentée par la fermeture avec un cadenas à combinaison intégré.<br />\u000aDe plus, la fente prévue pour le passage d’un câble de recharge la rend compatible avec le système de recharge Givi Power Hub.</p>\u000a<p>Matériaux :<br />\u000a• Couvercle en ABS<br />\u000a• Fond en EVA<br />\u000a• Matériaux extérieurs à haute résistance aux rayons UV</p>\u000a<p>En standard:<br />\u000a• Housse de pluie<br />\u000a• Cadenas à combinaison intégré pour verrouiller les tirettes<br />\u000a• Fente de sortie de câble compatible avec le système de recharge Givi Power Hub<br />\u000a• Poche intérieure porte-documents sous le couvercle<br />\u000a• Poignée pour le transport à main<br />\u000a• Sangle de sécurité réglable, permettant le transport en bandoulière<br />\u000a• Impressions à motifs réfléchissants pour plus de visibilité<br />\u000a• Fermeture éclair d''ouverture de marque YKK* (*marque enregistrée)</p>\u000a<p>Le système TanklockED permet à la sacoche tanklock d’être sécurisée à la bague spécifique montée sur le réservoir, grâce à une serrure de sécurité.<br />\u000aLa sacoche peut être enlevée ou fixée au réservoir sans utiliser la clef à chaque fois. La clef sert uniquement à verrouiller la sacoche lorsque la moto est sans surveillance.<br />\u000aLa serrure utilisée sur ce système peut être identique avec celles des top case et valises latérales, du trolley et même de la sacoche à outil S250 , grâce aux kits SL102 / SL103 ou SL105.<br />\u000aÀ associer nécessairement aux brides spécifiques BF_ _</p>\u000a<p>Le système TanklockED est composé d''une bride spécifique BF_ _, nécessaire pour permettre le montage des sacoches TanklockED. Avant d''acheter, veuillez vérifier soigneusement que la sacoche n''affectera pas la maniabilité du véhicule, en accordant une attention particulière à toute interférence possible avec le guidon.</p>\u000a<p>Cherchez dans la section POUR VOTRE MOTO afin de vérifier l’existence de la bride spécifique pour votre moto</p>\u000a'),'',51,756,1599.0,1599.0,NULL,NULL,'published','GIVI WL902 TANKLOCKED SACOCHE DE RÉSERVOIR SEMI-RIGIDE TANKLOCKED®, 5 LITRES','GIVI WL902 TANKLOCKED SACOCHE DE RÉSERVOIR SEMI-RIGIDE TANKLOCKED®, 5 LITRES au Maroc. Achetez au meilleur prix chez MOTO PACO.',71,'2026-06-20 14:09:08',0,0,0,0);
INSERT INTO products VALUES(262,'CASQUE KENNY TITANIUM NAVY NEON YELLOW 22.06','kenny-casque-cross-titanium-graphic-2',unistr('<p>Casque Kenny Titanium Navy Neon Yellow 22.06<br />\u000aPerformance, sécurité et style audacieux : le casque Kenny Titanium Navy Neon Yellow 22.06 est conçu pour les pilotes qui recherchent un équipement fiable, confortable et certifié selon les dernières normes.<br />\u000a- Caractéristiques principales :<br />\u000aHomologation 22.06 : conforme à la nouvelle norme européenne, garantissant un niveau de sécurité supérieur.<br />\u000aDesign Navy & Neon Yellow : un look moderne, ultra-visible et dynamique, parfait pour se démarquer sur la piste.<br />\u000aCoque légère et résistante : fabrication robuste assurant une excellente absorption des chocs sans compromis sur le poids.<br />\u000aVentilation optimisée : système d’aération performant pour maintenir une température agréable même dans les conditions les plus intenses.<br />\u000aIntérieur démontable & lavable : mousses confortables, antibactériennes et faciles à entretenir.<br />\u000aLarge ouverture frontale : parfaite compatibilité avec la majorité des masques de motocross.<br />\u000aFermeture double D : sécurisation maximale, adaptée à la pratique sportive et aux compétitions.<br />\u000a-Idéal pour :<br />\u000aMotocross<br />\u000aEnduro<br />\u000aQuad<br />\u000aTout-terrain<br />\u000a-Pourquoi le choisir ?<br />\u000aSécurité renforcée (norme 22.06)<br />\u000aConfort durable<br />\u000aStyle agressif et moderne<br />\u000aMatériaux de haute qualité</p>\u000a'),'',53,890,3499.0,2499.0,NULL,NULL,'published','CASQUE KENNY TITANIUM NAVY NEON YELLOW 22.06','CASQUE KENNY TITANIUM NAVY NEON YELLOW 22.06 au Maroc. Achetez au meilleur prix chez MOTO PACO.',148,'2026-06-20 14:09:08',0,0,0,0);
INSERT INTO products VALUES(263,'KENNY CASQUE CROSS TITANIUM GRAPHIC','kenny-casque-cross-titanium-graphic',unistr('<p>Alliez style, protection et performance avec le casque KENNY Cross Titanium Graphic, conçu pour les pilotes exigeants qui recherchent un équipement fiable et visuellement percutant.<br />\u000aCaractéristiques principales :<br />\u000aCoque légère et résistante : fabrication en matériaux de haute qualité pour un maximum de sécurité sans alourdir la tête.<br />\u000aDesign Titanium Graphic : graphismes modernes et dynamiques, pour un look agressif sur les pistes comme sur les terrains d’enduro.<br />\u000aVentilation optimisée : système d’aération efficace assurant une circulation d’air maximale pour garder la tête au frais lors des sessions intenses.<br />\u000aIntérieur confortable et démontable : mousse hypoallergénique, entièrement amovible et lavable pour une hygiène parfaite.<br />\u000aCompatibilité masque : ouverture large pour accueillir la plupart des masques de motocross du marché.<br />\u000aFermeture sécurisée : boucle double D pour un maintien sûr et conforme aux standards de compétition.<br />\u000aPour qui ?<br />\u000aIdéal pour les pratiquants de motocross, enduro, quad ou tout passionné d’off-road souhaitant un casque alliant sécurité, confort et esthétique affirmée.<br />\u000aAvantages :<br />\u000aProtection optimale<br />\u000aExcellent confort de conduite<br />\u000aLook professionnel et agressif<br />\u000aMatériaux durables</p>\u000a'),'',53,890,3199.0,2099.0,NULL,NULL,'published','KENNY CASQUE CROSS TITANIUM GRAPHIC','KENNY CASQUE CROSS TITANIUM GRAPHIC au Maroc. Achetez au meilleur prix chez MOTO PACO.',103,'2026-06-20 14:09:08',0,0,0,0);
INSERT INTO products VALUES(264,'LAGUNA SECA 5 ENSEMBLE EN CUIR 2 PIÈCES','laguna-seca-5-ensemble-en-cuir-2-pieces',unistr('<p>Fabriquée entièrement encuir <strong>de vache Tutu </strong>, la Laguna Seca 5 2PCS est l''essence même de la <strong>conduite sportive sur route</strong>.<br />\u000aÉquipée d''un système d’attache à la taille pour raccorder veste et pantalon, c''est la première combinaison deux-pièces à être dotée de <strong>l’insert élastique Tri-Axial</strong> dans le dos qui, conjugué aux inserts en tissu élastique S1 et aux inserts élastiques en cuir Microelastic 2.0., offre des degrés d’ergonomie et de mobilité jamais atteints jusqu’ici.<br />\u000aLa protection maximale est le fruit de l’expérience directe sur piste et elle est garantie par <strong>les protections composites</strong> certifiées <strong>au niveau des épaules, des coudes et des genoux</strong>, mais aussi par les<strong> </strong>protections souples Pro-Shape 2.0 au niveau des hanches et par les sliders amovibles sur les coudes (RSS). La présence de <strong>plaques en aluminium</strong> interchangeables sur les épaules et les coudes assure une résistance maximale à l’abrasion à hauteur des articulations, pour accompagner la glissade en cas de chute.<br />\u000aLa doublure respirante avec inserts en<strong> tissu 3D Bubble </strong>et les fermetures éclair de ventilation au niveau de la poitrine et des cuisses garantissent un maximum de confort thermique et de polyvalence en toutes saisons, même face aux climats les plus torrides.</p>\u000a<pre>LAGUNA SECA 5 ENSEMBLE EN CUIR 2 PIÈCES</pre>\u000a'),unistr('<p>Fabriquée entièrement encuir <strong>de vache Tutu </strong>, la Laguna Seca 5 2PCS est l&#8217;essence même de la <strong>conduite sportive sur route</strong>.<br />\u000aÉquipée d&#8217;un système d’attache à la taille pour raccorder veste et pantalon, c&#8217;est la première combinaison deux-pièces à être dotée de <strong>l’insert élastique Tri-Axial</strong> dans le dos qui, conjugué aux inserts en tissu élastique S1 et aux inserts élastiques en cuir Microelastic 2.0., offre des degrés d’ergonomie et de mobilité jamais atteints jusqu’ici.<br />\u000aLa protection maximale est le fruit de l’expérience directe sur piste et elle est garantie par <strong>les protections composites</strong> certifiées <strong>au niveau des épaules, des coudes et des genoux</strong>, mais aussi par les<strong> </strong>protections souples Pro-Shape 2.0 au niveau des hanches et par les sliders amovibles sur les coudes (RSS). La présence de <strong>plaques en aluminium</strong> interchangeables sur les épaules et les coudes assure une résistance maximale à l’abrasion à hauteur des articulations, pour accompagner la glissade en cas de chute.<br />\u000aLa doublure respirante avec inserts en<strong> tissu 3D Bubble </strong>et les fermetures éclair de ventilation au niveau de la poitrine et des cuisses garantissent un maximum de confort thermique et de polyvalence en toutes saisons, même face aux climats les plus torrides.</p>\u000a<p>&nbsp;</p>\u000a'),31,13,11199.0,8999.0,NULL,NULL,'published','LAGUNA SECA 5 ENSEMBLE EN CUIR 2 PIÈCES',unistr('<p>Fabriquée entièrement encuir <strong>de vache Tutu </strong>, la Laguna Seca 5 2PCS est l&#8217;essence même de la <strong>conduite sportive sur route</strong>.<br />\u000aÉquipée d&#8217;un système d’attache à la taille pour raccorder veste et pantalon, c&#8217;est la première combinaison deux-pièces à être dotée de <strong>l’insert élastique Tri-Axial</strong> dans le dos qui, conjugué aux inserts en tissu élastique S1 et aux inserts élastiques en cuir Microelastic 2.0., offre des degrés d’ergonomie et de mobilité jamais atteints jusqu’ici.<br />\u000aLa protection maximale est le fruit de l’expérience directe sur piste et elle est garantie par <strong>les protections composites</strong> certifiées <strong>au niveau des épaules, des coudes et des genoux</strong>, mais aussi par les<strong> </strong>protections souples Pro-Shape 2.0 au niveau des hanches et par les sliders amovibles sur les coudes (RSS). La présence de <strong>plaques en aluminium</strong> interchangeables sur les épaules et les coudes assure une résistance maximale à l’abrasion à hauteur des articulations, pour accompagner la glissade en cas de chute.<br />\u000aLa doublure respirante avec inserts en<strong> tissu 3D Bubble </strong>et les fermetures éclair de ventilation au niveau de la poitrine et des cuisses garantissent un maximum de confort thermique et de polyvalence en toutes saisons, même face aux climats les plus torrides.</p>\u000a<p>&nbsp;</p>\u000a'),113,'2026-06-20 14:09:08',0,0,0,0);
