INSERT INTO products VALUES(306,'BASKETS TCX IKASU AIR NOIR GRIS','tcx-ikasu-air-baskets-moto',unistr('<p>TCX vous présente ses baskets moto, les Ikasu Air en coloris noir et gris.</p>\u000a<p>Ces chaussures de moto certifiées et respirantes garantissent d''un maximum de confort pour un usage quotidien : idéales pour une utilisation par temps doux, elles présentent des renforts aux malléoles avec inserts D30®, des protections au niveau de la pointe des pieds et du talon ainsi qu''un protège-sélecteur en caoutchouc pour vous assurer une protection optimale en moto.</p>\u000a<p>COMPOSITION<br />\u000aTissu respirant Mesh<br />\u000aTige en microfibre<br />\u000aDoublure Mesh<br />\u000aPROTECTION<br />\u000aRenforts malléoles avec insertions D3O<br />\u000aRenforts pointe et talon<br />\u000aPAD de décalage en caoutchouc<br />\u000aCONFORT<br />\u000aChaussures offrant un haut niveau de confort pour le pilotage et la marche<br />\u000aBonne ventilation pour les climats chauds<br />\u000aSemelle intermédiaire avec insert Zplate optimisant la flexibilité avant et la rigidité transversale<br />\u000aSemelle plantaire OrthoLite® hautement respirante à amortissement durable<br />\u000aSemelle extérieure Groundtrax® en caoutchouc résistante à l''usure et offrant une stabilité supérieure grâce à son design<br />\u000aFermeture éclair élastique à l''avant<br />\u000aCARACTÉRISTIQUES<br />\u000aSaisonnalité<br />\u000aToutes saisons<br />\u000aType de produit<br />\u000aChaussures<br />\u000aType de chaussures<br />\u000aBaskets<br />\u000aGenre<br />\u000aHomme<br />\u000aMatière<br />\u000aCuir<br />\u000aCouleur<br />\u000aMarron<br />\u000aOptions<br />\u000aImperméable<br />\u000aUnivers<br />\u000aUrbain / Vintage/Néo rétro<br />\u000aGarantie<br />\u000a2 ans<br />\u000aProtection sélecteur<br />\u000aOui<br />\u000aProtection malléole<br />\u000aOui<br />\u000aProtection tibia<br />\u000aNon<br />\u000aSliders<br />\u000aNon<br />\u000aHomologation EN 13634<br />\u000aOui<br />\u000aType de fermeture<br />\u000aLacets / Zip<br />\u000aVentilé<br />\u000aOui</p>\u000a'),unistr('<p>BASKETS TCX IKASU AIR NOIR GRIS</p>\u000a'),52,770,1899.0,1299.0,NULL,NULL,'published','BASKETS TCX IKASU AIR NOIR GRIS',unistr('<p>BASKETS TCX IKASU AIR NOIR GRIS</p>\u000a'),480,'2026-06-20 14:09:12',0,1,0,0);
INSERT INTO products VALUES(307,'DAINESE – ENERGYCA D-WP SHOES BLACK/FLUO-RED','dainese-energyca-bottes-moto',unistr('<p>Chaussures sportives avec membrane imperméable D-WP, réalisées conformément aux normes de protection Dainese. motard Maroc. Un pied maintenu au sec tout en confort, sur tous les itinéraires urbains, quelles que soient les conditions. motard Maroc. Dotées de la membrane imperméable D-WP® exclusive, ces chaussures incarnent l’essence sportive de Dainese : certifiées, elles garantissent les meilleures normes de protection pour vos activités au quotidien.</p>\u000a'),unistr('<p>DAINESE – ENERGYCA D-WP SHOES BLACK/FLUO-RED</p>\u000a'),52,753,2799.0,1699.0,NULL,NULL,'published','DAINESE – ENERGYCA D-WP SHOES BLACK/FLUO-RED',unistr('<p>DAINESE – ENERGYCA D-WP SHOES BLACK/FLUO-RED</p>\u000a'),70,'2026-06-20 14:09:12',0,0,0,0);
INSERT INTO products VALUES(308,'DAINESE – FREELAND GORE-TEX® BOOTS – BLACK','dainese-freeland-bottes-moto',unistr('<p>Bottes de moto imperméables en Gore-Tex®, idéales au quotidien, pour les adeptes du touring comme pour les trajets en ville.</p>\u000a<p>Dainese engineers have worked long and hard to develop a tall GORE-TEX® boot with a high level of protection, and with the waterproof, CE-certified Freeland, the goal has been achieved. Comfort is aided by soft joint pads, in key locations, as well as a new rubber sole with an unique design.</p>\u000a'),unistr('<p>DAINESE – FREELAND GORE-TEX® BOOTS – BLACK</p>\u000a'),52,753,3499.0,1999.0,NULL,NULL,'published','DAINESE – FREELAND GORE-TEX® BOOTS – BLACK',unistr('<p>DAINESE – FREELAND GORE-TEX® BOOTS – BLACK</p>\u000a'),90,'2026-06-20 14:09:13',0,0,0,0);
INSERT INTO products VALUES(309,'Dainese Dinamica – Bottes moto sportives black/fluo red','dainese-dinamica-bottes-moto',unistr('<p>Les Dainese Dinamica incarnent l’esprit racing de la marque italienne, conçues pour les motards qui recherchent style, performance et sécurité.<br />\u000a✅ Protection optimale : renforts stratégiques et inserts en TPU résistants à l’abrasion pour une sécurité maximale.<br />\u000a✅ Confort et mobilité : empiècements flexibles et fermeture pratique pour un ajustement parfait et une liberté de mouvement totale.<br />\u000a✅ Respirabilité : zones ventilées assurant une circulation d’air efficace, même lors des longues sorties.<br />\u000a✅ Matériaux premium : microfibre résistante et semelle ergonomique pour un maintien durable.<br />\u000a✅ Design racing : ligne agressive et moderne, 100% style italien signé Dainese.<br />\u000aIdéales pour la route comme pour la piste, les Dinamica offrent le compromis parfait entre légèreté, protection et esthétique.</p>\u000a'),unistr('<p>Les Dainese Dinamica sont des bottes moto sportives alliant protection avancée, confort et design racing. Légères et ventilées, elles sont parfaites pour la route comme la piste.</p>\u000a<p>Dainese Dinamica – Bottes moto sportives black/fluo red</p>\u000a'),52,753,2899.0,1699.0,NULL,NULL,'published','Dainese Dinamica – Bottes moto sportives black/fluo red',unistr('<p>Les Dainese Dinamica sont des bottes moto sportives alliant protection avancée, confort et design racing. Légères et ventilées, elles sont parfaites pour la route comme la piste.</p>\u000a<p>Dainese Dinamica – Bottes moto sportives black/fluo red</p>\u000a'),489,'2026-06-20 14:09:13',0,1,0,0);
INSERT INTO products VALUES(310,'Dainese Dinamica – Bottes moto sportives black/fluo','dainese-dinamica-bottes-moto-sportives-black-fluo',unistr('<p>Les Dainese Dinamica incarnent l’esprit racing de la marque italienne, conçues pour les motards qui recherchent style, performance et sécurité.<br />\u000a✅ Protection optimale : renforts stratégiques et inserts en TPU résistants à l’abrasion pour une sécurité maximale.<br />\u000a✅ Confort et mobilité : empiècements flexibles et fermeture pratique pour un ajustement parfait et une liberté de mouvement totale.<br />\u000a✅ Respirabilité : zones ventilées assurant une circulation d’air efficace, même lors des longues sorties.<br />\u000a✅ Matériaux premium : microfibre résistante et semelle ergonomique pour un maintien durable.<br />\u000a✅ Design racing : ligne agressive et moderne, 100% style italien signé Dainese.<br />\u000aIdéales pour la route comme pour la piste, les Dinamica offrent le compromis parfait entre légèreté, protection et esthétique.</p>\u000a'),'',52,753,2899.0,1799.0,NULL,NULL,'published','Dainese Dinamica – Bottes moto sportives black/fluo','Dainese Dinamica – Bottes moto sportives black/fluo au Maroc. Achetez au meilleur prix chez MOTO PACO.',488,'2026-06-20 14:09:13',0,1,0,0);
INSERT INTO products VALUES(311,'DAINESE – NEXUS 2 BOOTS – BLACK SPORTIVES','dainese-nexus-2-black-bottes-moto',unistr('<p>Les Dainese Nexus 2 Black sont conçues pour les motards passionnés qui recherchent sécurité, confort et style sur route comme sur piste. Inspirées du savoir-faire racing de Dainese, elles combinent des matériaux haut de gamme et une protection avancée.<br />\u000a✅ Protection maximale : système de protection Dainese Axial Distortion Control System pour limiter les torsions dangereuses de la cheville.<br />\u000a✅ Confort supérieur : empiècements flexibles pour une liberté de mouvement optimale et semelle ergonomique pour un maintien parfait.<br />\u000a✅ Matériaux résistants : microfibre de qualité et inserts en TPU résistants à l’abrasion.<br />\u000a✅ Ventilation efficace : zones perforées pour garder le pied au frais même lors des longues sorties.<br />\u000a✅ Design racing 100% italien : look sportif et agressif en noir intégral, parfait pour compléter votre équipement.<br />\u000aCes bottes sont idéales pour les motards exigeants qui veulent rouler en toute confiance sans compromis entre style et sécurité.</p>\u000a'),unistr('<p>Les Dainese Nexus 2 Black sont des bottes de moto sportives offrant protection avancée, confort et design racing. Idéales pour route et piste, elles allient style agressif et sécurité maximale.</p>\u000a'),52,753,3499.0,1999.0,NULL,NULL,'published','DAINESE – NEXUS 2 BOOTS – BLACK SPORTIVES',unistr('<p>Les Dainese Nexus 2 Black sont des bottes de moto sportives offrant protection avancée, confort et design racing. Idéales pour route et piste, elles allient style agressif et sécurité maximale.</p>\u000a'),102,'2026-06-20 14:09:13',0,0,0,0);
INSERT INTO products VALUES(312,'DAINESE – NEXUS 2 BOOTS – BLACK/FLUO','dainese-nexus-2-black-bottes-moto-2',unistr('<p>Les bottes de moto sportives Dainese Nexus 2 sont réalisées en microfibre et en D-Stone, avec un insert en nylon au talon.</p>\u000a<p>Dotées de curseurs thermoplastiques remplaçables, du système exclusif Dainese Axial Distortion Control System et d’inserts en nylon sur le talon, elles garantissent les plus hauts niveaux de protection, un confort maximal et une grande légèreté.</p>\u000a<p><strong>Caractéristiques</strong></p>\u000a<p>Insert de protection au niveau du sélecteur<br />\u000aInserts TPU à adhérence élevée<br />\u000aSlider en plastique remplaçable, 16 (1999948 Ensemble de sliders pour bottes en magnésium, 1999885 Ensemble de sliders pour bottes en acier inoxydable<br />\u000aSemelle en caoutchouc au design différencié<br />\u000aFourni avec clé à vis de pression<br />\u000aErgonomie<br />\u000aFermeture par zip à l''arrière<br />\u000aArticulations flexibles pour un meilleur confort de marche<br />\u000aMatériaux principaux<br />\u000aTissu D-Stone™<br />\u000aPartie supérieure en microfibre<br />\u000aInserts de protection<br />\u000aBottes certifiées CE - Cat. II - norme EN 13634<br />\u000aSystème de contrôle de distorsion interne AXIAL<br />\u000aTalon en nylon<br />\u000aCoque intérieure de protection en nylon<br />\u000aOrteils renforcés en nylon<br />\u000aInserts en polyuréthane thermoplastique sur le tibia</p>\u000a'),unistr('<p>Les Dainese Nexus 2 Black sont des bottes de moto sportives offrant protection avancée, confort et design racing. Idéales pour route et piste, elles allient style agressif et sécurité maximale.</p>\u000a'),52,753,3499.0,2299.0,NULL,NULL,'published','DAINESE – NEXUS 2 BOOTS – BLACK/FLUO',unistr('<p>Les Dainese Nexus 2 Black sont des bottes de moto sportives offrant protection avancée, confort et design racing. Idéales pour route et piste, elles allient style agressif et sécurité maximale.</p>\u000a'),66,'2026-06-20 14:09:13',0,0,0,0);
INSERT INTO products VALUES(313,'Dainese Nighthawk D1 GORE-TEX® – Bottes Moto Incontournables pour Touring','dainese-nighthawk-d1-gore-tex',unistr('<p data-start="473" data-end="801"><br data-start="497" data-end="500" />Les <strong data-start="1383" data-end="1429">bottes moto Dainese Nighthawk D1 GORE-TEX®</strong> sont conçues pour les motards exigeants. Grâce à leur <strong data-start="1484" data-end="1518">membrane imperméable GORE-TEX®</strong>, elles gardent vos pieds au sec en toutes conditions. Cette paire de <strong data-start="1588" data-end="1614">bottes touring Dainese</strong> combine <strong data-start="1623" data-end="1648">sécurité certifiée CE</strong> et un confort exceptionnel, idéale pour la ville comme pour les longues routes.</p>\u000a<p data-start="803" data-end="832"><strong data-start="803" data-end="830">Caractéristiques clés :</strong></p>\u000a<ul data-start="833" data-end="1274">\u000a<li data-start="833" data-end="944">\u000a<p data-start="835" data-end="944"><strong data-start="835" data-end="861">Protection renforcée :</strong> Inserts rigides aux chevilles, protège-tibia thermoformé et renfort TPU externe.</p>\u000a</li>\u000a<li data-start="945" data-end="1037">\u000a<p data-start="947" data-end="1037"><strong data-start="947" data-end="960">Confort :</strong> Inserts élastiques aux points de flexion, perforations pour respirabilité.</p>\u000a</li>\u000a<li data-start="1038" data-end="1114">\u000a<p data-start="1040" data-end="1114"><strong data-start="1040" data-end="1065">Fermeture sécurisée :</strong> Combinaison fermeture éclair et strap Velcro®.</p>\u000a</li>\u000a<li data-start="1115" data-end="1196">\u000a<p data-start="1117" data-end="1196"><strong data-start="1117" data-end="1130">Semelle :</strong> Semelle en caoutchouc différenciée pour adhérence et stabilité.</p>\u000a</li>\u000a<li data-start="1197" data-end="1274">\u000a<p data-start="1199" data-end="1274"><strong data-start="1199" data-end="1215">Visibilité :</strong> Inserts réfléchissants pour une sécurité accrue de nuit.</p>\u000a</li>\u000a</ul>\u000a<p data-start="1276" data-end="1423">Idéales pour vos trajets quotidiens comme pour les longues balades, ces bottes offrent <strong data-start="1363" data-end="1393">style, sécurité et confort</strong> dans toutes les conditions.</p>\u000a<p data-start="1425" data-end="1552"><strong data-start="1425" data-end="1456">Mots-clés SEO recommandés :</strong> bottes moto Dainese, bottes touring imperméables, bottes urbaines moto, Nighthawk D1 GORE-TEX</p>\u000a'),unistr('<p>Découvrez les bottes moto Dainese Nighthawk D1 GORE-TEX®. Sécurité certifiée CE, confort optimal, semelle antidérapante et imperméabilité GORE-TEX®. Idéales pour la ville et le touring.</p>\u000a'),52,753,2999.0,1699.0,NULL,NULL,'published','Dainese Nighthawk D1 GORE-TEX® – Bottes Moto Incontournables pour Touring',unistr('<p>Découvrez les bottes moto Dainese Nighthawk D1 GORE-TEX®. Sécurité certifiée CE, confort optimal, semelle antidérapante et imperméabilité GORE-TEX®. Idéales pour la ville et le touring.</p>\u000a'),479,'2026-06-20 14:09:13',0,1,0,0);
INSERT INTO products VALUES(314,'DAINESE – NEXUS 2 BOOTS – BLACK/ANTHRACITE – Ultra-protectrices et Ultra-performantes','bottes-moto-dainese-nexus-2',unistr('<h2 data-qa="pdp-description-seo-title">Nexus 2Bottes</h2>\u000a<div id="pdp-description-text">Avec les Dainese *Nexus 2* tu fais l''acquisition de véritable bottes de moto sport composées essentiellement de tissus D-Stone (microfibre). Inserts en nylon au talon, curseurs thermoplastiques remplaçables, Axial Distortion Control-System, un système de flexion contrôlée de l’articulation de la cheville ainsi que des inserts en nylon sur le talon sont des équipement de qualité supérieure. Elles représentent le mariage parfait entre hauts niveaux de protection, confort maximal et grande légèreté.</p>\u000a<p>Matière :</p>\u000a<ul>\u000a<li>Revêtement en tissus D-Stone (microfibre)</li>\u000a<li>Semelle en caoutchouc</li>\u000a</ul>\u000a<p>Confort/Équipement :</p>\u000a<ul>\u000a<li>Renfort sélecteur</li>\u000a<li>Sliders plastique remplaçables</li>\u000a<li>Inserts en polyuréthane thermoplastique sur le tibia</li>\u000a<li>Fermeture par zip à l''arrière</li>\u000a<li>Articulations flexibles pour un meilleur confort de marche</li>\u000a<li>Pointe renforcée en nylon</li>\u000a<li>Système de contrôle de distorsion interne AXIAL en carbone et fibre d''aramide (tient la cheville dans son mouvement pour une protection renforcée, confort maximal et légèreté)</li>\u000a</ul>\u000a<p>Hauteur de tige :</p>\u000a<ul>\u000a<li>env. 27 cm (taille 44)</li>\u000a</ul>\u000a<p>Homologation :</p>\u000a<ul>\u000a<li>Certification selon la norme EN 13634:2017</li>\u000a</ul>\u000a</div>\u000a<div id="pdp-safety-hint-text">Fabricant : Dainese S.p.A. | Via Louvigny, 35 | 36064 Colceresa | Italie | info@dainese.com</div>\u000a'),'',31,753,3699.0,1999.0,NULL,NULL,'published','DAINESE – NEXUS 2 BOOTS – BLACK/ANTHRACITE – Ultra-protectrices et Ultra-performantes','DAINESE – NEXUS 2 BOOTS – BLACK/ANTHRACITE – Ultra-protectrices et Ultra-performantes au Maroc. Achetez au meilleur prix chez MOTO PACO.',149,'2026-06-20 14:09:14',0,0,0,0);
INSERT INTO products VALUES(315,'Chaussures Moto Dainese Dinamica – Performance Sportive et Protection Haut de Gamme','chaussures-moto-dainese-dinamica',unistr('<p data-start="693" data-end="895">Les <strong data-start="697" data-end="717">Dainese Dinamica</strong> incarnent l’esprit racing dans une chaussure moto au format urbain.<br data-start="785" data-end="788" />Conçues pour offrir un <strong data-start="811" data-end="836">maximum de protection</strong> et de confort, elles sont disponibles en deux versions :</p>\u000a<ul data-start="896" data-end="1059">\u000a<li data-start="896" data-end="987">\u000a<p data-start="898" data-end="987"><strong data-start="898" data-end="916">Dinamica D-WP®</strong> : étanches et respirantes, idéales pour toutes les conditions météo.</p>\u000a</li>\u000a<li data-start="988" data-end="1059">\u000a<p data-start="990" data-end="1059"><strong data-start="990" data-end="1006">Dinamica Air</strong> : ventilées pour un confort optimal par temps chaud.</p>\u000a</li>\u000a</ul>\u000a<p data-start="1061" data-end="1344">Elles disposent d’une tige en microfibre résistante à l’abrasion, de protections rigides à la malléole, d’un renfort sélecteur, et d’une semelle antidérapante pour un grip optimal.<br data-start="1241" data-end="1244" />Leur système de fermeture rapide par <strong data-start="1281" data-end="1298">zip et velcro</strong> assure un maintien sûr et un enfilage rapide.</p>\u000a<hr data-start="1346" data-end="1349" />\u000a<h2 data-start="1351" data-end="1374"><strong data-start="1354" data-end="1374">Caractéristiques</strong></h2>\u000a<ul data-start="1375" data-end="1788">\u000a<li data-start="1375" data-end="1408">\u000a<p data-start="1377" data-end="1408"><strong data-start="1377" data-end="1397">Certification CE</strong> EN 13634</p>\u000a</li>\u000a<li data-start="1409" data-end="1464">\u000a<p data-start="1411" data-end="1464"><strong data-start="1411" data-end="1434">Protections rigides</strong> : malléoles, talon, orteils</p>\u000a</li>\u000a<li data-start="1465" data-end="1513">\u000a<p data-start="1467" data-end="1513"><strong data-start="1467" data-end="1488">Renfort sélecteur</strong> pour préserver la tige</p>\u000a</li>\u000a<li data-start="1514" data-end="1572">\u000a<p data-start="1516" data-end="1572"><strong data-start="1516" data-end="1533">Version D-WP®</strong> : membrane imperméable et respirante</p>\u000a</li>\u000a<li data-start="1573" data-end="1617">\u000a<p data-start="1575" data-end="1617"><strong data-start="1575" data-end="1590">Version Air</strong> : panneaux mesh ventilés</p>\u000a</li>\u000a<li data-start="1618" data-end="1652">\u000a<p data-start="1620" data-end="1652"><strong data-start="1620" data-end="1628">Tige</strong> en microfibre durable</p>\u000a</li>\u000a<li data-start="1653" data-end="1699">\u000a<p data-start="1655" data-end="1699"><strong data-start="1655" data-end="1668">Fermeture</strong> : zip latéral + patte velcro</p>\u000a</li>\u000a<li data-start="1700" data-end="1757">\u000a<p data-start="1702" data-end="1757"><strong data-start="1702" data-end="1713">Semelle</strong> : caoutchouc antidérapant haute adhérence</p>\u000a</li>\u000a<li data-start="1758" data-end="1788">\u000a<p data-start="1760" data-end="1788"><strong data-start="1760" data-end="1769">Style</strong> : sport / urbain</p>\u000a</li>\u000a</ul>\u000a<hr data-start="1790" data-end="1793" />\u000a<p>&nbsp;</p>\u000a'),unistr('<p data-start="693" data-end="895">Les <strong data-start="697" data-end="717">Dainese Dinamica</strong> incarnent l’esprit racing dans une chaussure moto au format urbain.<br data-start="785" data-end="788" />Conçues pour offrir un <strong data-start="811" data-end="836">maximum de protection</strong> et de confort, elles sont disponibles en deux versions :</p>\u000a<ul data-start="896" data-end="1059">\u000a<li data-start="896" data-end="987">\u000a<p data-start="898" data-end="987"><strong data-start="898" data-end="916">Dinamica D-WP®</strong> : étanches et respirantes, idéales pour toutes les conditions météo.</p>\u000a</li>\u000a<li data-start="988" data-end="1059">\u000a<p data-start="990" data-end="1059"><strong data-start="990" data-end="1006">Dinamica Air</strong> : ventilées pour un confort optimal par temps chaud.</p>\u000a</li>\u000a</ul>\u000a<p data-start="1061" data-end="1344">Elles disposent d’une tige en microfibre résistante à l’abrasion, de protections rigides à la malléole, d’un renfort sélecteur, et d’une semelle antidérapante pour un grip optimal.<br data-start="1241" data-end="1244" />Leur système de fermeture rapide par <strong data-start="1281" data-end="1298">zip et velcro</strong> assure un maintien sûr et un enfilage rapide.</p>\u000a<hr data-start="1346" data-end="1349" />\u000a<h2 data-start="1351" data-end="1374"><strong data-start="1354" data-end="1374">Caractéristiques</strong></h2>\u000a<ul data-start="1375" data-end="1788">\u000a<li data-start="1375" data-end="1408">\u000a<p data-start="1377" data-end="1408"><strong data-start="1377" data-end="1397">Certification CE</strong> EN 13634</p>\u000a</li>\u000a<li data-start="1409" data-end="1464">\u000a<p data-start="1411" data-end="1464"><strong data-start="1411" data-end="1434">Protections rigides</strong> : malléoles, talon, orteils</p>\u000a</li>\u000a<li data-start="1465" data-end="1513">\u000a<p data-start="1467" data-end="1513"><strong data-start="1467" data-end="1488">Renfort sélecteur</strong> pour préserver la tige</p>\u000a</li>\u000a<li data-start="1514" data-end="1572">\u000a<p data-start="1516" data-end="1572"><strong data-start="1516" data-end="1533">Version D-WP®</strong> : membrane imperméable et respirante</p>\u000a</li>\u000a<li data-start="1573" data-end="1617">\u000a<p data-start="1575" data-end="1617"><strong data-start="1575" data-end="1590">Version Air</strong> : panneaux mesh ventilés</p>\u000a</li>\u000a<li data-start="1618" data-end="1652">\u000a<p data-start="1620" data-end="1652"><strong data-start="1620" data-end="1628">Tige</strong> en microfibre durable</p>\u000a</li>\u000a<li data-start="1653" data-end="1699">\u000a<p data-start="1655" data-end="1699"><strong data-start="1655" data-end="1668">Fermeture</strong> : zip latéral + patte velcro</p>\u000a</li>\u000a<li data-start="1700" data-end="1757">\u000a<p data-start="1702" data-end="1757"><strong data-start="1702" data-end="1713">Semelle</strong> : caoutchouc antidérapant haute adhérence</p>\u000a</li>\u000a<li data-start="1758" data-end="1788">\u000a<p data-start="1760" data-end="1788"><strong data-start="1760" data-end="1769">Style</strong> : sport / urbain</p>\u000a</li>\u000a</ul>\u000a<hr data-start="1790" data-end="1793" />\u000a<p>&nbsp;</p>\u000a'),52,753,2899.0,1699.0,NULL,NULL,'published','Chaussures Moto Dainese Dinamica – Performance Sportive et Protection Haut de Gamme',unistr('<p data-start="693" data-end="895">Les <strong data-start="697" data-end="717">Dainese Dinamica</strong> incarnent l’esprit racing dans une chaussure moto au format urbain.<br data-start="785" data-end="788" />Conçues pour offrir un <strong data-start="811" data-end="836">maximum de protection</strong> et de confort, elles sont disponibles en deux versions :</p>\u000a<ul data-start="896" data-end="1059">\u000a<li data-start="896" data-end="987">\u000a<p data-start="898" data-end="987"><strong data-start="898" data-end="916">Dinamica D-WP®</strong> : étanches et respirantes, idéales pour toutes les conditions météo.</p>\u000a</li>\u000a<li data-start="988" data-end="1059">\u000a<p data-start="990" data-end="1059"><strong data-start="990" data-end="1006">Dinamica Air</strong> : ventilées pour un confort optimal par temps chaud.</p>\u000a</li>\u000a</ul>\u000a<p data-start="1061" data-end="1344">Elles disposent d’une tige en microfibre résistante à l’abrasion, de protections rigides à la malléole, d’un renfort sélecteur, et d’une semelle antidérapante pour un grip optimal.<br data-start="1241" data-end="1244" />Leur système de fermeture rapide par <strong data-start="1281" data-end="1298">zip et velcro</strong> assure un maintien sûr et un enfilage rapide.</p>\u000a<hr data-start="1346" data-end="1349" />\u000a<h2 data-start="1351" data-end="1374"><strong data-start="1354" data-end="1374">Caractéristiques</strong></h2>\u000a<ul data-start="1375" data-end="1788">\u000a<li data-start="1375" data-end="1408">\u000a<p data-start="1377" data-end="1408"><strong data-start="1377" data-end="1397">Certification CE</strong> EN 13634</p>\u000a</li>\u000a<li data-start="1409" data-end="1464">\u000a<p data-start="1411" data-end="1464"><strong data-start="1411" data-end="1434">Protections rigides</strong> : malléoles, talon, orteils</p>\u000a</li>\u000a<li data-start="1465" data-end="1513">\u000a<p data-start="1467" data-end="1513"><strong data-start="1467" data-end="1488">Renfort sélecteur</strong> pour préserver la tige</p>\u000a</li>\u000a<li data-start="1514" data-end="1572">\u000a<p data-start="1516" data-end="1572"><strong data-start="1516" data-end="1533">Version D-WP®</strong> : membrane imperméable et respirante</p>\u000a</li>\u000a<li data-start="1573" data-end="1617">\u000a<p data-start="1575" data-end="1617"><strong data-start="1575" data-end="1590">Version Air</strong> : panneaux mesh ventilés</p>\u000a</li>\u000a<li data-start="1618" data-end="1652">\u000a<p data-start="1620" data-end="1652"><strong data-start="1620" data-end="1628">Tige</strong> en microfibre durable</p>\u000a</li>\u000a<li data-start="1653" data-end="1699">\u000a<p data-start="1655" data-end="1699"><strong data-start="1655" data-end="1668">Fermeture</strong> : zip latéral + patte velcro</p>\u000a</li>\u000a<li data-start="1700" data-end="1757">\u000a<p data-start="1702" data-end="1757"><strong data-start="1702" data-end="1713">Semelle</strong> : caoutchouc antidérapant haute adhérence</p>\u000a</li>\u000a<li data-start="1758" data-end="1788">\u000a<p data-start="1760" data-end="1788"><strong data-start="1760" data-end="1769">Style</strong> : sport / urbain</p>\u000a</li>\u000a</ul>\u000a<hr data-start="1790" data-end="1793" />\u000a<p>&nbsp;</p>\u000a'),490,'2026-06-20 14:09:14',0,1,0,0);
INSERT INTO products VALUES(316,'Chaussures de moto Dainese ENERGYCA D-WP Sport noir anthracite','chaussures-moto-dainese-energica-d-wp-sport-noir-anthracite',unistr('<p data-start="346" data-end="671">Les <strong data-start="350" data-end="381">Dainese ENERGICA D-WP Sport</strong> combinent un design sportif et agressif avec une protection moto de haut niveau.<br data-start="462" data-end="465" />Grâce à la membrane <strong data-start="485" data-end="520">D-WP® imperméable et respirante</strong>, elles gardent vos pieds au sec par tous les temps tout en assurant un confort optimal, que ce soit pour les trajets urbains ou les sorties sportives.</p>\u000a<p data-start="673" data-end="930">Leur tige en microfibre résistante à l’abrasion intègre des protections rigides à la malléole, un renfort sélecteur et un talon renforcé pour une sécurité maximale.<br data-start="837" data-end="840" />La semelle extérieure antidérapante assure une excellente adhérence, même sur sol mouillé.</p>\u000a<hr data-start="932" data-end="935" />\u000a<h2 data-start="937" data-end="974"><strong data-start="940" data-end="972">Caractéristiques principales</strong></h2>\u000a<ul data-start="975" data-end="1405">\u000a<li data-start="975" data-end="1023">\u000a<p data-start="977" data-end="1023"><strong data-start="977" data-end="997">Certification CE</strong> selon la norme EN 13634</p>\u000a</li>\u000a<li data-start="1024" data-end="1074">\u000a<p data-start="1026" data-end="1074"><strong data-start="1026" data-end="1044">Membrane D-WP®</strong> : imperméable et respirante</p>\u000a</li>\u000a<li data-start="1075" data-end="1146">\u000a<p data-start="1077" data-end="1146"><strong data-start="1077" data-end="1118">Construction en microfibre résistante</strong> à l’usure et à l’abrasion</p>\u000a</li>\u000a<li data-start="1147" data-end="1201">\u000a<p data-start="1149" data-end="1201"><strong data-start="1149" data-end="1172">Protections rigides</strong> : malléoles, talon, pointe</p>\u000a</li>\u000a<li data-start="1202" data-end="1250">\u000a<p data-start="1204" data-end="1250"><strong data-start="1204" data-end="1225">Renfort sélecteur</strong> pour préserver la tige</p>\u000a</li>\u000a<li data-start="1251" data-end="1309">\u000a<p data-start="1253" data-end="1309"><strong data-start="1253" data-end="1289">Semelle extérieure antidérapante</strong> pour plus de grip</p>\u000a</li>\u000a<li data-start="1310" data-end="1369">\u000a<p data-start="1312" data-end="1369"><strong data-start="1312" data-end="1325">Fermeture</strong> par lacets et patte à scratch de maintien</p>\u000a</li>\u000a<li data-start="1370" data-end="1405">\u000a<p data-start="1372" data-end="1405"><strong data-start="1372" data-end="1383">Couleur</strong> : Noir / Anthracite</p>\u000a</li>\u000a</ul>\u000a<hr data-start="1407" data-end="1410" />\u000a<h2 data-start="1412" data-end="1471"><strong data-start="1415" data-end="1469">Pourquoi choisir les Dainese ENERGICA D-WP Sport ?</strong></h2>\u000a<ul data-start="1472" data-end="1668">\u000a<li data-start="1472" data-end="1533">\u000a<p data-start="1474" data-end="1533"><strong data-start="1474" data-end="1499">Style sportif affirmé</strong> adapté à la route et à la ville</p>\u000a</li>\u000a<li data-start="1534" data-end="1565">\u000a<p data-start="1536" data-end="1565"><strong data-start="1536" data-end="1563">Protection certifiée CE</strong></p>\u000a</li>\u000a<li data-start="1566" data-end="1615">\u000a<p data-start="1568" data-end="1615"><strong data-start="1568" data-end="1585">100% étanches</strong> tout en restant respirantes</p>\u000a</li>\u000a<li data-start="1616" data-end="1668">\u000a<p data-start="1618" data-end="1668"><strong data-start="1618" data-end="1642">Confort longue durée</strong> même en usage quotidien</p>\u000a</li>\u000a</ul>\u000a'),unistr('<p>Chaussures de moto Dainese ENERGYCA D-WP Sport noir anthracite</p>\u000a'),52,753,2499.0,1799.0,NULL,NULL,'published','Chaussures de moto Dainese ENERGYCA D-WP Sport noir anthracite',unistr('<p>Chaussures de moto Dainese ENERGYCA D-WP Sport noir anthracite</p>\u000a'),478,'2026-06-20 14:09:14',0,1,0,0);
INSERT INTO products VALUES(317,'TCX Infinity 3 Gore-Tex® – Bottes Moto Adventure Hautes Performances Noires','bottes-moto-tcx-infinity-3-gore-tex-noir',unistr('<p data-start="225" data-end="560">Les <strong data-start="229" data-end="257">TCX Infinity 3 Gore-Tex®</strong> sont conçues pour les motards exigeants, adeptes de voyages longue distance, d’aventure et de tout-terrain.<br data-start="365" data-end="368" />Avec leur membrane <strong data-start="387" data-end="420">Gore-Tex® Performance Comfort</strong>, elles garantissent une étanchéité totale, une respirabilité optimale et un confort durable, quelles que soient les conditions climatiques.</p>\u000a<p data-start="562" data-end="894">Leur structure robuste offre une excellente protection grâce aux renforts au niveau du tibia, de la malléole, du talon et des orteils.<br data-start="696" data-end="699" />Le système de serrage <strong data-start="721" data-end="751">Double Flex Control System</strong> et la fermeture micrométrique <strong data-start="782" data-end="801">BOA® Fit System</strong> assurent un ajustement précis et un maintien parfait, même lors des utilisations intensives.</p>\u000a<p data-start="896" data-end="1052">La semelle <strong data-start="907" data-end="922">Groundtrax®</strong> est conçue pour offrir une adhérence exceptionnelle sur toutes les surfaces, qu’il s’agisse d’asphalte ou de terrains accidentés.</p>\u000a<hr data-start="1054" data-end="1057" />\u000a<h2 data-start="1059" data-end="1096"><strong data-start="1062" data-end="1094">Caractéristiques principales</strong></h2>\u000a<ul data-start="1097" data-end="1620">\u000a<li data-start="1097" data-end="1145">\u000a<p data-start="1099" data-end="1145"><strong data-start="1099" data-end="1119">Certification CE</strong> selon la norme EN 13634</p>\u000a</li>\u000a<li data-start="1146" data-end="1220">\u000a<p data-start="1148" data-end="1220"><strong data-start="1148" data-end="1190">Membrane Gore-Tex® Performance Comfort</strong> : imperméable et respirante</p>\u000a</li>\u000a<li data-start="1221" data-end="1295">\u000a<p data-start="1223" data-end="1295"><strong data-start="1223" data-end="1243">Système BOA® Fit</strong> + boucle micrométrique pour un ajustement parfait</p>\u000a</li>\u000a<li data-start="1296" data-end="1359">\u000a<p data-start="1298" data-end="1359"><strong data-start="1298" data-end="1323">Protections complètes</strong> : tibia, malléole, talon, orteils</p>\u000a</li>\u000a<li data-start="1360" data-end="1453">\u000a<p data-start="1362" data-end="1453"><strong data-start="1362" data-end="1392">Double Flex Control System</strong> : soutien de la cheville tout en conservant la flexibilité</p>\u000a</li>\u000a<li data-start="1454" data-end="1526">\u000a<p data-start="1456" data-end="1526"><strong data-start="1456" data-end="1479">Semelle Groundtrax®</strong> : adhérence optimale sur route et hors route</p>\u000a</li>\u000a<li data-start="1527" data-end="1597">\u000a<p data-start="1529" data-end="1597"><strong data-start="1529" data-end="1562">Semelle intérieure OrthoLite®</strong> : confort et amorti longue durée</p>\u000a</li>\u000a<li data-start="1598" data-end="1620">\u000a<p data-start="1600" data-end="1620"><strong data-start="1600" data-end="1611">Couleur</strong> : Noir</p>\u000a</li>\u000a</ul>\u000a<hr data-start="1622" data-end="1625" />\u000a<h2 data-start="1627" data-end="1683"><strong data-start="1630" data-end="1681">Pourquoi choisir les TCX Infinity 3 Gore-Tex® ?</strong></h2>\u000a<ul data-start="1684" data-end="1898">\u000a<li data-start="1684" data-end="1737">\u000a<p data-start="1686" data-end="1737"><strong data-start="1686" data-end="1708">Polyvalence totale</strong> : route, trail et aventure</p>\u000a</li>\u000a<li data-start="1738" data-end="1796">\u000a<p data-start="1740" data-end="1796"><strong data-start="1740" data-end="1768">Protection haut de gamme</strong> avec confort longue durée</p>\u000a</li>\u000a<li data-start="1797" data-end="1846">\u000a<p data-start="1799" data-end="1846"><strong data-start="1799" data-end="1816">100% étanches</strong> tout en restant respirantes</p>\u000a</li>\u000a<li data-start="1847" data-end="1898">\u000a<p data-start="1849" data-end="1898"><strong data-start="1849" data-end="1874">Ajustement sur mesure</strong> grâce au système BOA®</p>\u000a</li>\u000a</ul>\u000a'),unistr('<p>TCX Infinity 3 Gore-Tex® – Bottes Moto Adventure Hautes Performances Noires</p>\u000a'),52,770,5399.0,3299.0,NULL,NULL,'published','TCX Infinity 3 Gore-Tex® – Bottes Moto Adventure Hautes Performances Noires',unistr('<p>TCX Infinity 3 Gore-Tex® – Bottes Moto Adventure Hautes Performances Noires</p>\u000a'),483,'2026-06-20 14:09:15',0,1,0,0);
INSERT INTO products VALUES(318,'TCX IKASU – Sneakers moto certifiées pour un style urbain et une protection optimale','chaussures-moto-tcx-ikasu-wp',unistr('<p data-start="349" data-end="731">Les <strong data-start="353" data-end="366">TCX Ikasu</strong> réinventent la chaussure moto urbaine : l’allure décontractée d’une sneaker, alliée à la protection et à la certification nécessaires pour rouler en toute sécurité. Disponibles en version <strong data-start="555" data-end="562">Air</strong> pour les journées chaudes ou <strong data-start="592" data-end="598">WP</strong> avec membrane imperméable <strong data-start="625" data-end="635">T-DRY®</strong> pour affronter la pluie, elles s’adaptent à tous les trajets quotidiens, en ville comme à pied.</p>\u000a<p data-start="733" data-end="1127">Dotées d’inserts de protection <strong data-start="764" data-end="772">D3O®</strong> aux chevilles, d’un renfort sélecteur et d’une structure interne <strong data-start="838" data-end="849">Zplate®</strong> garantissant rigidité et confort, elles assurent un haut niveau de sécurité sans sacrifier le style.<br data-start="950" data-end="953" />La semelle extérieure <strong data-start="975" data-end="990">Groundtrax®</strong> offre une excellente adhérence, tandis que la semelle intérieure <strong data-start="1056" data-end="1070">OrthoLite®</strong> procure un amorti durable et une respirabilité optimale.</p>\u000a<hr data-start="1129" data-end="1132" />\u000a<h2 data-start="1134" data-end="1169"><strong data-start="1137" data-end="1169">Caractéristiques principales</strong></h2>\u000a<ul data-start="1170" data-end="1655">\u000a<li data-start="1170" data-end="1218">\u000a<p data-start="1172" data-end="1218"><strong data-start="1172" data-end="1192">Certification CE</strong> selon la norme EN 13634</p>\u000a</li>\u000a<li data-start="1219" data-end="1253">\u000a<p data-start="1221" data-end="1253"><strong data-start="1221" data-end="1241">Protections D3O®</strong> malléoles</p>\u000a</li>\u000a<li data-start="1254" data-end="1331">\u000a<p data-start="1256" data-end="1331"><strong data-start="1256" data-end="1277">Structure Zplate®</strong> : rigidité transversale + flexibilité longitudinale</p>\u000a</li>\u000a<li data-start="1332" data-end="1375">\u000a<p data-start="1334" data-end="1375"><strong data-start="1334" data-end="1346">Renforts</strong> sélecteur, talon et pointe</p>\u000a</li>\u000a<li data-start="1376" data-end="1417">\u000a<p data-start="1378" data-end="1417"><strong data-start="1378" data-end="1401">Semelle Groundtrax®</strong> antidérapante</p>\u000a</li>\u000a<li data-start="1418" data-end="1471">\u000a<p data-start="1420" data-end="1471"><strong data-start="1420" data-end="1442">Semelle OrthoLite®</strong> respirante et amortissante</p>\u000a</li>\u000a<li data-start="1472" data-end="1534">\u000a<p data-start="1474" data-end="1534"><strong data-start="1474" data-end="1487">Fermeture</strong> par lacets avec boucle élastique de maintien</p>\u000a</li>\u000a<li data-start="1535" data-end="1588">\u000a<p data-start="1537" data-end="1588"><strong data-start="1537" data-end="1552">Version Air</strong> : mesh respirant pour temps chaud</p>\u000a</li>\u000a<li data-start="1589" data-end="1655">\u000a<p data-start="1591" data-end="1655"><strong data-start="1591" data-end="1605">Version WP</strong> : membrane <strong data-start="1617" data-end="1627">T-DRY®</strong> imperméable et respirante</p>\u000a</li>\u000a</ul>\u000a<hr data-start="1657" data-end="1660" />\u000a<h2 data-start="1662" data-end="1701"><strong data-start="1665" data-end="1701">Pourquoi choisir les TCX Ikasu ?</strong></h2>\u000a<ul data-start="1702" data-end="1936">\u000a<li data-start="1702" data-end="1766">\u000a<p data-start="1704" data-end="1766"><strong data-start="1704" data-end="1713">Style</strong> : look sneaker moderne, utilisable aussi hors moto</p>\u000a</li>\u000a<li data-start="1767" data-end="1826">\u000a<p data-start="1769" data-end="1826"><strong data-start="1769" data-end="1784">Polyvalence</strong> : adaptées à la conduite et à la marche</p>\u000a</li>\u000a<li data-start="1827" data-end="1889">\u000a<p data-start="1829" data-end="1889"><strong data-start="1829" data-end="1841">Sécurité</strong> : protections certifiées et semelle technique</p>\u000a</li>\u000a<li data-start="1890" data-end="1936">\u000a<p data-start="1892" data-end="1936"><strong data-start="1892" data-end="1903">Confort</strong> : port prolongé sans inconfort</p>\u000a</li>\u000a</ul>\u000a<hr data-start="1938" data-end="1941" />\u000a<h2 data-start="1943" data-end="1966"><strong data-start="1946" data-end="1966">Appel à l’action</strong></h2>\u000a<p data-start="1967" data-end="2041"><strong data-start="1967" data-end="2041">Roulez avec style et sécurité – Adoptez les TCX Ikasu dès aujourd’hui.</strong></p>\u000a'),unistr('<p>TCX IKASU – Sneakers moto certifiées pour un style urbain et une protection optimale</p>\u000a'),52,770,1899.0,1399.0,NULL,NULL,'published','TCX IKASU – Sneakers moto certifiées pour un style urbain et une protection optimale',unistr('<p>TCX IKASU – Sneakers moto certifiées pour un style urbain et une protection optimale</p>\u000a'),87,'2026-06-20 14:09:15',0,0,0,0);
INSERT INTO products VALUES(319,'TCX INFINITY 3 WP – BOTTES MOTO IMPERMÉABLES TOURING & TRAIL BLACK','tcx-infinity-3-wp-bottes-moto-impermeables-touring',unistr('<p data-start="250" data-end="565">Conçues pour les motards exigeants, les bottes <strong data-start="297" data-end="318">TCX Infinity 3 WP</strong> offrent un équilibre parfait entre <strong data-start="354" data-end="392">protection, confort et performance</strong>, que ce soit sur route ou en dehors. Grâce à leur membrane <strong data-start="452" data-end="484">Gore-Tex Performance Comfort</strong>, elles assurent une <strong data-start="505" data-end="530">imperméabilité totale</strong> tout en laissant le pied respirer.</p>\u000a<p data-start="567" data-end="605">✅ <strong data-start="569" data-end="603">CARACTÉRISTIQUES PRINCIPALES :</strong></p>\u000a<ul data-start="606" data-end="918">\u000a<li data-start="606" data-end="697">\u000a<p data-start="608" data-end="697">Semelle <strong data-start="616" data-end="631">Groundtrax®</strong> en caoutchouc : adhérence optimale sur route et terrains légers</p>\u000a</li>\u000a<li data-start="698" data-end="773">\u000a<p data-start="700" data-end="773"><strong data-start="700" data-end="722">OrthoLite® footbed</strong> : confort longue durée, excellente respirabilité</p>\u000a</li>\u000a<li data-start="774" data-end="832">\u000a<p data-start="776" data-end="832">Inserts réfléchissants : <strong data-start="801" data-end="822">visibilité accrue</strong> de nuit</p>\u000a</li>\u000a<li data-start="833" data-end="918">\u000a<p data-start="835" data-end="918"><strong data-start="835" data-end="857">Bouclier thermique</strong> : protection contre la chaleur du moteur ou de l’échappement</p>\u000a</li>\u000a</ul>\u000a<p data-start="920" data-end="940">👖 <strong data-start="923" data-end="938">ERGONOMIE :</strong></p>\u000a<ul data-start="941" data-end="1066">\u000a<li data-start="941" data-end="1008">\u000a<p data-start="943" data-end="1008">Fermeture rapide avec molette micrométrique + bande <strong data-start="995" data-end="1006">Velcro®</strong></p>\u000a</li>\u000a<li data-start="1009" data-end="1066">\u000a<p data-start="1011" data-end="1066">Coupe adaptée pour être portée sous un pantalon touring</p>\u000a</li>\u000a</ul>\u000a<p data-start="1068" data-end="1102">🛡️ <strong data-start="1072" data-end="1100">MATÉRIAUX &amp; PROTECTION :</strong></p>\u000a<ul data-start="1103" data-end="1231">\u000a<li data-start="1103" data-end="1160">\u000a<p data-start="1105" data-end="1160">Cuir suédé, tissu technique et matériaux synthétiques</p>\u000a</li>\u000a<li data-start="1161" data-end="1231">\u000a<p data-start="1163" data-end="1231"><strong data-start="1163" data-end="1175">Renforts</strong> aux zones sensibles : tibia, malléole, orteils et talon</p>\u000a</li>\u000a</ul>\u000a<p data-start="1233" data-end="1275">🌧️ <strong data-start="1237" data-end="1273">UTILISATION PAR TOUS LES TEMPS :</strong></p>\u000a<ul data-start="1276" data-end="1357">\u000a<li data-start="1276" data-end="1357">\u000a<p data-start="1278" data-end="1357">Membrane <strong data-start="1287" data-end="1319">Gore-Tex Performance Comfort</strong> : pieds au sec, même sous forte pluie</p>\u000a</li>\u000a</ul>\u000a'),'',32,770,3199.0,1999.0,NULL,NULL,'published','TCX INFINITY 3 WP – BOTTES MOTO IMPERMÉABLES TOURING & TRAIL BLACK','TCX INFINITY 3 WP – BOTTES MOTO IMPERMÉABLES TOURING & TRAIL BLACK au Maroc. Achetez au meilleur prix chez MOTO PACO.',485,'2026-06-20 14:09:16',0,1,0,0);
INSERT INTO products VALUES(320,'TCX Infinity 3 WP – Bottes moto imperméables homme ultra résistantes – Noir / Vert militaire','botte-moto-tcx-infinity-3-wp',unistr('<h3 data-start="129" data-end="188"><strong data-start="133" data-end="188">TCX Infinity 3 WP – Bottes moto Adventure &amp; Touring</strong></h3>\u000a<p data-start="190" data-end="454">Affrontez toutes les conditions avec style et sécurité grâce aux bottes <strong data-start="262" data-end="283">TCX Infinity 3 WP</strong>, conçues pour les motards les plus exigeants. Pensées pour le voyage, l’aventure et les longues distances, elles allient robustesse, confort et protection sans compromis.</p>\u000a<h4 data-start="456" data-end="497">✅ <strong data-start="463" data-end="497">Caractéristiques principales :</strong></h4>\u000a<ul data-start="498" data-end="1161">\u000a<li data-start="498" data-end="620">\u000a<p data-start="500" data-end="620"><strong data-start="500" data-end="537">Construction en cuir pleine fleur</strong> de haute qualité, combinée à des inserts techniques pour une flexibilité optimale.</p>\u000a</li>\u000a<li data-start="621" data-end="703">\u000a<p data-start="623" data-end="703"><strong data-start="623" data-end="663">Membrane T-Dry étanche et respirante</strong>, idéale pour rouler par tous les temps.</p>\u000a</li>\u000a<li data-start="704" data-end="820">\u000a<p data-start="706" data-end="820"><strong data-start="706" data-end="758">Système de serrage micrométrique Fast Fit System</strong> avec molette (type Boa®) pour un ajustement précis et rapide.</p>\u000a</li>\u000a<li data-start="821" data-end="905">\u000a<p data-start="823" data-end="905"><strong data-start="823" data-end="846">Protection complète</strong> : renforts au niveau du tibia, malléoles, talon et pointe.</p>\u000a</li>\u000a<li data-start="906" data-end="1020">\u000a<p data-start="908" data-end="1020"><strong data-start="908" data-end="931">Semelle Groundtrax®</strong> antidérapante, conçue pour la stabilité sur tous les terrains et le confort à la marche.</p>\u000a</li>\u000a<li data-start="1021" data-end="1095">\u000a<p data-start="1023" data-end="1095"><strong data-start="1023" data-end="1065">Intérieur doublé et semelle Ortholite®</strong> pour un confort longue durée.</p>\u000a</li>\u000a<li data-start="1096" data-end="1161">\u000a<p data-start="1098" data-end="1161"><strong data-start="1098" data-end="1125">Homologation CE EN13634</strong> pour un niveau de sécurité optimal.</p>\u000a</li>\u000a</ul>\u000a<h4 data-start="1163" data-end="1187">🧭 <strong data-start="1171" data-end="1187">Idéal pour :</strong></h4>\u000a<ul data-start="1188" data-end="1299">\u000a<li data-start="1188" data-end="1227">\u000a<p data-start="1190" data-end="1227">Les aventuriers en quête de fiabilité</p>\u000a</li>\u000a<li data-start="1228" data-end="1258">\u000a<p data-start="1230" data-end="1258">Les motards touring ou trail</p>\u000a</li>\u000a<li data-start="1259" data-end="1299">\u000a<p data-start="1261" data-end="1299">Une utilisation mixte route / off-road</p>\u000a</li>\u000a</ul>\u000a'),unistr('<p>TCX Infinity 3 WP – Bottes moto imperméables homme ultra résistantes – Noir / Vert militaire</p>\u000a'),32,770,3299.0,1999.0,NULL,NULL,'published','TCX Infinity 3 WP – Bottes moto imperméables homme ultra résistantes – Noir / Vert militaire',unistr('<p>TCX Infinity 3 WP – Bottes moto imperméables homme ultra résistantes – Noir / Vert militaire</p>\u000a'),112,'2026-06-20 14:09:16',0,0,0,0);
INSERT INTO products VALUES(321,'AGV K6 S NARDO GREY - CASQUE MOTO INTÉGRAL E2206','agv-k6-s-nardo-grey-casque-moto-integral-e2206',unistr('<p>Toute la technologie développée pour les pilotes du MotoGP™ dans un casque parfait pour chaque usage sur route.</p>\u000a<p>Le K6 S est l''essence même de la polyvalence, conçu pour un maximum de performances. <strong>Adapté à tout type de conduite</strong> et à tout type de route, il réunit les meilleures caractéristiques du monde <strong>sportif et touring</strong> pour relever tous les défis sur deux-roues. Des virages sur les routes les plus sinueuses aux longs trajets, en passant par les déplacements quotidiens en ville.</p>\u000a<p>Sa calotte en <strong>fibre de carbone et d’aramide</strong> garantit une protection de premier plan et en fait <strong>le casque intégral routier le plus léger au monde.</strong> Grâce au strict protocole de conception Extreme Safety d''AGV, le K6 S dépasse largement tous les tests requis par la norme stricte <strong>ECE22.06</strong>, <strong>ce qui rend le casque </strong>36 % plus sûr par rapport aux niveaux requis par les homologations routières les plus modernes.</p>\u000a<p>Ses formes aérodynamiques développées en soufflerie sont optimisées pour une pénétration idéale de l’air <strong>dans toutes les positions de conduite</strong> : une solution qui permet de choisir librement son style, sans faire de compromis. Le <strong>spoiler aérodynamique</strong> évolue, pour fendre l’air et limiter les tremblements à vitesse de croisière. Un confort supérieur, pour éliminer les distractions et se concentrer uniquement sur la route et les obstacles, tout au long du trajet.</p>\u000a<p>L’<strong>intérieur premium</strong>, imperméable et respirant, est étudié pour parcourir des kilomètres à l’infini dans un confort absolu, pour ne penser qu’à la route devant soi. Ses <strong>prises d’air innovantes à l’avant</strong> et <strong>sur la </strong>mentonnière<strong> sont dessinées afin de moduler facilement la ventilation, </strong>même en portant des gants, et de toujours fournir l’aération souhaitée. L''intérieur de la mentonnière, large et confortable, est conçu pour une ventilation maximale avec les ventilations ouvertes.</p>\u000a'),'',53,1010,0.0,NULL,NULL,NULL,'published','AGV K6 S NARDO GREY - CASQUE MOTO INTÉGRAL E2206','AGV K6 S NARDO GREY - CASQUE MOTO INTÉGRAL E2206 au Maroc. Achetez au meilleur prix chez MOTO PACO.',114,'2026-06-20 14:09:17',0,0,0,0);
INSERT INTO products VALUES(322,'RayZR scooter','rayzr-scooter',unistr('<p>Bénéficier du <strong>meilleur</strong> <strong>rapport</strong> <strong>qualité</strong>-<strong>prix</strong> est plus important que jamais. Le scooter RayZR, aux lignes élancées, a été spécialement conçu par Yamaha pour offrir un moyen de transport urbain abordable et fiable, toujours prêt à démarrer.</p>\u000a<div class=" aem-GridColumn aem-GridColumn--tablet--8 aem-GridColumn--offset--tablet--0 aem-GridColumn--tablet--none aem-GridColumn--default--12 aem-GridColumn--offset--default--0 aem-GridColumn--default--none aem-GridColumn--phone--4 aem-GridColumn--offset--phone--0 aem-GridColumn--phone--none">\u000a<section class="styled__SectionWrapperStyled-sc-1b955xv-1" data-test-id="wrapper-component-default">\u000a<div class="styled__ContainerStyled-sc-1pg5x44-0 ixRWEV">\u000a<div class="Row-sc-1t8ifd-0 styled__RowStyled-sc-1g8uqrl-0 hIhdaX kIpBpQ">\u000a<div class="Col__CommonColStyled-sc-1vakr7x-0 Col-sc-1vakr7x-1 styled__ColStyled-sc-1g8uqrl-1 AibYF iiVLPN bVianP">\u000a<div class="flexTokens__FlexWrapper-sc-1jxq5qm-0 styled__FlexWrapperStyled-sc-1g8uqrl-2 kWJHgn gMFkgI">\u000a<div class="styled__ContainerStyled-sc-1pg5x44-0 kepCTr">\u000a<div class="Row-sc-1t8ifd-0 fugnom">\u000a<div class="Col__CommonColStyled-sc-1vakr7x-0 Col-sc-1vakr7x-1 erjcnc hqploJ">\u000a<h2 class="typography__HeadingLevel2-sc-17h5z1x-1 ecXnVa">Caractéristiques</h2>\u000a<div class="Row-sc-1t8ifd-0 fugnom">\u000a<div class="Col__CommonColStyled-sc-1vakr7x-0 Col-sc-1vakr7x-1 kvdvCf hqploJ"><button class="styled__MiniButtonStyled-sc-1rb21k9-0 nmbTt" tabindex="0" title="" type="button" aria-label="" data-testid="id_mini_button"><span class="styled__MiniButtonContent-sc-1rb21k9-1 hTzQdD">Télécharger la fiche produit</span></button></div>\u000a<div></div>\u000a</div>\u000a</div>\u000a</div>\u000a<div class="Row-sc-1t8ifd-0 hIhdaX">\u000a<div class="Col__CommonColStyled-sc-1vakr7x-0 Col-sc-1vakr7x-1 AibYF iiVLPN">\u000a<