INSERT INTO products VALUES(341,'Kenny Sacoche Tools – Sacoche Banane Porte-Outils','sacoche-banane-kenny-tools',unistr('<h3 class="" data-start="172" data-end="228">🧰 Sacoche Tools Kenny – Sacoche Banane Porte-Outils</h3>\u000a<p class="" data-start="230" data-end="509">Gardez vos outils essentiels toujours à portée de main avec la <strong data-start="293" data-end="316">Sacoche Tools Kenny</strong>, conçue pour les sorties tout-terrain en motocross, enduro ou VTT. Compacte, robuste et fonctionnelle, elle s’attache facilement à la taille et vous accompagne sans gêne sur tous les terrains.</p>\u000a<h4 class="" data-start="511" data-end="536">✅ Caractéristiques :</h4>\u000a<ul data-start="537" data-end="779">\u000a<li class="" data-start="537" data-end="588">\u000a<p class="" data-start="539" data-end="588">Compartiment principal zippé + poches secondaires</p>\u000a</li>\u000a<li class="" data-start="589" data-end="646">\u000a<p class="" data-start="591" data-end="646">Système de réglage rapide à la taille (velcro + boucle)</p>\u000a</li>\u000a<li class="" data-start="647" data-end="693">\u000a<p class="" data-start="649" data-end="693">Conception résistante pour un usage intensif</p>\u000a</li>\u000a<li class="" data-start="694" data-end="752">\u000a<p class="" data-start="696" data-end="752">Idéal pour transporter outils, clés, démonte-pneus, etc.</p>\u000a</li>\u000a<li class="" data-start="753" data-end="779">\u000a<p class="" data-start="755" data-end="779">Taille unique, ajustable</p>\u000a</li>\u000a</ul>\u000a'),'',51,890,599.0,599.0,NULL,NULL,'published','Kenny Sacoche Tools – Sacoche Banane Porte-Outils','Kenny Sacoche Tools – Sacoche Banane Porte-Outils au Maroc. Achetez au meilleur prix chez MOTO PACO.',146,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(342,'KENNY SAC A DOS HYDRATATION','kenny-sac-a-dos-hydratation-moto',unistr('<h3 class="" data-start="129" data-end="178">💧 Sac à Dos d’Hydratation – Léger &amp; Pratique</h3>\u000a<p class="" data-start="180" data-end="390">Restez hydraté en toutes circonstances avec ce <strong data-start="227" data-end="254">sac à dos d’hydratation</strong> compact et fonctionnel. Conçu pour le motocross, le VTT, la randonnée ou les sports outdoor, il combine légèreté, confort et autonomie.</p>\u000a<h4 class="" data-start="392" data-end="417">✅ Caractéristiques :</h4>\u000a<ul data-start="418" data-end="675">\u000a<li class="" data-start="418" data-end="484">\u000a<p class="" data-start="420" data-end="484">Compartiment principal avec poche à eau (2L )</p>\u000a</li>\u000a<li class="" data-start="485" data-end="529">\u000a<p class="" data-start="487" data-end="529">Système d’attache pour tuyau d’hydratation</p>\u000a</li>\u000a<li class="" data-start="530" data-end="592">\u000a<p class="" data-start="532" data-end="592">Bretelles réglables et dos matelassé pour un confort optimal</p>\u000a</li>\u000a<li class="" data-start="593" data-end="644">\u000a<p class="" data-start="595" data-end="644">Poches supplémentaires pour accessoires et outils</p>\u000a</li>\u000a<li class="" data-start="645" data-end="675">\u000a<p class="" data-start="647" data-end="675">Tissu résistant et déperlant</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="677" data-end="769">💡 <strong data-start="680" data-end="769">Idéal pour vos sorties sportives où l’hydratation est essentielle, sans encombrement.</strong></p>\u000a'),'',32,890,699.0,699.0,NULL,NULL,'published','KENNY SAC A DOS HYDRATATION','KENNY SAC A DOS HYDRATATION au Maroc. Achetez au meilleur prix chez MOTO PACO.',148,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(343,'GILET DE PROTECTION KENNY TRACK-adulte','gilet-de-protection-track-adulte',unistr('<h3 class="" data-start="183" data-end="225">🛡️ Gilet de Protection TRACK – Adulte</h3>\u000a<p class="" data-start="227" data-end="577">Conçu pour la pratique du motocross, de l’enduro ou du VTT, le gilet de protection TRACK offre une excellente sécurité sans compromettre le confort. Léger, respirant et ergonomique, il intègre une dorsale certifiée CE, des coques de protection et une ceinture lombaire ajustable. Idéal pour les pilotes recherchant un bon rapport protection/mobilité.</p>\u000a<p class="" data-start="579" data-end="645"> _Dorsale CE</p>\u000a<p class="" data-start="579" data-end="645">_ Respirant</p>\u000a<p class="" data-start="579" data-end="645"> _Ceinture velcro</p>\u000a<p class="" data-start="579" data-end="645"> _Tailles S à XXXL</p>\u000a'),'',55,890,990.0,990.0,NULL,NULL,'published','GILET DE PROTECTION KENNY TRACK-adulte','GILET DE PROTECTION KENNY TRACK-adulte au Maroc. Achetez au meilleur prix chez MOTO PACO.',136,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(344,'KENNY GILET DE PROTECTION PERFORMANCE','kenny-gilet-protection-performance',unistr('<h3 class="" data-start="111" data-end="153">Gilet de Protection Kenny PERFORMANCE+</h3>\u000a<p class="" data-start="155" data-end="425">Alliez <strong data-start="162" data-end="174">sécurité</strong>, <strong data-start="176" data-end="187">confort</strong> et <strong data-start="191" data-end="215">liberté de mouvement</strong> avec le gilet de protection Kenny PERFORMANCE+. Conçu pour les pratiques intensives comme le motocross, l’enduro ou le VTT, ce gilet offre une protection complète tout en garantissant une excellente ergonomie.</p>\u000a<h4 class="" data-start="427" data-end="448">✅ Points forts :</h4>\u000a<ul data-start="449" data-end="900">\u000a<li class="" data-start="449" data-end="556">\u000a<p class="" data-start="451" data-end="556"><strong data-start="451" data-end="482">Tissu extensible et ventilé</strong> : légèreté et respirabilité pour un confort optimal en toutes conditions.</p>\u000a</li>\u000a<li class="" data-start="557" data-end="665">\u000a<p class="" data-start="559" data-end="665"><strong data-start="559" data-end="584">Protections amovibles</strong> : faciles à retirer pour l’entretien, elles permettent un ajustement sur mesure.</p>\u000a</li>\u000a<li class="" data-start="666" data-end="750">\u000a<p class="" data-start="668" data-end="750"><strong data-start="668" data-end="708">Ceinture lombaire avec double velcro</strong> : maintien renforcé et ajustement précis.</p>\u000a</li>\u000a<li class="" data-start="751" data-end="900">\u000a<p class="" data-start="753" data-end="772"><strong data-start="753" data-end="770">Homologations</strong> :</p>\u000a<ul data-start="775" data-end="900">\u000a<li class="" data-start="775" data-end="833">\u000a<p class="" data-start="777" data-end="833">Dorsale certifiée EN 1621-2 (niveau 1 ou 2 selon modèle)</p>\u000a</li>\u000a<li class="" data-start="836" data-end="866">\u000a<p class="" data-start="838" data-end="866">Pectorale certifiée EN 14021</p>\u000a</li>\u000a<li class="" data-start="869" data-end="900">\u000a<p class="" data-start="871" data-end="900">Conforme aux normes CE et FFM</p>\u000a</li>\u000a</ul>\u000a</li>\u000a</ul>\u000a<h4 class="" data-start="902" data-end="921">📏 Tailles :</h4>\u000a<p class="" data-start="922" data-end="933">Du S au 3XL</p>\u000a'),'',37,890,1349.0,1349.0,NULL,NULL,'published','KENNY GILET DE PROTECTION PERFORMANCE','KENNY GILET DE PROTECTION PERFORMANCE au Maroc. Achetez au meilleur prix chez MOTO PACO.',136,'2026-06-20 14:09:20',0,0,0,0);
