INSERT INTO products VALUES(365,'Gants Hevik CALIFORNIA-R - Noir / Gris','vente-gants-hevik-california',unistr('<div class="mbz-accordion" data-v-e6b1c23a="">\u000a<div class="mbz-accordion-item mbz-accordion-item--opened mbz-accordion-item--should-rotate" data-v-e6b1c23a="" data-v-ce74b8f8="">\u000a<div class="mbz-accordion-item__content" data-v-ce74b8f8="">\u000a<div data-v-e6b1c23a="">\u000a<p>HEVIK vous propose son gant été CALIFORNIA-R :</p>\u000a</div>\u000a</div>\u000a</div>\u000a<div class="mbz-accordion-item mbz-accordion-item--opened mbz-accordion-item--should-rotate" data-v-e6b1c23a="" data-v-ce74b8f8="">\u000a<div class="mbz-accordion-item__header" data-v-ce74b8f8="">\u000a<div class="mbz-accordion-item__header__icon" data-v-ce74b8f8=""></div>\u000a</div>\u000a<div class="mbz-accordion-item__content" data-v-ce74b8f8="">\u000a<div data-v-e6b1c23a="">\u000a<ul>\u000a<li>En polyester pour sa résistance</li>\u000a<li>En Clarino pour une résistance accrue à l''abrasion et aux déchirements</li>\u000a<li>Inserts en Mesh 3D pour un flux d''air optimisé</li>\u000a</ul>\u000a</div>\u000a</div>\u000a</div>\u000a<div class="mbz-accordion-item mbz-accordion-item--opened mbz-accordion-item--should-rotate" data-v-e6b1c23a="" data-v-ce74b8f8="">\u000a<div class="mbz-accordion-item__header" data-v-ce74b8f8="">\u000a<div class="mbz-accordion-item__header__icon" data-v-ce74b8f8=""></div>\u000a</div>\u000a<div class="mbz-accordion-item__content" data-v-ce74b8f8="">\u000a<div data-v-e6b1c23a="">\u000a<ul>\u000a<li>Inserts en polycarbonate sur les articulations homologuées CE</li>\u000a<li>Coussinets EVA sur les doigts homologués CE</li>\u000a<li>Renfort sur la paume</li>\u000a</ul>\u000a</div>\u000a</div>\u000a</div>\u000a<div class="mbz-accordion-item mbz-accordion-item--opened mbz-accordion-item--should-rotate" data-v-e6b1c23a="" data-v-ce74b8f8="">\u000a<div class="mbz-accordion-item__header" data-v-ce74b8f8="">\u000a<div class="mbz-accordion-item__header__icon" data-v-ce74b8f8=""></div>\u000a</div>\u000a<div class="mbz-accordion-item__content" data-v-ce74b8f8="">\u000a<div data-v-e6b1c23a="">\u000a<ul>\u000a<li>Poignets en Néopréne pour un ajustement parfait</li>\u000a<li>Patte de serrage auto-agrippant</li>\u000a<li>Touch Screen Compatible pour une utilisation de vos écrans tactiles sans ôter vos gants</li>\u000a<li>Inserts réfléchissants pour une visibilité accrue</li>\u000a<li>Inserts auto-agrippants sur les doigts et la paume</li>\u000a</ul>\u000a</div>\u000a</div>\u000a</div>\u000a</div>\u000a<div class="product-features__bg-block" data-v-e6b1c23a="">\u000a<h3 class="product-features__bg-block__heading" data-v-e6b1c23a=""><span class="visible-md-up" data-v-e6b1c23a="">INFORMATIONS</span> COMPLÉMENTAIRES :</h3>\u000a<div data-v-e6b1c23a="">\u000a<p>Certifiés CE EN13594 niveau 1</p>\u000a<div class="technical-features__container" data-v-dbf31c40="">\u000a<div class="technical-features-item" data-v-dbf31c40="" data-v-19883ddc="">\u000a<div class="technical-features-item__value" data-v-19883ddc="">\u000a<div class="technical-features__heading" data-v-dbf31c40="">INFORMATIONS TECHNIQUES <span class="visible-md-up" data-v-dbf31c40="">:</span></div>\u000a<div class="technical-features__container" data-v-dbf31c40="">\u000a<div class="technical-features-item" data-v-dbf31c40="" data-v-19883ddc="">\u000a<div class="technical-features-item__name" data-v-19883ddc="">Référence</div>\u000a<div class="technical-features-item__value" data-v-19883ddc="">HEV0065</div>\u000a</div>\u000a<div class="technical-features-item" data-v-dbf31c40="" data-v-19883ddc="">\u000a<div class="technical-features-item__name" data-v-19883ddc="">Genre</div>\u000a<div class="technical-features-item__value" data-v-19883ddc="">Homme</div>\u000a</div>\u000a<div class="technical-features-item" data-v-dbf31c40="" data-v-19883ddc="">\u000a<div class="technical-features-item__name" data-v-19883ddc="">Saisonnalité</div>\u000a<div class="technical-features-item__value" data-v-19883ddc="">été</div>\u000a</div>\u000a<div class="technical-features-item" data-v-dbf31c40="" data-v-19883ddc="">\u000a<div class="technical-features-item__name" data-v-19883ddc="">Niveau de certification</div>\u000a<div class="technical-features-item__value" data-v-19883ddc="">1</div>\u000a</div>\u000a<div class="technical-features-item" data-v-dbf31c40="" data-v-19883ddc="">\u000a<div class="technical-features-item__name" data-v-19883ddc="">Protection phalanges</div>\u000a<div class="technical-features-item__value" data-v-19883ddc="">Oui (coqués)</div>\u000a</div>\u000a<div class="technical-features-item" data-v-dbf31c40="" data-v-19883ddc="">\u000a<div class="technical-features-item__name" data-v-19883ddc="">Renfort paume</div>\u000a<div class="technical-features-item__value" data-v-19883ddc="">Oui</div>\u000a</div>\u000a<div class="technical-features-item" data-v-dbf31c40="" data-v-19883ddc="">\u000a<div class="technical-features-item__name" data-v-19883ddc="">Serrage poignet</div>\u000a<div class="technical-features-item__value" data-v-19883ddc="">Oui</div>\u000a</div>\u000a</div>\u000a</div>\u000a</div>\u000a</div>\u000a</div>\u000a</div>\u000a'),'',54,13,449.0,449.0,NULL,NULL,'published','Gants Hevik CALIFORNIA-R - Noir / Gris','Gants Hevik CALIFORNIA-R - Noir / Gris au Maroc. Achetez au meilleur prix chez MOTO PACO.',90,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(366,'Blouson Hevik Asterope gris','hevik-asterope-homme-hevik-asterope-veste-moto-homme-hiver-entre-saison-scooter-urbain-thermique-impermeable',unistr('<h3 class="MuiTypography-root MuiTypography-h3 MuiTypography-gutterBottom __className_7f5e9f css-8ly3f5">Blouson moto polyvalent homologué Hevik Asterope. Il offre une doublure intérieure fixe imperméable et une doublure thermique amovible, il comprend également quatre grandes poches fermées par des boutons, une poche Napoléon et deux poches intérieures supplémentaires.</h3>\u000a<div class="MuiPaper-root MuiPaper-elevation MuiPaper-rounded MuiPaper-elevation0 css-1cy6hzb">\u000a<div class="MuiBox-root css-0">\u000a<p>La <strong>firme italienne Hevik,</strong> spécialisée dans le développement d'' <strong>équipements pour motards</strong> , a pris soin de confectionner un vêtement confortable qui permet une liberté de mouvement lors de la conduite de votre moto. <strong>Veste de moto Hevik Asterope,</strong> intègre des protections des coudes et des épaules approuvées selon la réglementation et la prédisposition <strong>CE EN 1621-1 2012 niveau 1</strong>protection <strong>dorsale homologuée CE</strong> (en option).</p>\u000a<p>Caractéristiques:</p>\u000a<ul>\u000a<li>Fabriqué en <strong>100 % polyester</strong></li>\u000a<li><strong>Doublure thermique amovible</strong></li>\u000a<li>Revêtement <strong>imperméable</strong> fixe</li>\u000a<li>Ajustements de taille entièrement réglables</li>\u000a<li>4 poches extérieures, 2 poches intérieures et 1 poche napoléon</li>\u000a<li>Protections CE sur les épaules et les coudes <strong>EN 1621-1 2012 Niveau 1</strong></li>\u000a<li><strong>Veste certifiée</strong> selon <strong>EN 17092 : 2020 classe A</strong></li>\u000a<li>compartiment <strong> </strong> pour protection dorsale HFB et HCB <strong>homologuée CE</strong> (non incluse)</li>\u000a</ul>\u000a</div>\u000a</div>\u000a'),'',55,13,1999.0,1999.0,NULL,NULL,'published','Blouson Hevik Asterope gris','Blouson Hevik Asterope gris au Maroc. Achetez au meilleur prix chez MOTO PACO.',96,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(367,'Sac Étanche GIVI EA115GR 40 Litres CAMO GRIS JAUNE','sac-givi-arriere-etanche-40l',unistr('<p>En termes de modèle, ce nouveau Easy-T est un sac traditionnel, dont l’ouverture se fait sur toute la longueur et pas seulement à une extrémité. Ce sac peut être fixé aussi bien sur la selle du passager, que sur le porte-bagages ou sur le porte-valises. Peu importe. Cette variante kaki est un espace de rangement cylindrique, étanche et non compartimenté qui s’attache aisément.<br />\u000aDans cette version, vous pouvez ranger sans problème un sac de couchage (ou deux) et quelques vêtements supplémentaires, sa capacité est de 40 litres. Tout reste au sec grâce à la combinaison de matière PVC Tarpaulin, aux coutures soudées et à la fermeture roll-up complétée de Velcro. La présence d’une double poignée et d’une bandoulière fournie d’origine permettent de déplacer ce sac facilement et de manière pratique lors d’une étape ou à la destination finale.<br />\u000aCe modèle a une capacité de 40 litres pour des dimensions de 50 cm x 30 cm x 30 cm.<br />\u000aCe sac Givi de 40 litres est livré avec deux tendeurs aux crochets plastifiés pour un montage en toute sécurité.</p>\u000a<h2>Spécification technique</h2>\u000a<div class="part_content padv_bottom">\u000a<table class="keyvalue">\u000a<tbody>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Dimensions</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Volume en litres</td>\u000a<td class="value ">40</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Dimensions en cm (Largeur x Profondeur x Hauteur)</td>\u000a<td class="value ">50 x 30 x 30</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Contenu</td>\u000a<td class="value ">31 - 40 L</td>\u000a</tr>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Caractéristiques</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Étanche</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Matière</td>\u000a<td class="value ">Tarpaulin/PVC</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Bandoulière</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Bandes réfléchissantes</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Poignée</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Éléments de fixation inclus</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Code barres</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">EAN</td>\u000a<td class="value ">8019606210111</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">MPN</td>\u000a<td class="value ">EA115BK</td>\u000a</tr>\u000a</tbody>\u000a</table>\u000a</div>\u000a'),'',51,756,750.0,750.0,NULL,NULL,'published','Sac Étanche GIVI EA115GR 40 Litres CAMO GRIS JAUNE','Sac Étanche GIVI EA115GR 40 Litres CAMO GRIS JAUNE au Maroc. Achetez au meilleur prix chez MOTO PACO.',107,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(368,'Sac étanche GIVI EA115GR 40 Litres Noir Rouge','sac-arriere-etanch-givi',unistr('<h2>Description</h2>\u000a<div class="part_content padv_half_bottom">\u000a<article class="rt">\u000a<div class="fade_collaps opened">\u000a<div class="collaps_inner">\u000a<p>En termes de modèle, ce nouveau Easy-T est un sac traditionnel, dont l’ouverture se fait sur toute la longueur et pas seulement à une extrémité. Ce sac peut être fixé aussi bien sur la selle du passager, que sur le porte-bagages ou sur le porte-valises. Peu importe. Cette variante kaki est un espace de rangement cylindrique, étanche et non compartimenté qui s’attache aisément.<br />\u000aDans cette version, vous pouvez ranger sans problème un sac de couchage (ou deux) et quelques vêtements supplémentaires, sa capacité est de 40 litres. Tout reste au sec grâce à la combinaison de matière PVC Tarpaulin, aux coutures soudées et à la fermeture roll-up complétée de Velcro. La présence d’une double poignée et d’une bandoulière fournie d’origine permettent de déplacer ce sac facilement et de manière pratique lors d’une étape ou à la destination finale.<br />\u000aCe modèle a une capacité de 40 litres pour des dimensions de 50 cm x 30 cm x 30 cm.<br />\u000aCe sac Givi de 40 litres est livré avec deux tendeurs aux crochets plastifiés pour un montage en toute sécurité.</p>\u000a<h2>Spécification technique</h2>\u000a<div class="part_content padv_bottom">\u000a<table class="keyvalue">\u000a<tbody>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Dimensions</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Volume en litres</td>\u000a<td class="value ">40</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Dimensions en cm (Largeur x Profondeur x Hauteur)</td>\u000a<td class="value ">50 x 30 x 30</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Contenu</td>\u000a<td class="value ">31 - 40 L</td>\u000a</tr>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Caractéristiques</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Étanche</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Matière</td>\u000a<td class="value ">Tarpaulin/PVC</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Bandoulière</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Bandes réfléchissantes</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Poignée</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Éléments de fixation inclus</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Code barres</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">EAN</td>\u000a<td class="value ">8019606210111</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">MPN</td>\u000a<td class="value ">EA115BK</td>\u000a</tr>\u000a</tbody>\u000a</table>\u000a</div>\u000a</div>\u000a</div>\u000a</article>\u000a</div>\u000a'),'',51,756,750.0,750.0,NULL,NULL,'published','Sac étanche GIVI EA115GR 40 Litres Noir Rouge','Sac étanche GIVI EA115GR 40 Litres Noir Rouge au Maroc. Achetez au meilleur prix chez MOTO PACO.',482,'2026-06-20 14:09:20',0,1,0,0);
INSERT INTO products VALUES(369,'GIVI GRT724 Sac rouleau Canyon 12l Noir','sac-givi-canyon-rouleau',unistr('<div id="beschrijving" class="padv_top">\u000a<div class="part_content padv_half_bottom">\u000a<article class="rt">\u000a<div class="fade_collaps opened">\u000a<div class="collaps_inner">\u000a<p>Le nom « Canyon » est assez révélateur : il s’agit d’aventure ici. Ce sac rouleau de 12 litres est donc un touche-à-tout que vous pouvez combiner.</p>\u000a<p>Cela ouvre deux portes : utilisez ce sac rouleau comme compagnon d’aventure sur l’enduro pendant la sortie du week-end, ou transformez-le en un sac supplémentaire de 12 litres en plus de vos options de bagage existantes.<br />\u000aLe Canyon est un sac rouleau à deux ouvertures. Un sac sans fausse prétention... Le matériau utilisé est le TPU (plastique) 840D, qui constitue une double couche résistante à l’usure et aux déchirures. Résistant aux UV, avec des coutures soudées, imperméable et équipé de sangles de fixation avec des boulons à came de Duraflex<sup>®</sup> qui assurent la bonne tension : la liste de nouveautés techniques est assez impressionnante. Tous les matériaux sont fabriqués conformément à la norme <a title="Plus d''infos sur REACH" href="https://www.rad.eu/fr/concepts/reach-28.html" target="_blank" rel="noopener">REACH</a>.</p>\u000a<p>La double fermeture avec velcro équipée du système roll-up est la meilleure fermeture possible dans ce domaine et donne accès à un compartiment de rangement central. Ce modèle a une capacité de 12 litres pour des dimensions de 50 cm x 20 cm x 12 cm.</p>\u000a<p>Grâce à la bandoulière réglable (avec rembourrage) et à la poignée ergonomique, vous avez beaucoup d’options. Les sangles réglables avec des clips constituent le principal lien avec la moto. Des matériaux de fixation supplémentaires sont bien sûr toujours disponibles. Pour ceux qui savent et peuvent l’utiliser, le système ‘MOLLE’ (« <em>Modular Lightweight Load-carrying Equipment</em> ») est très pratique : c’est un système de portage léger et modulaire pour les aventuriers d’entre nous.</p>\u000a<p>Pour augmenter votre visibilité de nuit, le Canyon Cargo est doté de détails réfléchissants.</p>\u000a<p>Que vous utilisiez le sac rouleau Canyon <a href="https://www.rad.eu/fr/c/p/73968-givi-grt724-sac-rouleau-canyon-12l-noir.htm" target="_blank" rel="noopener">GRT724</a> avec un sac moto souple tel que le <a href="https://www.rad.eu/fr/c/p/73969-givi-grt723-canyon-monokey-noir.htm" target="_blank" rel="noopener">GRT723</a> <a title="Plus d''infos sur Monokey" href="https://www.rad.eu/fr/concepts/monokey-19.html" target="_blank" rel="noopener">Monokey</a><sup>®</sup>, que vous le fixiez comme charge supplémentaire à la base universelle <a href="https://www.rad.eu/fr/c/p/67223-givi-grt721-base-base.htm" target="_blank" rel="noopener">GRT721</a> Canyon, ou que vous le placiez simplement au-dessus d’un ensemble de valises latérales en aluminium dur – ce sac se prête à tout, et est prêt à tout.</p>\u000a<p>La collection Canyon de GIVI, récemment renouvelée, est un peu plus axée sur l’offroad et l’enduro, mais vous pouvez bien sûr l’utiliser là où vous la trouvez la mieux adaptée. Le principe est presque le même pour tous les modèles : un espace de stockage cylindrique étanche avec fermeture à enroulement qui est flexible et adaptable. Et donc énormément pratique sur n’importe quelle moto.</p>\u000a</div>\u000a<p><a class="open_fade_collaps"><i class="minus icon"></i> <span data-more="En savoir plus" data-less="Montrer moins">Montrer moins</span></a></div>\u000a</article>\u000a</div>\u000a</div>\u000a<div id="specificaties" class="padv_top">\u000a<h2>Spécification technique</h2>\u000a<div class="part_content padv_bottom">\u000a<table class="keyvalue">\u000a<tbody>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Dimensions</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Volume en litres</td>\u000a<td class="value ">12</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Dimensions en cm (Largeur x Profondeur x Hauteur)</td>\u000a<td class="value ">50 x 20 x 12</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Contenu</td>\u000a<td class="value ">11 - 20 L</td>\u000a</tr>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Caractéristiques</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Étanche</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Matière</td>\u000a<td class="value ">TPU 840D</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Bandoulière</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Bandes réfléchissantes</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Poignée</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Éléments de fixation inclus</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Code barres</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">EAN</td>\u000a<td class="value ">8019606307606</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">MPN</td>\u000a<td class="value ">GRT724</td>\u000a</tr>\u000a</tbody>\u000a</table>\u000a</div>\u000a</div>\u000a'),'',51,756,1099.0,1099.0,NULL,NULL,'published','GIVI GRT724 Sac rouleau Canyon 12l Noir','GIVI GRT724 Sac rouleau Canyon 12l Noir au Maroc. Achetez au meilleur prix chez MOTO PACO.',101,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(370,'GIVI Sac à dos Urban EA129B 15L','sac-a-dos-moto',unistr('<div id="beschrijving" class="padv_top">\u000a<div class="part_content padv_half_bottom">\u000a<article class="rt">\u000a<div class="fade_collaps opened">\u000a<div class="collaps_inner">\u000a<p>Le sac à dos Urban de GIVI est un compagnon polyvalent, tant à moto qu’ailleurs, et présente le côté pratique du polyester. Petit mais vaillant. Avec une housse de protection et une pochette pour un ordinateur portable de 15 pouces.</p>\u000a<p>Au sujet de l’ordinateur portable : GIVI prétend pouvoir y ranger un ordinateur portable de 17 pouces. Après une phase de test approfondie, nous maintenons nos 15 pouces.</p>\u000a<p>Ce sac à dos urbain, d’une capacité de 15 litres, est un ‘long étroit’, qui, grâce à une bande de fixation à l’arrière, peut être placé sans problème sur un trolley. Pour tout vous dire : à la maison, à moto ou en avion.</p>\u000a<p>Le principal matériau utilisé est du 600D, avec une finition réfléchissante noir mat et des touches de jaune fluo. Une base solide, renforcée par l’espace de rangement externe préformé ‘thermoformé’. Parfait pour y ranger de fragiles lunettes solaires. Ce premier compartiment externe se prolonge sur toute la longueur, jusqu’en bas, donc, pourquoi se limiter simplement aux lunettes solaires ? Sur ce sac à dos Urban, tout, ou presque, se referme au moyen de tirettes.</p>\u000a<p>Un deuxième et un troisième compartiment complètent les 15 litres. Tous deux sont partiellement structurés, ce qui permet de ranger l’ordinateur portable de 15 pouces ou la tablette à l’endroit le plus approprié. Une pochette latérale – munie d’une tirette également – offre d’autres options. Il y a donc de quoi faire avec ce sac à dos que vous pouvez également poser sur un trolley.</p>\u000a<p>Il est pratique et même, très pratique. Son profil ‘long et étroit’ y contribue sans nul doute, tout comme ses bandoulières ergonomiques. Réglable, avec une douce finition, pourvu d’une sangle de torse, comme l’on peut s’y attendre de tout sac à dos. Il ne s’attache toutefois pas autour de la taille.</p>\u000a<p>Une poignée, la possibilité de fixer ou d’attacher le contenu avec de petites sangles et sa housse protection sont des atouts supplémentaires.</p>\u000a</div>\u000a<p><a class="open_fade_collaps"><i class="minus icon"></i> <span data-more="En savoir plus" data-less="Montrer moins">Montrer moins</span></a></p>\u000a</div>\u000a</article>\u000a</div>\u000a</div>\u000a<div id="specificaties" class="padv_top">\u000a<h2>Spécification technique</h2>\u000a<div class="part_content padv_bottom">\u000a<table class="keyvalue">\u000a<tbody>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Dimensions</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Contenu</td>\u000a<td class="value ">11 - 20 L</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Volume en litres</td>\u000a<td class="value ">15</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Dimensions en cm (Largeur x Profondeur x Hauteur)</td>\u000a<td class="value ">30 x 20 x 49</td>\u000a</tr>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Caractéristiques</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Étanche</td>\u000a<td class="value "><i class="green check icon"></i> oui (housse pluie fourni)</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Matière réfléchissante</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Ceinture ajustable</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Sangle de poitrine</td>\u000a<td class="value "><i class="green check icon"></i> oui</td>\u000a</tr>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Poches de rangement</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Pochette PC portable</td>\u000a<td class="value "><i class="green check icon"></i> oui, jusqu''à 15 pouces</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">Porte-casque</td>\u000a<td class="value "><i class="red remove circle icon"></i> non</td>\u000a</tr>\u000a<tr class="row_title">\u000a<td class="font_medium" colspan="2">Code barres</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">EAN</td>\u000a<td class="value ">8019606323743</td>\u000a</tr>\u000a<tr>\u000a<td class="key ">MPN</td>\u000a<td class="value ">EA129B</td>\u000a</tr>\u000a</tbody>\u000a</table>\u000a</div>\u000a</div>\u000a'),'',51,756,899.0,899.0,NULL,NULL,'published','GIVI Sac à dos Urban EA129B 15L','GIVI Sac à dos Urban EA129B 15L au Maroc. Achetez au meilleur prix chez MOTO PACO.',85,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(371,'Sac à dos moto technique Givi EASY-T EA148 Noir Fermeture Roll Top 20 lt','motocycle-backpack',unistr('<p>20 litres.</p>\u000a<p><strong>Fiche technique:</strong></p>\u000a<ul>\u000a<li>Gamme : EASY-T</li>\u000a<li>Dimensions : 480 x 260 x 160 mm</li>\u000a<li>Capacité : 20 Litres</li>\u000a</ul>\u000a<p>Matériaux:</p>\u000a<ul>\u000a<li>Polyester 600D et polyester laminé PU</li>\u000a<li>Inserts en PU et passepoil réfléchissant jaune fluo</li>\u000a<li>Tous les matériaux sont fabriqués conformément à la réglementation REACH.</li>\u000a</ul>\u000a<p>Équipement:</p>\u000a<ul>\u000a<li>Système de fermeture à retournement pour assurer l''étanchéité du sac</li>\u000a<li>Doublure intérieure étanche à haute fréquence (indice d''étanchéité IPX5, résiste aux fortes pluies et aux conditions extrêmes)</li>\u000a<li>Poche frontale avec porte-clés intégré</li>\u000a<li>2 poches latérales, 1 avec zip et 1 avec filet élastique</li>\u000a<li>Poche interne pour ordinateur portable, jusqu''à 17"</li>\u000a<li>Dos rembourré pour plus de confort</li>\u000a<li>Bretelles rembourrées ergonomiques pour plus de confort</li>\u000a<li>Poignée pour porter à la main</li>\u000a<li>Ceinture de sécurité rétractable à la taille;</li>\u000a<li>Imprimés et inserts réfléchissants pour une meilleure visibilité</li>\u000a</ul>\u000a'),'',51,756,899.0,899.0,NULL,NULL,'published','Sac à dos moto technique Givi EASY-T EA148 Noir Fermeture Roll Top 20 lt','Sac à dos moto technique Givi EASY-T EA148 Noir Fermeture Roll Top 20 lt au Maroc. Achetez au meilleur prix chez MOTO PACO.',147,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(372,'DAINESE Genouillères Knee V E1','protege-genou',unistr('<p><strong>Genouillères Dainese V1 (gauche et droite). </strong>Protections composites certifiées CE-Lev.II-EN 1621.1. Ils protègent le genou et le tibia. Avec plaques perforées en polypropylène, partiellement superposées. Structure intérieure double couche en polyamide, élasthanne et polyuréthane. Sangles Velcro extensibles pour un ajustement parfait.</p>\u000a'),'',1,753,890.0,580.0,NULL,NULL,'published','DAINESE Genouillères Knee V E1','DAINESE Genouillères Knee V E1 au Maroc. Achetez au meilleur prix chez MOTO PACO.',145,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(373,'TCX RO4D WP boots BLACK','tcx-ro4d-wp-boots-black',unistr('<p>Light, direct, safe - that''s the sort of road feel you know you''re going to get with TCX Ro4d WP motorcycle boots the moment you see them. And when you actually wear them, it''s even better. Ro4d WP boots have laces and and hook-and-loop fastening, which makes them very easy to adjust, while the WP version with T-Dry membrane is also waterproof. Sporty and chic - the TCX Ro4d WP is incredibly popular among fans of ankle boots!</p>\u000a<p>TCX R04D WP are waterproof motorcycle shoes that guarantee certified protection, versatility and comfort suited to prolonged use. The T-DRY waterproof membrane ensures perfect protection against water and atmospheric agents, for perfectly comfortable feet in all conditions. The microfiber upper guarantees great sensitivity for riding and a precise fit. R04D WP is laced, with gaiter and Velcro for adjusting the collar area and, for maximum safety, the Bycast leather lever guard and the reflective element on the back. Protection is ensured by the D3O® inserts on the ankle and reinforcements on the toe, heel and gear area. TCX RO4D WP shoes incorporate the OrthoLite® insole for long-lasting cushioning and high breathability, the Groundtrax® sole made of wear-resistant rubber, ensuring maximum grip, sensitivity and comfort suited to a motorcycle shoe to be worn all day, while the upper is made of mesh fabric with hot melt coating.</p>\u000a<p><strong>BENEFITS</strong></p>\u000a<ul>\u000a<li>Lightness and riding sensibility</li>\u000a<li>Riding comfort</li>\u000a<li>Waterproof</li>\u000a</ul>\u000a<p><strong>TECHNICAL FEATURES</strong></p>\u000a<ul>\u000a<li>Mesh upper with hot melt coating</li>\u000a<li>Bycast shift pad</li>\u000a<li>Rear reflective inserts for high visibility</li>\u000a<li>D3O ankle reinforcements</li>\u000a<li>Reinforcements on toe and heel</li>\u000a<li>T Dry waterproof membrane</li>\u000a<li>Fastening with laces and Velcro</li>\u000a<li>Gaitor to store the laces</li>\u000a<li>OrthoLite® footbed with long term cushioning and high levels of breathability</li>\u000a<li>New Groundtrax® rubber outsole for sport riding.</li>\u000a</ul>\u000a'),'',52,770,0.0,NULL,NULL,NULL,'published','TCX RO4D WP boots BLACK','TCX RO4D WP boots BLACK au Maroc. Achetez au meilleur prix chez MOTO PACO.',79,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(374,'AGV K1 S MATT BLACK - CASQUE MOTO INTÉGRAL E2206','casque-agv-k1s-noir-matt',unistr('<h3 data-start="0" data-end="73"><strong data-start="4" data-end="71">Casque AGV K1 S Noir Matt – Performance et Sécurité pour les Motards</strong></h3>\u000a<p data-start="75" data-end="378">Le <strong data-start="78" data-end="95">AGV K1 S Noir</strong> est un casque intégral conçu pour offrir un équilibre parfait entre <strong data-start="164" data-end="202">sécurité, confort et aérodynamisme</strong>. Inspiré des technologies développées en MotoGP, il est idéal pour les motards recherchant un <strong data-start="297" data-end="329">casque sportif et polyvalent</strong>, adapté aussi bien à la route qu’aux circuits.</p>\u000a<h4 data-start="380" data-end="409"><strong data-start="385" data-end="407">Caractéristiques :</strong></h4>\u000a<p data-start="410" data-end="925">✔ <strong data-start="412" data-end="457">Coque en thermoplastique haute résistance</strong> pour une protection optimale.<br data-start="487" data-end="490" />✔ <strong data-start="492" data-end="518">Aérodynamisme optimisé</strong> avec spoiler intégré pour une meilleure stabilité à grande vitesse.<br data-start="586" data-end="589" />✔ <strong data-start="591" data-end="639">Visière anti-rayures et prédisposée Pinlock®</strong> pour une vision claire en toutes conditions.<br data-start="684" data-end="687" />✔ <strong data-start="689" data-end="712">Ventilation avancée</strong> avec entrées d’air multiples pour un flux d’air maximal.<br data-start="769" data-end="772" />✔ <strong data-start="774" data-end="818">Intérieur en tissu respirant et amovible</strong>, lavable pour un confort durable.<br data-start="852" data-end="855" />✔ <strong data-start="857" data-end="884">Fermeture micrométrique</strong> pour un ajustement précis et sécurisé.</p>\u000a<h3 data-start="927" data-end="971"><strong data-start="931" data-end="969">Pourquoi choisir l’AGV K1 S Noir ?</strong></h3>\u000a<ul data-start="972" data-end="1151">\u000a<li data-start="972" data-end="1021">Design agressif et sportif inspiré du MotoGP.</li>\u000a<li data-start="1022" data-end="1087">Léger, confortable et conçu pour une utilisation quotidienne.</li>\u000a<li data-start="1088" data-end="1151">Excellente ventilation pour un confort optimal même en été.</li>\u000a</ul>\u000a<p data-start="1153" data-end="1230"><strong data-start="1153" data-end="1228">Optez pour la performance et la sécurité avec le casque AGV K1 S Noir !</strong></p>\u000a<p data-start="1232" data-end="1264" data-is-last-node="" data-is-only-node="">➡ <strong data-start="1234" data-end="1264" data-is-last-node="">Commandez dès maintenant !</strong></p>\u000a'),'',53,1010,2899.0,2199.0,NULL,NULL,'published','AGV K1 S MATT BLACK - CASQUE MOTO INTÉGRAL E2206','AGV K1 S MATT BLACK - CASQUE MOTO INTÉGRAL E2206 au Maroc. Achetez au meilleur prix chez MOTO PACO.',78,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(375,'AGV K1 S BLACK - CASQUE MOTO INTÉGRAL E2206','casque-agv-k1s-noir',unistr('<h3 data-start="0" data-end="73"><strong data-start="4" data-end="71">Casque AGV K1 S Noir – Performance et Sécurité pour les Motards</strong></h3>\u000a<p data-start="75" data-end="378">Le <strong data-start="78" data-end="95">AGV K1 S Noir</strong> est un casque intégral conçu pour offrir un équilibre parfait entre <strong data-start="164" data-end="202">sécurité, confort et aérodynamisme</strong>. Inspiré des technologies développées en MotoGP, il est idéal pour les motards recherchant un <strong data-start="297" data-end="329">casque sportif et polyvalent</strong>, adapté aussi bien à la route qu’aux circuits.</p>\u000a<h4 data-start="380" data-end="409"><strong data-start="385" data-end="407">Caractéristiques :</strong></h4>\u000a<p data-start="410" data-end="925">✔ <strong data-start="412" data-end="457">Coque en thermoplastique haute résistance</strong> pour une protection optimale.<br data-start="487" data-end="490" />✔ <strong data-start="492" data-end="518">Aérodynamisme optimisé</strong> avec spoiler intégré pour une meilleure stabilité à grande vitesse.<br data-start="586" data-end="589" />✔ <strong data-start="591" data-end="639">Visière anti-rayures et prédisposée Pinlock®</strong> pour une vision claire en toutes conditions.<br data-start="684" data-end="687" />✔ <strong data-start="689" data-end="712">Ventilation avancée</strong> avec entrées d’air multiples pour un flux d’air maximal.<br data-start="769" data-end="772" />✔ <strong data-start="774" data-end="818">Intérieur en tissu respirant et amovible</strong>, lavable pour un confort durable.<br data-start="852" data-end="855" />✔ <strong data-start="857" data-end="884">Fermeture micrométrique</strong> pour un ajustement précis et sécurisé.</p>\u000a<h3 data-start="927" data-end="971"><strong data-start="931" data-end="969">Pourquoi choisir l’AGV K1 S Noir ?</strong></h3>\u000a<ul data-start="972" data-end="1151">\u000a<li data-start="972" data-end="1021">Design agressif et sportif inspiré du MotoGP.</li>\u000a<li data-start="1022" data-end="1087">Léger, confortable et conçu pour une utilisation quotidienne.</li>\u000a<li data-start="1088" data-end="1151">Excellente ventilation pour un confort optimal même en été.</li>\u000a</ul>\u000a<p data-start="1153" data-end="1230"><strong data-start="1153" data-end="1228">Optez pour la performance et la sécurité avec le casque AGV K1 S Noir !</strong></p>\u000a<p data-start="1232" data-end="1264" data-is-last-node="" data-is-only-node="">➡ <strong data-start="1234" data-end="1264" data-is-last-node="">Commandez dès maintenant !</strong></p>\u000a'),'',53,1010,2999.0,2199.0,NULL,NULL,'published','AGV K1 S BLACK - CASQUE MOTO INTÉGRAL E2206','AGV K1 S BLACK - CASQUE MOTO INTÉGRAL E2206 au Maroc. Achetez au meilleur prix chez MOTO PACO.',92,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(376,'AGV K-5 S/K3 SV/K1 S Visiere / écran (iridium argent).','agv-k-5-s-k3-sv-k1-s-visiere-ecran-iridium-argent',unistr('<div>\u000a<h2>Description Visière AGV  K3 SV / K5 S / K1 S / COMPACT ST.</h2>\u000a</div>\u000a<div class="description">\u000a<div><strong>AGV </strong>vous présente sa <strong>visière </strong>en coloris iridium argent.</div>\u000a<div></div>\u000a<div><strong>Elle est compatible avec les casques AGV suivants :</strong></div>\u000a<ul>\u000a<li>K3 SV</li>\u000a<li>K5 S</li>\u000a<li>K1 S</li>\u000a<li>COMPACT ST</li>\u000a</ul>\u000a<p><strong>Attention </strong>: les visières iridium sont très fragiles et la plupart des fabricants ne les reprennent pas si elles sont défectueuses suite à un mauvais entretien !</p>\u000a<p><strong>Petit conseil </strong>: pour le nettoyage, il vous suffit d’utiliser <strong>un peu d’eau légèrement tiède, du savon et un chiffon microfibre</strong>. Évitez d’utiliser du produit pour les vitres ou tout autre produit avec de l''alcool à l''intérieur, ou un chiffon autre que microfibre au risque de l''endommager.</p>\u000a</div>\u000a<div class="desc-technique row">\u000a<div class="left">\u000a<ul class="descriptif-technique-list">\u000a<li class="title">DESCRIPTIF TECHNIQUE</li>\u000a<li>Visière pour casques AGV</li>\u000a<li>Matière : 100% polycarbonate</li>\u000a<li>Champ visuel horizontal de 190 °</li>\u000a<li>Traitée anti-rayures et anti-UV</li>\u000a<li>Prédisposée à recevoir un Pinlock (en option)</li>\u000a<li>Non homologuée sur route</li>\u000a</ul>\u000a</div>\u000a</div>\u000a'),'',53,1010,499.0,349.0,NULL,NULL,'published','AGV K-5 S/K3 SV/K1 S Visiere / écran (iridium argent).','AGV K-5 S/K3 SV/K1 S Visiere / écran (iridium argent). au Maroc. Achetez au meilleur prix chez MOTO PACO.',113,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(377,'tenue cross fox racing 360 Voke combo fluo yellow off-road','tenue-foxracing-mx',unistr('<h2>Description</h2>\u000a<div class="tab-content">\u000a<p><strong>Tenue Tout-Terrain Fox Racing 360 voke/fluo yellow.</strong></p>\u000a<ul>\u000a<li>Ensemble Maillot + Pantalon.</li>\u000a<li>Coloris : Noir, rouge fluo, Jaune Fluo.</li>\u000a<li>Impression par sublimation.</li>\u000a</ul>\u000a<p>Arborez <strong>un look stylé</strong> avec la tenue de cross Fox Racing 360 Voke cambo ! D''une conception <strong>légère et aérée</strong>, elle procure un<strong> confort optimal</strong>ainsi qu''une<strong> excellente respirabilité</strong>. Cet ensemble maillot/pantalon est<strong> idéal pour pratiquer vos sports tout-terrain</strong> (Cross, Enduro, Quad...) tout au long de l''année.</p>\u000a<p><strong>Maillot Cross Fox Racing 360 Voke cambo :</strong></p>\u000a<div>\u000a<ul>\u000a<li>Conception 100% Polyester anti-humidité et léger.</li>\u000a<li>Empiècements en tissu mesh sur les côtés et les manches assurant une respirabilité optimale.</li>\u000a<li>Manches longues.</li>\u000a<li>Col athlétique avec insert en tissu mesh.</li>\u000a<li>Poignets extensibles en tissu mesh.</li>\u000a<li>Bas du dos prolongé pour l''insérer à l''intérieur du pantalon.</li>\u000a</ul>\u000a</div>\u000a<p><strong>Pantalon Cross Fox Racing 360 Voke cambo :</strong></p>\u000a<ul>\u000a<li>Matières : 84% Polyester, 8% Polyamide Nylon, 5% Cuir de vache et 3% Elasthanne.</li>\u000a<li>Conception en Polyester 600 deniers pour une utilisation longue durée.</li>\u000a<li>Empiècements en tissu mesh à l''arrière des jambes pour une bonne ventilation.</li>\u000a<li>Perforations au laser au niveau des genoux et des cuisses pour accroître la respirabilité.</li>\u000a<li>Structure préformée RAP (Rider Attack Position) offrant confort.</li>\u000a<li>Zones stratégiques en tissu TruMotion assurant mobilité.</li>\u000a<li>Rembourrage au niveau des genoux.</li>\u000a<li>Anneaux en cuir à l''intérieur du genou pour une meilleure résistance à la chaleur et une durabilité supérieure.</li>\u000a<li>Détails 3D en caoutchouc thermo-injecté.</li>\u000a<li>Elastique au niveau des hanches.</li>\u000a<li>Fermeture par zip et par boucle micrométrique pour un ajustement optimal.</li>\u000a<li>Intérieur de la taille siliconé améliorant le maintien.</li>\u000a<li>Protections de hanches incluses.</li>\u000a<li>Doublure interne respirante jusqu''au genou.</li>\u000a</ul>\u000a<p>&nbsp;</p>\u000a</div>\u000a'),unistr('<p>tenue cross fox racing 360 Voke combo fluo yellow off-road</p>\u000a'),32,1084,1890.0,1350.0,NULL,NULL,'published','tenue cross fox racing 360 Voke combo fluo yellow off-road',unistr('<p>tenue cross fox racing 360 Voke combo fluo yellow off-road</p>\u000a'),97,'2026-06-20 14:09:20',0,0,0,0);
INSERT INTO products VALUES(378,'TENUE CROSS FOX RACING 180 BLACK/WHITE','foxracing-offroad',unistr('<h2>Description</h2>\u000a<div class="tab-content">\u000a<p><strong>Tenue Tout-Terrain Fox Racing 180 </strong><b>black/white</b></p>\u000a<ul>\u000a<li>Ensemble Maillot + Pantalon</li>\u000a<li>Impression par sublimation</li>\u000a</ul>\u000a<p>Arborez <strong>un look stylé</strong> avec la tenue de cross Fox Racing 180 ! D''une conception <strong>légère et aérée</strong>, elle procure un<strong> confort optimal</strong>ainsi qu''une<strong> excellente respirabilité</strong>. Cet ensemble maillot/pantalon est<strong> idéal pour pratiquer vos sports tout-terrain</strong> (Cross, Enduro, Quad...) tout au long de l''année.</p>\u000a<p><strong>Maillot Cross Fox Racing 180 :</strong></p>\u000a<div>\u000a<ul>\u000a<li>Conception 100% Polyester anti-humidité et léger.</li>\u000a<li>Empiècements en tissu mesh sur les côtés et les manches assurant une respirabilité optimale.</li>\u000a<li>Manches longues.</li>\u000a<li>Col athlétique avec insert en tissu mesh.</li>\u000a<li>Poignets extensibles en tissu mesh.</li>\u000a<li>Bas du dos prolongé pour l''insérer à l''intérieur du pantalon.</li>\u000a</ul>\u000a</div>\u000a<p><strong>Pantalon Cross Fox Racing 180  :</strong></p>\u000a<ul>\u000a<li>Matières : 84% Polyester, 8% Polyamide Nylon, 5% Cuir de vache et 3% Elasthanne.</li>\u000a<li>Conception en Polyester 600 deniers pour une utilisation longue durée.</li>\u000a<li>Empiècements en tissu mesh à l''arrière des jambes pour une bonne ventilation.</li>\u000a<li>Perforations au laser au niveau des genoux et des cuisses pour accroître la respirabilité.</li>\u000a<li>Structure préformée RAP (Rider Attack Position) offrant confort.</li>\u000a<li>Zones stratégiques en tissu TruMotion assurant mobilité.</li>\u000a<li>Rembourrage au niveau des genoux.</li>\u000a<li>Anneaux en cuir à l''intérieur du genou pour une meilleure résistance à la chaleur et une durabilité supérieure</li>\u000a<li>Elastique au niveau des hanches.</li>\u000a<li>Fermeture par zip et par boucle micrométrique pour un ajustement optimal.</li>\u000a<li>Intérieur de la taille siliconé améliorant le maintien.</li>\u000a<li>Protections de hanches incluses.</li>\u000a<li>Doublure interne respirante jusqu''au genou.</li>\u000a</ul>\u000a<p>&nbsp;</p>\u000a</div>\u000a'),unistr('<p>TENUE CROSS FOX RACING 180 BLACK/WHITE</p>\u000a'),31,1084,1890.0,1350.0,NULL,NULL,'published','TENUE CROSS FOX RACING 180 BLACK/WHITE',unistr('<p>TENUE CROSS FOX RACING 180 BLACK/WHITE</p>\u000a'),150,'2026-06-20 14:09:21',0,0,0,0);
INSERT INTO products VALUES(379,'DAINESE ALLIGATOR TEX - MEN''S MOTORCYCLE JACKET','jacket-dainese',unistr('<div class="offcanvas-header px-4 py-3 px-md-6 py-md-4 px-xl-9">\u000a<div class="position-relative">\u000a<h3 id="product-description" class="fs-md-3 fs-4 text-uppercase pt-xl-6">PRODUCT DESCRIPTION</h3>\u000a</div>\u000a<p>&nbsp;</p>\u000a</div>\u000a<div class="offcanvas-body px-4 py-3 px-md-6 py-md-7 py-xl-2 px-xl-9 ">\u000a<p class="fs-7">On or off road, Alligator Tex is the ideal motorcycle jacket for early winter or the beginning of summer.</p>\u000a<p>Protective and abrasion-resistant, the garment is made with water repellent fabric that protects against bad weather. Complete with seven air vents for optimum ventilation in all conditions.</p>\u000a<p>Equipped with practical pockets for all the essentials, the jacket’s fit ensures total freedom of movement in the saddle. The chest pockets are also padded, to protect against any stones thrown up by fellow enduro riders when traveling on dirt.</p>\u000a<p>Alligator Tex is compatible with the range of Dainese MX protectors and Pro-Armor technology for the highest level of chest protection. 3D-Stone fabric inserts ensure this motorcycle jacket is abrasion-resistant at the elbows.</p>\u000a<h3 class="product-facts-title">Product details</h3>\u000a<ul class="a-nostyle">\u000a<li>\u000a<div class="a-fixed-left-grid product-facts-detail">\u000a<div class="a-fixed-left-grid-inner">\u000a<div class="a-fixed-left-grid-col a-col-left"><span class="a-color-base">Material composition</span></div>\u000a<div class="a-fixed-left-grid-col a-col-right"><span class="a-color-base">Outer Garment: 100% Nylon; Inner Lining: 100% Polyester; Front, rear and sleeve inserts: 100% Polyester</span></div>\u000a</div>\u000a</div>\u000a</li>\u000a<li>\u000a<div class="a-fixed-left-grid product-facts-detail">\u000a<div class="a-fixed-left-grid-inner">\u000a<div class="a-fixed-left-grid-col a-col-left"><span class="a-color-base">Care instructions</span></div>\u000a<div class="a-fixed-left-grid-col a-col-right"><span class="a-color-base">Hand Wash Only</span></div>\u000a</div>\u000a</div>\u000a</li>\u000a</ul>\u000a<hr class="a-spacing-base a-spacing-top-base a-divider-normal" aria-hidden="true" />\u000a<h3 class="product-facts-title">About this item</h3>\u000a<ul class="a-unordered-list a-vertical a-spacing-small">\u000a<li><span class="a-list-item a-size-base a-color-base">CHARACTERISTICS: 1 cargo pocket on the back; 4 outer pockets on the front; Detachable Keyholder; Detachable Sleeves; EN 17092 A certified motorbike garment; Pocket for G1 and G2 back protector; Pockets for Pro-Armor Chest 2 pcs; Protective foam on the upper pockets; Splitted Fastening</span></li>\u000a<li><span class="a-list-item a-size-base a-color-base">ERGONOMICS: waist adjustment with coulisse; Wide adjustments on the waist, arms and forearms</span></li>\u000a<li><span class="a-list-item a-size-base a-color-base">MAIN MATERIALS: 3D-Stone fabric; Mugello fabric</span></li>\u000a<li><span class="a-list-item a-size-base a-color-base">PERFORMANCE SHOCK: Removable composite protectors certified to EN 1621.1 Standard on elbows; Removable composite protectors certified to EN 1621.1 Standard on shoulders</span></li>\u000a<li><span class="a-list-item a-size-base a-color-base">TEMPERATURE: 2 direct-to-the-body vent zip on chest; Breathable mesh lining</span></li>\u000a</ul>\u000a</div>\u000a'),unistr('<p>DAINESE ALLIGATOR TEX &#8211; MEN&#8217;S MOTORCYCLE JACKET</p>\u000a'),55,753,4390.0,2890.0,NULL,NULL,'published','DAINESE ALLIGATOR TEX - MEN''S MOTORCYCLE JACKET',unistr('<p>DAINESE ALLIGATOR TEX &#8211; MEN&#8217;S MOTORCYCLE JACKET</p>\u000a'),136,'2026-06-20 14:09:21',0,0,0,0);
INSERT INTO products VALUES(380,'Tenues Motocross FOX RACING 360 Voke Aqua','jersey-fox-360-voke-aqua',unistr('<p><strong>t-Shirt Fox 360 Voke</strong><strong> Aqua</strong><strong>. </strong>dans un slinky TruDri® et tissu de réseau, il offre une excellente ventilation, de garder le corps au frais et au sec en tout temps. Grâce à sa forme ergonomique coupe généreuse et offre un grand confort.</p>\u000a<p><strong>Caractéristiques principales:</strong></p>\u000a<ul>\u000a<li type="">dans un slinky TruDri® (tissu léger et confortable qui absorbe rapidement l''humidité et maintient le corps au frais et au sec).</li>\u000a<li type="">les Grands panneaux de mesh à l''avant, l''arrière, les côtés et les manches pour une ventilation superbe.</li>\u000a<li type="">Panneau de tissu durable PK sur les manches pour une durabilité accrue.</li>\u000a<li type="">Col de la chaleur d''étanchéité élastique poignets et un design minimaliste pour un maximum de confort.</li>\u000a<li type="">Manches pré-courbées pour une position naturelle de la conduction RAP (Rider Attack Position); fournir un ajustement parfait sur la moto.</li>\u000a<li type="">l''arrière plus long que l''avant de sorte qu''il ne se détache pas de la jambe droite du pantalon.</li>\u000a<li type="">Graphiques de haute qualité, des estampes de la transmission de la chaleur.</li>\u000a</ul>\u000a'),unistr('<p>Jersey FOX 360 Voke Aqua</p>\u000a'),31,1084,1890.0,1350.0,NULL,NULL,'published','Tenues Motocross FOX RACING 360 Voke Aqua',unistr('<p>Jersey FOX 360 Voke Aqua</p>\u000a'),121,'2026-06-20 14:09:22',0,0,0,0);
INSERT INTO products VALUES(381,'Tenues Motocross FOXRACING 180 OKTIV offroad','fox-180',unistr('<p><strong>JERSEY FOX 180 OKTIV  MEN''S Bleu</strong>. Avec le pantalon 180, forme standard de l''équipement de niveau moyen plus élaboré de l''industrie de l''Off-Road. Le t-shirt 180 se distingue pour être très polyvalent et extrêmement durable.</p>\u000a<p><strong>Caractéristiques principales:</strong></p>\u000a<ul>\u000a<li type="">Fait de polyester hautement respirant et à séchage rapide qui offre une excellente évacuation de l''humidité.</li>\u000a<li type="">Panneaux de maille sur les côtés et les manches pour une bonne ventilation.</li>\u000a<li type="">Col et poignets en tissu mesh pour plus de confort.</li>\u000a<li type="">l''arrière plus long que l''avant de sorte qu''il ne se détache pas de la jambe droite du pantalon.</li>\u000a<li type="">Graphiques de haute qualité.</li>\u000a</ul>\u000a'),unistr('<p>Tenues Motocross FOXRACING 180 OKTIV offroad</p>\u000a'),31,1084,1890.0,1350.0,NULL,NULL,'published','Tenues Motocross FOXRACING 180 OKTIV offroad',unistr('<p>Tenues Motocross FOXRACING 180 OKTIV offroad</p>\u000a'),83,'2026-06-20 14:09:22',0,0,0,0);
INSERT INTO products VALUES(382,'Dainese Outlaw Tex Jacket – BLACK/CARAFE/WALNUT/CHARCOAL-GREY','dainese-jacket-moto',unistr('<p>Dainese Outlaw Tex Jacket – BLACK/CARAFE/WALNUT/CHARCOAL-GREY</p>\u000a<p>Outlaw Tex is an ideal motorcycle jacket for summer and provides protection on any adventure, on or off road.</p>\u000a<p>Perfect in high temperatures, it is lightweight, resistant and well ventilated.</p>\u000a<p>Made with water-repellent fabric, it features a series of practical and functional details such as detachable sleeves and useful adjustments to ensure the ideal fit.</p>\u000a<p>A large pocket on the back allows for the practical storage of essential equipment.</p>\u000a<p>Suitable for use with a range of Dainese MX protectors and compatible with Pro-Armor chest technology, the Outlaw Tex jacket offers the ideal protection on any path.</p>\u000a<p>3D-Stone fabric inserts ensure this motorcycle jacket is abrasion-resistant at the elbows.</p>\u000a<p><strong>CHARACTERISTICS:</strong></p>\u000a<ul>\u000a<li>1 cargo pocket on the back.</li>\u000a<li>3 pockets in front.</li>\u000a<li>Detachable Sleeves.</li>\u000a<li>EN 17092 A certified motorbike garment.</li>\u000a<li>Pocket for G1 and G2 back protector.</li>\u000a<li>Pockets for Pro-Armor Chest 2 pcs.</li>\u000a<li>Wide adjustments on the waist, arms and forearms.</li>\u000a</ul>\u000a<p><strong>MAIN MATERIALS:</strong></p>\u000a<ul>\u000a<li>High tenacity mesh fabric.</li>\u000a<li>Breathable mesh lining.</li>\u000a</ul>\u000a<p>&nbsp;</p>\u000a<p>&nbsp;</p>\u000a'),unistr('<p>Dainese Outlaw Tex Jacket – BLACK/CARAFE/WALNUT/CHARCOAL-GREY</p>\u000a'),55,753,3390.0,2190.0,NULL,NULL,'published','Dainese Outlaw Tex Jacket – BLACK/CARAFE/WALNUT/CHARCOAL-GREY',unistr('<p>Dainese Outlaw Tex Jacket – BLACK/CARAFE/WALNUT/CHARCOAL-GREY</p>\u000a'),101,'2026-06-20 14:09:23',0,0,0,0);
INSERT INTO products VALUES(383,'DAINESE MISTIKA TEX MEN''S JACKET','dainese-mitika-tex-jacket-black',unistr('<h3>Dainese Mistica Tex Jacket</h3>\u000a<p>This fabric sports jacket is a versatile garment, designed for everyday sports riding. Protection is guaranteed by certified composite inserts at the shoulders and elbows, as well as a pocket on the back to accommodate a Dainese G model back protector, not included.<br />\u000aMistica Tex features a removable thermal lining to ensure maximum usability even on the coldest days. Adjustable zippered air vents are included on the sides.</p>\u000a<h4>Features</h4>\u000a<div class="row missing-icon">\u000a<div class="col-sm-10 col-xs-9 vertical-aligned">\u000a<ul>\u000a<li>1 inner pocket on thermal liner</li>\u000a<li>2 inner pockets</li>\u000a<li>2 outer pockets</li>\u000a<li>prEN 17092 certified motorbike protective jacket</li>\u000a<li>Reflective inserts</li>\u000a<li>Jacket-pants fastening system</li>\u000a<li>Neck, Waist and Wrists adjustments</li>\u000a<li>D-Synth 350 fabric</li>\u000a<li>Pocket for G1 &amp; G2 back protector</li>\u000a<li>Polyurethane rigid shoulders covered with D-Synth 350 fabric</li>\u000a<li>Removable composite protectors certified to EN 1621.1 Standard</li>\u000a<li>Air vents on chest and back</li>\u000a<li>Liner in breathable and perforated Sanitized® fabric</li>\u000a<li>Removable thermal liner</li>\u000a</ul>\u000a</div>\u000a</div>\u000a'),unistr('<p>DAINESE MISTIKA TEX MEN&#8217;S JACKET</p>\u000a'),55,753,3399.0,2899.0,NULL,NULL,'published','DAINESE MISTIKA TEX MEN''S JACKET',unistr('<p>DAINESE MISTIKA TEX MEN&#8217;S JACKET</p>\u000a'),143,'2026-06-20 14:09:24',0,0,0,0);
INSERT INTO products VALUES(384,'DAINESE SUPER RIDER D-DRY BLACK/WHITE JACKET','dainese-super-rider-d-dry-black-white-jacket',unistr('<p>Si la veste D-Dry® est légère et imperméable, c’est parce qu’elle a été fabriquée dans le même cuir de qualité supérieure employé pour la réalisation de vêtements de motos sportives.</p>\u000a<p>La veste Super Rider D-Dry® ultra-légère arbore ce look agressif s’inspirant des équipements de moto en cuir de qualité supérieure, portés par les pilotes de motos de course.  Elle est équipée d’inserts en cuir de vachette, de plaques en aluminium au niveau des épaules, d’un tissu bi-élastique Mugello et de grands panneaux en filet.  Et pour lui conférer cette finition encore plus technique tout en conservant son côté versatile, la veste est rehaussée d’une bosse aérodynamique et d’une doublure imperméable D-Dry®.</p>\u000a'),unistr('<p>DAINESE SUPER RIDER D-DRY BLACK/WHITE JACKET</p>\u000a'),55,753,6210.0,3790.0,NULL,NULL,'published','DAINESE SUPER RIDER D-DRY BLACK/WHITE JACKET',unistr('<p>DAINESE SUPER RIDER D-DRY BLACK/WHITE JACKET</p>\u000a'),145,'2026-06-20 14:09:24',0,0,0,0);
INSERT INTO products VALUES(385,'DAINESE SUPER RIDER D-DRY JACKET BLACK/RED','dainese-super-rider-d-dry-jacket-black-red',unistr('<p>Si la veste D-Dry® est légère et imperméable, c’est parce qu’elle a été fabriquée dans le même cuir de qualité supérieure employé pour la réalisation de vêtements de motos sportives.</p>\u000a<p>La veste Super Rider D-Dry® ultra-légère arbore ce look agressif s’inspirant des équipements de moto en cuir de qualité supérieure, portés par les pilotes de motos de course. Elle est équipée d’inserts en cuir de vachette, de plaques en aluminium au niveau des épaules, d’un tissu bi-élastique Mugello et de grands panneaux en filet.  Et pour lui conférer cette finition encore plus technique tout en conservant son côté versatile, la veste est rehaussée d’une bosse aérodynamique et d’une doublure imperméable D-Dry®.</p>\u000a'),unistr('<p>DAINESE SUPER RIDER D-DRY JACKET BLACK/RED</p>\u000a'),55,753,6290.0,3790.0,NULL,NULL,'published','DAINESE SUPER RIDER D-DRY JACKET BLACK/RED',unistr('<p>DAINESE SUPER RIDER D-DRY JACKET BLACK/RED</p>\u000a'),140,'2026-06-20 14:09:24',0,0,0,0);
INSERT INTO products VALUES(386,'DAINESE OUTLAW TEX-MEN''S SUMMER MOTORCYCLE JACKET','dainese-outlaw-tex-mens-summer-motorcycle-jacket',unistr('<p>Outlaw Tex is an ideal motorcycle jacket for summer and provides protection on any adventure, on or off road.</p>\u000a<p>Perfect in high temperatures, it is lightweight, resistant and well ventilated. Made with water-repellent fabric, it features a series of practical and functional details such as detachable sleeves and useful adjustments to ensure the ideal fit.</p>\u000a<p>A large pocket on the back allows for the practical storage of essential equipment.</p>\u000a<p>Suitable for use with a range of Dainese MX protectors and compatible with Pro-Armor chest technology, the Outlaw Tex jacket offers the ideal protection on any path. 3D-Stone fabric inserts ensure this motorcycle jacket is abrasion-resistant at the elbows.</p>\u000a'),unistr('<p>DAINESE OUTLAW TEX-MEN&#8217;S SUMMER MOTORCYCLE JACKET</p>\u000a'),55,753,0.0,NULL,NULL,NULL,'published','DAINESE OUTLAW TEX-MEN''S SUMMER MOTORCYCLE JACKET',unistr('<p>DAINESE OUTLAW TEX-MEN&#8217;S SUMMER MOTORCYCLE JACKET</p>\u000a'),147,'2026-06-20 14:09:24',0,0,0,0);
INSERT INTO products VALUES(387,'AGV K1 S E2206 – GRAZIE VALE','agv-k1s-e2206-grazie-vale',unistr('<h3 class="" data-start="119" data-end="195">AGV K1 S Grazie Vale – Casque Intégral Édition Hommage à Valentino Rossi</h3>\u000a<p class="" data-start="197" data-end="478">Le <strong data-start="200" data-end="224">AGV K1 S Grazie Vale</strong> est un modèle <strong data-start="239" data-end="252">collector</strong> qui célèbre la carrière légendaire de <strong data-start="291" data-end="310">Valentino Rossi</strong>. Avec ses graphismes emblématiques et chargés d’émotion, ce casque est bien plus qu’un équipement : c’est un hommage vibrant au "Doctor" et à ses fans du monde entier.</p>\u000a<p class="" data-start="480" data-end="514"><strong data-start="480" data-end="514">Caractéristiques principales :</strong></p>\u000a<ul data-start="516" data-end="1368">\u000a<li class="" data-start="516" data-end="678">\u000a<p class="" data-start="518" data-end="678"><strong data-start="518" data-end="542">Design "Grazie Vale"</strong> : réplique du casque porté par Rossi lors de son dernier GP à Valence en 2021, avec messages de remerciement et ses couleurs iconiques.</p>\u000a</li>\u000a<li class="" data-start="679" data-end="762">\u000a<p class="" data-start="681" data-end="762"><strong data-start="681" data-end="707">Homologation ECE 22.06</strong> : répond aux dernières normes européennes de sécurité.</p>\u000a</li>\u000a<li class="" data-start="763" data-end="888">\u000a<p class="" data-start="765" data-end="888"><strong data-start="765" data-end="816">Coque HIR-TH (Thermoplastique Haute Résistance)</strong> : forme aérodynamique avec aileron intégré pour une stabilité optimale.</p>\u000a</li>\u000a<li class="" data-start="889" data-end="1012">\u000a<p class="" data-start="891" data-end="1012"><strong data-start="891" data-end="933">Ventilation inspirée de la compétition</strong> : 5 prises d’air frontales + 2 extracteurs arrière pour une aération efficace.</p>\u000a</li>\u000a<li class="" data-start="1013" data-end="1112">\u000a<p class="" data-start="1015" data-end="1112"><strong data-start="1015" data-end="1036">Écran Ultravision</strong> : champ de vision large, traitement anti-rayures, prédisposé pour Pinlock®.</p>\u000a</li>\u000a<li class="" data-start="1113" data-end="1196">\u000a<p class="" data-start="1115" data-end="1196"><strong data-start="1115" data-end="1140">Intérieur Dry-Comfort</strong> : doux, démontable, lavable, avec un ajustement précis.</p>\u000a</li>\u000a<li class="" data-start="1197" data-end="1301">\u000a<p class="" data-start="1199" data-end="1301"><strong data-start="1199" data-end="1237">Prédisposé pour intercom Bluetooth</strong> : compatibilité avec la majorité des systèmes de communication.</p>\u000a</li>\u000a<li class="" data-start="1302" data-end="1368">\u000a<p class="" data-start="1304" data-end="1368"><strong data-start="1304" data-end="1331">Fermeture micrométrique</strong> : sécurisée et facile d''utilisation.</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="1370" data-end="1566">Le <strong data-start="1373" data-end="1393">K1 S Grazie Vale</strong> est un casque incontournable pour les admirateurs de Rossi, alliant <strong data-start="1462" data-end="1485">technologie moderne</strong>, <strong data-start="1487" data-end="1505">design hommage</strong> et <strong data-start="1509" data-end="1532">authenticité racing</strong>. Un vrai symbole de passion moto.</p>\u000a'),unistr('<p>AGV K1 S E2206 – GRAZIE VALE</p>\u000a'),31,1010,0.0,NULL,NULL,NULL,'published','AGV K1 S E2206 – GRAZIE VALE',unistr('<p>AGV K1 S E2206 – GRAZIE VALE</p>\u000a'),475,'2026-06-20 14:09:24',0,1,0,0);
INSERT INTO products VALUES(389,'AGV-K1 S E2206 – KRIPTON BLACK/GREEN','agv-k1-s-e2206-2',unistr('<h3 class="" data-start="118" data-end="184">AGV K1 S Kripton – Casque Intégral Sportif au Design Futuriste</h3>\u000a<p class="" data-start="186" data-end="466">Le <strong data-start="189" data-end="209">AGV K1 S Kripton</strong> séduit par son look avant-gardiste, ses lignes tranchées et ses détails graphiques audacieux. Inspiré par la vitesse et la technologie, ce casque est conçu pour offrir un haut niveau de confort et de sécurité, tout en affirmant un style résolument moderne.</p>\u000a<p class="" data-start="468" data-end="502"><strong data-start="468" data-end="502">Caractéristiques principales :</strong></p>\u000a<ul data-start="504" data-end="1289">\u000a<li class="" data-start="504" data-end="608">\u000a<p class="" data-start="506" data-end="608"><strong data-start="506" data-end="527">Graphisme Kripton</strong> : design futuriste et couleurs métalliques pour un look unique et ultra-moderne.</p>\u000a</li>\u000a<li class="" data-start="609" data-end="699">\u000a<p class="" data-start="611" data-end="699"><strong data-start="611" data-end="637">Homologation ECE 22.06</strong> : sécurité optimale avec la norme européenne la plus récente.</p>\u000a</li>\u000a<li class="" data-start="700" data-end="829">\u000a<p class="" data-start="702" data-end="829"><strong data-start="702" data-end="750">Coque HIR-TH (High Resistance Thermoplastic)</strong> : légère, aérodynamique et stable à haute vitesse grâce à son aileron intégré.</p>\u000a</li>\u000a<li class="" data-start="830" data-end="939">\u000a<p class="" data-start="832" data-end="939"><strong data-start="832" data-end="859">Ventilation performante</strong> : 5 prises d’air frontales et 2 extracteurs arrière pour un flux d’air continu.</p>\u000a</li>\u000a<li class="" data-start="940" data-end="1039">\u000a<p class="" data-start="942" data-end="1039"><strong data-start="942" data-end="963">Écran Ultravision</strong> : champ de vision large, prédisposé Pinlock®, avec traitement anti-rayures.</p>\u000a</li>\u000a<li class="" data-start="1040" data-end="1140">\u000a<p class="" data-start="1042" data-end="1140"><strong data-start="1042" data-end="1067">Intérieur Dry-Comfort</strong> : démontable, lavable et confortable pour un usage quotidien ou sportif.</p>\u000a</li>\u000a<li class="" data-start="1141" data-end="1229">\u000a<p class="" data-start="1143" data-end="1229"><strong data-start="1143" data-end="1170">Prédisposition intercom</strong> : compatible avec les systèmes de communication Bluetooth.</p>\u000a</li>\u000a<li class="" data-start="1230" data-end="1289">\u000a<p class="" data-start="1232" data-end="1289"><strong data-start="1232" data-end="1259">Fermeture micrométrique</strong> : pratique, rapide et fiable.</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="1291" data-end="1456">Le <strong data-start="1294" data-end="1314">AGV K1 S Kripton</strong> est parfait pour les motards qui recherchent un casque technique, sécuritaire, et au style affirmé, prêt à affronter la route avec caractère.</p>\u000a'),unistr('<div class="et-pro-summary-top">\u000a<div class="woocommerce-product-details__short-description">\u000a<h6>AGV-K1 S E2206</h6>\u000a</div>\u000a</div>\u000a<div class="et-pro-summary-content"></div>\u000a'),31,1010,2999.0,1699.0,NULL,NULL,'published','AGV-K1 S E2206 – KRIPTON BLACK/GREEN',unistr('<div class="et-pro-summary-top">\u000a<div class="woocommerce-product-details__short-description">\u000a<h6>AGV-K1 S E2206</h6>\u000a</div>\u000a</div>\u000a<div class="et-pro-summary-content"></div>\u000a'),82,'2026-06-20 14:09:25',0,0,0,0);
INSERT INTO products VALUES(390,'AGV-K1 S E2206 – DREAMTIME','agv-k1-s-e2206',unistr('<h3 class="" data-start="118" data-end="202">AGV K1 S Dreamtime – Casque Intégral Sportif Édition Valentino Rossi "Dreamtime"</h3>\u000a<p class="" data-start="204" data-end="508">Le <strong data-start="207" data-end="229">AGV K1 S Dreamtime</strong> rend hommage à l’un des casques les plus emblématiques de <strong data-start="288" data-end="307">Valentino Rossi</strong>, inspiré par l’art aborigène australien. Doté de graphismes colorés et symboliques, ce casque intègre des technologies avancées pour un usage routier et sportif, tout en célébrant l’esprit du MotoGP™.</p>\u000a<p class="" data-start="510" data-end="544"><strong data-start="510" data-end="544">Caractéristiques principales :</strong></p>\u000a<ul data-start="546" data-end="1408">\u000a<li class="" data-start="546" data-end="705">\u000a<p class="" data-start="548" data-end="705"><strong data-start="548" data-end="570">Design "Dreamtime"</strong> : reproduction fidèle du casque porté par Rossi lors du GP d’Australie 2005, mêlant art tribal, symboles personnels et couleurs vives.</p>\u000a</li>\u000a<li class="" data-start="706" data-end="811">\u000a<p class="" data-start="708" data-end="811"><strong data-start="708" data-end="734">Homologation ECE 22.06</strong> : conforme à la norme européenne la plus récente pour une sécurité optimale.</p>\u000a</li>\u000a<li class="" data-start="812" data-end="965">\u000a<p class="" data-start="814" data-end="965"><strong data-start="814" data-end="865">Coque HIR-TH (Haute Résistance Thermoplastique)</strong> : légère, aérodynamique et résistante, avec aileron intégré pour plus de stabilité à haute vitesse.</p>\u000a</li>\u000a<li class="" data-start="966" data-end="1079">\u000a<p class="" data-start="968" data-end="1079"><strong data-start="968" data-end="990">Ventilation racing</strong> : 5 prises d’air frontales et 2 extracteurs arrière pour une circulation d’air efficace.</p>\u000a</li>\u000a<li class="" data-start="1080" data-end="1180">\u000a<p class="" data-start="1082" data-end="1180"><strong data-start="1082" data-end="1103">Écran Ultravision</strong> : champ de vision élargi, compatible Pinlock®, avec traitement anti-rayures.</p>\u000a</li>\u000a<li class="" data-start="1181" data-end="1273">\u000a<p class="" data-start="1183" data-end="1273"><strong data-start="1183" data-end="1208">Intérieur Dry-Comfort</strong> : doux, démontable, lavable et conçu pour un ajustement parfait.</p>\u000a</li>\u000a<li class="" data-start="1274" data-end="1356">\u000a<p class="" data-start="1276" data-end="1356"><strong data-start="1276" data-end="1301">Préparé pour intercom</strong> : prêt à accueillir la plupart des systèmes Bluetooth.</p>\u000a</li>\u000a<li class="" data-start="1357" data-end="1408">\u000a<p class="" data-start="1359" data-end="1408"><strong data-start="1359" data-end="1386">Fermeture micrométrique</strong> : pratique et fiable.</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="1410" data-end="1587">Casque au design légendaire et aux performances modernes, le <strong data-start="1471" data-end="1493">AGV K1 S Dreamtime</strong> s’adresse aux motards qui veulent conjuguer histoire, passion et technologie à chaque sortie.</p>\u000a'),unistr('<p>AGV-K1 S E2206</p>\u000a'),31,1010,3199.0,1699.0,NULL,NULL,'published','AGV-K1 S E2206 – DREAMTIME',unistr('<p>AGV-K1 S E2206</p>\u000a'),143,'2026-06-20 14:09:25',0,0,0,0);
INSERT INTO products VALUES(391,'AGV-K1 S BLIPPER GREY/RED','agv-k1-s-blipper-grey-red',unistr('<h3 class="" data-start="118" data-end="184">AGV K1 S Blipper – Casque Intégral Sportif Homologué ECE 22.06</h3>\u000a<p class="" data-start="186" data-end="374">Inspiré par la course, pensé pour la route : le <strong data-start="234" data-end="254">AGV K1 S Blipper</strong> est un casque intégral au design dynamique, parfait pour les motards en quête de performances, de sécurité et de style.</p>\u000a<p class="" data-start="376" data-end="410"><strong data-start="376" data-end="410">Caractéristiques principales :</strong></p>\u000a<ul data-start="412" data-end="1130">\u000a<li class="" data-start="412" data-end="497">\u000a<p class="" data-start="414" data-end="497"><strong data-start="414" data-end="440">Homologation ECE 22.06</strong> : conforme aux dernières normes de sécurité européennes.</p>\u000a</li>\u000a<li class="" data-start="498" data-end="658">\u000a<p class="" data-start="500" data-end="658"><strong data-start="500" data-end="533">Coque aérodynamique en HIR-TH</strong> (thermoplastique haute résistance) : stabilité optimale à haute vitesse grâce à son aileron intégré développé en soufflerie.</p>\u000a</li>\u000a<li class="" data-start="659" data-end="784">\u000a<p class="" data-start="661" data-end="784"><strong data-start="661" data-end="696">Système de ventilation efficace</strong> : 5 prises d''air frontales + 2 extracteurs arrière pour une circulation d''air optimale.</p>\u000a</li>\u000a<li class="" data-start="785" data-end="883">\u000a<p class="" data-start="787" data-end="883"><strong data-start="787" data-end="808">Écran Ultravision</strong> : champ de vision large avec traitement anti-rayures, prédisposé Pinlock®.</p>\u000a</li>\u000a<li class="" data-start="884" data-end="983">\u000a<p class="" data-start="886" data-end="983"><strong data-start="886" data-end="920">Intérieur en tissu Dry-Comfort</strong> : démontable, lavable et conçu pour un ajustement confortable.</p>\u000a</li>\u000a<li class="" data-start="984" data-end="1075">\u000a<p class="" data-start="986" data-end="1075"><strong data-start="986" data-end="1031">Prédisposé pour systèmes de communication</strong> : pour rester connecté en toute simplicité.</p>\u000a</li>\u000a<li class="" data-start="1076" data-end="1130">\u000a<p class="" data-start="1078" data-end="1130"><strong data-start="1078" data-end="1105">Fermeture micrométrique</strong> : pratique et sécurisée.</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="1132" data-end="1292">Le design <strong data-start="1142" data-end="1162">Blipper Grey/Red</strong> apporte une touche sportive et agressive, fidèle à l’ADN racing d’AGV. Un choix idéal pour les passionnés de vitesse et de style.</p>\u000a'),'',31,1010,2999.0,1699.0,NULL,NULL,'published','AGV-K1 S BLIPPER GREY/RED','AGV-K1 S BLIPPER GREY/RED au Maroc. Achetez au meilleur prix chez MOTO PACO.',495,'2026-06-20 14:09:26',0,1,0,0);
INSERT INTO products VALUES(392,'AGV-K1 S E2206 – TRACK 46','agv-k1-s-e2206-track-46',unistr('<h3 class="" data-start="119" data-end="190">AGV K1 S Track 46 – Casque Intégral Sportif Édition Valentino Rossi</h3>\u000a<p class="" data-start="192" data-end="499">Le <strong data-start="195" data-end="216">AGV K1 S Track 46</strong> est un casque intégral sport au look agressif et coloré, directement inspiré de l’univers racing de <strong data-start="317" data-end="336">Valentino Rossi</strong>. Combinant design iconique et performance technique, il est conçu pour les motards qui recherchent à la fois style, sécurité et confort sur route comme sur piste.</p>\u000a<p class="" data-start="501" data-end="535"><strong data-start="501" data-end="535">Caractéristiques principales :</strong></p>\u000a<ul data-start="537" data-end="1373">\u000a<li class="" data-start="537" data-end="656">\u000a<p class="" data-start="539" data-end="656"><strong data-start="539" data-end="561">Graphisme Track 46</strong> : couleurs vives et numéro 46 signature, pour un style dynamique et reconnaissable entre tous.</p>\u000a</li>\u000a<li class="" data-start="657" data-end="742">\u000a<p class="" data-start="659" data-end="742"><strong data-start="659" data-end="685">Homologation ECE 22.06</strong> : conforme aux dernières normes européennes de sécurité.</p>\u000a</li>\u000a<li class="" data-start="743" data-end="884">\u000a<p class="" data-start="745" data-end="884"><strong data-start="745" data-end="796">Coque HIR-TH (Haute Résistance Thermoplastique)</strong> : forme aérodynamique avec aileron intégré pour une stabilité maximale à haute vitesse.</p>\u000a</li>\u000a<li class="" data-start="885" data-end="1002">\u000a<p class="" data-start="887" data-end="1002"><strong data-start="887" data-end="920">Système de ventilation avancé</strong> : 5 entrées d’air frontales et 2 extracteurs arrière pour un flux d''air optimisé.</p>\u000a</li>\u000a<li class="" data-start="1003" data-end="1120">\u000a<p class="" data-start="1005" data-end="1120"><strong data-start="1005" data-end="1026">Écran Ultravision</strong> : large champ de vision horizontal et vertical, traitement anti-rayures, compatible Pinlock®.</p>\u000a</li>\u000a<li class="" data-start="1121" data-end="1207">\u000a<p class="" data-start="1123" data-end="1207"><strong data-start="1123" data-end="1148">Intérieur Dry-Comfort</strong> : démontable, lavable et conçu pour un excellent maintien.</p>\u000a</li>\u000a<li class="" data-start="1208" data-end="1309">\u000a<p class="" data-start="1210" data-end="1309"><strong data-start="1210" data-end="1236">Compatibilité intercom</strong> : prédisposé pour l’installation de systèmes de communication Bluetooth.</p>\u000a</li>\u000a<li class="" data-start="1310" data-end="1373">\u000a<p class="" data-start="1312" data-end="1373"><strong data-start="1312" data-end="1339">Fermeture micrométrique</strong> : sécurisée et facile à utiliser.</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="1375" data-end="1562">Le <strong data-start="1378" data-end="1395">K1 S Track 46</strong> est le choix parfait pour les fans du Doctor et pour tous les motards en quête d’un casque sportif avec un style affirmé et des performances dignes de la compétition.</p>\u000a'),unistr('<p>AGV-K1 S E2206 – TRACK 46</p>\u000a'),31,1010,3199.0,1999.0,NULL,NULL,'published','AGV-K1 S E2206 – TRACK 46',unistr('<p>AGV-K1 S E2206 – TRACK 46</p>\u000a'),491,'2026-06-20 14:09:26',0,1,0,0);
INSERT INTO products VALUES(393,'AGV-K1 S E2206 – VR46 SKY RACING TEAM','agv-k1-s-e2206-vr46-sky-racing-team-black-red',unistr('<h3 class="" data-start="116" data-end="191">AGV K1 S Sky 46 – Casque Intégral Sportif Édition Valentino Rossi "Sky"</h3>\u000a<p class="" data-start="193" data-end="468">Le <strong data-start="196" data-end="215">AGV K1 S Sky 46</strong> est un casque intégral au design inspiré par l’univers coloré et audacieux de <strong data-start="294" data-end="313">Valentino Rossi</strong>, emblématique numéro 46. Pensé pour les motards passionnés, il associe un look racing distinctif à des technologies issues de l''expérience AGV en MotoGP™.</p>\u000a<p class="" data-start="470" data-end="504"><strong data-start="470" data-end="504">Caractéristiques principales :</strong></p>\u000a<ul data-start="506" data-end="1308">\u000a<li class="" data-start="506" data-end="631">\u000a<p class="" data-start="508" data-end="631"><strong data-start="508" data-end="528">Graphisme Sky 46</strong> : couleurs vives et motifs inspirés par le style unique de Rossi – un véritable clin d''œil à ses fans.</p>\u000a</li>\u000a<li class="" data-start="632" data-end="712">\u000a<p class="" data-start="634" data-end="712"><strong data-start="634" data-end="660">Homologation ECE 22.06</strong> : dernière norme européenne en matière de sécurité.</p>\u000a</li>\u000a<li class="" data-start="713" data-end="854">\u000a<p class="" data-start="715" data-end="854"><strong data-start="715" data-end="731">Coque HIR-TH</strong> (Thermoplastique Haute Résistance) : forme aérodynamique avec aileron intégré pour une stabilité optimale à haute vitesse.</p>\u000a</li>\u000a<li class="" data-start="855" data-end="975">\u000a<p class="" data-start="857" data-end="975"><strong data-start="857" data-end="894">Système de ventilation performant</strong> : 5 prises d’air frontales et 2 extracteurs arrière pour un flux d''air constant.</p>\u000a</li>\u000a<li class="" data-start="976" data-end="1084">\u000a<p class="" data-start="978" data-end="1084"><strong data-start="978" data-end="999">Écran Ultravision</strong> : large champ de vision latéral et vertical, anti-rayures, prédisposé pour Pinlock®.</p>\u000a</li>\u000a<li class="" data-start="1085" data-end="1150">\u000a<p class="" data-start="1087" data-end="1150"><strong data-start="1087" data-end="1112">Intérieur Dry-Comfort</strong> : confortable, démontable et lavable.</p>\u000a</li>\u000a<li class="" data-start="1151" data-end="1246">\u000a<p class="" data-start="1153" data-end="1246"><strong data-start="1153" data-end="1176">Prédisposé intercom</strong> : compatible avec la plupart des systèmes de communication Bluetooth.</p>\u000a</li>\u000a<li class="" data-start="1247" data-end="1308">\u000a<p class="" data-start="1249" data-end="1308"><strong data-start="1249" data-end="1276">Fermeture micrométrique</strong> : rapide, précise et sécurisée.</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="1310" data-end="1487">Avec son style affirmé et ses performances techniques, le <strong data-start="1368" data-end="1383">K1 S Sky 46</strong> est un choix de prédilection pour les motards qui veulent rouler avec le style et l’esprit du "Doctor".</p>\u000a'),unistr('<p><a href="https://motopaco.ma/">AGV-K1 S E2206 – VR46 SKY RACING TEAM BLACK/RED</a></p>\u000a'),53,1010,3199.0,1999.0,NULL,NULL,'published','AGV-K1 S E2206 – VR46 SKY RACING TEAM',unistr('<p><a href="https://motopaco.ma/">AGV-K1 S E2206 – VR46 SKY RACING TEAM BLACK/RED</a></p>\u000a'),145,'2026-06-20 14:09:27',0,0,0,0);
INSERT INTO products VALUES(394,'TCX R04D WP BLACK/RED','tcx-r04d-wp-black-red',unistr('<h3 class="" data-start="112" data-end="168">TCX RO4D WP – Bottes Moto Sport-Touring Imperméables</h3>\u000a<p class="" data-start="170" data-end="429">Conçues pour les motards qui recherchent un équilibre idéal entre <strong data-start="236" data-end="260">performance sportive</strong>, <strong data-start="262" data-end="285">confort de conduite</strong> et <strong data-start="289" data-end="304">polyvalence</strong>, les <strong data-start="310" data-end="325">TCX RO4D WP</strong> sont des bottes à la fois techniques, protectrices et adaptées à toutes les conditions météorologiques.</p>\u000a<p class="" data-start="431" data-end="465"><strong data-start="431" data-end="465">Caractéristiques principales :</strong></p>\u000a<ul data-start="467" data-end="1098">\u000a<li class="" data-start="467" data-end="544">\u000a<p class="" data-start="469" data-end="544"><strong data-start="469" data-end="499">Membrane T-Dry imperméable</strong> : garde vos pieds au sec par tous les temps.</p>\u000a</li>\u000a<li class="" data-start="545" data-end="624">\u000a<p class="" data-start="547" data-end="624"><strong data-start="547" data-end="579">Tige en microfibre technique</strong> : souple, légère et résistante à l''abrasion.</p>\u000a</li>\u000a<li class="" data-start="625" data-end="742">\u000a<p class="" data-start="627" data-end="742"><strong data-start="627" data-end="652">Renforts stratégiques</strong> : protections intégrées aux malléoles, talon, pointe et tibia pour une sécurité optimale.</p>\u000a</li>\u000a<li class="" data-start="743" data-end="839">\u000a<p class="" data-start="745" data-end="839"><strong data-start="745" data-end="789">Fermeture par zip latéral + bande Velcro</strong> : facilité d’enfilage et ajustement personnalisé.</p>\u000a</li>\u000a<li class="" data-start="840" data-end="911">\u000a<p class="" data-start="842" data-end="911"><strong data-start="842" data-end="880">Slider en polyuréthane remplaçable</strong> : idéal pour un usage sportif.</p>\u000a</li>\u000a<li class="" data-start="912" data-end="999">\u000a<p class="" data-start="914" data-end="999"><strong data-start="914" data-end="947">Semelle intérieure OrthoLite®</strong> : confort longue durée et excellente respirabilité.</p>\u000a</li>\u000a<li class="" data-start="1000" data-end="1098">\u000a<p class="" data-start="1002" data-end="1098"><strong data-start="1002" data-end="1036">Semelle extérieure Groundtrax®</strong> : adhérence optimale sur toutes les surfaces, même mouillées.</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="1100" data-end="1271">Les <strong data-start="1104" data-end="1119">TCX RO4D WP</strong> sont le choix parfait pour les motards qui veulent une botte <strong data-start="1181" data-end="1222">technique, protectrice et imperméable</strong>, aussi efficace sur route qu’en usage quotidien.</p>\u000a'),unistr('<p>TCX R04D WP BLACK/RED</p>\u000a'),31,770,1899.0,1199.0,NULL,NULL,'published','TCX R04D WP BLACK/RED',unistr('<p>TCX R04D WP BLACK/RED</p>\u000a'),474,'2026-06-20 14:09:27',0,1,0,0);
INSERT INTO products VALUES(395,'BOTTES TCX HUB WATERPROOF NOIR','bottes-hub-waterproof-noir',unistr('<div class="short-description-section">Bottines de touring dotées d’une membrane imperméable en T-DRY. Un modèle qui allie protection, confort et polyvalence.</div>\u000a<div class="long-description-toggle hide-mobile"></div>\u000a<div>Les <strong>Hub Waterproof</strong> sont des bottes de moto semi-montantes, imperméables et respirantes, garantissant protection, polyvalence et confort de conduite. La <strong>membrane imperméable en T-DRY</strong>permet aux Hub Waterproof d’être utilisées même sous la pluie et par mauvais temps, tandis que la semelle de propreté OrthoLite® les rend respirantes et améliore le confort par temps chaud. La tige est fabriquée en cuir bycast et présente une coupe « low cut » afin de permettre un chaussant rapide et facile. Elle est construite en microfibre souple et équipée de soufflets rembourrés à l’avant et à l’arrière pour augmenter le confort et favoriser la flexibilité. La protection certifiée maximale est assurée par les<strong> renforts au niveau des malléoles, du tibia, du bout et du talon </strong>ainsi que par le <strong>protège-sélecteur en polyuréthane thermoplastique</strong> et par l’insert réfléchissant à l’arrière. La semelle extérieure en caoutchouc résistant à l’usure présente différentes épaisseurs, garantissant une stabilité et une sécurité de conduite maximales ainsi qu’une adhérence optimale même en cas de pluie. La fermeture est très facile grâce à la bande en velcro avec micro-injections ; de plus, la boucle au niveau du cou-de-pied permet d’ajuster parfaitement le chaussant, respectant ainsi l’ergonomie du pied.</div>\u000a'),unistr('<p><a href="https://motopaco.ma/">BOTTES HUB WATERPROOF NOIR</a></p>\u000a'),52,770,1799.0,1099.0,NULL,NULL,'published','BOTTES TCX HUB WATERPROOF NOIR',unistr('<p><a href="https://motopaco.ma/">BOTTES HUB WATERPROOF NOIR</a></p>\u000a'),95,'2026-06-20 14:09:28',0,0,0,0);
INSERT INTO products VALUES(396,'TCX R04D WP – BLACK/WHITE','tcx-r04d-wp-black-white',unistr('<h3 class="" data-start="112" data-end="168">TCX RO4D WP – Bottes Moto Sport-Touring Imperméables</h3>\u000a<p class="" data-start="170" data-end="429">Conçues pour les motards qui recherchent un équilibre idéal entre <strong data-start="236" data-end="260">performance sportive</strong>, <strong data-start="262" data-end="285">confort de conduite</strong> et <strong data-start="289" data-end="304">polyvalence</strong>, les <strong data-start="310" data-end="325">TCX RO4D WP</strong> sont des bottes à la fois techniques, protectrices et adaptées à toutes les conditions météorologiques.</p>\u000a<p class="" data-start="431" data-end="465"><strong data-start="431" data-end="465">Caractéristiques principales :</strong></p>\u000a<ul data-start="467" data-end="1098">\u000a<li class="" data-start="467" data-end="544">\u000a<p class="" data-start="469" data-end="544"><strong data-start="469" data-end="499">Membrane T-Dry imperméable</strong> : garde vos pieds au sec par tous les temps.</p>\u000a</li>\u000a<li class="" data-start="545" data-end="624">\u000a<p class="" data-start="547" data-end="624"><strong data-start="547" data-end="579">Tige en microfibre technique</strong> : souple, légère et résistante à l''abrasion.</p>\u000a</li>\u000a<li class="" data-start="625" data-end="742">\u000a<p class="" data-start="627" data-end="742"><strong data-start="627" data-end="652">Renforts stratégiques</strong> : protections intégrées aux malléoles, talon, pointe et tibia pour une sécurité optimale.</p>\u000a</li>\u000a<li class="" data-start="743" data-end="839">\u000a<p class="" data-start="745" data-end="839"><strong data-start="745" data-end="789">Fermeture par zip latéral + bande Velcro</strong> : facilité d’enfilage et ajustement personnalisé.</p>\u000a</li>\u000a<li class="" data-start="840" data-end="911">\u000a<p class="" data-start="842" data-end="911"><strong data-start="842" data-end="880">Slider en polyuréthane remplaçable</strong> : idéal pour un usage sportif.</p>\u000a</li>\u000a<li class="" data-start="912" data-end="999">\u000a<p class="" data-start="914" data-end="999"><strong data-start="914" data-end="947">Semelle intérieure OrthoLite®</strong> : confort longue durée et excellente respirabilité.</p>\u000a</li>\u000a<li class="" data-start="1000" data-end="1098">\u000a<p class="" data-start="1002" data-end="1098"><strong data-start="1002" data-end="1036">Semelle extérieure Groundtrax®</strong> : adhérence optimale sur toutes les surfaces, même mouillées.</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="1100" data-end="1271">Les <strong data-start="1104" data-end="1119">TCX RO4D WP</strong> sont le choix parfait pour les motards qui veulent une botte <strong data-start="1181" data-end="1222">technique, protectrice et imperméable</strong>, aussi efficace sur route qu’en usage quotidien.</p>\u000a'),unistr('<p>TCX R04D WP – BLACK/WHITE</p>\u000a'),52,770,1899.0,1199.0,NULL,NULL,'published','TCX R04D WP – BLACK/WHITE',unistr('<p>TCX R04D WP – BLACK/WHITE</p>\u000a'),473,'2026-06-20 14:09:28',0,1,0,0);
INSERT INTO products VALUES(397,'TCX ZETA WP - BLACK','tcx-zeta-wp-black',unistr('<h3 class="" data-start="128" data-end="183">TCX Zeta WP – Chaussures Moto Urbaines Imperméables</h3>\u000a<p class="" data-start="185" data-end="434">Alliant style sportif, confort de marche et protection optimale, les <strong data-start="254" data-end="269">TCX Zeta WP</strong> sont conçues pour les motards urbains exigeants. Avec leur design compact et moderne, elles sont idéales pour une utilisation quotidienne, en ville comme sur route.</p>\u000a<p class="" data-start="436" data-end="470"><strong data-start="436" data-end="470">Caractéristiques principales :</strong></p>\u000a<ul data-start="472" data-end="1087">\u000a<li class="" data-start="472" data-end="570">\u000a<p class="" data-start="474" data-end="570"><strong data-start="474" data-end="504">Membrane T-Dry imperméable</strong> : garde vos pieds au sec quelles que soient les conditions météo.</p>\u000a</li>\u000a<li class="" data-start="571" data-end="635">\u000a<p class="" data-start="573" data-end="635"><strong data-start="573" data-end="606">Tige en microfibre résistante</strong> : souple, légère et durable.</p>\u000a</li>\u000a<li class="" data-start="636" data-end="738">\u000a<p class="" data-start="638" data-end="738"><strong data-start="638" data-end="657">Renforts ciblés</strong> : protections au niveau des malléoles, talon et pointe pour une sécurité accrue.</p>\u000a</li>\u000a<li class="" data-start="739" data-end="842">\u000a<p class="" data-start="741" data-end="842"><strong data-start="741" data-end="764">Fermeture sécurisée</strong> : lacets avec bande Velcro pour un ajustement parfait et un maintien optimal.</p>\u000a</li>\u000a<li class="" data-start="843" data-end="930">\u000a<p class="" data-start="845" data-end="930"><strong data-start="845" data-end="878">Semelle intérieure OrthoLite®</strong> : confort longue durée et excellente respirabilité.</p>\u000a</li>\u000a<li class="" data-start="931" data-end="990">\u000a<p class="" data-start="933" data-end="990"><strong data-start="933" data-end="957">Insert réfléchissant</strong> : meilleure visibilité nocturne.</p>\u000a</li>\u000a<li class="" data-start="991" data-end="1087">\u000a<p class="" data-start="993" data-end="1087"><strong data-start="993" data-end="1047">Semelle extérieure en caoutchouc à haute adhérence</strong> : parfaite pour tous types de surfaces.</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="1089" data-end="1251">Disponibles en plusieurs coloris, les TCX Zeta WP sont le choix parfait pour les motards à la recherche de polyvalence sans compromis sur la sécurité ni le style.</p>\u000a'),unistr('<p>TCX ZETA WP &#8211; BLACK</p>\u000a'),52,770,0.0,NULL,NULL,NULL,'published','TCX ZETA WP - BLACK',unistr('<p>TCX ZETA WP &#8211; BLACK</p>\u000a'),492,'2026-06-20 14:09:29',0,1,0,0);
INSERT INTO products VALUES(398,'TCX – ZETA WP – BLACK/RED','tcx-zeta-wp-black-red',unistr('<h3 class="" data-start="128" data-end="183">TCX Zeta WP – Chaussures Moto Urbaines Imperméables</h3>\u000a<p class="" data-start="185" data-end="434">Alliant style sportif, confort de marche et protection optimale, les <strong data-start="254" data-end="269">TCX Zeta WP</strong> sont conçues pour les motards urbains exigeants. Avec leur design compact et moderne, elles sont idéales pour une utilisation quotidienne, en ville comme sur route.</p>\u000a<p class="" data-start="436" data-end="470"><strong data-start="436" data-end="470">Caractéristiques principales :</strong></p>\u000a<ul data-start="472" data-end="1087">\u000a<li class="" data-start="472" data-end="570">\u000a<p class="" data-start="474" data-end="570"><strong data-start="474" data-end="504">Membrane T-Dry imperméable</strong> : garde vos pieds au sec quelles que soient les conditions météo.</p>\u000a</li>\u000a<li class="" data-start="571" data-end="635">\u000a<p class="" data-start="573" data-end="635"><strong data-start="573" data-end="606">Tige en microfibre résistante</strong> : souple, légère et durable.</p>\u000a</li>\u000a<li class="" data-start="636" data-end="738">\u000a<p class="" data-start="638" data-end="738"><strong data-start="638" data-end="657">Renforts ciblés</strong> : protections au niveau des malléoles, talon et pointe pour une sécurité accrue.</p>\u000a</li>\u000a<li class="" data-start="739" data-end="842">\u000a<p class="" data-start="741" data-end="842"><strong data-start="741" data-end="764">Fermeture sécurisée</strong> : lacets avec bande Velcro pour un ajustement parfait et un maintien optimal.</p>\u000a</li>\u000a<li class="" data-start="843" data-end="930">\u000a<p class="" data-start="845" data-end="930"><strong data-start="845" data-end="878">Semelle intérieure OrthoLite®</strong> : confort longue durée et excellente respirabilité.</p>\u000a</li>\u000a<li class="" data-start="931" data-end="990">\u000a<p class="" data-start="933" data-end="990"><strong data-start="933" data-end="957">Insert réfléchissant</strong> : meilleure visibilité nocturne.</p>\u000a</li>\u000a<li class="" data-start="991" data-end="1087">\u000a<p class="" data-start="993" data-end="1087"><strong data-start="993" data-end="1047">Semelle extérieure en caoutchouc à haute adhérence</strong> : parfaite pour tous types de surfaces.</p>\u000a</li>\u000a</ul>\u000a<p class="" data-start="1089" data-end="1251">Disponibles en plusieurs coloris, les TCX Zeta WP sont le choix parfait pour les motards à la recherche de polyvalence sans compromis sur la sécurité ni le style.</p>\u000a'),unistr('<p>TCX – ZETA WP – BLACK/RED</p>\u000a'),31,770,0.0,NULL,NULL,NULL,'published','TCX – ZETA WP – BLACK/RED',unistr('<p>TCX – ZETA WP – BLACK/RED</p>\u000a'),496,'2026-06-20 14:09:29',0,1,0,0);
INSERT INTO products VALUES(399,'TCX BOOTS R04D AIR/BLACK Baskets','tcx-boots-r04d-air-baskets',unistr('<h2 class="product-sheet__description-title">Description complète Baskets RO4D Air</h2>\u000a<div class="product-sheet__description-full"></div>\u000a<div class="product-sheet__description-aside">\u000a<div class="brand-logo" data-v-f2918154="" data-v-f5765882=""><span class="brand-logo__link link" data-v-f5765882=""><a class="link__content" href="https://www.motoblouz.com/en/brand/tcx-boots.html"><picture class="mbz-imgproxy-picture brand-logo__link__picture" data-v-f5765882="" data-v-46947508=""><img src="https://media-imgproxy.motoblouz.com/_/rs100h/images/marques/TCX_Boots_big.png" srcset="//media-imgproxy.motoblouz.com/_/rs100h/images/marques/TCX_Boots_big.png, //media-imgproxy.motoblouz.com/_/rs100hx2/images/marques/TCX_Boots_big.png 3x" alt="Logo TCX Boots" height="100" data-v-46947508="" /></picture></a></span></div>\u000a<div class="highlight-features" data-v-f2918154="" data-v-fc2306d6="">\u000a<div class="highlight-features__top-side" data-v-fc2306d6="">\u000a<div class="short-description highlight-features__top-side__short-description" data-v-fc2306d6="" data-v-0fa1fff6="">These men''''s motorcycle sneakers feature sporty lines and large Mesh panels to keep your feet cool on hot days!</div>\u000a</div>\u000a</div>\u000a<div class="description-tab__features" data-v-f2918154="">\u000a<div class="product-features" data-v-f2918154="" data-v-e6b1c23a="">\u000a<div class="product-features__heading" data-v-e6b1c23a="">Product details <span class="visible-md-up" data-v-e6b1c23a="">:</span></div>\u000a<div data-v-e6b1c23a="">\u000a<p>TCX offers you its R04D AIR ventilated men''''s motorcycle sneakers:</p>\u000a<h3>Material:</h3>\u000a<ul>\u000a<li>Mesh upper with thermofusible coating for high abrasion resistance</li>\u000a<li>Large Mesh side panels for optimum ventilation.</li>\u000a</ul>\u000a<h3>Protections:</h3>\u000a<ul>\u000a<li>Reinforced malleoli with D3O® insert</li>\u000a<li>Reinforced tip</li>\u000a<li>Reinforced heel</li>\u000a<li>Bycast selector guard</li>\u000a</ul>\u000a<h3>The "+":</h3>\u000a<ul>\u000a<li>Lace and velcro closure</li>\u000a<li>Gaiter for storing laces</li>\u000a<li>OrthoLite® footbed for long-lasting cushioning and breathability</li>\u000a<li>Groundtrax® outsole, abrasion-resistant rubber for excellent stability</li>\u000a<li>Reflective inserts for optimum visibility</li>\u000a</ul>\u000a</div>\u000a</div>\u000a</div>\u000a</div>\u000a'),unistr('<p>TCX BOOTS R04D AIR Baskets</p>\u000a'),52,770,1899.0,1199.0,NULL,NULL,'published','TCX BOOTS R04D AIR/BLACK Baskets',unistr('<p>TCX BOOTS R04D AIR Baskets</p>\u000a'),481,'2026-06-20 14:09:29',0,1,0,0);
INSERT INTO products VALUES(400,'TCX BOOTS R04D AIR – BLACK/RED','tcx-baskets-ro4d-air-noir-rouge',unistr('<p>Certified ventilated motorcycle shoes. motard Maroc. Maximum protection in the saddle and greater practicality in hotter climates. motard Maroc. TCX <strong>R04D AIR</strong> are highly breathable motorcycle shoes that guarantee certified protection and versatility in all situations, from urban transfers to short trips out of town.</p>\u000a<div class="product-sheet__description-full">\u000a<h3>Conception</h3>\u000a<ul>\u000a<li>Construction en mesh avec revêtement thermofusible.</li>\u000a</ul>\u000a<h3>Confort / Ergonomie</h3>\u000a<ul>\u000a<li>Empiècements latéraux en maille apportant une ventilation optimale.</li>\u000a<li>Semelle extérieure en caoutchouc Groundtrax®.</li>\u000a<li>Assise plantaire Ortholite assurant un amorti durable ainsi qu''un haut niveau de respirabilité.</li>\u000a<li>Fermeture par laçage et patte de serrage velcro permettant un ajustement sûr et personnalisé.</li>\u000a<li>Lacets pouvant être dissimulés sous une guêtre élastiquée.</li>\u000a</ul>\u000a<h3>Protection / Sécurité</h3>\u000a<ul>\u000a<li>Protège-sélecteur Bycast.</li>\u000a<li>Renforts aux orteils et au talon.</li>\u000a<li>Renforts D3O® aux chevilles.</li>\u000a<li><strong>Les baskets moto TCX RO4D Air</strong> sont certifiées CE comme EPI.</li>\u000a</ul>\u000a<h3>Autres détails</h3>\u000a<ul>\u000a<li>Inserts réfléchissants.</li>\u000a</ul>\u000a</div>\u000a<div class="product-sheet__description-aside">\u000a<table class="table-associative mb-40">\u000a<tbody>\u000a<tr>\u000a<th>Genre</th>\u000a<td>\u000a<ul>\u000a<li class="js-genders">Homme</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th>Style</th>\u000a<td>\u000a<ul>\u000a<li>Sport - Roadster</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th>matière</th>\u000a<td>\u000a<ul>\u000a<li>textile</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th>étanchéité</th>\u000a<td>\u000a<ul>\u000a<li>non</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th>fermeture</th>\u000a<td>\u000a<ul>\u000a<li>lacets</li>\u000a<li>velcro</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th>sliders</th>\u000a<td>\u000a<ul>\u000a<li>non</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th>renfort malléole</th>\u000a<td>\u000a<ul>\u000a<li>oui</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th>renfort sélecteur</th>\u000a<td>\u000a<ul>\u000a<li>oui</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th>Homologation CE EPI - EN13634</th>\u000a<td>\u000a<ul>\u000a<li>Oui</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th>garantie</th>\u000a<td>\u000a<ul>\u000a<li>2 ans</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a</tbody>\u000a</table>\u000a</div>\u000a'),unistr('<p><a href="https://motopaco.ma/">TCX BOOTS R04D AIR – BLACK/RED</a></p>\u000a'),52,770,1199.0,1199.0,NULL,NULL,'published','TCX BOOTS R04D AIR – BLACK/RED',unistr('<p><a href="https://motopaco.ma/">TCX BOOTS R04D AIR – BLACK/RED</a></p>\u000a'),105,'2026-06-20 14:09:29',0,0,0,0);
INSERT INTO products VALUES(401,'TCX - Bottes X-Blast Noir','tcx-bottes-x-blast-noir',unistr('<h2 class="product-sheet__description-title">Description complète Bottes X-Blast</h2>\u000a<div class="product-sheet__description-full">\u000a<ul>\u000a<li><strong>Bottes TCX</strong> X-Blast.</li>\u000a<li><strong>Bottes motocross homme</strong>.</li>\u000a</ul>\u000a<h3 class="h3">Conception</h3>\u000a<ul>\u000a<li>Microfibre hautement résistante à l’usure et coque en PU.</li>\u000a<li>Protection interne contre la chaleur en microfibre.</li>\u000a</ul>\u000a<h3 class="h3">Confort / Ergonomie</h3>\u000a<ul>\u000a<li>Doublure en tissu respirant Air Tech.</li>\u000a<li>Semelle anatomique.</li>\u000a<li>Fermeture par velcro.</li>\u000a<li>4 boucles en polyuréthane réglables et remplaçables au design ergonomique permettant un ajustement sûr et personnalisé.</li>\u000a</ul>\u000a<h3 class="h3">Protection / Sécurité :</h3>\u000a<ul>\u000a<li>Renfort tibia.</li>\u000a<li>Renfort talon et cheville en polyuréthane.</li>\u000a<li>Rembourrage frontale.</li>\u000a<li>Protège sélecteur en polyuréthane.</li>\u000a<li>Fer avant en acier.</li>\u000a<li>Semelle externe Goodyear résistante à l’usure.</li>\u000a<li><strong>Les bottes moto TCX X-Blast</strong> sont homologuées CE comme EPI.</li>\u000a<li>TCX - Bottes X-Blast Noir</li>\u000a</ul>\u000a</div>\u000a<div class="product-sheet__description-aside">\u000a<table class="table-associative mb-40" style="height: 720px;" width="735">\u000a<tbody>\u000a<tr>\u000a<th style="text-align: left;">Genre</th>\u000a<td style="text-align: left;">\u000a<ul>\u000a<li class="js-genders">Homme</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th style="text-align: left;">Style</th>\u000a<td>\u000a<ul>\u000a<li style="text-align: left;">cross</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th style="text-align: left;">matière</th>\u000a<td style="text-align: left;">\u000a<ul>\u000a<li>textile</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th style="text-align: left;">étanchéité</th>\u000a<td>\u000a<ul>\u000a<li style="text-align: left;">non</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th style="text-align: left;">fermeture</th>\u000a<td>\u000a<ul>\u000a<li style="text-align: left;">micrométrique</li>\u000a<li style="text-align: left;">velcro</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th style="text-align: left;">renfort malléole</th>\u000a<td>\u000a<ul>\u000a<li style="text-align: left;">oui</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th style="text-align: left;">renfort sélecteur</th>\u000a<td>\u000a<ul>\u000a<li style="text-align: left;">oui</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th style="text-align: left;">renfort tibia</th>\u000a<td>\u000a<ul>\u000a<li style="text-align: left;">oui</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a<tr>\u000a<th style="text-align: left;">garantie</th>\u000a<td>\u000a<ul>\u000a<li style="text-align: left;">2 ans</li>\u000a</ul>\u000a</td>\u000a</tr>\u000a</tbody>\u000a</table>\u000a</div>\u000a'),unistr('<p>TCX &#8211; Bottes X-Blast Noir</p>\u000a'),52,770,2390.0,1790.0,NULL,NULL,'published','TCX - Bottes X-Blast Noir',unistr('<p>TCX &#8211; Bottes X-Blast Noir</p>\u000a'),119,'2026-06-20 14:09:30',0,0,0,0);
